NAmanage._gmx31 = NAmanage._gmx31 or function(bytes, seed)
	local out = {}
	seed = tonumber(seed) or 0
	for i = 1, #bytes do
		local key = ((seed + (i * 3)) % 11) + 17
		out[i] = string.char((tonumber(bytes[i]) or 0) - key)
	end
	return table.concat(out)
end
