NAmanage.NA_getCloneRef = NAmanage.NA_getCloneRef or function()
	local ref = (type(cloneref) == "function") and cloneref or opt.NA_cloneref
	if type(ref) == "function" then
		opt.NA_cloneref = ref
		return ref
	end
	return nil
end
NAmanage.NA_getServiceRef = function(name)
	local ref = NAmanage.NA_getCloneRef()
	if ref then
		return __lt.cs(name, ref)
	end
	return __lt.gs(name)
end
NAmanage.NA_getServiceRaw = NAmanage.NA_getServiceRaw or function(name)
	return __lt.gs(name)
end

local NA_SRV = setmetatable({}, {
	__index = function(self, name)
		local ok, svc = pcall(NAmanage.NA_getServiceRef, name)
		if ok and svc then
			rawset(self, name, svc)
			return svc
		end
	end
})

local NA_SRV_RAW = setmetatable({}, {
	__index = function(self, name)
		local ok, svc = pcall(NAmanage.NA_getServiceRaw, name)
		if ok and svc then
			rawset(self, name, svc)
			return svc
		end
	end
})

function SafeGetService(name, useCloneRef)
	if useCloneRef == false then
		return NA_SRV_RAW[name]
	end
	local cached = rawget(NA_SRV, name)
	local ref = NAmanage.NA_getCloneRef and NAmanage.NA_getCloneRef() or nil
	if cached ~= nil and (not ref or cached ~= NA_SRV_RAW[name]) then
		return cached
	end
	local ok, svc = pcall(NAmanage.NA_getServiceRef, name)
	if ok and svc then
		rawset(NA_SRV, name, svc)
		return svc
	end
	return NA_SRV[name]
end

NAmanage.SafeCloneRef = NAmanage.SafeCloneRef or function(value)
	if value == nil then
		return nil
	end
	local ref = NAmanage.NA_getCloneRef and NAmanage.NA_getCloneRef() or nil
	if type(ref) == "function" then
		local ok, cloned = pcall(ref, value)
		if ok and cloned ~= nil then
			return cloned
		end
	end
	return value
end

NAmanage.GetMouse = NAmanage.GetMouse or function(plr)
	if not plr then
		local ps = SafeGetService and SafeGetService("Players") or nil
		plr = ps and ps.LocalPlayer or nil
	end
	if not plr then
		return nil
	end
	local ref = NAmanage.NA_getCloneRef and NAmanage.NA_getCloneRef() or nil
	if type(ref) == "function" then
		local ok, mouse = pcall(function()
			return ref(plr:GetMouse())
		end)
		if ok and mouse then
			return mouse
		end
	end
	local ok, mouse = pcall(function()
		return plr:GetMouse()
	end)
	if ok and mouse then
		return mouse
	end
	return nil
end

NAmanage.uiObj = NAmanage.uiObj or function(v, seen)
	if typeof(v) == "Instance" and v:IsA("ScreenGui") then
		return v
	end

	if type(v) == "function" then
		local ok, res = pcall(v)
		if ok then
			return NAmanage.uiObj(res, seen)
		end
		return nil
	end

	if type(v) == "table" then
		seen = seen or {}
		if seen[v] then
			return nil
		end
		seen[v] = true

		local keys = {
			"ScreenGui",
			"screenGui",
			"Gui",
			"gui",
			"UI",
			"ui",
			"Instance",
			"instance",
		}

		for i = 1, #keys do
			local gui = NAmanage.uiObj(rawget(v, keys[i]), seen)
			if gui then
				return gui
			end
		end
	end

	return nil
end

NAmanage.getUI = NAmanage.getUI or function()
	local gui = NAmanage.uiObj(NAStuff and NAStuff.NASCREENGUI)
	if gui then
		return gui
	end

	if _na_env then
		gui = NAmanage.uiObj(rawget(_na_env, "NA_UI_INSTANCE"))
			or NAmanage.uiObj(rawget(_na_env, "NA_RAW_UI"))
			or NAmanage.uiObj(rawget(_na_env, "NA_UI"))
		if gui then
			return gui
		end
	end

	if _na_shared then
		gui = NAmanage.uiObj(rawget(_na_shared, "NA_UI_INSTANCE"))
			or NAmanage.uiObj(rawget(_na_shared, "NA_RAW_UI"))
			or NAmanage.uiObj(rawget(_na_shared, "NA_UI"))
		if gui then
			return gui
		end
	end

	return nil
end

NAmanage.NARegisterUI=function(gui)
	gui = NAmanage.uiObj(gui)
	if not gui then
		return false
	end

	NAStuff.NASCREENGUI = gui
	NAStuff.uiBootHidden = true

	pcall(function()
		gui.Enabled = false
	end)

	local function get()
		if type(checkcaller) == "function" and not checkcaller() then
			return nil
		end
		return NAStuff.NASCREENGUI
	end

	if _na_env then
		_na_env.NAUILOADEDORSUM = true
		_na_env.NA_UI_INSTANCE = gui
		_na_env.NA_RAW_UI = gui
		_na_env.NA_UI = get
	end

	if _na_shared then
		_na_shared.NAUILOADEDORSUM = true
		_na_shared.NA_UI_INSTANCE = gui
		_na_shared.NA_RAW_UI = gui
		_na_shared.NA_UI = get
	end

	return true
end

NAmanage.waitForPlay=function()
	local function ready()
		local localPlayer = SafeGetService("Players").LocalPlayer
		if not localPlayer or not localPlayer.Parent then
			return nil
		end
		local placeId = tonumber(game.PlaceId) or 0
		local gameId = tonumber(game.GameId) or 0
		if placeId == 0 and gameId == 0 then
			return nil
		end
		return localPlayer
	end

	local function safeReady()
		local ok, result = pcall(ready)
		if ok then
			return result
		else
			return nil
		end
	end

	local localPlayer = safeReady()
	if localPlayer then
		return localPlayer
	end

	while not localPlayer do
		Wait(0.1)
		localPlayer = safeReady()
	end

	return localPlayer
end

