NAlib = NAlib or {}
NAStuff.conns = (type(NAStuff.conns) == "table") and NAStuff.conns or {}
NAStuff.prCnt = tonumber(NAStuff.prCnt) or 0

NAmanage.prnCon = NAmanage.prnCon or function(name)
	local conns = NAStuff.conns
	if type(conns) ~= "table" then
		conns = {}
		NAStuff.conns = conns
		return 0
	end

	local bucket = conns[name]
	if type(bucket) ~= "table" then
		return 0
	end

	local write = 1
	for i = 1, #bucket do
		local conn = bucket[i]
		local keep = NAmanage.isLiveConnection(conn)
		if keep then
			bucket[write] = conn
			write += 1
		end
	end

	for i = write, #bucket do
		bucket[i] = nil
	end

	local alive = write - 1
	if alive <= 0 then
		conns[name] = nil
		return 0
	end
	return alive
end

NAlib.connect = function(name, conn)
	if not name or not conn then
		return conn
	end
	local conns = NAStuff.conns
	if type(conns) ~= "table" then
		conns = {}
		NAStuff.conns = conns
	end
	NAmanage.prnCon(name)
	local bucket = conns[name]
	if type(bucket) ~= "table" then
		bucket = {}
		conns[name] = bucket
	end
	table.insert(bucket, conn)
	NAStuff.prCnt = (tonumber(NAStuff.prCnt) or 0) + 1
	if NAStuff.prCnt % 128 == 0 then
		for key in pairs(conns) do
			NAmanage.prnCon(key)
		end
	end
	return conn
end

NAlib.disconnect = function(name)
	if not name then
		return
	end
	local conns = NAStuff.conns
	if type(conns) ~= "table" then
		NAStuff.conns = {}
		return
	end
	local bucket = conns[name]
	if type(bucket) == "table" then
		for _, conn in ipairs(bucket) do
			pcall(function()
				if conn and type(conn.Disconnect) == "function" then
					conn:Disconnect()
				end
			end)
		end
		conns[name] = nil
	end
end

NAlib.isConnected = function(name)
	if not name then
		return false
	end
	return NAmanage.prnCon(name) > 0
end

NAmanage.countMapKeys = NAmanage.countMapKeys or function(map, hardLimit)
	if type(map) ~= "table" then
		return 0
	end
	local count = 0
	local limit = tonumber(hardLimit)
	if limit ~= nil then
		limit = math.max(1, math.floor(limit))
	end
	for _ in pairs(map) do
		count += 1
		if limit and count >= limit then
			break
		end
	end
	return count
end

NAmanage.prnAllCon = NAmanage.prnAllCon or function(limit)
	local conns = NAStuff.conns
	if type(conns) ~= "table" then
		NAStuff._prnAllConCursor = nil
		return 0
	end
	local maxKeys = tonumber(limit)
	if maxKeys ~= nil then
		maxKeys = math.max(1, math.floor(maxKeys))
	end
	local checked = 0

	local function nextConnKey(afterKey)
		if afterKey == nil then
			return next(conns)
		end
		local ok, result = pcall(next, conns, afterKey)
		if ok then
			return result
		end
		return next(conns)
	end

	if maxKeys == nil then
		for key in pairs(conns) do
			NAmanage.prnCon(key)
			checked += 1
		end
		NAStuff._prnAllConCursor = nil
		return checked
	end

	local cursor = rawget(NAStuff, "_prnAllConCursor")
	local key = nextConnKey(cursor)
	if key == nil then
		cursor = nil
		key = nextConnKey(nil)
	end

	while key ~= nil and checked < maxKeys do
		NAmanage.prnCon(key)
		checked += 1
		cursor = key
		key = nextConnKey(key)
		if key == nil and checked < maxKeys then
			cursor = nil
			key = nextConnKey(nil)
		end
	end

	NAStuff._prnAllConCursor = cursor
	return checked
end

NAmanage.pruneChatLogState = NAmanage.pruneChatLogState or function()
	local state = NAStuff and NAStuff.ChatLogState
	if type(state) ~= "table" then
		return
	end
	if type(state.entries) == "table" then
		NAmanage.pruneInstanceArray(state.entries)
		local maxMessages = tonumber(state.maxMessages) or tonumber(NAmanage and NAmanage.jlCfg and NAmanage.jlCfg.ChatMaxMessages) or 200
		maxMessages = math.max(20, math.floor(maxMessages))
		while #state.entries > maxMessages do
			local old = table.remove(state.entries, 1)
			if typeof(old) == "Instance" and old.Parent then
				pcall(function()
					old:Destroy()
				end)
			end
		end
	end
end

NAmanage.pruneAdminChatRainbow = NAmanage.pruneAdminChatRainbow or function()
	local state = NAStuff
	if type(state) ~= "table" then
		return
	end
	if type(state.AdminChatRainbowMessages) == "table" then
		NAmanage.pruneInstanceArray(state.AdminChatRainbowMessages)
		if #state.AdminChatRainbowMessages == 0 and state.AdminChatRainbowConnection then
			pcall(function()
				state.AdminChatRainbowConnection:Disconnect()
			end)
			state.AdminChatRainbowConnection = nil
		end
	end
end

NAmanage.safeConnect = NAmanage.safeConnect or function(sig, fn)
	if sig == nil or type(fn) ~= "function" then
		return nil
	end
	local ok, conn = pcall(function()
		return sig:Connect(fn)
	end)
	if ok then
		return conn
	end
	return nil
end

NAmanage._evtHubDispatch = NAmanage._evtHubDispatch or function(handlers, inst)
	for _, rec in pairs(handlers or {}) do
		local fn = rec
		local filter = nil
		if type(rec) == "table" then
			fn = rec.fn
			filter = rec.filter
		end
		if type(fn) == "function" then
			local pass = true
			if type(filter) == "function" then
				local ok, allowed = pcall(filter, inst)
				pass = ok and allowed == true
			end
			if pass then
				pcall(fn, inst)
			end
		end
	end
end

NAmanage._evtHubHasInterested = NAmanage._evtHubHasInterested or function(handlers, inst)
	for _, rec in pairs(handlers or {}) do
		local fn = rec
		local filter = nil
		if type(rec) == "table" then
			fn = rec.fn
			filter = rec.filter
		end
		if type(fn) == "function" then
			if type(filter) == "function" then
				local ok, pass = pcall(filter, inst)
				if ok and pass then
					return true
				end
			else
				return true
			end
		end
	end
	return false
end

NAmanage._evtHubBudget = NAmanage._evtHubBudget or function(baseBudget, opts)
	local budget = math.max(1, math.floor(tonumber(baseBudget) or 120))
	local waitDelay = 0
	if NAmanage and NAmanage.lpProf then
		local cfg = type(opts) == "table" and opts or {}
		local ok, calcBudget, calcDelay = pcall(NAmanage.lpProf, budget, {
			delay = tonumber(cfg.delay) or 0,
			ldSc = tonumber(cfg.ldSc) or 0.4,
			ldDel = tonumber(cfg.ldDel) or 0.008,
		})
		if ok then
			if tonumber(calcBudget) then
				budget = math.max(1, math.floor(tonumber(calcBudget) or budget))
			end
			if tonumber(calcDelay) then
				waitDelay = math.max(0, tonumber(calcDelay) or 0)
			end
		end
	end
	return budget, waitDelay
end

NAmanage.rawDesc = NAmanage.rawDesc or function(root, className, opts)
	if typeof(root) ~= "Instance" then
		return {}
	end
	className = type(className) == "string" and className or "Instance"
	opts = type(opts) == "table" and opts or {}
	local out = {}
	local hard = tonumber(opts.hardLimit) or 0
	local budget = tonumber(opts.budget) or 1200
	local delayTime = tonumber(opts.delay) or 0
	local function add(inst)
		if not inst then
			return false
		end
		if className == "Instance" then
			out[#out + 1] = inst
		else
			local ok, pass = pcall(function()
				return inst:IsA(className)
			end)
			if ok and pass then
				out[#out + 1] = inst
			end
		end
		return hard > 0 and #out >= hard
	end
	if opts.query ~= false and type(root.QueryDescendants) == "function" then
		local ok, list = pcall(function()
			return root:QueryDescendants(className)
		end)
		if ok and type(list) == "table" then
			for i = 1, #list do
				if add(list[i]) then
					break
				end
				if budget > 0 and i % budget == 0 then
					Wait(delayTime)
				end
			end
			return out
		end
	end
	if opts.native ~= false and type(root.GetDescendants) == "function" then
		local ok, list = pcall(function()
			return root:GetDescendants()
		end)
		if ok and type(list) == "table" then
			for i = 1, #list do
				if add(list[i]) then
					break
				end
				if budget > 0 and i % budget == 0 then
					Wait(delayTime)
				end
			end
			return out
		end
	end
	local stack = {}
	local okChildren, children = pcall(function()
		return root:GetChildren()
	end)
	if okChildren and type(children) == "table" then
		for i = #children, 1, -1 do
			stack[#stack + 1] = children[i]
		end
	end
	local steps = 0
	while #stack > 0 do
		local inst = stack[#stack]
		stack[#stack] = nil
		if inst then
			if add(inst) then
				break
			end
			local okCh, ch = pcall(function()
				return inst:GetChildren()
			end)
			if okCh and type(ch) == "table" then
				for i = #ch, 1, -1 do
					stack[#stack + 1] = ch[i]
				end
			end
		end
		steps += 1
		if budget > 0 and steps % budget == 0 then
			Wait(delayTime)
		end
	end
	return out
end

NAmanage.qDesc = NAmanage.qDesc or function(root, className, opts)
	if typeof(root) ~= "Instance" then
		return {}
	end
	className = type(className) == "string" and className or "Instance"
	opts = type(opts) == "table" and opts or {}
	if root == workspace and type(NAmanage.wsDescs) == "function" and opts.workspaceCache ~= false then
		local base = NAmanage.wsDescs()
		if className == "Instance" then
			return base
		end
		local out = {}
		local budget = tonumber(opts.budget) or 1600
		for i = 1, #base do
			local inst = base[i]
			if inst and inst.Parent then
				local ok, pass = pcall(function()
					return inst:IsA(className)
				end)
				if ok and pass then
					out[#out + 1] = inst
				end
			end
			if budget > 0 and i % budget == 0 then
				Wait(tonumber(opts.delay) or 0)
			end
		end
		return out
	end
	return NAmanage.rawDesc(root, className, opts)
end

NAmanage._wsHub = NAmanage._wsHub or nil

NAmanage._wsHubDispose = NAmanage._wsHubDispose or function(hub)
	hub = hub or NAmanage._wsHub
	if type(hub) ~= "table" then
		return
	end
	hub.alive = false
	if hub.cAdd then
		pcall(function()
			hub.cAdd:Disconnect()
		end)
		hub.cAdd = nil
	end
	if hub.cRem then
		pcall(function()
			hub.cRem:Disconnect()
		end)
		hub.cRem = nil
	end
	hub.added = {}
	hub.removing = {}
	hub.addCount = 0
	hub.remCount = 0
	hub.cacheLive = false
	hub.cache = {}
	hub.idx = {}
	hub.aQ = {}
	hub.rQ = {}
	hub.aSet = {}
	hub.rSet = {}
	hub.sQ = {}
	hub.aHead = 1
	hub.aTail = 0
	hub.rHead = 1
	hub.rTail = 0
	hub.sHead = 1
	hub.sTail = 0
	hub.qBusy = false
	hub.qKick = false
	hub.sBusy = false
	hub.cIdx = 1
	hub.cacheLastTouch = 0
	if NAmanage._wsHub == hub then
		NAmanage._wsHub = nil
	end
end

NAmanage._wsHubGet = NAmanage._wsHubGet or function()
	local cRoot = workspace
	local hub = NAmanage._wsHub
	if hub and hub.root == cRoot then
		return hub
	end

	if hub then
		NAmanage._wsHubDispose(hub)
	end

	hub = {
		root = cRoot,
		nextId = 0,
		added = {},
		removing = {},
		addCount = 0,
		remCount = 0,
		cache = {},
		idx = {},
		cacheLive = false,
		aQ = {},
		rQ = {},
		aSet = {},
		rSet = {},
		aHead = 1,
		aTail = 0,
		rHead = 1,
		rTail = 0,
		qBusy = false,
		qKick = false,
		sQ = {},
		sHead = 1,
		sTail = 0,
		sBusy = false,
		cIdx = 1,
		cacheLastTouch = 0,
		cAdd = nil,
		cRem = nil,
		alive = true,
	}

	local function addC(inst)
		if not (inst and inst.Parent) then
			return
		end
		if hub.idx[inst] then
			return
		end
		local n = #hub.cache + 1
		hub.cache[n] = inst
		hub.idx[inst] = n
	end

	local function remC(inst)
		local i = hub.idx[inst]
		if not i then
			return
		end
		local last = #hub.cache
		local lastInst = hub.cache[last]
		hub.cache[last] = nil
		if i ~= last then
			hub.cache[i] = lastInst
			if lastInst then
				hub.idx[lastInst] = i
			end
		end
		hub.idx[inst] = nil
	end

	local function scrub(limit)
		local n = #hub.cache
		if n == 0 then
			hub.cIdx = 1
			return
		end
		local i = hub.cIdx
		local steps = 0
		while steps < limit and n > 0 do
			if i > n then
				i = 1
				break
			end
			local inst = hub.cache[i]
			if not (inst and inst.Parent) then
				local lastInst = hub.cache[n]
				hub.cache[n] = nil
				n -= 1
				if i <= n then
					hub.cache[i] = lastInst
					if lastInst then
						hub.idx[lastInst] = i
					end
				end
				if inst then
					hub.idx[inst] = nil
				end
			else
				i += 1
			end
			steps += 1
		end
		hub.cIdx = i
	end

	local dispatch = NAmanage._evtHubDispatch
	local hasInterested = NAmanage._evtHubHasInterested

	local function runQ()
		if hub.qBusy or not hub.alive then
			return
		end
		hub.qBusy = true
		Spawn(function()
			while hub.alive and (hub.aHead <= hub.aTail or hub.rHead <= hub.rTail) do
				local budget, waitDelay = NAmanage._evtHubBudget(140, {
					delay = 0,
					ldSc = 0.4,
					ldDel = 0.008,
				})
				while budget > 0 and hub.alive and (hub.aHead <= hub.aTail or hub.rHead <= hub.rTail) do
					if hub.rHead <= hub.rTail then
						local inst = hub.rQ[hub.rHead]
						hub.rQ[hub.rHead] = nil
						hub.rHead += 1
						if inst then
							hub.rSet[inst] = nil
							dispatch(hub.removing, inst)
						end
					elseif hub.aHead <= hub.aTail then
						local inst = hub.aQ[hub.aHead]
						hub.aQ[hub.aHead] = nil
						hub.aHead += 1
						if inst then
							hub.aSet[inst] = nil
							dispatch(hub.added, inst)
						end
					end
					budget -= 1
				end
				if hub.cacheLive then
					scrub(32)
				end
				if waitDelay > 0 then
					Wait(waitDelay)
				else
					Wait()
				end
			end
			hub.aQ = {}
			hub.rQ = {}
			hub.aHead = 1
			hub.aTail = 0
			hub.rHead = 1
			hub.rTail = 0
			hub.qBusy = false
		end)
	end

	local function kickQ()
		if hub.qKick then
			return
		end
		hub.qKick = true
		Defer(function()
			hub.qKick = false
			runQ()
		end)
	end

	local function qEvt(kind, inst)
		if not (hub.alive and inst) then
			return
		end
		if kind == "add" then
			if (hub.addCount or 0) <= 0 then
				return
			end
			if not hasInterested(hub.added, inst) then
				return
			end
			if hub.aSet[inst] then
				return
			end
			hub.aSet[inst] = true
			hub.aTail += 1
			hub.aQ[hub.aTail] = inst
		else
			if (hub.remCount or 0) <= 0 then
				return
			end
			if not hasInterested(hub.removing, inst) then
				return
			end
			if hub.rSet[inst] then
				return
			end
			hub.rSet[inst] = true
			hub.rTail += 1
			hub.rQ[hub.rTail] = inst
		end
		kickQ()
	end

	local function runScan()
		if hub.sBusy or not hub.alive then
			return
		end
		hub.sBusy = true
		Spawn(function()
			while hub.alive and hub.sHead <= hub.sTail do
				local budget, waitDelay = NAmanage._evtHubBudget(90, {
					delay = 0,
					ldSc = 0.3,
					ldDel = 0.006,
				})
				while budget > 0 and hub.alive and hub.sHead <= hub.sTail do
					local inst = hub.sQ[hub.sHead]
					hub.sQ[hub.sHead] = nil
					hub.sHead += 1
					if inst and inst.Parent then
						addC(inst)
						local ch = inst:GetChildren()
						for i = 1, #ch do
							hub.sTail += 1
							hub.sQ[hub.sTail] = ch[i]
						end
					end
					budget -= 1
				end
				if waitDelay > 0 then
					Wait(waitDelay)
				else
					Wait()
				end
			end
			hub.sQ = {}
			hub.sHead = 1
			hub.sTail = 0
			hub.sBusy = false
		end)
	end

	if cRoot then
		hub.cAdd = NAmanage.safeConnect(cRoot.DescendantAdded, function(inst)
			if hub.cacheLive then
				addC(inst)
			end
			qEvt("add", inst)
		end)
		hub.cRem = NAmanage.safeConnect(cRoot.DescendantRemoving, function(inst)
			if hub.cacheLive then
				remC(inst)
			end
			qEvt("rem", inst)
		end)
	end

	NAmanage._wsHub = hub
	return hub
end

NAmanage.wsReleaseCache = NAmanage.wsReleaseCache or function(hub)
	hub = hub or NAmanage._wsHub
	if type(hub) ~= "table" then
		return false
	end
	if not hub.cacheLive then
		return false
	end
	hub.cacheLive = false
	hub.cache = {}
	hub.idx = {}
	hub.cIdx = 1
	hub.sQ = {}
	hub.sHead = 1
	hub.sTail = 0
	hub.cacheLastTouch = 0
	if (hub.addCount or 0) <= 0 and (hub.remCount or 0) <= 0 then
		NAmanage._wsHubDispose(hub)
	end
	return true
end

NAmanage.wsReleaseCacheIfIdle = NAmanage.wsReleaseCacheIfIdle or function(maxIdle)
	local hub = NAmanage._wsHub
	if type(hub) ~= "table" or not hub.cacheLive then
		return false
	end
	local idleLimit = tonumber(maxIdle)
	if idleLimit == nil then
		idleLimit = tonumber(NAStuff and NAStuff.WSCacheIdleSeconds) or 30
	end
	idleLimit = math.max(2, idleLimit)
	local lastTouch = tonumber(hub.cacheLastTouch) or 0
	if lastTouch <= 0 then
		return NAmanage.wsReleaseCache(hub)
	end
	if os.clock() - lastTouch < idleLimit then
		return false
	end
	return NAmanage.wsReleaseCache(hub)
end

NAmanage.wsDescs = NAmanage.wsDescs or function()
	local hub = NAmanage._wsHubGet()
	if not hub then
		return {}
	end
	if not hub.cacheLive then
		hub.cacheLive = true
		hub.cache = {}
		hub.idx = {}
		local root = hub.root
		local ok, descs = pcall(function()
			if root then
				return NAmanage.rawDesc(root, "Instance")
			end
			return {}
		end)
		if ok and descs then
			local n = 0
			for i = 1, #descs do
				local inst = descs[i]
				if inst and inst.Parent then
					n += 1
					hub.cache[n] = inst
					hub.idx[inst] = n
				end
			end
		end
		hub.cIdx = 1
	end
	hub.cacheLastTouch = os.clock()
	if hub.alive then
		local n = #hub.cache
		if n > 0 then
			local i = hub.cIdx
			if i > n then
				i = 1
			end
			local inst = hub.cache[i]
			if not (inst and inst.Parent) then
				local lastInst = hub.cache[n]
				hub.cache[n] = nil
				n -= 1
				if i <= n then
					hub.cache[i] = lastInst
					if lastInst then
						hub.idx[lastInst] = i
					end
				end
				if inst then
					hub.idx[inst] = nil
				end
			else
				hub.cIdx = i + 1
			end
		end
	end
	return hub.cache
end

NAmanage.fastDesc = NAmanage.fastDesc or function(root, className, opts)
	if typeof(root) ~= "Instance" then
		return {}
	end

	className = type(className) == "string" and className or "Instance"
	opts = type(opts) == "table" and opts or {}

	local match = type(opts.match) == "function" and opts.match or nil
	local hardLimit = tonumber(opts.hardLimit) or tonumber(opts.limit) or 0
	local source = {}

	if root == workspace then
		local hub = NAmanage._wsHub
		if type(hub) == "table" and hub.root == workspace and hub.cacheLive and type(hub.cache) == "table" then
			hub.cacheLastTouch = os.clock()
			source = hub.cache
		else
			local ok, descs = pcall(function()
				return workspace:GetDescendants()
			end)
			if ok and type(descs) == "table" then
				source = descs
			end
		end
	else
		local ok, descs = pcall(function()
			return root:GetDescendants()
		end)
		if ok and type(descs) == "table" then
			source = descs
		end
	end

	local out = {}
	for i = 1, #source do
		local inst = source[i]
		if inst and inst.Parent then
			local pass = className == "Instance"
			if not pass then
				local ok, isA = pcall(function()
					return inst:IsA(className)
				end)
				pass = ok and isA == true
			end

			if pass and (not match or match(inst)) then
				out[#out + 1] = inst
				if hardLimit > 0 and #out >= hardLimit then
					break
				end
			end
		end
	end

	return out
end

NAmanage.wsSub = NAmanage.wsSub or function(spec)
	spec = spec or {}
	local onAdd = type(spec.added) == "function" and spec.added or nil
	local onRem = type(spec.removing) == "function" and spec.removing or nil
	local addFilter = type(spec.filterAdded) == "function" and spec.filterAdded
		or (type(spec.filter) == "function" and spec.filter or nil)
	local remFilter = type(spec.filterRemoving) == "function" and spec.filterRemoving
		or (type(spec.filter) == "function" and spec.filter or nil)
	local noop = {
		Connected = false,
		Disconnect = function() end,
	}
	if not onAdd and not onRem then
		return noop
	end

	local hub = NAmanage._wsHubGet()
	hub.nextId += 1
	local id = hub.nextId
	if onAdd then
		hub.added[id] = addFilter and {
			fn = onAdd,
			filter = addFilter,
		} or onAdd
		hub.addCount = (hub.addCount or 0) + 1
	end
	if onRem then
		hub.removing[id] = remFilter and {
			fn = onRem,
			filter = remFilter,
		} or onRem
		hub.remCount = (hub.remCount or 0) + 1
	end

	local conn = {
		Connected = true,
	}
	function conn:Disconnect()
		if not self.Connected then
			return
		end
		self.Connected = false
		if hub.added[id] then
			hub.added[id] = nil
			hub.addCount = math.max(0, (hub.addCount or 0) - 1)
		end
		if hub.removing[id] then
			hub.removing[id] = nil
			hub.remCount = math.max(0, (hub.remCount or 0) - 1)
		end
		if (hub.addCount or 0) <= 0 and (hub.remCount or 0) <= 0 then
			if hub.cacheLive then
				hub.aQ = {}
				hub.rQ = {}
				hub.aSet = {}
				hub.rSet = {}
				hub.aHead = 1
				hub.aTail = 0
				hub.rHead = 1
				hub.rTail = 0
			else
				NAmanage._wsHubDispose(hub)
			end
		end
	end
	return conn
end

NAmanage.wsAdd = NAmanage.wsAdd or function(fn)
	return NAmanage.wsSub({
		added = fn
	})
end

NAmanage.wsRem = NAmanage.wsRem or function(fn)
	return NAmanage.wsSub({
		removing = fn
	})
end

NAmanage._cgHub = NAmanage._cgHub or nil

NAmanage._cgHubDispose = NAmanage._cgHubDispose or function(hub)
	hub = hub or NAmanage._cgHub
	if type(hub) ~= "table" then
		return
	end
	hub.alive = false
	if hub.cAdd then
		pcall(function()
			hub.cAdd:Disconnect()
		end)
		hub.cAdd = nil
	end
	if hub.cRem then
		pcall(function()
			hub.cRem:Disconnect()
		end)
		hub.cRem = nil
	end
	hub.added = {}
	hub.removing = {}
	hub.addCount = 0
	hub.remCount = 0
	hub.aQ = {}
	hub.rQ = {}
	hub.aSet = {}
	hub.rSet = {}
	hub.aHead = 1
	hub.aTail = 0
	hub.rHead = 1
	hub.rTail = 0
	hub.qBusy = false
	hub.qKick = false
	hub.root = nil
	if NAmanage._cgHub == hub then
		NAmanage._cgHub = nil
	end
end

NAmanage._cgHubGet = NAmanage._cgHubGet or function()
	local root = (typeof(COREGUI) == "Instance" and COREGUI) or SafeGetService("CoreGui")
	local hub = NAmanage._cgHub
	if hub and hub.root == root and hub.alive then
		return hub
	end

	if hub then
		NAmanage._cgHubDispose(hub)
	end

	hub = {
		root = root,
		nextId = 0,
		added = {},
		removing = {},
		addCount = 0,
		remCount = 0,
		aQ = {},
		rQ = {},
		aSet = {},
		rSet = {},
		aHead = 1,
		aTail = 0,
		rHead = 1,
		rTail = 0,
		qBusy = false,
		qKick = false,
		cAdd = nil,
		cRem = nil,
		alive = true,
	}

	local dispatch = NAmanage._evtHubDispatch
	local hasInterested = NAmanage._evtHubHasInterested

	local function runQ()
		if hub.qBusy or not hub.alive then
			return
		end
		hub.qBusy = true
		Spawn(function()
			while hub.alive and (hub.aHead <= hub.aTail or hub.rHead <= hub.rTail) do
				local budget, waitDelay = NAmanage._evtHubBudget(160, {
					delay = 0,
					ldSc = 0.4,
					ldDel = 0.008,
				})
				while budget > 0 and hub.alive and (hub.aHead <= hub.aTail or hub.rHead <= hub.rTail) do
					if hub.rHead <= hub.rTail then
						local inst = hub.rQ[hub.rHead]
						hub.rQ[hub.rHead] = nil
						hub.rHead += 1
						if inst then
							hub.rSet[inst] = nil
							dispatch(hub.removing, inst)
						end
					elseif hub.aHead <= hub.aTail then
						local inst = hub.aQ[hub.aHead]
						hub.aQ[hub.aHead] = nil
						hub.aHead += 1
						if inst then
							hub.aSet[inst] = nil
							dispatch(hub.added, inst)
						end
					end
					budget -= 1
				end
				if waitDelay > 0 then
					Wait(waitDelay)
				else
					Wait()
				end
			end
			hub.aQ = {}
			hub.rQ = {}
			hub.aHead = 1
			hub.aTail = 0
			hub.rHead = 1
			hub.rTail = 0
			hub.qBusy = false
		end)
	end

	local function kickQ()
		if hub.qKick then
			return
		end
		hub.qKick = true
		Defer(function()
			hub.qKick = false
			runQ()
		end)
	end

	local function qEvt(kind, inst)
		if not (hub.alive and inst) then
			return
		end
		if kind == "add" then
			if (hub.addCount or 0) <= 0 then
				return
			end
			if not hasInterested(hub.added, inst) then
				return
			end
			if hub.aSet[inst] then
				return
			end
			hub.aSet[inst] = true
			hub.aTail += 1
			hub.aQ[hub.aTail] = inst
		else
			if (hub.remCount or 0) <= 0 then
				return
			end
			if not hasInterested(hub.removing, inst) then
				return
			end
			if hub.rSet[inst] then
				return
			end
			hub.rSet[inst] = true
			hub.rTail += 1
			hub.rQ[hub.rTail] = inst
		end
		kickQ()
	end

	local function wantsRootEvents()
		return (hub.addCount or 0) > 0 or (hub.remCount or 0) > 0
	end

	local function disconnectRootHooks()
		if hub.cAdd then
			hub.cAdd:Disconnect()
			hub.cAdd = nil
		end
		if hub.cRem then
			hub.cRem:Disconnect()
			hub.cRem = nil
		end
	end

	local function connectRootHooks()
		if not (hub.alive and root and wantsRootEvents()) then
			return
		end
		if not hub.cAdd then
			hub.cAdd = NAmanage.safeConnect(root.DescendantAdded, function(inst)
				qEvt("add", inst)
			end)
		end
		if not hub.cRem then
			hub.cRem = NAmanage.safeConnect(root.DescendantRemoving, function(inst)
				qEvt("rem", inst)
			end)
		end
	end
	hub.enableRootHooks = connectRootHooks
	hub.disableRootHooks = disconnectRootHooks

	NAmanage._cgHub = hub
	return hub
end

NAmanage.cgSub = NAmanage.cgSub or function(spec)
	spec = spec or {}
	local onAdd = type(spec.added) == "function" and spec.added or nil
	local onRem = type(spec.removing) == "function" and spec.removing or nil
	local addFilter = type(spec.filterAdded) == "function" and spec.filterAdded
		or (type(spec.filter) == "function" and spec.filter or nil)
	local remFilter = type(spec.filterRemoving) == "function" and spec.filterRemoving
		or (type(spec.filter) == "function" and spec.filter or nil)
	local noop = {
		Connected = false,
		Disconnect = function() end,
	}
	if not onAdd and not onRem then
		return noop
	end

	local hub = NAmanage._cgHubGet()
	hub.nextId += 1
	local id = hub.nextId
	if onAdd then
		hub.added[id] = addFilter and {
			fn = onAdd,
			filter = addFilter,
		} or onAdd
		hub.addCount = (hub.addCount or 0) + 1
	end
	if onRem then
		hub.removing[id] = remFilter and {
			fn = onRem,
			filter = remFilter,
		} or onRem
		hub.remCount = (hub.remCount or 0) + 1
	end
	if type(hub.enableRootHooks) == "function" then
		hub.enableRootHooks()
	end

	local conn = {
		Connected = true,
	}
	function conn:Disconnect()
		if not self.Connected then
			return
		end
		self.Connected = false
		if hub.added[id] then
			hub.added[id] = nil
			hub.addCount = math.max(0, (hub.addCount or 0) - 1)
		end
		if hub.removing[id] then
			hub.removing[id] = nil
			hub.remCount = math.max(0, (hub.remCount or 0) - 1)
		end
		if (hub.addCount or 0) <= 0 and (hub.remCount or 0) <= 0 then
			NAmanage._cgHubDispose(hub)
		end
	end
	return conn
end

NAmanage.cgAdd = NAmanage.cgAdd or function(fn, filter)
	return NAmanage.cgSub({
