NAmanage._playersHub = NAmanage._playersHub or nil

NAmanage._playersHubDispose = NAmanage._playersHubDispose or function(hub)
	hub = hub or NAmanage._playersHub
	if type(hub) ~= "table" then
		return
	end
	hub.alive = false
	if hub.cAdd then
		pcall(function()
