NAmanage.GetAttr=function(inst, key)
	if not inst or not key then return nil end
	local actualKey = NAmanage.GetSessionAttrKey(key)
	local ok, value = pcall(function() return inst:GetAttribute(actualKey) end)
	if ok and value ~= nil then
		return value
	end
	ok, value = pcall(function() return inst:GetAttribute(key) end)
	if ok and value ~= nil then
		return value
	end
	local tag = inst:FindFirstChild(NAmanage.GetSessionAttrTagName(key))
	if tag and tag:IsA("ValueBase") then
		return tag.Value
	end
	tag = inst:FindFirstChild("_NAATTR_"..tostring(key))
	if tag and tag:IsA("ValueBase") then
		return tag.Value
	end
	return nil
end

NAmanage.SetAttr=function(inst, key, value)
	if not inst or not key then return end
	local actualKey = NAmanage.GetSessionAttrKey(key)
	local ok = pcall(function() inst:SetAttribute(actualKey, value) end)
	if ok then
		return
	end

	local tagName = NAmanage.GetSessionAttrTagName(key)
	local existing = inst:FindFirstChild(tagName)

	if value == nil then
		if existing then pcall(function() existing:Destroy() end) end
		return
	end

	local class = "StringValue"
	if type(value) == "boolean" then
		class = "BoolValue"
	elseif type(value) == "number" then
		class = "NumberValue"
	end

	if not existing or existing.ClassName ~= class then
		if existing then pcall(function() existing:Destroy() end) end
		existing = Instance.new(class)
		existing.Name = tagName
		existing.Archivable = false
		existing.Parent = inst
	end

	existing.Value = value
end

NAmanage.NewCancelToken = NAmanage.NewCancelToken or function()
	return { cancelled = false }
end

NAmanage.CancelTokenCancel = NAmanage.CancelTokenCancel or function(token)
	if type(token) == "table" then
		token.cancelled = true
	end
end

NAmanage.isLoad = NAmanage.isLoad or function()
	local load = nil
	if type(_G) == "table" then
		load = rawget(_G, "NAAssetsLoading")
	end
	if type(load) ~= "table" then
		load = NAAssetsLoading
	end
	if type(load) ~= "table" then
		return false
	end
	local done = load.completed
	if typeof(done) == "Instance" then
		local completedAttr = NAmanage.GetAttr(done, "Completed")
		if type(completedAttr) == "boolean" then
			return completedAttr ~= true
		end
		if done:IsA("BoolValue") then
			return done.Value ~= true
		end
	end
	return load._finalized ~= true
end

NAmanage.lpProf = NAmanage.lpProf or function(baseBud, opts)
	opts = opts or {}
	local bud = math.max(1, math.floor(tonumber(baseBud) or 1))
	local del = tonumber(opts.delay) or 0
	if NAmanage.isLoad and NAmanage.isLoad() then
		local sc = tonumber(opts.ldSc)
		if not sc then
			sc = 0.4
		end
		sc = math.clamp(sc, 0.05, 1)
		bud = math.max(1, math.floor(bud * sc))
		local ld = tonumber(opts.ldDel)
		if ld and ld > del then
			del = ld
		elseif del <= 0 then
			del = 0.01
		end
	end
	return bud, del
end

NAmanage.ForEachDescendantYield = NAmanage.ForEachDescendantYield or function(root, handler, opts)
	opts = opts or {}
	if typeof(root) ~= "Instance" or type(handler) ~= "function" then
		return 0
	end

	local yieldEvery = tonumber(opts.yieldEvery) or 250
	if yieldEvery < 1 then
		yieldEvery = 1
	end

	local delayTime = opts.delayTime
	local cancelToken = opts.cancelToken
	local includeRoot = opts.includeRoot == true
	if NAmanage.isLoad and NAmanage.isLoad() then
		yieldEvery = math.min(yieldEvery, 96)
		if delayTime == nil then
			delayTime = 0.01
		end
	end

	local stack = {}
	local stackN = 0
	local function push(inst)
		stackN += 1
		stack[stackN] = inst
	end
	local function pop()
		local inst = stack[stackN]
		stack[stackN] = nil
		stackN -= 1
		return inst
	end

	if includeRoot then
		push(root)
	else
		local okChildren, children = pcall(root.GetChildren, root)
		if okChildren and children then
			for i = 1, #children do
				push(children[i])
			end
		end
	end

	local processed = 0
	while stackN > 0 do
		if cancelToken and cancelToken.cancelled then
			break
		end

		local inst = pop()
		processed += 1
		handler(inst)

		local okChildren, children = pcall(inst.GetChildren, inst)
		if okChildren and children then
			for i = 1, #children do
				push(children[i])
			end
		end

		if processed % yieldEvery == 0 then
			if cancelToken and cancelToken.cancelled then
				break
			end
			if delayTime ~= nil then
				Wait(delayTime)
			else
				Wait()
			end
		end
	end

	return processed
end

NAmanage.ForEachWorkspaceYield = NAmanage.ForEachWorkspaceYield or function(handler, opts)
	opts = opts or {}
	if type(handler) ~= "function" then
		return 0
	end

	local list = NAmanage.wsDescs and NAmanage.wsDescs() or {}
	local total = #list
	if total <= 0 then
		return 0
	end

	local yieldEvery = tonumber(opts.yieldEvery) or tonumber(NAStuff.ESP_ScanBatchSize) or 160
	if yieldEvery < 1 then
		yieldEvery = 1
	end
	local delayTime = opts.delayTime
	if delayTime == nil then
		delayTime = tonumber(NAStuff.ESP_ScanDelay) or 0
	end
	local cancelToken = opts.cancelToken

	local processed = 0
	for i = 1, total do
		if cancelToken and cancelToken.cancelled then
			break
		end

		local inst = list[i]
		processed += 1
		handler(inst, i, total)

		if processed % yieldEvery == 0 then
			if cancelToken and cancelToken.cancelled then
				break
			end
			if delayTime and delayTime > 0 then
				Wait(delayTime)
			else
				Wait()
			end
		end
	end

	return processed
end

NAmanage.ESP_CancelScanToken = NAmanage.ESP_CancelScanToken or function(key)
	if type(key) ~= "string" or key == "" then
		return
	end
	local tokens = NAStuff.espScanTokens
	if type(tokens) ~= "table" then
		return
	end
	local tok = tokens[key]
	if tok then
		NAmanage.CancelTokenCancel(tok)
		tokens[key] = nil
	end
end

NAmanage.ESP_StartScanToken = NAmanage.ESP_StartScanToken or function(key)
	if type(key) ~= "string" or key == "" then
		return nil
	end
	NAmanage.ESP_CancelScanToken(key)
	local tok = NAmanage.NewCancelToken()
	NAStuff.espScanTokens[key] = tok
	return tok
end

NAmanage.ESP_ListAdd = NAmanage.ESP_ListAdd or function(list, indexMap, item)
	if type(list) ~= "table" or type(indexMap) ~= "table" or item == nil then
		return false
	end
	if indexMap[item] then
		return false
	end
	local n = #list + 1
	list[n] = item
	indexMap[item] = n
	return true
end

NAmanage.ESP_ListRemove = NAmanage.ESP_ListRemove or function(list, indexMap, item)
	if type(list) ~= "table" or type(indexMap) ~= "table" or item == nil then
		return false
	end
	local idx = indexMap[item]
	if not idx then
		return false
	end
	local lastIdx = #list
	local lastItem = list[lastIdx]
	list[lastIdx] = nil
	indexMap[item] = nil
	if idx < lastIdx then
		list[idx] = lastItem
		indexMap[lastItem] = idx
	end
	return true
end

NAmanage.ESP_GetListMeta = NAmanage.ESP_GetListMeta or function(list)
	if type(list) ~= "table" then
		return nil
	end
	local store = NAStuff and NAStuff.genericESPListMeta
	if type(store) ~= "table" then
		store = {}
		NAStuff.genericESPListMeta = store
	end
	local meta = store[list]
	if type(meta) ~= "table" then
		meta = {
			index = {};
			counts = {};
			objects = {};
		}
		store[list] = meta
	end
	if type(meta.index) ~= "table" then
		meta.index = {}
	end
	if type(meta.counts) ~= "table" then
		meta.counts = {}
	end
	if type(meta.objects) ~= "table" then
		meta.objects = {}
	end
	return meta
end

NAmanage.ESP_GetListMap = NAmanage.ESP_GetListMap or function(list)
	local meta = NAmanage.ESP_GetListMeta(list)
	return meta and meta.index or nil
end

NAmanage.ESP_GetListCountMap = NAmanage.ESP_GetListCountMap or function(list)
	local meta = NAmanage.ESP_GetListMeta(list)
	return meta and meta.counts or nil
end

NAmanage.ESP_GetListObjectMap = NAmanage.ESP_GetListObjectMap or function(list)
	local meta = NAmanage.ESP_GetListMeta(list)
	return meta and meta.objects or nil
end

NAlib.huiGrabber = function()
	return (__NAUIProtector and __NAUIProtector.huiGrabber and __NAUIProtector.huiGrabber()) or
		(gethui and gethui()) or
		(gethiddenui and gethiddenui()) or
		(gethiddengui and gethiddengui()) or
		(get_hidden_ui and get_hidden_ui()) or
		(get_hidden_gui and get_hidden_gui()) or
		nil
end

local HttpService = SafeGetService('HttpService');
local Players = SafeGetService("Players");
local UserInputService = SafeGetService("UserInputService");
local TweenService = SafeGetService("TweenService");
local RunService = SafeGetService("RunService");
local ContextActionService = SafeGetService("ContextActionService");
local TeleportService = SafeGetService("TeleportService");
local Lighting = SafeGetService("Lighting");
local ReplicatedStorage = SafeGetService("ReplicatedStorage");
local COREGUI = SafeGetService("CoreGui");
local SoundService = SafeGetService("SoundService");
local TextChatService = SafeGetService("TextChatService");
local TextService = SafeGetService("TextService");
local StarterGui = SafeGetService("StarterGui");
local ContentProvider = SafeGetService("ContentProvider");
local LocalizationService = SafeGetService("LocalizationService");
local MarketplaceService = SafeGetService("MarketplaceService");
local GuiService = SafeGetService("GuiService");
local ContextActionService = SafeGetService("ContextActionService");
local StatsService = SafeGetService("Stats");

NAmanage.GetDataPingStat = NAmanage.GetDataPingStat or function()
	local ok, pingStat = pcall(function()
		if not StatsService then
			return nil
		end

		local network = StatsService:FindFirstChild("Network")
		if not network then
			return nil
		end

		local serverStats = network:FindFirstChild("ServerStatsItem")
		if serverStats then
			local nested = serverStats:FindFirstChild("Data Ping")
			if nested then
				return nested
			end
		end

		return network:FindFirstChild("Data Ping")
	end)

	if ok then
		return pingStat
	end

	return nil
end

NAmanage.GetDataPingMs = NAmanage.GetDataPingMs or function()
	local pingStat = NAmanage.GetDataPingStat()
	if not pingStat then
		return nil
	end

	local okValue, value = pcall(function()
		if pingStat.GetValue then
			return pingStat:GetValue()
		end
	end)
	if okValue and type(value) == "number" then
		return math.max(0, math.floor(value + 0.5))
	end

	local okString, str = pcall(function()
		if pingStat.GetValueString then
			return pingStat:GetValueString()
		end
	end)
	if okString and type(str) == "string" then
		local num = tonumber((str:gsub("[^%d%.]", "")))
		if num then
			return math.max(0, math.floor(num + 0.5))
		end
	end

	return nil
end

NAmanage.GetDataPingText = NAmanage.GetDataPingText or function()
	local pingStat = NAmanage.GetDataPingStat()
	if not pingStat then
		return nil
	end

	local ms = NAmanage.GetDataPingMs()
	if type(ms) == "number" then
		return Format("%d ms", math.floor(ms + 0.5)), ms
	end

	local okString, str = pcall(function()
		if pingStat.GetValueString then
			return pingStat:GetValueString()
		end
	end)
	if okString and type(str) == "string" and str ~= "" then
		return str, nil
	end

	return nil
end

NAmanage.StreamerEscapePattern = NAmanage.StreamerEscapePattern or function(value)
	value = tostring(value or "")
	return value:gsub("([%%%^%$%(%)%.%[%]%*%+%-%?])", "%%%1")
end

NAmanage.StreamerGetState = NAmanage.StreamerGetState or function()
	local state = NAStuff and NAStuff.StreamerModeState
	if type(state) ~= "table" then
		state = {
			cache = {};
			nameTokens = {};
			token = nil;
			restoreToken = nil;
			applied = false;
			scrubBusy = false;
		}
		NAStuff.StreamerModeState = state
	end
	if type(state.cache) ~= "table" then
		state.cache = {}
	end
	if type(state.nameTokens) ~= "table" then
		state.nameTokens = {}
	end
	return state
end

NAmanage.StreamerSetPlayerListHidden = NAmanage.StreamerSetPlayerListHidden or function(hidden)
	local state = NAmanage.StreamerGetState()
	local starterGui = StarterGui or SafeGetService("StarterGui")
	if not starterGui or not Enum or not Enum.CoreGuiType or not Enum.CoreGuiType.PlayerList then
		return false
	end

	if hidden == true then
		if state.playerListOriginal == nil then
			local okEnabled, enabled = pcall(function()
				return __lt.cm("StarterGui", "GetCoreGuiEnabled", Enum.CoreGuiType.PlayerList)
			end)
			if okEnabled then
				state.playerListOriginal = enabled == true
			else
				state.playerListOriginal = true
			end
		end
		local okSet = pcall(function()
			__lt.cm("StarterGui", "SetCoreGuiEnabled", Enum.CoreGuiType.PlayerList, false)
		end)
		state.playerListHidden = okSet == true
		return okSet == true
	end

	if state.playerListOriginal ~= nil or state.playerListHidden == true then
		local restoreValue = state.playerListOriginal ~= false
		pcall(function()
			__lt.cm("StarterGui", "SetCoreGuiEnabled", Enum.CoreGuiType.PlayerList, restoreValue)
		end)
	end
	state.playerListOriginal = nil
	state.playerListHidden = nil
	return true
end

NAmanage.StreamerCacheCount = NAmanage.StreamerCacheCount or function(cache)
	local count = 0
	if type(cache) == "table" then
		for _ in pairs(cache) do
			count += 1
		end
	end
	return count
end

NAmanage.StreamerIsRunActive = NAmanage.StreamerIsRunActive or function(token)
	if not (NAStuff and NAStuff.StreamerModeEnabled == true) then
		return false
	end
	if type(token) ~= "table" then
		return true
	end
	if token.cancelled then
		return false
	end
	local state = NAmanage.StreamerGetState()
	return state.token == token
end

NAmanage.StreamerGetRecord = NAmanage.StreamerGetRecord or function(inst)
	if typeof(inst) ~= "Instance" then
		return nil
	end
	local state = NAmanage.StreamerGetState()
	local cache = state.cache
	local rec = cache[inst]
	if type(rec) ~= "table" then
		rec = {}
		cache[inst] = rec
	end
	return rec
end

NAmanage.StreamerRefreshNameTokens = NAmanage.StreamerRefreshNameTokens or function()
	local state = NAmanage.StreamerGetState()
	local tokens = {}
	local seen = {}
	if Players then
		for _, plr in ipairs(__lt.cm("Players", "GetPlayers")) do
			local names = {
				plr and plr.Name or nil,
				plr and plr.DisplayName or nil,
			}
			for i = 1, #names do
				local value = names[i]
				if type(value) == "string" and value ~= "" and not seen[value] then
					seen[value] = true
					Insert(tokens, value)
				end
			end
		end
	end
	table.sort(tokens, function(a, b)
		if #a == #b then
			return a < b
		end
		return #a > #b
	end)
	state.nameTokens = tokens
	return tokens
end

NAmanage.StreamerScheduleNameRefresh = NAmanage.StreamerScheduleNameRefresh or function(refreshCached)
	local state = NAmanage.StreamerGetState()
	if refreshCached then
		state.nameRefreshNeedsCached = true
	end
	if state.nameRefreshQueued then
		return
	end
	state.nameRefreshQueued = true
	Delay(0.05, function()
		state.nameRefreshQueued = false
		if not (NAStuff and NAStuff.StreamerModeEnabled == true) then
			state.nameRefreshNeedsCached = false
			return
		end
		NAmanage.StreamerRefreshNameTokens()
		if state.nameRefreshNeedsCached then
			state.nameRefreshNeedsCached = false
			NAmanage.StreamerRefreshCachedTargets()
		end
	end)
end

NAmanage.StreamerRefreshCachedTargets = NAmanage.StreamerRefreshCachedTargets or function()
	local state = NAmanage.StreamerGetState()
	local pending = {}
	for inst in pairs(state.cache) do
		if typeof(inst) == "Instance" and inst.Parent and NAmanage.StreamerIsTarget(inst) then
			Insert(pending, inst)
		end
	end
	for i = 1, #pending do
		NAmanage.StreamerScrubInstance(pending[i])
	end
end

NAmanage.StreamerMaskText = NAmanage.StreamerMaskText or function(text)
	if text == nil then
		return nil
	end
	local source = tostring(text)
	local tokens = NAmanage.StreamerGetState().nameTokens
	if type(tokens) ~= "table" or #tokens == 0 then
		return source
	end
	local masked = source
	local replacement = tostring(NAStuff.StreamerModeText or "\0")
	for i = 1, #tokens do
		local token = tokens[i]
		if token ~= "" then
			masked = masked:gsub(NAmanage.StreamerEscapePattern(token), replacement)
		end
	end
	return masked
end

NAmanage.StreamerShouldMaskImage = NAmanage.StreamerShouldMaskImage or function(image)
	local value = Lower(tostring(image or ""))
	if value == "" then
		return false
	end
	if value:find("rbxthumb://", 1, true) then
		return true
	end
	if value:find("avatar", 1, true) or value:find("headshot", 1, true) or value:find("bust", 1, true) then
		return true
	end
	if value:find("user-thumbnail", 1, true) or value:find("thumbnail", 1, true) then
		return true
	end
	if value:find("rbxcdn.com", 1, true) and value:find("/users/", 1, true) then
		return true
	end
	return false
end

NAmanage.StreamerIsContainer = NAmanage.StreamerIsContainer or function(inst)
	if typeof(inst) ~= "Instance" then
		return false
	end
	return inst:IsA("BillboardGui")
		or inst:IsA("SurfaceGui")
end

NAmanage.StreamerIsTarget = NAmanage.StreamerIsTarget or function(inst)
	if typeof(inst) ~= "Instance" then
		return false
	end
	return inst:IsA("TextLabel")
		or inst:IsA("TextButton")
		or inst:IsA("TextBox")
		or inst:IsA("ImageLabel")
		or inst:IsA("ImageButton")
end

NAmanage.StreamerIsRelevant = NAmanage.StreamerIsRelevant or function(inst)
	return NAmanage.StreamerIsTarget(inst) or NAmanage.StreamerIsContainer(inst)
end

NAmanage.StreamerDisconnectConn = NAmanage.StreamerDisconnectConn or function(conn)
	if conn and type(conn.Disconnect) == "function" then
		pcall(function()
			conn:Disconnect()
		end)
	end
end

NAmanage.StreamerWatchTarget = NAmanage.StreamerWatchTarget or function(inst)
	if not NAmanage.StreamerIsTarget(inst) then
		return
	end
	local rec = NAmanage.StreamerGetRecord(inst)
	rec.signalConns = rec.signalConns or {}
	local function bindSignal(key, signal)
		if rec.signalConns[key] then
			return
		end
		rec.signalConns[key] = signal:Connect(function()
			if NAStuff and NAStuff.StreamerModeEnabled == true then
				NAmanage.StreamerScrubInstance(inst)
			end
		end)
	end
	if inst:IsA("TextLabel") or inst:IsA("TextButton") or inst:IsA("TextBox") then
		bindSignal("Text", inst:GetPropertyChangedSignal("Text"))
		if inst:IsA("TextBox") then
			bindSignal("PlaceholderText", inst:GetPropertyChangedSignal("PlaceholderText"))
		end
	end
	if inst:IsA("ImageLabel") or inst:IsA("ImageButton") then
		bindSignal("Image", inst:GetPropertyChangedSignal("Image"))
	end
	if not rec.ancConn then
		rec.ancConn = inst.AncestryChanged:Connect(function(_, parent)
			if parent then
				return
			end
			NAmanage.StreamerRestoreInstance(inst)
		end)
	end
end

NAmanage.StreamerScanContainer = NAmanage.StreamerScanContainer or function(root, token, opts)
	if typeof(root) ~= "Instance" then
		return
	end
	if token and not NAmanage.StreamerIsRunActive(token) then
		return
	end
	opts = opts or {}
	if opts.includeRoot == true and NAmanage.StreamerIsTarget(root) then
		NAmanage.StreamerScrubInstance(root)
	end
	NAmanage.ForEachDescendantYield(root, function(inst)
		if token and not NAmanage.StreamerIsRunActive(token) then
			return
		end
		if NAmanage.StreamerIsTarget(inst) then
			NAmanage.StreamerScrubInstance(inst)
		end
	end, {
		yieldEvery = tonumber(opts.yieldEvery) or 96;
		cancelToken = token;
	})
end

NAmanage.StreamerScanContainerAsync = NAmanage.StreamerScanContainerAsync or function(root, opts)
	if typeof(root) ~= "Instance" then
		return
	end
	opts = opts or {}
	local state = NAmanage.StreamerGetState()
	local scanToken = opts.cancelToken
	if type(scanToken) ~= "table" then
		scanToken = state.token
	end
	local rec = NAmanage.StreamerGetRecord(root)
	if rec.scanQueued == true and rec.scanToken == scanToken then
		return
	end
	rec.scanQueued = true
	rec.scanToken = scanToken
	Spawn(function()
		if NAmanage.StreamerIsRunActive(scanToken) then
			NAmanage.StreamerScanContainer(root, scanToken, opts)
		end
		local liveState = NAmanage.StreamerGetState()
		local liveRec = liveState.cache and liveState.cache[root]
		if type(liveRec) == "table" and liveRec.scanToken == scanToken then
			liveRec.scanQueued = false
			liveRec.scanToken = nil
		end
	end)
end

NAmanage.StreamerWatchContainer = NAmanage.StreamerWatchContainer or function(container)
	if not NAmanage.StreamerIsContainer(container) then
		return
	end
	local rec = NAmanage.StreamerGetRecord(container)
	if not rec.containerDescConn then
		rec.containerDescConn = NAmanage.descAdd(container, function(inst)
			if NAmanage.StreamerIsRelevant(inst) then
				NAmanage.StreamerHandleAdded(inst)
			end
		end, NAmanage.StreamerIsRelevant)
	end
	if not rec.containerAncConn then
		rec.containerAncConn = container.AncestryChanged:Connect(function(_, parent)
			if parent then
				return
			end
			NAmanage.StreamerRestoreInstance(container)
		end)
	end
end

NAmanage.StreamerApplyProp = NAmanage.StreamerApplyProp or function(inst, prop, newValue)
	if typeof(inst) ~= "Instance" then
		return false
	end
	local current = NAlib.isProperty(inst, prop)
	if current == nil then
		return false
	end
	local rec = NAmanage.StreamerGetRecord(inst)
	local originalKey = prop .. "Original"
	local appliedKey = prop .. "Applied"
	if rec[appliedKey] == nil or current ~= rec[appliedKey] then
		rec[originalKey] = current
	end
	local okSet = NAlib.setProperty(inst, prop, newValue)
	if okSet then
		rec[appliedKey] = newValue
		return true
	end
	rec[appliedKey] = current
	return false
end

NAmanage.StreamerApplyCharacterVisual = NAmanage.StreamerApplyCharacterVisual or function(inst)
	if not (NAStuff and NAStuff.StreamerModeEnabled == true) then
		return
	end
	if typeof(inst) ~= "Instance" then
		return
	end

	local gray = NAStuff.StreamerModeGray or Color3.fromRGB(127, 127, 127)
	local inAccessory = inst:FindFirstAncestorOfClass("Accessory") ~= nil

	if inst:IsA("BasePart") then
		if inAccessory then
			NAmanage.StreamerApplyProp(inst, "LocalTransparencyModifier", 1)
			return
		end
		NAmanage.StreamerApplyProp(inst, "Color", gray)
		NAmanage.StreamerApplyProp(inst, "Material", Enum.Material.SmoothPlastic)
		NAmanage.StreamerApplyProp(inst, "Reflectance", 0)
		if inst:IsA("MeshPart") then
			NAmanage.StreamerApplyProp(inst, "TextureID", "")
		end
		return
	end

	if inst:IsA("Decal") or inst:IsA("Texture") then
		if not inAccessory then
			NAmanage.StreamerApplyProp(inst, "Transparency", 1)
		end
		return
	end

	if inst:IsA("CharacterMesh") then
		NAmanage.StreamerApplyProp(inst, "BaseTextureId", "")
		NAmanage.StreamerApplyProp(inst, "OverlayTextureId", "")
		NAmanage.StreamerApplyProp(inst, "MeshId", "")
		return
	end

	if inst:IsA("DataModelMesh") then
		NAmanage.StreamerApplyProp(inst, "TextureId", "")
		NAmanage.StreamerApplyProp(inst, "MeshId", "")
		NAmanage.StreamerApplyProp(inst, "VertexColor", Vector3.new(gray.R, gray.G, gray.B))
		return
	end

	if inst:IsA("Shirt") then
		NAmanage.StreamerApplyProp(inst, "ShirtTemplate", "")
		return
	end

	if inst:IsA("Pants") then
		NAmanage.StreamerApplyProp(inst, "PantsTemplate", "")
		return
	end

	if inst:IsA("ShirtGraphic") then
		NAmanage.StreamerApplyProp(inst, "Graphic", "")
		return
	end

	if inst:IsA("BodyColors") then
		local bodyColorProps = {
			"HeadColor3",
			"LeftArmColor3",
			"RightArmColor3",
			"LeftLegColor3",
			"RightLegColor3",
			"TorsoColor3",
		}
		for i = 1, #bodyColorProps do
			NAmanage.StreamerApplyProp(inst, bodyColorProps[i], gray)
		end
		return
	end
end

NAmanage.StreamerHandleCharacterDesc = NAmanage.StreamerHandleCharacterDesc or function(inst, token)
	if typeof(inst) ~= "Instance" then
		return
	end
	if token and not NAmanage.StreamerIsRunActive(token) then
		return
	end
	if inst:IsA("Humanoid") then
		NAmanage.StreamerApplyHumanoid(inst)
		return
	end
	if inst:IsA("Accessory") then
		NAmanage.ForEachDescendantYield(inst, function(desc)
			if token and not NAmanage.StreamerIsRunActive(token) then
				return
			end
			NAmanage.StreamerApplyCharacterVisual(desc)
		end, {
			includeRoot = true;
			yieldEvery = 48;
			cancelToken = token;
		})
		return
	end
	NAmanage.StreamerApplyCharacterVisual(inst)
end

NAmanage.StreamerApplyHumanoid = NAmanage.StreamerApplyHumanoid or function(hum)
	if not (NAStuff and NAStuff.StreamerModeEnabled == true) then
		return
	end
	if typeof(hum) ~= "Instance" or not hum:IsA("Humanoid") then
		return
	end
	local rec = NAmanage.StreamerGetRecord(hum)
	local replacement = tostring(NAStuff.StreamerModeText or "\0")
	NAmanage.StreamerApplyProp(hum, "DisplayDistanceType", Enum.HumanoidDisplayDistanceType.None)
	NAmanage.StreamerApplyProp(hum, "NameDisplayDistance", 0)
	NAmanage.StreamerApplyProp(hum, "Name", replacement)
	NAmanage.StreamerApplyProp(hum, "DisplayName", replacement)
	if not rec.ancConn then
		rec.ancConn = hum.AncestryChanged:Connect(function(_, parent)
			if parent then
				return
			end
			NAmanage.StreamerRestoreInstance(hum)
		end)
	end
end

NAmanage.StreamerHandleCharacter = NAmanage.StreamerHandleCharacter or function(char, token)
	if typeof(char) ~= "Instance" or not char:IsA("Model") then
		return
	end
	local scanToken = token
	if type(scanToken) ~= "table" then
		scanToken = NAmanage.StreamerGetState().token
	end
	local charRec = NAmanage.StreamerGetRecord(char)
	if charRec.charDescConn then
		return
	end
	local function isRelevant(inst)
		if not inst then
			return false
		end
		return inst:IsA("Humanoid")
			or inst:IsA("Accessory")
			or inst:IsA("BasePart")
			or inst:IsA("Decal")
			or inst:IsA("Texture")
			or inst:IsA("CharacterMesh")
			or inst:IsA("DataModelMesh")
			or inst:IsA("Shirt")
			or inst:IsA("Pants")
			or inst:IsA("ShirtGraphic")
			or inst:IsA("BodyColors")
	end
	charRec.charDescConn = NAmanage.descAdd(char, function(inst)
		if isRelevant(inst) then
			NAmanage.StreamerHandleCharacterDesc(inst, scanToken)
		end
	end, isRelevant)
	charRec.charAncConn = char.AncestryChanged:Connect(function(_, parent)
		if parent then
			return
		end
		NAmanage.StreamerRestoreInstance(char)
	end)
	charRec.charScanToken = scanToken
	Spawn(function()
		if scanToken and not NAmanage.StreamerIsRunActive(scanToken) then
			local liveState = NAmanage.StreamerGetState()
			local liveRec = liveState.cache and liveState.cache[char]
			if type(liveRec) == "table" and liveRec.charScanToken == scanToken then
				liveRec.charScanToken = nil
			end
			return
		end
		NAmanage.ForEachDescendantYield(char, function(inst)
			if scanToken and not NAmanage.StreamerIsRunActive(scanToken) then
				return
			end
			NAmanage.StreamerHandleCharacterDesc(inst, scanToken)
		end, {
			includeRoot = true;
			yieldEvery = 24;
			cancelToken = scanToken;
		})
		local liveState = NAmanage.StreamerGetState()
		local liveRec = liveState.cache and liveState.cache[char]
		if type(liveRec) == "table" and liveRec.charScanToken == scanToken then
			liveRec.charScanToken = nil
		end
	end)
end

NAmanage.StreamerApplyTextProp = NAmanage.StreamerApplyTextProp or function(inst, prop)
	local current = NAlib.isProperty(inst, prop)
	if current == nil then
		return
	end
	current = tostring(current)
	local rec = NAmanage.StreamerGetRecord(inst)
	local originalKey = prop .. "Original"
	local appliedKey = prop .. "Applied"
	if rec[appliedKey] == nil or current ~= rec[appliedKey] then
		rec[originalKey] = current
	end
	local original = rec[originalKey]
	if original == nil then
		original = current
		rec[originalKey] = original
	end
	local masked = NAmanage.StreamerMaskText(original)
	rec[appliedKey] = masked
	if current ~= masked then
		NAlib.setProperty(inst, prop, masked)
	end
end

NAmanage.StreamerApplyImageProp = NAmanage.StreamerApplyImageProp or function(inst)
	local current = NAlib.isProperty(inst, "Image")
	if current == nil then
		return
	end
	current = tostring(current)
	local rec = NAmanage.StreamerGetRecord(inst)
	if rec.ImageApplied == nil or current ~= rec.ImageApplied then
		rec.ImageOriginal = current
	end
	local original = rec.ImageOriginal
	if original == nil then
		original = current
		rec.ImageOriginal = original
	end
	local replacement = original
	if NAmanage.StreamerShouldMaskImage(original) then
		replacement = tostring(NAStuff.StreamerModeImage or "")
	end
	rec.ImageApplied = replacement
	if current ~= replacement then
		NAlib.setProperty(inst, "Image", replacement)
	end
end

NAmanage.StreamerScrubInstance = NAmanage.StreamerScrubInstance or function(inst)
	if not (NAStuff and NAStuff.StreamerModeEnabled == true) then
		return
	end
	if not NAmanage.StreamerIsTarget(inst) then
		return
	end
	NAmanage.StreamerWatchTarget(inst)
	if inst:IsA("TextLabel") or inst:IsA("TextButton") or inst:IsA("TextBox") then
		NAmanage.StreamerApplyTextProp(inst, "Text")
		if inst:IsA("TextBox") then
			NAmanage.StreamerApplyTextProp(inst, "PlaceholderText")
		end
	end
	if inst:IsA("ImageLabel") or inst:IsA("ImageButton") then
		NAmanage.StreamerApplyImageProp(inst)
	end
end

NAmanage.StreamerRestoreInstance = NAmanage.StreamerRestoreInstance or function(inst)
	if typeof(inst) ~= "Instance" then
		return false
	end
	local state = NAmanage.StreamerGetState()
	local rec = state.cache and state.cache[inst]
	if type(rec) ~= "table" then
		return true
	end
	if type(rec.signalConns) == "table" then
		for key, conn in pairs(rec.signalConns) do
			NAmanage.StreamerDisconnectConn(conn)
			rec.signalConns[key] = nil
		end
	end
	if rec.ancConn then
		NAmanage.StreamerDisconnectConn(rec.ancConn)
		rec.ancConn = nil
	end
	if rec.charDescConn then
		NAmanage.StreamerDisconnectConn(rec.charDescConn)
		rec.charDescConn = nil
	end
	if rec.charAncConn then
		NAmanage.StreamerDisconnectConn(rec.charAncConn)
		rec.charAncConn = nil
	end
	if rec.containerDescConn then
		NAmanage.StreamerDisconnectConn(rec.containerDescConn)
		rec.containerDescConn = nil
	end
	if rec.containerAncConn then
		NAmanage.StreamerDisconnectConn(rec.containerAncConn)
		rec.containerAncConn = nil
	end
	rec.scanQueued = nil
	rec.scanToken = nil
	rec.charScanToken = nil
	local failed = false
	local function restoreProp(prop)
		local originalKey = prop .. "Original"
		local appliedKey = prop .. "Applied"
		local original = rec[originalKey]
		local current = NAlib.isProperty(inst, prop)
		if original ~= nil and current ~= nil then
			if not NAlib.setProperty(inst, prop, original) then
				failed = true
				return
			end
		end
		rec[originalKey] = nil
		rec[appliedKey] = nil
	end
	restoreProp("Text")
	restoreProp("PlaceholderText")
	restoreProp("Image")
	restoreProp("Color")
	restoreProp("Material")
	restoreProp("Reflectance")
	restoreProp("LocalTransparencyModifier")
	restoreProp("Transparency")
	restoreProp("TextureID")
	restoreProp("TextureId")
	restoreProp("MeshId")
	restoreProp("VertexColor")
	restoreProp("BaseTextureId")
	restoreProp("OverlayTextureId")
	restoreProp("ShirtTemplate")
	restoreProp("PantsTemplate")
	restoreProp("Graphic")
	restoreProp("HeadColor3")
	restoreProp("LeftArmColor3")
	restoreProp("RightArmColor3")
	restoreProp("LeftLegColor3")
	restoreProp("RightLegColor3")
	restoreProp("TorsoColor3")
	restoreProp("DisplayDistanceType")
	restoreProp("NameDisplayDistance")
	restoreProp("Name")
	restoreProp("DisplayName")
	if failed then
		return false
	end
	state.cache[inst] = nil
	return true
end

NAmanage.StreamerGetRoots = NAmanage.StreamerGetRoots or function(opts)
	opts = opts or {}
	local roots = {}
	local seen = {}
	local function addRoot(root)
		if typeof(root) ~= "Instance" or seen[root] then
			return
		end
		seen[root] = true
		Insert(roots, root)
	end

	addRoot(COREGUI)
	do
		local ok, hub = pcall(function()
			return NAmanage._pgHubGet and NAmanage._pgHubGet()
		end)
		if ok and type(hub) == "table" then
			addRoot(hub.root)
		end
	end
	addRoot(NAlib.huiGrabber and NAlib.huiGrabber() or nil)
	if opts.includeWorkspace == true then
		addRoot(workspace)
	end
	return roots
end

NAmanage.StreamerScrubAll = NAmanage.StreamerScrubAll or function(token, opts)
	opts = opts or {}
	local state = NAmanage.StreamerGetState()
	if state.scrubBusy then
		return
	end
	state.scrubBusy = true
	pcall(function()
		local roots = NAmanage.StreamerGetRoots(opts)
		for i = 1, #roots do
			local root = roots[i]
			if token and token.cancelled then
				break
			end
			if root == workspace then
				NAmanage.ForEachDescendantYield(root, function(inst)
					if token and token.cancelled then
						return
					end
					if NAmanage.StreamerIsContainer(inst) then
						NAmanage.StreamerHandleAdded(inst)
					end
				end, {
					yieldEvery = tonumber(opts.yieldEvery) or 144;
					cancelToken = token;
				})
			else
				NAmanage.StreamerScanContainer(root, token, {
					yieldEvery = tonumber(opts.yieldEvery) or 96;
				})
			end
		end
	end)
	state.scrubBusy = false
end

NAmanage.StreamerSortRestorePending = NAmanage.StreamerSortRestorePending or function(pending)
	if type(pending) ~= "table" or #pending <= 1 then
		return pending
	end
	local sortMeta = {}
	for i = 1, #pending do
		local inst = pending[i]
		local depth = 0
		local current = inst
		while typeof(current) == "Instance" and current.Parent do
			depth += 1
			current = current.Parent
		end
		sortMeta[inst] = {
			depth = depth;
			key = tostring(inst);
		}
	end
	table.sort(pending, function(a, b)
		local metaA = sortMeta[a]
		local metaB = sortMeta[b]
		if metaA.depth == metaB.depth then
			return metaA.key > metaB.key
		end
		return metaA.depth > metaB.depth
	end)
	return pending
end

NAmanage.StreamerGetPriorityRoots = NAmanage.StreamerGetPriorityRoots or function()
	local roots = {}
	local seen = {}
	local function addRoot(root)
		if typeof(root) ~= "Instance" or seen[root] then
			return
		end
		seen[root] = true
		Insert(roots, root)
	end
	if Players and Players.LocalPlayer and Players.LocalPlayer.Character then
		addRoot(Players.LocalPlayer.Character)
	end
	local baseRoots = NAmanage.StreamerGetRoots({
		includeWorkspace = false;
	})
	for i = 1, #baseRoots do
		addRoot(baseRoots[i])
	end
	return roots
end

NAmanage.StreamerRestorePriority = NAmanage.StreamerRestorePriority or function(opts)
	opts = opts or {}
	local state = NAmanage.StreamerGetState()
	local cache = state.cache
	if type(cache) ~= "table" then
		return 0
	end
	local roots = opts.roots
	if type(roots) ~= "table" then
		roots = NAmanage.StreamerGetPriorityRoots()
	end
	if #roots == 0 then
		return 0
	end
	local pending = {}
	local function isPriority(inst)
		if typeof(inst) ~= "Instance" then
			return false
		end
		for i = 1, #roots do
			local root = roots[i]
			if inst == root then
				return true
			end
			local ok, result = pcall(function()
				return inst:IsDescendantOf(root)
			end)
			if ok and result then
				return true
			end
		end
		return false
	end
	for inst in pairs(cache) do
		if isPriority(inst) then
			Insert(pending, inst)
		end
	end
	NAmanage.StreamerSortRestorePending(pending)
	for i = 1, #pending do
		NAmanage.StreamerRestoreInstance(pending[i])
	end
	return #pending
end

NAmanage.StreamerRestoreAll = NAmanage.StreamerRestoreAll or function(opts)
	opts = opts or {}
	local state = NAmanage.StreamerGetState()
	if state.restoreToken then
		NAmanage.CancelTokenCancel(state.restoreToken)
		state.restoreToken = nil
	end
	local pending = {}
	for inst in pairs(state.cache) do
		Insert(pending, inst)
	end
	NAmanage.StreamerSortRestorePending(pending)
	if #pending == 0 then
		if type(opts.onComplete) == "function" then
			pcall(opts.onComplete, 0, false)
		end
		return 0
	end
	local maxPerStep = tonumber(opts.maxPerStep) or tonumber(opts.yieldEvery) or 24
	if maxPerStep < 1 then
		maxPerStep = 1
	end
	local timeBudget = tonumber(opts.timeBudget)
	if timeBudget == nil then
		timeBudget = 0.002
	end
	if timeBudget < 0 then
		timeBudget = 0
	end
	local restoreAsync = opts.async ~= false
	local delayTime = opts.delayTime
	local restoreToken = NAmanage.NewCancelToken()
	state.restoreToken = restoreToken
	local onComplete = type(opts.onComplete) == "function" and opts.onComplete or nil
	local retries = tonumber(opts.retries)
	if retries == nil then
		retries = 2
	end
	local restored = 0
	local idx = 1
	local total = #pending

	local function finish()
		local cancelled = restoreToken.cancelled == true
		if state.restoreToken == restoreToken then
			state.restoreToken = nil
		end
		local remaining = NAmanage.StreamerCacheCount(state.cache)
		if not cancelled and remaining > 0 and retries > 0 then
			Delay(0.15, function()
				local liveState = NAmanage.StreamerGetState()
				if not (NAStuff and NAStuff.StreamerModeEnabled == true) and not liveState.restoreToken then
					NAmanage.StreamerRestoreAll({
						maxPerStep = maxPerStep;
						timeBudget = timeBudget;
						delayTime = delayTime;
						async = restoreAsync;
						retries = retries - 1;
						onComplete = onComplete;
					})
				elseif onComplete then
					pcall(onComplete, restored, true)
				end
			end)
			return
		end
		if onComplete then
			pcall(onComplete, restored, cancelled)
		end
	end

	if not restoreAsync then
		while idx <= total do
			if restoreToken.cancelled then
				break
			end
			local okRestore, didRestore = pcall(NAmanage.StreamerRestoreInstance, pending[idx])
			if okRestore and didRestore ~= false then
				restored += 1
			end
			idx += 1
		end
		finish()
		return restored
	end

	local function runWorker()
		while idx <= total do
			if restoreToken.cancelled then
				break
			end
			local started = os.clock()
			local stepCount = 0
			while idx <= total do
				if restoreToken.cancelled then
					break
				end
				local okRestore, didRestore = pcall(NAmanage.StreamerRestoreInstance, pending[idx])
				if okRestore and didRestore ~= false then
					restored += 1
				end
				idx += 1
				stepCount += 1
				if stepCount >= maxPerStep then
					break
				end
				if timeBudget > 0 and (os.clock() - started) >= timeBudget then
					break
				end
			end
			if idx <= total and not restoreToken.cancelled then
				if delayTime and delayTime > 0 then
					Wait(delayTime)
				else
					Wait()
				end
			end
		end
		finish()
	end

	Spawn(runWorker)
	return total
end

NAmanage.StreamerWatchPlayer = NAmanage.StreamerWatchPlayer or function(plr)
	if not (plr and Players) then
		return
	end
	local userId = tonumber(plr.UserId)
	if not userId then
		return
	end
	local function onNameChanged()
		NAmanage.StreamerScheduleNameRefresh(true)
		if plr.Character then
			local hum = plr.Character:FindFirstChildOfClass("Humanoid")
			if hum then
				NAmanage.StreamerApplyHumanoid(hum)
			end
		end
	end
	NAlib.connect("streamermode_player_names", plr:GetPropertyChangedSignal("DisplayName"):Connect(onNameChanged))
	NAlib.connect("streamermode_player_names", plr:GetPropertyChangedSignal("Name"):Connect(onNameChanged))
	if plr.Character then
		NAmanage.StreamerHandleCharacter(plr.Character, NAmanage.StreamerGetState().token)
	end
	NAlib.connect("streamermode_player_chars", plr.CharacterAdded:Connect(function(char)
		if NAStuff and NAStuff.StreamerModeEnabled == true then
			NAmanage.StreamerHandleCharacter(char, NAmanage.StreamerGetState().token)
		end
	end))
end

NAmanage.StreamerHandleAdded = NAmanage.StreamerHandleAdded or function(inst)
	if not (NAStuff and NAStuff.StreamerModeEnabled == true) then
		return
	end
	if NAmanage.StreamerIsTarget(inst) then
		NAmanage.StreamerScrubInstance(inst)
		return
	end
	if NAmanage.StreamerIsContainer(inst) then
		NAmanage.StreamerWatchContainer(inst)
		NAmanage.StreamerScanContainerAsync(inst, {
			includeRoot = true;
			yieldEvery = 96;
			cancelToken = NAmanage.StreamerGetState().token;
		})
	end
end

NAmanage.setStreamerMode = NAmanage.setStreamerMode or function(enable, opts)
	opts = opts or {}
	local state = enable == true
	local wasEnabled = NAStuff.StreamerModeEnabled == true
	local smState = NAmanage.StreamerGetState()

	if opts.force ~= true and wasEnabled == state and not (state and smState.applied ~= true) then
		if opts.save ~= false then
			pcall(NAmanage.NASettingsSet, "streamerMode", state)
		end
		if state then
			NAmanage.StreamerSetPlayerListHidden(true)
			NAmanage.StreamerScheduleNameRefresh(true)
		end
		return state
	end

	NAStuff.StreamerModeEnabled = state
	if opts.save ~= false then
		pcall(NAmanage.NASettingsSet, "streamerMode", state)
	end

	if smState.token then
		NAmanage.CancelTokenCancel(smState.token)
		smState.token = nil
	end
	if smState.restoreToken then
		NAmanage.CancelTokenCancel(smState.restoreToken)
		smState.restoreToken = nil
	end

	if not state then
		smState.applied = false
		NAmanage.StreamerSetPlayerListHidden(false)
		NAlib.disconnect("streamermode_coregui")
		NAlib.disconnect("streamermode_playergui")
		NAlib.disconnect("streamermode_hui")
		NAlib.disconnect("streamermode_workspace")
		NAlib.disconnect("streamermode_player_chars")
		NAlib.disconnect("streamermode_players")
		NAlib.disconnect("streamermode_player_names")
		local restoreAsync = opts.restoreAsync ~= false
		local queued = NAmanage.StreamerRestoreAll({
			maxPerStep = tonumber(opts.maxPerStep) or tonumber(opts.yieldEvery) or 32;
			timeBudget = tonumber(opts.timeBudget) or 0.003;
			delayTime = opts.delayTime;
			async = restoreAsync;
		})
		if not opts.silent and DoNotif then
			if (tonumber(queued) or 0) > 0 and restoreAsync then
				DoNotif("Streamer Mode disabled (restoring in background)", 2)
			else
				DoNotif("Streamer Mode disabled", 2)
			end
		end
		return false
	end

	NAmanage.StreamerRefreshNameTokens()
	NAmanage.StreamerSetPlayerListHidden(true)
	Delay(0.25, function()
		if NAStuff and NAStuff.StreamerModeEnabled == true then
			NAmanage.StreamerSetPlayerListHidden(true)
		end
	end)
	NAlib.disconnect("streamermode_player_chars")
	NAlib.disconnect("streamermode_player_names")
	if Players then
		for _, plr in ipairs(__lt.cm("Players", "GetPlayers")) do
			NAmanage.StreamerWatchPlayer(plr)
		end
	end

	NAlib.disconnect("streamermode_coregui")
	NAlib.connect("streamermode_coregui", NAmanage.cgSub({
		added = NAmanage.StreamerHandleAdded,
		filterAdded = NAmanage.StreamerIsRelevant,
	}))
	NAlib.disconnect("streamermode_playergui")
	NAlib.connect("streamermode_playergui", NAmanage.pgSub({
		added = NAmanage.StreamerHandleAdded,
		filterAdded = NAmanage.StreamerIsRelevant,
	}))
	NAlib.disconnect("streamermode_hui")
	do
		local hui = NAlib.huiGrabber and NAlib.huiGrabber() or nil
		if hui then
			NAlib.connect("streamermode_hui", NAmanage.descSub(hui, {
				added = NAmanage.StreamerHandleAdded,
				filterAdded = NAmanage.StreamerIsRelevant,
			}))
		end
	end
	NAlib.disconnect("streamermode_workspace")
	NAlib.connect("streamermode_workspace", NAmanage.wsSub({
		added = NAmanage.StreamerHandleAdded,
		filterAdded = NAmanage.StreamerIsContainer,
	}))
	NAlib.disconnect("streamermode_players")
	NAlib.connect("streamermode_players", NAmanage.playersSub({
		added = function(plr)
			NAmanage.StreamerWatchPlayer(plr)
			NAmanage.StreamerScheduleNameRefresh(false)
		end,
		removing = function()
			NAmanage.StreamerScheduleNameRefresh(false)
		end,
	}))

	local token = NAmanage.NewCancelToken()
	smState.token = token
	NAmanage.StreamerScrubAll(token, {
		includeWorkspace = true;
		yieldEvery = 72;
	})

	if not opts.silent and DoNotif then
		DoNotif("Streamer Mode enabled", 2)
	end
	smState.applied = true
	return true
end

NAStuff.CmdBar2 = {
	defaultWidth = 340;
	defaultHeight = 78;
	minWidth = 200;
	maxWidth = 500;
	minHeight = 70;
	maxHeight = 160;
	topHeight = 26;
	bodyOffsetY = 34;
	bodyBottomPadding = 8;
	bodyMinHeight = 24;
}

function NAmanage.CmdBar2ClampValue(value, minValue, maxValue, fallback)
	local numberValue = tonumber(value)
	if not numberValue then
		return fallback
	end
	numberValue = math.floor(numberValue + 0.5)
	if numberValue < minValue then
		return minValue
	elseif numberValue > maxValue then
		return maxValue
	end
	return numberValue
end

function NAmanage.CmdBar2ComputeBodyHeight(totalHeight)
	local cfg = NAStuff.CmdBar2 or {}
	local available = totalHeight - (cfg.bodyOffsetY or 0) - (cfg.bodyBottomPadding or 0)
	if available < (cfg.bodyMinHeight or 0) then
		return cfg.bodyMinHeight or 0
	end
	return available
end

local CustomFunctionSupport = isfile and isfolder and writefile and readfile and listfiles and appendfile;
local FileSupport = isfile and isfolder and writefile and readfile and makefolder;

local IsOnMobile=(function()
	local platform=__lt.cm("UserInputService", "GetPlatform")
	if platform==Enum.Platform.IOS or platform==Enum.Platform.Android or platform==Enum.Platform.AndroidTV or platform==Enum.Platform.Chromecast or platform==Enum.Platform.MetaOS then
		return true
	end
	if platform==Enum.Platform.None then
		return UserInputService.TouchEnabled and not (UserInputService.KeyboardEnabled or UserInputService.MouseEnabled)
	end
	return false
end)()
local IsOnPC=(function()
	local platform=__lt.cm("UserInputService", "GetPlatform")
	if platform==Enum.Platform.Windows or platform==Enum.Platform.OSX or platform==Enum.Platform.Linux or platform==Enum.Platform.SteamOS or platform==Enum.Platform.UWP or platform==Enum.Platform.DOS or platform==Enum.Platform.BeOS then
		return true
	end
	if platform==Enum.Platform.None then
		return UserInputService.KeyboardEnabled or UserInputService.MouseEnabled
	end
	return false
end)()

--[[ Character helpers ]]--
NA_GRAB_BODY = (function()
	local T = {};
	local _cache = setmetatable({}, {
		__mode = "k"
	});
	local overrideModel = nil;
	local overrideConn = nil;
	local selectingOverride = false;
	local lastOverridePickAt = 0;
	local OVERRIDE_PICK_COOLDOWN = 1.25;
	local setOverrideModel;
	local pickOverrideModel;
	local function asChar(obj)
		if not obj or typeof(obj) ~= "Instance" then
			return nil;
		end;
		if obj:IsA("Player") then
			return obj.Character;
		end;
		if obj:IsA("Model") then
			return obj;
		end;
		return nil;
	end;
	local function firstPart(model)
		if not model then
			return nil
		end
		local q = { model }
		local qi, qn = 1, 1
		while qi <= qn do
			local inst = q[qi]
			qi += 1
			if inst:IsA("BasePart") then
				return inst
			end
			local ch = inst:GetChildren()
			for i = 1, #ch do
				qn += 1
				q[qn] = ch[i]
			end
		end
		return nil
	end
	setOverrideModel = function(model)
		if overrideConn then
			overrideConn:Disconnect();
			overrideConn = nil;
		end;
		overrideModel = model;
		if model then
			overrideConn = model.AncestryChanged:Connect(function(_, parent)
				if not parent then
					if overrideConn then
						overrideConn:Disconnect();
						overrideConn = nil;
					end;
					overrideModel = nil;
					selectingOverride = false;
					if Players and Players.LocalPlayer and workspace then
						local lp = Players.LocalPlayer;
						local cur = lp.Character;
						if cur and cur.Parent and (not cur:IsDescendantOf(workspace)) then
							Spawn(function()
								pickOverrideModel();
							end);
						end;
					end;
				end;
			end);
		end;
	end;
	pickOverrideModel = function(force)
		if selectingOverride then
			return overrideModel;
		end;
		if not (Window and Players and Players.LocalPlayer and workspace) then
			return overrideModel;
		end;
		local lp = Players.LocalPlayer;
		local cur = lp.Character;
		if not cur then
			return overrideModel;
		end;
		if not force and cur:IsDescendantOf(workspace) then
			return overrideModel;
		end;
		selectingOverride = true;
		local btns = {};
		local cands = {};
		local seen = {};
		for _, plr in ipairs(__lt.cm("Players", "GetPlayers")) do
			local ch = plr.Character;
			if ch and ch:IsDescendantOf(workspace) and (not seen[ch]) then
				seen[ch] = true;
				Insert(cands, ch);
			end;
		end;
		if CheckIfNPC then
			local q = { workspace }
			local qi, qn = 1, 1
			while qi <= qn do
				local inst = q[qi]
				qi += 1

				if inst:IsA("Model") and not seen[inst] and CheckIfNPC(inst) then
					seen[inst] = true
					Insert(cands, inst)
				end

				local ch = inst:GetChildren()
				for i = 1, #ch do
					qn += 1
					q[qn] = ch[i]
				end
			end
		end
		local nCnt = {};
		for i = 1, #cands do
			local m = cands[i];
			local n = m.Name;
			nCnt[n] = (nCnt[n] or 0) + 1;
		end;
		local nUse = {};
		local done = false;
		local function fin()
			if done then
				return;
			end;
			done = true;
			selectingOverride = false;
		end;
		if #cands == 0 then
			Insert(btns, {
				Text = "No characters found",
				Callback = function()
					setOverrideModel(nil);
					fin();
				end
			});
		else
			for i = 1, #cands do
				local m = cands[i];
				local n = m.Name;
				local suffix = "";
				if nCnt[n] and nCnt[n] > 1 then
					nUse[n] = (nUse[n] or 0) + 1;
					suffix = " (" .. nUse[n] .. ")";
				end;
				Insert(btns, {
					Text = n .. suffix,
					Callback = function()
						setOverrideModel(m);
						fin();
					end
				});
			end;
		end;
		Insert(btns, {
			Text = "Cancel",
			Callback = function()
				setOverrideModel(nil);
				fin();
			end
		});
		Window({
			WindowTitle = "Select Character",
			Duration = nil,
			Text = "Choose a character or NPC model",
			Buttons = btns
		});
		return overrideModel;
	end;
	local function rebuild(model, rec)
		rec.head = nil
		rec.root = nil
		rec.torso = nil
		rec.humanoid = nil
		if not model then
			rec.dirty = false
			return rec
		end
		local q = { model }
		local qi, qn = 1, 1
		while qi <= qn do
			local inst = q[qi]
			qi += 1
			if inst:IsA("Humanoid") or inst:IsA("AnimationController") then
				rec.humanoid = rec.humanoid or inst
			elseif inst:IsA("BasePart") then
				local name = inst.Name:lower()
				if not rec.root and name:find("root", 1, true) then
					rec.root = inst
				elseif not rec.torso and name:find("torso", 1, true) then
					rec.torso = inst
				elseif not rec.head and name:find("head", 1, true) then
					rec.head = inst
				end
			end
			if rec.head and rec.root and rec.torso and rec.humanoid then
				break
			end
			local ch = inst:GetChildren()
			for i = 1, #ch do
				qn += 1
				q[qn] = ch[i]
			end
		end
		rec.dirty = false
		return rec
	end
	local function ensure(obj)
		local model = asChar(obj);
		if obj == Players.LocalPlayer then
			if overrideModel then
				model = overrideModel;
			elseif model and model.Parent and (not model:IsDescendantOf(workspace)) then
				local now = os.clock()
				if now - lastOverridePickAt >= OVERRIDE_PICK_COOLDOWN then
					lastOverridePickAt = now
					model = pickOverrideModel(true) or model;
				end
			end;
		elseif not model then
			model = overrideModel;
		end;
		if not model then
			return nil;
		end;
		local rec = _cache[model];
		if not rec then
			rec = {
				dirty = true
			};
			_cache[model] = rec;

			local function applyCandidate(inst)
				if not inst then
					return
				end
				if not rec.humanoid and (inst:IsA("Humanoid") or inst:IsA("AnimationController")) then
					rec.humanoid = inst
					return
				end
				if not inst:IsA("BasePart") then
					return
				end
				local name = inst.Name:lower()
				if not rec.root and name:find("root", 1, true) then
					rec.root = inst
					return
				end
				if not rec.torso and name:find("torso", 1, true) then
					rec.torso = inst
					return
				end
				if not rec.head and name:find("head", 1, true) then
					rec.head = inst
				end
			end

			rec.a = NAmanage.descAdd(model, function(d)
				applyCandidate(d)
			end);

			rec.r = NAmanage.descRem(model, function(d)
				local removedTracked = false
				if rec.head == d then
					rec.head = nil;
					removedTracked = true
				end;
				if rec.root == d then
					rec.root = nil;
					removedTracked = true
				end;
				if rec.torso == d then
					rec.torso = nil;
					removedTracked = true
				end;
				if rec.humanoid == d then
					rec.humanoid = nil;
					removedTracked = true
				end;
				if removedTracked then
					rec.dirty = true;
				end
			end);

			rec.c = model.AncestryChanged:Connect(function(_, parent)
				if not parent then
					if rec.a then
						rec.a:Disconnect();
						rec.a = nil;
					end;
					if rec.r then
						rec.r:Disconnect();
						rec.r = nil;
					end;
					if rec.c then
						rec.c:Disconnect();
						rec.c = nil;
					end;
					_cache[model] = nil;
				end;
			end);
		end;
		if rec.dirty or rec.humanoid and rec.humanoid.Parent == nil then
			rebuild(model, rec);
		end;
		return rec, model;
	end;
	T.ensure = ensure;
	T.firstPart = firstPart;
	T.asChar = asChar;
	T.pickOverride = function()
		selectingOverride = false;
		setOverrideModel(nil);
		return pickOverrideModel(true);
	end;
	return T;
end)();

function getRoot(char)
	local rec, model = NA_GRAB_BODY.ensure(char)
	if not rec then return nil end
	return rec.root or (model and NA_GRAB_BODY.firstPart(model)) or nil
end

function getTorso(char)
	local rec, model = NA_GRAB_BODY.ensure(char)
	if not rec then return nil end
	return rec.torso or (model and NA_GRAB_BODY.firstPart(model)) or nil
end

function getHead(char)
	local rec, model = NA_GRAB_BODY.ensure(char)
	if not rec then return nil end
	return rec.head or (model and NA_GRAB_BODY.firstPart(model)) or nil
end

function getChar()
	local plr = Players.LocalPlayer
	if not plr then return nil end
	local rec, model = NA_GRAB_BODY.ensure(plr)
	return model
end

function getPlrChar(plr)
	return NA_GRAB_BODY.asChar(plr)
end

function getBp()
	local plr = Players.LocalPlayer
	return plr and plr:FindFirstChildOfClass("Backpack") or nil
end

function getHum(char, waitSeconds)
	local target

	if char then
		target = NA_GRAB_BODY.asChar(char) or char
	else
		local plr = Players.LocalPlayer
		if plr then
			target = plr.Character
		end
	end

	if not target then
		return nil
	end

	local hum = target:FindFirstChildOfClass("Humanoid") or target:FindFirstChildOfClass("AnimationController")
	if hum then
		return hum
	end

	local timeout = tonumber(waitSeconds)
	if not timeout or timeout <= 0 then
		local rec = NA_GRAB_BODY.ensure(target)
		return rec and rec.humanoid or nil
	end

	timeout = math.max(0, timeout)
	local deadline = os.clock() + timeout

	local function findHumanoid()
		return target:FindFirstChildOfClass("Humanoid") or target:FindFirstChildOfClass("AnimationController")
	end

	while not hum and os.clock() < deadline do
		Wait(0.05)
		hum = findHumanoid()
	end

	if hum then
		return hum
	end

	local rec = NA_GRAB_BODY.ensure(target)
	return rec and rec.humanoid or nil
end

NAmanage.GetJumpLaunchVelocity = function(hum)
	if not hum then return nil end

	local jumpPower = tonumber(NAlib.isProperty(hum, "JumpPower"))
	if hum.UseJumpPower ~= false and jumpPower and jumpPower > 0 then
		return jumpPower
	end

	local jumpHeight = tonumber(NAlib.isProperty(hum, "JumpHeight"))
	if jumpHeight and jumpHeight > 0 then
		return math.sqrt(2 * workspace.Gravity * jumpHeight)
	end

	return jumpPower
end

NAmanage.PrepareHumanoidForLaunch = function(hum)
	if not hum then return end

	pcall(function()
		if NAlib.isProperty(hum, "Sit") ~= nil then
			hum.Sit = false
		end
	end)

	pcall(function()
		if NAlib.isProperty(hum, "PlatformStand") ~= nil then
			hum.PlatformStand = false
		end
	end)

	local state
	pcall(function()
		state = hum:GetState()
	end)

	if state == Enum.HumanoidStateType.Seated
		or state == Enum.HumanoidStateType.FallingDown
		or state == Enum.HumanoidStateType.Ragdoll
		or state == Enum.HumanoidStateType.PlatformStanding then
		pcall(function()
			hum:ChangeState(Enum.HumanoidStateType.GettingUp)
		end)
	end
end

NAmanage.LaunchHumanoid = function(hum, root)
	if not hum then return false end

	if NAStuff.SafeJumpMethod == false then
		return pcall(function()
			hum:ChangeState(Enum.HumanoidStateType.Jumping)
		end)
	end

	root = root or getRoot(hum.Parent)
	if not root then return false end

	NAmanage.PrepareHumanoidForLaunch(hum)

	local launchY = NAmanage.GetJumpLaunchVelocity(hum)
	if not launchY then return false end

	local velocity = NAlib.isProperty(root, "AssemblyLinearVelocity") or root.Velocity
	if typeof(velocity) ~= "Vector3" then
		velocity = Vector3.new()
	end

	local boostedY = math.max(velocity.Y, launchY)
	if NAlib.setProperty(root, "AssemblyLinearVelocity", Vector3.new(velocity.X, boostedY, velocity.Z)) then
		return true
	end

	return pcall(function()
		root.Velocity = Vector3.new(velocity.X, boostedY, velocity.Z)
	end)
end

function getPlrHum(plr)
	return getHum(plr)
end

function IsR15(plr)
	plr=(plr or Players.LocalPlayer)
	if plr then
		local h=getPlrHum(plr)
		if h and h.RigType==Enum.HumanoidRigType.R15 then return true end
	end
	return false
end

function IsR6(plr)
	plr=(plr or Players.LocalPlayer)
	if plr then
		local h=getPlrHum(plr)
		if h and h.RigType==Enum.HumanoidRigType.R6 then return true end
	end
	return false
end

Foreach = function(Table, Func, Loop)
	for Index, Value in next, Table do
		pcall(function()
			if Loop and typeof(Value) == 'table' then
				for Index2, Value2 in next, Value do
					Func(Index2, Value2)
				end
			else
				Func(Index, Value)
			end
		end)
	end
end

CheckIfNPC = function(character)
	if not (character and character:IsA("Model")) then
		return false
	end
	local function isPlayerModel(model)
		if not Players then
			return false
		end
		local okPlr, plr = pcall(function()
			return __lt.cm("Players", "GetPlayerFromCharacter", model)
		end)
		if okPlr and plr then
			return true
		end
		for _, p in ipairs(__lt.cm("Players", "GetPlayers")) do
			local ch = p.Character
			if ch and (model == ch or model:IsDescendantOf(ch) or ch:IsDescendantOf(model)) then
				return true
			end
		end
		return false
	end

	local humanoid = character:FindFirstChildOfClass("Humanoid")
	if not humanoid then
		return false
	end
	if isPlayerModel(character) then
		return false
	end
	return true
end

NAmanage.IsValidESPModel = function(model, allowNPC)
	if not (model and model:IsA("Model")) then
		return false
	end
	if not model.Parent or not workspace or not model:IsDescendantOf(workspace) then
		return false
	end
	local hum = model:FindFirstChildOfClass("Humanoid")
	if not hum or hum.Health <= 0 or hum.Parent == nil then
		return false
	end
	local root = getRoot(model)
	if not root or root.Parent == nil then
		return false
	end
	if allowNPC then
		return true
	end
	local okPlr, plr = pcall(function()
		return __lt.cm("Players", "GetPlayerFromCharacter", model)
	end)
	return okPlr and plr ~= nil
end

FindInTable = function(tbl,val)
	if tbl==nil then return false end
	for _,v in pairs(tbl) do
		if v==val then return true end
	end
	return false
end

updateCanvasSize = function(frame, scale)
	if not (frame and frame.Parent) then
		return
	end

	NAmanage._canvasLayoutCache = NAmanage._canvasLayoutCache or {}
	NAmanage._canvasHeightCache = NAmanage._canvasHeightCache or {}

	local layout = NAmanage._canvasLayoutCache[frame]
	if not (layout and layout.Parent == frame) then
		layout = frame:FindFirstChildOfClass("UIListLayout")
		NAmanage._canvasLayoutCache[frame] = layout
	end
	if not layout then
		return
	end

	local targetHeight = layout.AbsoluteContentSize.Y
	if scale and scale ~= 0 then
		targetHeight = targetHeight / scale
	end
	targetHeight = math.max(0, math.floor(targetHeight + 0.5))

	local last = NAmanage._canvasHeightCache[frame]
	if last ~= nil and last == targetHeight then
		return
	end
	NAmanage._canvasHeightCache[frame] = targetHeight

	local cs = frame.CanvasSize
	if cs.Y.Scale == 0 and (cs.Y.Offset or 0) == targetHeight then
		if NAmanage.CustomScroll and NAmanage.CustomScroll.refreshByTarget then
			NAmanage.CustomScroll.refreshByTarget(frame);
		end
		return
	end

	frame.CanvasSize = UDim2.new(0, 0, 0, targetHeight)
	if NAmanage.CustomScroll and NAmanage.CustomScroll.refreshByTarget then
		NAmanage.CustomScroll.refreshByTarget(frame);
	end
end

NAmanage.GetUIScaleFactor = function(inst)
	local scale = 1
	local current = inst
	while current do
		local uiScale = current:FindFirstChildOfClass("UIScale")
		if uiScale and uiScale.Scale then
			local uiScaleValue = tonumber(uiScale.Scale)
			if uiScaleValue and uiScaleValue > 0 then
				scale *= uiScaleValue
			end
		end
		current = current.Parent
	end
	return scale
end

NAmanage.GetLogicalAbsoluteSize = function(inst)
	if not inst then
		return Vector2.new()
	end
	local size = inst.AbsoluteSize or Vector2.new()
	local scale = NAmanage.GetUIScaleFactor and NAmanage.GetUIScaleFactor(inst) or 1
	if not scale or scale <= 0 then
		scale = 1
	end
	return Vector2.new(size.X / scale, size.Y / scale)
end

NAmanage.CreateNAFreecam=function()
	local module = {}

	local pi = math.pi
	local clamp = math.clamp
	local exp = math.exp
	local rad = math.rad
	local sqrt = math.sqrt
	local tan = math.tan

	local Camera = workspace.CurrentCamera

	workspace:GetPropertyChangedSignal("CurrentCamera"):Connect(function()
		if workspace.CurrentCamera then
			Camera = workspace.CurrentCamera
		end
	end)

	local Spring = {} do
		Spring.__index = Spring

		function Spring.new(freq, pos)
			local self = setmetatable({}, Spring)
			self.f = freq
			self.p = pos
			self.v = pos*0
			return self
		end

		function Spring:Update(dt, goal)
			local f = self.f*2*pi
			local p0 = self.p
			local v0 = self.v

			local offset = goal - p0
			local decay = exp(-f*dt)

			local p1 = goal + (v0*dt - offset*(f*dt + 1))*decay
			local v1 = (f*dt*(offset*f - v0) + v0)*decay

			self.p = p1
			self.v = v1

			return p1
		end

		function Spring:SetFreq(freq)
			self.f = freq
		end

		function Spring:Reset(pos)
			self.p = pos
			self.v = pos*0
		end
	end

	local cameraPos = Vector3.new()
	local cameraRot = Vector2.new()
	local cameraFov = 70

	local velSpring = Spring.new(1.5, Vector3.new())
	local panSpring = Spring.new(1.0, Vector2.new())
	local fovSpring = Spring.new(4.0, 0)

	local NAV_GAIN = Vector3.new(1, 1, 1)*64
	local FOV_GAIN = 300
	local PITCH_LIMIT = rad(90)

	local PAN_PIXELS_TO_RADIANS = rad(0.5)
	local FOV_WHEEL_SPEED = 1.0
	local FOV_WHEEL_SPEED_DT = FOV_WHEEL_SPEED/60

	local NAV_ADJ_SPEED = 0.75
	local NAV_MIN_SPEED = 0.01
	local NAV_MAX_SPEED = 4.0
	local NAV_SHIFT_MUL = 0.25

	local keyboard = {
		[Enum.KeyCode.W] = 0,
		[Enum.KeyCode.A] = 0,
		[Enum.KeyCode.S] = 0,
		[Enum.KeyCode.D] = 0,
		[Enum.KeyCode.Q] = 0,
		[Enum.KeyCode.E] = 0,
		[Enum.KeyCode.Up] = 0,
		[Enum.KeyCode.Down] = 0,
	}

	local mouse = {
		Delta = Vector2.new(),
		MouseWheel = 0,
	}

	local navSpeed = 1

	local function zeroInput()
		for key in pairs(keyboard) do
			keyboard[key] = 0
		end
		mouse.Delta = Vector2.new()
		mouse.MouseWheel = 0
	end

	local capturing = false
	local touchConnection = nil

	local function onKeypress(_, inputState, input)
		if input.KeyCode and keyboard[input.KeyCode] ~= nil then
			if inputState == Enum.UserInputState.Begin then
				keyboard[input.KeyCode] = 1
			elseif inputState == Enum.UserInputState.End then
				keyboard[input.KeyCode] = 0
			end
			return Enum.ContextActionResult.Sink
		end
		return Enum.ContextActionResult.Pass
	end

	local function onMousePan(_, inputState, input)
		if inputState == Enum.UserInputState.Change then
			local delta = input.Delta
			mouse.Delta = Vector2.new(-delta.Y, -delta.X)
		end
		return Enum.ContextActionResult.Sink
	end

	local function onTouchPan(_, inputState, input)
		if inputState == Enum.UserInputState.Change then
			local delta = input.Delta
			mouse.Delta = Vector2.new(-delta.Y, -delta.X)
		end
		return Enum.ContextActionResult.Pass
	end

	local function onMouseWheel(_, inputState, input)
		if inputState == Enum.UserInputState.Change then
			mouse.MouseWheel = -input.Position.Z
		end
		return Enum.ContextActionResult.Sink
	end

	local function inputVel(dt)
		if not IsOnMobile then
			navSpeed = clamp(navSpeed + dt*(keyboard[Enum.KeyCode.Up] - keyboard[Enum.KeyCode.Down])*NAV_ADJ_SPEED, NAV_MIN_SPEED, NAV_MAX_SPEED)
		end

		local move = Vector3.new()

		if IsOnMobile and typeof(GetCustomMoveVector) == "function" then
			local ok, vec = pcall(GetCustomMoveVector)
			if ok and vec and vec.Magnitude > 0 then
				move = vec
			end
		else
			move = Vector3.new(
				(keyboard[Enum.KeyCode.D] - keyboard[Enum.KeyCode.A]),
				(keyboard[Enum.KeyCode.E] - keyboard[Enum.KeyCode.Q]),
				-(keyboard[Enum.KeyCode.W] - keyboard[Enum.KeyCode.S])
			)
		end

		local shift = __lt.cm("UserInputService", "IsKeyDown", Enum.KeyCode.LeftShift) or __lt.cm("UserInputService", "IsKeyDown", Enum.KeyCode.RightShift)

		return move*(navSpeed*(shift and NAV_SHIFT_MUL or 1))
	end

	local function inputPan(dt)
		local kMouse = mouse.Delta
		mouse.Delta = Vector2.new()
		return kMouse
	end

	local function inputFov(dt)
		local kMouse = mouse.MouseWheel*FOV_WHEEL_SPEED
		if dt > 0 then
			kMouse = (mouse.MouseWheel/dt)*FOV_WHEEL_SPEED_DT
		end
		mouse.MouseWheel = 0
		return kMouse
	end

	local enabled = false
	local storedState = {}

	local function stepFreecam(dt)
		if not Camera then
			return
		end

		local vel = inputVel(dt)
		local pan = inputPan(dt)
		local fovStep = inputFov(dt)

		local zoomFactor = sqrt(tan(rad(70/2))/tan(rad(cameraFov/2)))
		cameraFov = clamp(cameraFov + fovStep*FOV_GAIN*(dt/zoomFactor), 1, 120)

		cameraRot = cameraRot + pan*(PAN_PIXELS_TO_RADIANS/zoomFactor)
		cameraRot = Vector2.new(clamp(cameraRot.X, -PITCH_LIMIT, PITCH_LIMIT), cameraRot.Y%(2*pi))

		local cf = CFrame.new(cameraPos)*CFrame.fromOrientation(cameraRot.X, cameraRot.Y, 0)*CFrame.new(vel*NAV_GAIN*dt)

		cameraPos = cf.Position

		Camera.CFrame = cf
		Camera.Focus = cf
		Camera.FieldOfView = cameraFov
	end

	function module.Start(initialSpeed)
		if enabled or not Camera then
			return
		end

		enabled = true

		if initialSpeed ~= nil then
			local scaled = tonumber(initialSpeed)
			if scaled then
				navSpeed = clamp(scaled, NAV_MIN_SPEED, NAV_MAX_SPEED)
			end
		end

		storedState.cameraType = Camera.CameraType
		storedState.cameraCFrame = Camera.CFrame
		storedState.cameraFocus = Camera.Focus
		storedState.cameraFov = Camera.FieldOfView
		storedState.mouseIconEnabled = UserInputService.MouseIconEnabled
		storedState.mouseBehavior = UserInputService.MouseBehavior

		local cframe = Camera.CFrame
		local x, y, _ = cframe:ToOrientation()
		cameraPos = cframe.Position
		cameraRot = Vector2.new(x, y)
		cameraFov = Camera.FieldOfView

		Camera.CameraType = Enum.CameraType.Scriptable
		UserInputService.MouseIconEnabled = false
		UserInputService.MouseBehavior = Enum.MouseBehavior.LockCenter

		if not capturing and ContextActionService then
			local freecamKeyboardAction = NAmanage.GetSessionActionName("FreecamKeyboard")
			local freecamMousePanAction = NAmanage.GetSessionActionName("FreecamMousePan")
			local freecamMouseWheelAction = NAmanage.GetSessionActionName("FreecamMouseWheel")
			capturing = true
			__lt.cm("ContextActionService", "BindActionAtPriority", freecamKeyboardAction, onKeypress, false, Enum.ContextActionPriority.High.Value,
				Enum.KeyCode.W, Enum.KeyCode.A, Enum.KeyCode.S, Enum.KeyCode.D,
				Enum.KeyCode.Q, Enum.KeyCode.E,
				Enum.KeyCode.Up, Enum.KeyCode.Down
			)
			__lt.cm("ContextActionService", "BindActionAtPriority", freecamMousePanAction, onMousePan, false, Enum.ContextActionPriority.High.Value, Enum.UserInputType.MouseMovement)
			__lt.cm("ContextActionService", "BindActionAtPriority", freecamMouseWheelAction, onMouseWheel, false, Enum.ContextActionPriority.High.Value, Enum.UserInputType.MouseWheel)
		end

		if IsOnMobile and not touchConnection then
			touchConnection = UserInputService.InputChanged:Connect(function(input, gameProcessed)
				if input.UserInputType ~= Enum.UserInputType.Touch then
					return
				end
				if gameProcessed then
					return
				end
				if input.UserInputState ~= Enum.UserInputState.Change then
					return
				end
				local delta = input.Delta
				mouse.Delta = Vector2.new(-delta.Y, -delta.X)
			end)
		end

		local freecamRenderBind = NAmanage.GetSessionActionName("FreecamRenderStep")
		__lt.cm("RunService", "BindToRenderStep", freecamRenderBind, Enum.RenderPriority.Camera.Value, stepFreecam)
	end

	function module.Stop()
		if not enabled then
			return
		end

		enabled = false
		local freecamRenderBind = NAmanage.GetSessionActionName("FreecamRenderStep")
		__lt.cm("RunService", "UnbindFromRenderStep", freecamRenderBind)

		if capturing and ContextActionService then
			local freecamKeyboardAction = NAmanage.GetSessionActionName("FreecamKeyboard")
			local freecamMousePanAction = NAmanage.GetSessionActionName("FreecamMousePan")
			local freecamMouseWheelAction = NAmanage.GetSessionActionName("FreecamMouseWheel")
			capturing = false
			__lt.cm("ContextActionService", "UnbindAction", freecamKeyboardAction)
			__lt.cm("ContextActionService", "UnbindAction", freecamMousePanAction)
			__lt.cm("ContextActionService", "UnbindAction", freecamMouseWheelAction)
		end

		if touchConnection then
			touchConnection:Disconnect()
			touchConnection = nil
		end

		zeroInput()

		if Camera and storedState.cameraType then
			Camera.CameraType = storedState.cameraType
			Camera.CFrame = storedState.cameraCFrame
			Camera.Focus = storedState.cameraFocus
			Camera.FieldOfView = storedState.cameraFov
		end

		if storedState.mouseIconEnabled ~= nil then
			UserInputService.MouseIconEnabled = storedState.mouseIconEnabled
		end
		if storedState.mouseBehavior ~= nil then
			local behavior = storedState.mouseBehavior
			if behavior == Enum.MouseBehavior.LockCenter then
				behavior = Enum.MouseBehavior.Default
			end
			UserInputService.MouseBehavior = behavior
		end
	end

	function module.SetSpeed(newSpeed)
		local scaled = tonumber(newSpeed)
		if scaled then
			navSpeed = clamp(scaled, NAV_MIN_SPEED, NAV_MAX_SPEED)
		end
	end

	function module.Toggle(initialSpeed)
		if enabled then
			module.Stop()
		else
			module.Start(initialSpeed)
		end
	end

	function module.IsEnabled()
		return enabled
	end

	local FREECAM_MACRO_KEYS = { Enum.KeyCode.LeftShift, Enum.KeyCode.P }

	local function checkMacro()
		for i = 1, #FREECAM_MACRO_KEYS - 1 do
			if not __lt.cm("UserInputService", "IsKeyDown", FREECAM_MACRO_KEYS[i]) then
				return
			end
		end

		if _na_env.NAFreecamKeybindEnabled ~= true then
			return
		end

		module.Toggle()
	end

	if ContextActionService then
		local freecamToggleAction = NAmanage.GetSessionActionName("FreecamToggleKey")
		__lt.cm("ContextActionService", "BindActionAtPriority", freecamToggleAction, function(_, state, input)
			if state == Enum.UserInputState.Begin and input.KeyCode == FREECAM_MACRO_KEYS[#FREECAM_MACRO_KEYS] then
				checkMacro()
			end
			return Enum.ContextActionResult.Pass
		end, false, Enum.ContextActionPriority.Low.Value, FREECAM_MACRO_KEYS[#FREECAM_MACRO_KEYS])
	end

	return module
end

local NAFreecam = NAmanage.CreateNAFreecam()

--[[ legacy NAFreecam implementation (disabled)
