		testingName = yayApril(true)
		testingName = maybeMock(testingName)
	end
	adminName = testingName
else
	if isAprilFools() then
		mainName = yayApril(false)
		mainName = maybeMock(mainName)
	end
	adminName = mainName
end

NAgui._dragState = NAgui._dragState or {}
NAgui._touchGestureLock = NAgui._touchGestureLock or { owner = nil, mode = nil, input = nil }
NAgui._draggerCleanups = NAgui._draggerCleanups or {}
NAgui._draggerUiCleanups = NAgui._draggerUiCleanups or {}

NAgui.tryLockTouchGesture = NAgui.tryLockTouchGesture or function(owner, mode, input)
	if not (input and input.UserInputType == Enum.UserInputType.Touch) then
		return true
	end
	local lock = NAgui._touchGestureLock
	if lock.input and lock.input ~= input then
		return false
	end
	if lock.input == input then
		return lock.owner == owner and lock.mode == mode
	end
	lock.owner = owner
	lock.mode = mode
	lock.input = input
	return true
end

NAgui.releaseTouchGesture = NAgui.releaseTouchGesture or function(owner, mode, input)
	if not (input and input.UserInputType == Enum.UserInputType.Touch) then
		return
	end
	local lock = NAgui._touchGestureLock
	if lock.input == input and lock.owner == owner and lock.mode == mode then
		lock.owner = nil
		lock.mode = nil
		lock.input = nil
	end
end

NAgui.dragger = function(ui, dragui)
	if not ui then return end
	dragui = dragui or ui
	local draggerId = tostring((ui and ui.GetDebugId and ui:GetDebugId()) or ui)
	local connName = "Dragger_"..draggerId
	if type(NAgui._draggerUiCleanups[draggerId]) == "function" then
		pcall(NAgui._draggerUiCleanups[draggerId])
	end
	if type(NAgui._draggerCleanups[connName]) == "function" then
		pcall(NAgui._draggerCleanups[connName])
	end
	NAlib.disconnect(connName)
	local GS = GuiService
	local ds = NAgui._dragState
	local dragging = false
	local dragStart
	local startPos
	local cleaned = false
	local dragPointer
	local touchGestureLocked = false
	local pendingInput
	local moveConn
	local endConn
	local stepConn

	local function disconnectLiveInput()
		if moveConn then
			pcall(function() moveConn:Disconnect() end)
			moveConn = nil
		end
		if endConn then
			pcall(function() endConn:Disconnect() end)
			endConn = nil
		end
		if stepConn then
			pcall(function() stepConn:Disconnect() end)
			stepConn = nil
		end
		pendingInput = nil
		if NAmanage and NAmanage.prnCon then
			NAmanage.prnCon(connName)
		end
	end

	local function stopDrag()
		if touchGestureLocked then
			NAgui.releaseTouchGesture(ui, "move", dragPointer)
			touchGestureLocked = false
		end
		dragging = false
		dragPointer = nil
		pendingInput = nil
		if ds.owner == ui then
			ds.owner = nil
			ds.input = nil
		end
		disconnectLiveInput()
	end

	local function cleanupDragger()
		if cleaned then return end
		cleaned = true
		stopDrag()
		if NAgui._draggerCleanups[connName] == cleanupDragger then
			NAgui._draggerCleanups[connName] = nil
		end
		if NAgui._draggerUiCleanups[draggerId] == cleanupDragger then
			NAgui._draggerUiCleanups[draggerId] = nil
		end
		NAlib.disconnect(connName)
	end
	NAgui._draggerCleanups[connName] = cleanupDragger
	NAgui._draggerUiCleanups[draggerId] = cleanupDragger

	local function getOrder(g)
		local z = (g.ZIndex or 0)
		local lc = g:FindFirstAncestorWhichIsA("LayerCollector")
		local d = 0
		if lc and lc:IsA("ScreenGui") then
			d = lc.DisplayOrder or 0
		end
		return d * 10000 + z
	end

	local function isTopMost(root, input)
		local pos = input.Position
		local list
		local ok = pcall(function()
			list = GS:GetGuiObjectsAtPosition(pos.X, pos.Y)
		end)
		if not ok or type(list) ~= "table" or #list == 0 then
			return true
		end
		local top, topO
		for _, g in ipairs(list) do
			if typeof(g) == "Instance" and g:IsA("GuiObject") then
				local o = getOrder(g)
				if not top or o > topO then
					top = g
					topO = o
				end
			end
		end
		if not top then return true end
		return top == root or top:IsDescendantOf(root)
	end

	local function update(input)
		NACaller(function()
			if not ui or not ui.Parent then return end
			local delta = input.Position - dragStart
			local screenSize = ui.Parent.AbsoluteSize
			if not screenSize or screenSize.X <= 0 or screenSize.Y <= 0 then return end
			local newXScale = startPos.X.Scale + (startPos.X.Offset + delta.X) / screenSize.X
			local newYScale = startPos.Y.Scale + (startPos.Y.Offset + delta.Y) / screenSize.Y
			ui.Position = UDim2.new(newXScale, 0, newYScale, 0)
		end)
	end

	NAlib.connect(connName, dragui.InputBegan:Connect(function(input)
		NACaller(function()
			if (input.UserInputType == Enum.UserInputType.MouseButton1 or input.UserInputType == Enum.UserInputType.Touch)
				and (not ds.owner or ds.owner == ui)
				and isTopMost(dragui, input) then
				if input.UserInputType == Enum.UserInputType.Touch then
					if not (NAgui.tryLockTouchGesture and NAgui.tryLockTouchGesture(ui, "move", input)) then
						return
					end
					touchGestureLocked = true
				end
				ds.owner = ui
				ds.input = input
				dragging = true
				dragPointer = input
				dragStart = input.Position
				startPos = ui.Position
				disconnectLiveInput()
				moveConn = NAlib.connect(connName, UserInputService.InputChanged:Connect(function(changedInput)
					if not dragging or ds.owner ~= ui then
						return
					end
					local inputType = changedInput.UserInputType
					if inputType == Enum.UserInputType.MouseMovement then
						pendingInput = changedInput
						return
					end
					if inputType == Enum.UserInputType.Touch and changedInput == dragPointer then
						pendingInput = changedInput
					end
				end))
				endConn = NAlib.connect(connName, UserInputService.InputEnded:Connect(function(endedInput)
					if not dragging then
						return
					end
					local inputType = endedInput.UserInputType
					if inputType == Enum.UserInputType.MouseButton1
						or (inputType == Enum.UserInputType.Touch and endedInput == dragPointer) then
						stopDrag()
					end
				end))
				stepConn = NAlib.connect(connName, RunService.RenderStepped:Connect(function()
					local frameInput = pendingInput
					if not frameInput then
						return
					end
					pendingInput = nil
					if not dragging or ds.owner ~= ui then
						return
					end
					update(frameInput)
				end))
			end
		end)
	end))

	if ui and ui.AncestryChanged then
		NAlib.connect(connName, ui.AncestryChanged:Connect(function(_, parent)
			if not parent then
				Defer(function()
					cleanupDragger()
				end)
			end
		end))
	end
	if ui and ui.Destroying then
		NAlib.connect(connName, ui.Destroying:Connect(cleanupDragger))
	end
	if dragui and dragui ~= ui and dragui.AncestryChanged then
		NAlib.connect(connName, dragui.AncestryChanged:Connect(function(_, parent)
			if not parent then
				Defer(function()
					cleanupDragger()
				end)
			end
		end))
	end
	if dragui and dragui ~= ui and dragui.Destroying then
		NAlib.connect(connName, dragui.Destroying:Connect(cleanupDragger))
	end

	pcall(function() ui.Active = true end)
	pcall(function() dragui.Active = true end)
end

NAgui.draggerV2 = function(ui, dragui)
	if not ui then return end
	dragui = dragui or ui
	local draggerId = tostring((ui and ui.GetDebugId and ui:GetDebugId()) or ui)
	local connName = "DraggerV2_"..draggerId
	if type(NAgui._draggerUiCleanups[draggerId]) == "function" then
		pcall(NAgui._draggerUiCleanups[draggerId])
	end
	if type(NAgui._draggerCleanups[connName]) == "function" then
		pcall(NAgui._draggerCleanups[connName])
	end
	NAlib.disconnect(connName)
	local GS = GuiService
	local ds = NAgui._dragState
	local screenGui = ui:FindFirstAncestorWhichIsA("ScreenGui") or ui.Parent
	local dragging, dragStart, startPos
	local anchor = ui.AnchorPoint
	local cleaned = false
	local dragPointer
	local touchGestureLocked = false
	local pendingInput
	local moveConn
	local endConn
	local stepConn

	local function disconnectLiveInput()
		if moveConn then
			pcall(function() moveConn:Disconnect() end)
			moveConn = nil
		end
		if endConn then
			pcall(function() endConn:Disconnect() end)
			endConn = nil
		end
		if stepConn then
			pcall(function() stepConn:Disconnect() end)
			stepConn = nil
		end
		pendingInput = nil
		if NAmanage and NAmanage.prnCon then
			NAmanage.prnCon(connName)
		end
	end

	local function stopDrag()
		if touchGestureLocked then
			NAgui.releaseTouchGesture(ui, "move", dragPointer)
			touchGestureLocked = false
		end
		dragging = false
		dragPointer = nil
		pendingInput = nil
		if ds.owner == ui then
			ds.owner = nil
			ds.input = nil
		end
		disconnectLiveInput()
	end

	local function cleanupDragger()
		if cleaned then return end
		cleaned = true
		stopDrag()
		if NAgui._draggerCleanups[connName] == cleanupDragger then
			NAgui._draggerCleanups[connName] = nil
		end
		if NAgui._draggerUiCleanups[draggerId] == cleanupDragger then
			NAgui._draggerUiCleanups[draggerId] = nil
		end
		NAlib.disconnect(connName)
	end
	NAgui._draggerCleanups[connName] = cleanupDragger
	NAgui._draggerUiCleanups[draggerId] = cleanupDragger

	local function safeClamp(v, lo, hi)
		if hi < lo then hi = lo end
		return math.clamp(v, lo, hi)
	end

	local function getDragScale()
		local scale = 1
		local scaler = (NAUIMANAGER and NAUIMANAGER.AUTOSCALER) or (opt and opt.NAAUTOSCALER)
		if scaler and screenGui then
			local ok, inside = pcall(function()
				return scaler == screenGui or scaler:IsDescendantOf(screenGui)
			end)
			if ok and inside then
				scale = tonumber(scaler.Scale) or 1
			end
		end
		if not scale or scale <= 0 then
			scale = 1
		end
		return scale
	end

	local function getLogicalScreenSize()
		local absSize = screenGui.AbsoluteSize
		local scale = getDragScale()
		return Vector2.new((absSize.X or 0) / scale, (absSize.Y or 0) / scale), scale
	end

	local function isResizeActive()
		return NAmanage and NAmanage.GetAttr and NAmanage.GetAttr(ui, "NAResizeActive") == true
	end

	local function getOrder(g)
		local z = (g.ZIndex or 0)
		local lc = g:FindFirstAncestorWhichIsA("LayerCollector")
		local d = 0
		if lc and lc:IsA("ScreenGui") then
			d = lc.DisplayOrder or 0
		end
		return d * 10000 + z
	end

	local function isTopMost(root, input)
		local pos = input.Position
		local list
		local ok = pcall(function()
			list = GS:GetGuiObjectsAtPosition(pos.X, pos.Y)
		end)
		if not ok or type(list) ~= "table" or #list == 0 then
			return true
		end
		local top, topO
		for _, g in ipairs(list) do
			if typeof(g) == "Instance" and g:IsA("GuiObject") then
				local o = getOrder(g)
				if not top or o > topO then
					top = g
					topO = o
				end
			end
		end
		if not top then return true end
		return top == root or top:IsDescendantOf(root)
	end

	local function update(input)
		NACaller(function()
			if isResizeActive() then
				return
			end
			local p, dragScale = getLogicalScreenSize()
			local absSize = ui.AbsoluteSize
			local s = Vector2.new((absSize.X or 0) / dragScale, (absSize.Y or 0) / dragScale)
			if p.X <= 0 or p.Y <= 0 then return end
			local startX = startPos.X.Scale * p.X + startPos.X.Offset
			local startY = startPos.Y.Scale * p.Y + startPos.Y.Offset
			local dx = (input.Position.X - dragStart.X) / dragScale
			local dy = (input.Position.Y - dragStart.Y) / dragScale
			local minX = anchor.X * s.X
			local maxX = p.X - (1 - anchor.X) * s.X
			local minY = anchor.Y * s.Y
			local maxY = p.Y - (1 - anchor.Y) * s.Y
			local nx = safeClamp(startX + dx, minX, maxX)
			local ny = safeClamp(startY + dy, minY, maxY)
			ui.Position = UDim2.new(nx / p.X, 0, ny / p.Y, 0)
		end)
	end

	NAlib.connect(connName, dragui.InputBegan:Connect(function(input)
		NACaller(function()
			if (input.UserInputType == Enum.UserInputType.MouseButton1 or input.UserInputType == Enum.UserInputType.Touch)
				and (not ds.owner or ds.owner == ui)
				and isTopMost(dragui, input) then
				if isResizeActive() then
					return
				end
				if input.UserInputType == Enum.UserInputType.Touch then
					if not (NAgui.tryLockTouchGesture and NAgui.tryLockTouchGesture(ui, "move", input)) then
						return
					end
					touchGestureLocked = true
				end
				ds.owner = ui
				ds.input = input
				dragging = true
				dragPointer = input
				dragStart = input.Position
				startPos = ui.Position
				disconnectLiveInput()
				moveConn = NAlib.connect(connName, UserInputService.InputChanged:Connect(function(changedInput)
					if not dragging or ds.owner ~= ui then
						return
					end
					local inputType = changedInput.UserInputType
					if inputType == Enum.UserInputType.MouseMovement then
						pendingInput = changedInput
						return
					end
					if inputType == Enum.UserInputType.Touch and changedInput == dragPointer then
						pendingInput = changedInput
					end
				end))
				endConn = NAlib.connect(connName, UserInputService.InputEnded:Connect(function(endedInput)
					if not dragging then
						return
					end
					local inputType = endedInput.UserInputType
					if inputType == Enum.UserInputType.MouseButton1
						or (inputType == Enum.UserInputType.Touch and endedInput == dragPointer) then
						stopDrag()
					end
				end))
				stepConn = NAlib.connect(connName, RunService.RenderStepped:Connect(function()
					local frameInput = pendingInput
					if not frameInput then
						return
					end
					pendingInput = nil
					if not dragging or ds.owner ~= ui then
						return
					end
					update(frameInput)
				end))
			end
		end)
	end))

	local function clampToViewport()
		local ok, err = NACaller(function()
			if isResizeActive() then
				return
			end
			local p, dragScale = getLogicalScreenSize()
			local absSize = ui.AbsoluteSize
			local s = Vector2.new((absSize.X or 0) / dragScale, (absSize.Y or 0) / dragScale)
			if p.X <= 0 or p.Y <= 0 then return end
			local curr = ui.Position
			local absX = curr.X.Scale * p.X + curr.X.Offset
			local absY = curr.Y.Scale * p.Y + curr.Y.Offset
			local minX = anchor.X * s.X
			local maxX = p.X - (1 - anchor.X) * s.X
			local minY = anchor.Y * s.Y
			local maxY = p.Y - (1 - anchor.Y) * s.Y
			local nx = safeClamp(absX, minX, maxX)
			local ny = safeClamp(absY, minY, maxY)
			ui.Position = UDim2.new(nx / p.X, 0, ny / p.Y, 0)
		end)
		if not ok then warn("[DraggerV2] Clamp update error:", err) end
	end

	NAlib.connect(connName, screenGui:GetPropertyChangedSignal("AbsoluteSize"):Connect(clampToViewport))
	if ui and ui.GetPropertyChangedSignal then
		NAlib.connect(connName, ui:GetPropertyChangedSignal("AbsoluteSize"):Connect(clampToViewport))
	end
	if ui and ui.AncestryChanged then
		NAlib.connect(connName, ui.AncestryChanged:Connect(function(_, parent)
			if not parent then
				Defer(function()
					cleanupDragger()
				end)
			end
		end))
	end
	if dragui and dragui ~= ui and dragui.AncestryChanged then
		NAlib.connect(connName, dragui.AncestryChanged:Connect(function(_, parent)
			if not parent then
				Defer(function()
					cleanupDragger()
				end)
			end
		end))
	end
	if ui and ui.Destroying then
		NAlib.connect(connName, ui.Destroying:Connect(cleanupDragger))
	end
	if dragui and dragui ~= ui and dragui.Destroying then
		NAlib.connect(connName, dragui.Destroying:Connect(cleanupDragger))
	end
	clampToViewport()

	if ui and NAlib.isProperty(ui, "Active") then
		NAlib.setProperty(ui, "Active", true)
	end
	if dragui and NAlib.isProperty(dragui, "Active") then
		NAlib.setProperty(dragui, "Active", true)
	end
	pcall(function() ui.Active = true end)
	pcall(function() dragui.Active = true end)
end

NAmanage.createLoadingUI=function(text, opts)
	opts = opts or {}
	local startMinimized = opts.startMinimized
	if startMinimized == nil then
		startMinimized = opts.minimized
	end
	if startMinimized == nil then
		startMinimized = NALoadingStartMinimized == true
	else
		startMinimized = startMinimized and true or false
	end

	local ui = {}
	local flags = {
		minimized = startMinimized,
		autoSkip = false,
	}
	local widthConnName = "na_loadingui_width_"..tostring(math.floor((tick() % 1e7) * 1000))

	local wScale = tonumber(opts.widthScale) or 0.34
	local mobileWidthScale = tonumber(opts.mobileWidthScale) or math.max(wScale, 0.84)
	local desktopMinWidth = tonumber(opts.minWidth) or 340
	local mobileMinWidth = tonumber(opts.mobileMinWidth) or 320
	local desktopMargin = tonumber(opts.desktopMargin) or 120
	local mobileMargin = tonumber(opts.mobileMargin) or 24
	local blacklist = opts.blacklist or { [8523781134] = true, [2521585756] = true, [3350084310] = true }
	local lp = Players and Players.LocalPlayer

	if lp and blacklist[lp.UserId] then
		return "womp womp"
	end

	ui.sg = InstanceNew("ScreenGui")
	ui.sg.IgnoreGuiInset = true
	ui.sg.ResetOnSpawn = false
	ui.sg.DisplayOrder = 999999
	ui.sg.ZIndexBehavior = Enum.ZIndexBehavior.Global
	local okProtect = pcall(function() NAgui.NaProtectUI(ui.sg) end)
	if not okProtect then
		ui.sg.Parent = COREGUI
	end

	ui.overlay = InstanceNew("Frame", ui.sg)
	ui.overlay.Active = false
	ui.overlay.BackgroundColor3 = Color3.fromRGB(0, 0, 0)
	ui.overlay.BackgroundTransparency = 1
	ui.overlay.ZIndex = -1
	ui.overlay.Size = UDim2.fromScale(1, 1)
