NAmanage.jlNorm = function(cfg)
	local c = type(cfg) == "table" and cfg or {}
	local function boolDef(v, d)
		if type(v) == "boolean" then
			return v
		end
		return d
	end
	local function numDef(v, d, min, max)
		local n = tonumber(v)
		if not n then
			return d
		end
		if min ~= nil then
			n = math.max(min, n)
		end
		if max ~= nil then
			n = math.min(max, n)
		end
		return math.floor(n + 0.5)
	end
	for key, def in pairs(NAmanage.jlDef) do
		c[key] = boolDef(c[key], def)
	end
	c.ChatMaxMessages = numDef(c.ChatMaxMessages, NAmanage.jlNumDef.ChatMaxMessages, 20, 500)
	return c
end

NAmanage.jlCfg = NAmanage.jlNorm()

