function NamelessMigrate:Waypoints()
	NamelessMigrate:LoadIY_FE()
	if not FileSupport then
		return
	end

	if NamelessMigrate.IY_FE then
		local Objects = {}
		for i,v in pairs(NamelessMigrate.IY_FE["WayPoints"] or {}) do
			if not Objects[v.GAME] then
				Objects[v.GAME] = {}
			end
			local cord =  v.COORD
			cord[#cord+1] = 1
			cord[#cord+1] = 0
			cord[#cord+1] = 0
			cord[#cord+1] = 0
			cord[#cord+1] = 1
			cord[#cord+1] = 0
			cord[#cord+1] = 0
			cord[#cord+1] = 0
			cord[#cord+1] = 1
			Objects[v.GAME][v.NAME]= {["Components"] = v.COORD}
		end
		for i,v in pairs(Objects) do
			local Load = ("%s/WP_%s.json"):format(
				NAfiles.NAWAYPOINTFILEPATH,
				tostring(i)
			)
			writefile(Load, HttpService:JSONEncode(v))
		end
	end

end

NAmanage.NASettingsResolveDefault=function(def)
	local default = def.default
	if typeof(default) == "function" then
		local ok, value = pcall(default)
		if ok then
			default = value
		else
			default = nil
		end
	end
	return default
end

NAmanage.NASettingsCoerce=function(def, value)
	if value == nil then
		return NAmanage.NASettingsResolveDefault(def)
	end

	if def.coerce then
		local ok, coerced = pcall(def.coerce, value)
		if ok and coerced ~= nil then
			return coerced
		end
		return NAmanage.NASettingsResolveDefault(def)
	end

	return value
end

NAmanage.NASettingsGetSchema=function()
	if NAStuff.NASettingsSchema then
		return NAStuff.NASettingsSchema
	end

	local defaultStrokeColor = Color3.fromRGB(148, 93, 255)

	local function coerceBoolean(value, fallback)
		if type(value) == "boolean" then
			return value
		end
		if type(value) == "string" then
			local lowered = value:lower()
			if lowered == "true" or lowered == "1" then
				return true
			end
			if lowered == "false" or lowered == "0" then
				return false
			end
		end
		if type(value) == "number" then
			return value ~= 0
		end
		return fallback
	end

	local function clampChannel(value)
		local numberValue = tonumber(value)
		if not numberValue then
			return nil
		end
		if numberValue < 0 then
			numberValue = 0
		elseif numberValue > 1 then
			numberValue = 1
		end
		return numberValue
	end

	NAStuff.NASettingsSchema = {
		prefix = {
			pathKey = "NAPREFIXPATH";
			default = function()
				return NamelessMigrate:Prefix() or ";"
			end;
			coerce = function(value)
				if type(value) ~= "string" then
					value = tostring(value or ";")
				end
				if value == "" then
					return ";"
				end
				return value
			end;
		};
		buttonSize = {
			pathKey = "NABUTTONSIZEPATH";
			default = 1;
			coerce = function(value)
				local numberValue = tonumber(value)
				if not numberValue or numberValue <= 0 then
					return 1
				end
				return numberValue
			end;
		};
		iconShape = {
			default = "Circle";
			coerce = function(value)
				local shape = type(value) == "string" and value or tostring(value or "")
				shape = shape:match("^%s*(.-)%s*$") or shape
				shape = shape:lower()
				if shape == "square" then
					return "Square"
				elseif shape == "rounded" or shape == "round" then
					return "Rounded"
				elseif shape == "squircle" then
					return "Squircle"
				elseif shape == "circle" then
					return "Circle"
				end
				return "Circle"
			end;
		};
		iconBgTransparency = {
			default = 0;
			coerce = function(value)
				local n = clampChannel(value)
				if n == nil then return 0 end
				return n
			end;
		};
		iconImageTransparency = {
			default = 0;
			coerce = function(value)
				local n = clampChannel(value)
				if n == nil then return 0 end
				return n
			end;
		};
		iconTextTransparency = {
			default = 0;
			coerce = function(value)
				local n = clampChannel(value)
				if n == nil then return 0 end
				return n
			end;
		};
		iconStrokeTransparency = {
			default = 0.7;
			coerce = function(value)
				local n = clampChannel(value)
				if n == nil then return 0.7 end
				return n
			end;
		};
		iconPosition = {
			default = function()
				return { X = 0.5; Y = 0.1 }
			end;
			coerce = function(value)
				local parsed = value
				if type(value) == "string" then
					local ok, decoded = NACaller(function()
						return HttpService:JSONDecode(value)
					end)
					if ok and typeof(decoded) == "table" then
						parsed = decoded
					else
						parsed = nil
					end
				end

				if type(parsed) == "table" then
					local x = tonumber(parsed.X or parsed.x)
					local y = tonumber(parsed.Y or parsed.y)
					if x then
						x = math.clamp(x, 0, 1)
					end
					if y then
						y = math.clamp(y, 0, 1)
					end
					if x ~= nil and y ~= nil then
						return { X = x; Y = y }
					end
				end

				return { X = 0.5; Y = 0.1 }
			end;
		};
			iconKeepPosition = {
				default = false;
				coerce = function(value)
					return value == true
				end;
			};
		customMovementSoundsEnabled = {
			default = false;
			coerce = function(value)
				return coerceBoolean(value, false)
			end;
		};
		customMovementSoundsWalk = {
			default = "";
			coerce = function(value)
				return tostring(value or "")
			end;
		};
		customMovementSoundsJump = {
			default = "";
			coerce = function(value)
				return tostring(value or "")
			end;
		};
		customMovementSoundsFall = {
			default = "";
			coerce = function(value)
				return tostring(value or "")
			end;
		};
		customMovementSoundsLand = {
			default = "";
			coerce = function(value)
				return tostring(value or "")
			end;
		};
		customMovementSoundsVolume = {
			default = 1;
			coerce = function(value)
				local n = tonumber(value)
				if not n then
					return 1
				end
				return math.clamp(n, 0, 10)
			end;
		};
		uiScale = {
			pathKey = "NAUISIZEPATH";
			default = function()
				local migrated = NamelessMigrate:UiSize()
				local numberValue = tonumber(migrated)
				if not numberValue or numberValue <= 0 then
					numberValue = 1
				end
				return math.clamp(numberValue, NA_UI_SCALE_MIN, NA_UI_SCALE_MAX)
			end;
			coerce = function(value)
				local numberValue = tonumber(value)
				if not numberValue or numberValue <= 0 then
					return 1
				end
				return math.clamp(numberValue, NA_UI_SCALE_MIN, NA_UI_SCALE_MAX)
			end;
		};
		crosshairEnabled = {
			default = false;
			coerce = function(value)
				return coerceBoolean(value, false)
			end;
		};
		crosshairSize = {
			default = 8;
			coerce = function(value)
				local n = tonumber(value)
				if not n then return 8 end
				if n < 2 then n = 2 end
				if n > 100 then n = 100 end
				return n
			end;
		};
		crosshairThickness = {
			default = 2;
			coerce = function(value)
				local n = tonumber(value)
				if not n then return 2 end
				if n < 1 then n = 1 end
				if n > 20 then n = 20 end
				return n
			end;
		};
		crosshairGap = {
			default = 2;
			coerce = function(value)
				local n = tonumber(value)
				if not n then return 2 end
				return math.clamp(math.floor(n + 0.5), 0, 30)
			end;
		};
		crosshairShowCenter = {
			default = true;
			coerce = function(value)
				return coerceBoolean(value, true)
			end;
		};
		lightingStyleAutomation = {
			default = false;
			coerce = function(value)
				return coerceBoolean(value, false)
			end;
		};
		lightingStyleAutomationStyle = {
			default = "Soft";
			coerce = function(value)
				local name = type(value) == "string" and value or tostring(value or "Soft")
				name = name:match("^%s*(.-)%s*$") or name
				for _, item in ipairs(Enum.LightingStyle:GetEnumItems()) do
					if Lower(item.Name) == Lower(name) then
						return item.Name
