			local r = tonumber(tbl.R or tbl.r)
			local g = tonumber(tbl.G or tbl.g)
			local b = tonumber(tbl.B or tbl.b)
			if r and g and b then
				r = math.clamp(r, 0, 1)
				g = math.clamp(g, 0, 1)
				b = math.clamp(b, 0, 1)
				return Color3.new(r, g, b)
			end
		end
		return fallback
	end
