end

NAmanage.cloneArgsArray=function(source)
	local out = {}
	if source then
		for i, v in ipairs(source) do
			out[i] = v
		end
	end
	return out
end

NAmanage.updateLastCommand=function(rawArgs)
	if type(rawArgs) ~= "table" then return end
	local first = rawArgs[1]
	if type(first) ~= "string" then return end
	local lowerFirst = Lower(first)
	if lowerFirst == "lastcommand" or lowerFirst == "lastcmd" then
		return
	end
	if NAStuff._lastCommand then
		NAStuff._prevCommand = NAmanage.cloneArgsArray(NAStuff._lastCommand)
	else
		NAStuff._prevCommand = nil
	end
	NAStuff._lastCommand = rawArgs
end

NAmanage.tryCmdIntegration=function(rawArgs)
	local bridge = NAStuff.CmdIntegrationBridge
	if (not bridge or type(bridge.parse) ~= "function") and getgenv then
		if _na_env and type(_na_env.CmdIntegrationBridge) == "table" and type(_na_env.CmdIntegrationBridge.parse) == "function" then
			bridge = _na_env.CmdIntegrationBridge
			NAStuff.CmdIntegrationBridge = bridge
		end
	end
	if not bridge or type(bridge.parse) ~= "function" then
		return false
	end
	local args = rawArgs
	if type(args) == "table" and type(args[1]) == "string" then
		local first = args[1]
		if Sub(first, 1, 4):lower() == "cmd:" then
			args = NAmanage.cloneArgsArray(rawArgs)
			args[1] = Sub(first, 5)
		end
	end
	local prefix = bridge.prefix
	if type(prefix) ~= "string" or prefix == "" then
		prefix = ";"
	end
	local parts = {}
	for _, v in ipairs(args) do
		parts[#parts + 1] = tostring(v or "")
	end
	local line = prefix..Concat(parts, " ")
	local ok = pcall(bridge.parse, true, line)
	return ok == true
end

--[[ COMMAND FUNCTIONS ]]--
local commandcount=0
NAmanage.makeUniqueAlias=function(aliasName, seen)
	local base = tostring(aliasName or "")
	local lowerBase = Lower(base)
	if base == "" then
		return nil, false
	end
	if not seen[lowerBase] and not cmds.Commands[lowerBase] and not cmds.Aliases[lowerBase] then
		return base, false
	end
	local idx = 1
	while true do
		local candidate = base..tostring(idx)
		local lowerCandidate = Lower(candidate)
		if not seen[lowerCandidate] and not cmds.Commands[lowerCandidate] and not cmds.Aliases[lowerCandidate] then
			return candidate, true
		end
		idx = idx + 1
	end
end
Loops = {}
NAmanage.ensurePatchedInfo=function(info)
	local title = ""
	local desc = ""
	if type(info) == "table" then
		title = tostring(info[1] or "")
		desc = tostring(info[2] or "")
	elseif info ~= nil then
		title = tostring(info)
	end

	local lowerTitle = Lower(title)
	local lowerDesc = Lower(desc)

	if title == "" then
		title = "[PATCHED]"
	elseif not lowerTitle:find("patched", 1, true) then
		title = "[PATCHED] "..title
	end

	if desc == "" then
		desc = "Patched / may not work"
	elseif not lowerDesc:find("patched", 1, true) then
		desc = desc.." (patched)"
	end

	return {title, desc}
end

NAmanage.wrapPatchedFunc=function(func)
	if type(func) ~= "function" then
		return function()
			DoNotif("This command is patched and may not work", 3)
		end
	end
	return function(...)
		DoNotif("This command is patched and may not work", 3)
		return func(...)
	end
end

NAmanage.inferRequiresArguments=function(infoTable)
	local function hasRequiredPlaceholder(text)
		if type(text) ~= "string" then
			return false
		end

		local cleaned = text:gsub("%b[]", "")
		return cleaned:find("%b<>") ~= nil or cleaned:find("%b{}") ~= nil
	end

	if type(infoTable) == "table" then
		if hasRequiredPlaceholder(infoTable[1]) then
			return true
		end
		if (type(infoTable[1]) ~= "string" or infoTable[1] == "") and hasRequiredPlaceholder(infoTable[2]) then
			return true
		end
	elseif type(infoTable) == "string" then
		return hasRequiredPlaceholder(infoTable)
	end

	return false
end

cmd.add = function(aliases, info, func, requiresArguments, meta)
	if type(requiresArguments) == "table" and meta == nil then
		meta = requiresArguments
		requiresArguments = nil
	end

	if requiresArguments == nil then
		requiresArguments = NAmanage.inferRequiresArguments(info) or false
	end

	meta = type(meta) == "table" and meta or {}

	if type(aliases) ~= "table" or #aliases == 0 then
		return
	end

	local autoSuffix = cmds._skipAutoSuffix ~= true
	local seen = {}
	local normalized = {}
	local renamed = false

	for _, aliasName in ipairs(aliases) do
		if type(aliasName) == "string" and aliasName ~= "" then
			local finalName = aliasName
			if autoSuffix then
				local uniqueName, didRename = NAmanage.makeUniqueAlias(aliasName, seen)
				if uniqueName then
					finalName = uniqueName
				end
				if didRename then
					renamed = true
				end
			else
				finalName = tostring(aliasName)
			end
			local lowerFinal = Lower(finalName)
			if not seen[lowerFinal] then
				seen[lowerFinal] = true
				Insert(normalized, finalName)
			end
		end
	end

	if #normalized == 0 then
		return
	end

	local primary = normalized[1]
	local primaryLower = primary and primary:lower() or nil
	local infoTable = info
	if renamed and type(info) == "table" then
		infoTable = {
			Format("%s [renamed to %s]", tostring(info[1] or primary), tostring(primary)),
			tostring(info[2] or "")
		}
	end
	if meta.patched then
		infoTable = NAmanage.ensurePatchedInfo(infoTable)
	end
	local data = {func, infoTable, requiresArguments, meta}
	if primaryLower then
		if not cmds.Commands[primaryLower] then
			commandcount += 1
		end
		cmds.Commands[primaryLower] = data
	end

	for index = 2, #normalized do
		local aliasName = normalized[index]
		if type(aliasName) == "string" and aliasName ~= "" then
			cmds.Aliases[Lower(aliasName)] = data
		end
	end
	if type(NAmanage.invalidateCommandBuild) == "function" then
		NAmanage.invalidateCommandBuild()
	end
end

cmd.addPatched = function(aliases, info, func, requiresArguments)
	return cmd.add(aliases, NAmanage.ensurePatchedInfo(info), NAmanage.wrapPatchedFunc(func), requiresArguments, { patched = true })
end

cmd.run = function(args)
	local rawArgs = {}
	for i, v in ipairs(args) do
		rawArgs[i] = v
	end

	local function bumpRichPresenceAsync()
		if type(NAmanage.btBump) == "function" then
			task.defer(function()
				pcall(NAmanage.btBump)
			end)
		end
	end

	local function sendWebhookAsync(payloadArgs)
		if type(NAmanage.WebhookCommand) == "function" then
			task.defer(function()
				pcall(NAmanage.WebhookCommand, payloadArgs)
			end)
		end
	end

	local caller, arguments = args[1], args
	table.remove(args, 1)

	local callerLower = (type(caller) == "string") and caller:lower() or nil
	local shouldRecord = callerLower ~= "lastcommand" and callerLower ~= "lastcmd"

	local success, msg = pcall(function()
		local command = callerLower and (cmds.Commands[callerLower] or cmds.Aliases[callerLower]) or nil
		if command then
			command[1](unpack(arguments))
			bumpRichPresenceAsync()
			if shouldRecord then
				NAmanage.updateLastCommand(rawArgs)
			end
			sendWebhookAsync(rawArgs)
		else
			if NAmanage.tryCmdIntegration(rawArgs) then
				if shouldRecord then
					NAmanage.updateLastCommand(rawArgs)
				end
				sendWebhookAsync(rawArgs)
				return
			end
			local closest = callerLower and didYouMean(callerLower) or nil
			if closest and doPREDICTION then
				local commandFunc = cmds.Commands[closest] and cmds.Commands[closest][1] or cmds.Aliases[closest] and cmds.Aliases[closest][1]
				local requiresInput = cmds.Commands[closest] and cmds.Commands[closest][3] or cmds.Aliases[closest] and cmds.Aliases[closest][3]

				if requiresInput then
					Window({
						Title = adminName,
						Description = "Command [ "..caller.." ] doesn't exist\nDid you mean [ "..closest.." ]?",
						InputField = true,
						Buttons = {
							{
								Text = "Submit",
								Callback = function(input)
									local parsedArguments = ParseArguments(input)
									if parsedArguments then
										local predictedArguments = {}
										for i, v in ipairs(parsedArguments) do
											predictedArguments[i] = v
										end
										local record = {closest}
										for _, v in ipairs(predictedArguments) do
											record[#record + 1] = v
										end
										SpawnCall(function()
											commandFunc(unpack(predictedArguments))
											NAmanage.btBump()
											if shouldRecord then
												NAmanage.updateLastCommand(record)
											end
										end)
									else
										local record = {closest}
										SpawnCall(function()
											commandFunc()
											NAmanage.btBump()
											if shouldRecord then
												NAmanage.updateLastCommand(record)
											end
										end)
									end
								end
							}
						}
					})
				else
					Window({
						Title = adminName,
						Description = "Command [ "..caller.." ] doesn't exist\nDid you mean [ "..closest.." ]?",
						Buttons = {
							{
								Text = "Run Command",
								Callback = function()
									local record = {closest}
									SpawnCall(function()
										commandFunc()
										NAmanage.btBump()
										if shouldRecord then
											NAmanage.updateLastCommand(record)
										end
									end)
								end
							}
						}
					})
				end
			end
		end
	end)

	if not success then warn(adminName.." script error:\n"..msg) end
end

NAmanage.SanitizeLoopMethod = function(method)
	local value = type(method) == "string" and method or tostring(method or "")
	value = value:match("^%s*(.-)%s*$") or value
	local key = value:lower():gsub("[%s_%-]", "")
	if key == "presimulation" then
		return "PreSimulation"
	elseif key == "heartbeat" then
		return "Heartbeat"
	end
	return "RenderStepped"
end

NAmanage.GetLoopSignal = function(method)
	local picked = NAmanage.SanitizeLoopMethod(method or NAStuff.LoopMethod)
	local sig = RunService and RunService[picked]
	if sig and type(sig.Connect) == "function" then
		return sig, picked
	end
	if picked == "PreSimulation" then
		return nil, picked
	end
	if RunService and RunService.RenderStepped and type(RunService.RenderStepped.Connect) == "function" then
		return RunService.RenderStepped, "RenderStepped"
	end
	if RunService and RunService.Heartbeat and type(RunService.Heartbeat.Connect) == "function" then
		return RunService.Heartbeat, "Heartbeat"
	end
	return nil, picked
end

NAmanage.GetLoopDt = function(...)
	local n = select("#", ...)
	for i = n, 1, -1 do
		local v = select(i, ...)
		if type(v) == "number" then
			return v
		end
	end
	return 0
end

NAmanage.ConnectLoop = function(loopKey)
	local loopData = Loops and Loops[loopKey]
	if not loopData then
		return false, "Loop not found."
	end
	local connKey = loopData.key or ("loop::"..loopKey)
	loopData.key = connKey
	NAlib.disconnect(connKey)
	local sig, method = NAmanage.GetLoopSignal(NAStuff.LoopMethod)
	if not sig then
		return false, "Loop signal is unavailable."
	end
	loopData.method = method
	local acc = 0
	NAlib.connect(connKey, sig:Connect(function(...)
		local currentLoop = Loops[loopKey]
		if not currentLoop or not currentLoop.running then
			NAlib.disconnect(connKey)
			return
		end
		if currentLoop.interval <= 0 then
			pcall(function()
				currentLoop.command(Unpack(currentLoop.args))
			end)
			return
		end
		acc += NAmanage.GetLoopDt(...)
		if acc >= currentLoop.interval then
			acc %= currentLoop.interval
			pcall(function()
				currentLoop.command(Unpack(currentLoop.args))
			end)
		end
	end))
	return true, method
end

NAmanage.RebindLoops = function()
	if type(Loops) ~= "table" then
		return
	end
	for loopKey, loopData in pairs(Loops) do
		if loopData and loopData.running then
			NAmanage.ConnectLoop(loopKey)
		end
	end
end

NAmanage.SetLoopMethod = function(method, opts)
	local picked = NAmanage.SanitizeLoopMethod(method)
	NAStuff.LoopMethod = picked
	if not opts or opts.save ~= false then
		pcall(NAmanage.NASettingsSet, "loopMethod", picked)
	end
	if not opts or opts.rebind ~= false then
		NAmanage.RebindLoops()
	end
	return picked
end

NAStuff.LoopMethodOptions = NAStuff.LoopMethodOptions or { "RenderStepped", "PreSimulation", "Heartbeat" }
NAStuff.LoopMethod = NAmanage.SanitizeLoopMethod(NAStuff.LoopMethod or "RenderStepped")

NAmanage.FmtLoop = function(args)
	if not args or #args == 0 then
		return "(no args)"
	end
	return Concat(args, ", ")
end

NAmanage.LoopKey = function(name, args)
	local loopArgs = type(args) == "table" and args or {}
	return Lower(tostring(name or "")).." "..Concat(loopArgs, " ")
end

NAmanage.StartLoop = function(cmdName, args, interval)
	if type(cmdName) ~= "string" or cmdName == "" then
		return false, "Command name is required."
	end

	local command = cmds.Commands[cmdName:lower()] or cmds.Aliases[cmdName:lower()]
	if not command then
		return false, "Command '"..cmdName.."' does not exist."
	end

	interval = tonumber(interval)
	if not interval then
		return false, "Loop delay must be a number."
	end
	if interval < 0 then
		return false, "Invalid delay. Loop not started."
	end

	local loopArgs = type(args) == "table" and args or {}
	local loopKey = NAmanage.LoopKey(cmdName, loopArgs)
	if Loops[loopKey] then
		return false, "A loop with these arguments is already running for '"..cmdName.."'."
	end

	local connKey = "loop::"..loopKey
	NAlib.disconnect(connKey)

	local loopData = {
		commandName = cmdName,
		command = command[1],
		args = loopArgs,
		interval = interval,
		running = true,
		key = connKey,
		method = NAmanage.SanitizeLoopMethod(NAStuff.LoopMethod),
	}

	Loops[loopKey] = loopData

	pcall(function()
		loopData.command(Unpack(loopData.args))
	end)

	local ok, msg = NAmanage.ConnectLoop(loopKey)
	if not ok then
		Loops[loopKey] = nil
		return false, msg or "Loop signal is unavailable."
	end

	return true, loopKey, loopData
end

NAmanage.StopLoop = function(loopKey)
	local loopData = Loops[loopKey]
	if not loopData then
		return false, "Loop not found."
	end

	loopData.running = false
	if loopData.key then
		NAlib.disconnect(loopData.key)
	end
	Loops[loopKey] = nil

	return true, loopData
end

NAmanage.GetLoops = function()
	local entries = {}
	for loopKey, loopData in pairs(Loops) do
		Insert(entries, {
			key = loopKey,
			data = loopData,
			label = Format("'%s' | Args: %s | Delay: %ss | Method: %s", loopData.commandName, NAmanage.FmtLoop(loopData.args), loopData.interval, loopData.method or NAmanage.SanitizeLoopMethod(NAStuff.LoopMethod)),
		})
	end
	table.sort(entries, function(a, b)
		return tostring(a.label) < tostring(b.label)
	end)
	return entries
end

cmd.loop = function(commandName, args)
	if type(commandName) ~= "string" or commandName == "" then
		DoNotif("Command name is required.", 3)
		return
	end

	Window({
		Title = "Set Loop Delay",
		Description = "Enter the delay (in seconds) for the loop of command: "..commandName,
		InputField = true,
		Buttons = {
			{
				Text = "Submit",
				Callback = function(input)
					Spawn(function()
						local ok, result, loopData = NAmanage.StartLoop(commandName, args, tonumber(input) or 0)
						if not ok then
							DoNotif(result, 3)
							return
						end
						DoNotif("Loop started for '"..commandName.."' with delay: "..loopData.interval.."s. Method: "..(loopData.method or NAmanage.SanitizeLoopMethod(NAStuff.LoopMethod))..". Args: "..NAmanage.FmtLoop(loopData.args), 3)
					end)
				end
			}
		}
	})
end

cmd.stopLoop = function()
	local loopEnts = NAmanage.GetLoops()
	if #loopEnts == 0 then
		DoNotif("No active loops to stop.", 2)
		return
	end

	local buttons = {}
	for i = 1, #loopEnts do
		local entry = loopEnts[i]
		Insert(buttons, {
			Text = entry.label,
			Callback = function()
				local ok, loopData = NAmanage.StopLoop(entry.key)
				if not ok then
					DoNotif(loopData, 2)
					return
				end
				DoNotif("Stopped loop: '"..loopData.commandName.."' with args: "..NAmanage.FmtLoop(loopData.args), 3)
			end
		})
	end

	Window({
		Title = "Stop a Loop",
		Description = "Select a loop to stop:",
		Buttons = buttons
	})
end

--[[ LIBRARY FUNCTIONS ]]--
NAlib.wrap=function(f)
	return coroutine.wrap(f)()
end

local wrap=NAlib.wrap

function rngMsg()
	return msg[math.random(1,#msg)]
end

function MouseButtonFix(button, clickCallback)
	if not button or type(clickCallback) ~= "function" then
		return { Connected = false, Disconnect = function() end }
	end

	local clickTimeThreshold = 0.45
	local moveThreshold = 10

	local mouseDownTime = 0
	local isPointerDown = false
	local startPosition = nil
	local maxMoveDistance = 0
	local connections = {}
	local disconnected = false
	NAStuff._mouseButtonFixHooks = NAmanage.ensureWeakKeyTable(NAStuff._mouseButtonFixHooks)
	local hooks = NAStuff._mouseButtonFixHooks
	local existing = hooks[button]
	if existing then
		NAmanage.tryDisconnect(existing)
	end

	local state = {
		Connected = true,
	}

	local function disconnectAll()
		if disconnected then
			return
		end
		disconnected = true
		state.Connected = false
		for i = 1, #connections do
			NAmanage.tryDisconnect(connections[i])
			connections[i] = nil
		end
		if hooks[button] == state then
			hooks[button] = nil
		end
	end

	function state:Disconnect()
		disconnectAll()
	end

	hooks[button] = state

	local function getSignal(obj, signalName)
		local ok, signal = pcall(function()
			return obj[signalName]
		end)
		if ok and signal then
			return signal
		end
		return nil
	end

	local function connectSignal(signal, fn)
		if disconnected or not signal then
			return false
		end
		local ok, conn = pcall(function()
			return signal:Connect(fn)
		end)
		if ok and conn then
			connections[#connections + 1] = conn
			return true
		end
		return false
	end

	local function isPressInput(inputType)
		return inputType == Enum.UserInputType.MouseButton1
			or inputType == Enum.UserInputType.Touch
	end

	local function resetState()
		mouseDownTime = 0
		isPointerDown = false
		startPosition = nil
		maxMoveDistance = 0
	end

	local function beginPointer(input)
		if disconnected then
			return
		end
		isPointerDown = true
		mouseDownTime = tick()
		maxMoveDistance = 0
		local pos = input and input.Position
		startPosition = pos and Vector2.new(pos.X, pos.Y) or nil
	end

	local function endPointer()
		if disconnected then
			return
		end
		if not isPointerDown or mouseDownTime == 0 then
			resetState()
			return
		end

		local holdDuration = tick() - mouseDownTime
		local isClick = (holdDuration < clickTimeThreshold) and (maxMoveDistance <= moveThreshold)

		resetState()

		if isClick then
			clickCallback()
		end
	end

	local boundPress = false
	local isGuiButton = type(button.IsA) == "function" and button:IsA("GuiButton")
	if isGuiButton then
		local downSignal = getSignal(button, "MouseButton1Down")
		local upSignal = getSignal(button, "MouseButton1Up")
		local downBound = connectSignal(downSignal, function()
			beginPointer(nil)
		end)
		local upBound = connectSignal(upSignal, function()
			endPointer()
		end)
		boundPress = downBound and upBound
	end

	if not boundPress then
		local beganSignal = getSignal(button, "InputBegan")
		local endedSignal = getSignal(button, "InputEnded")
		local beganBound = connectSignal(beganSignal, function(input)
			if input and isPressInput(input.UserInputType) then
				beginPointer(input)
			end
		end)
		local endedBound = connectSignal(endedSignal, function(input)
			if input and isPressInput(input.UserInputType) then
				endPointer()
			end
		end)
		boundPress = beganBound and endedBound
	end

	local changedSignal = getSignal(button, "InputChanged")
	connectSignal(changedSignal, function(input)
		if not isPointerDown then
			return
		end

		if input.UserInputType ~= Enum.UserInputType.MouseMovement
			and input.UserInputType ~= Enum.UserInputType.Touch then
			return
		end

		local pos = input.Position
		if not pos then
			return
		end

		if not startPosition then
			startPosition = Vector2.new(pos.X, pos.Y)
			return
		end

		local currentPos = Vector2.new(pos.X, pos.Y)
		local delta = (currentPos - startPosition).Magnitude
		if delta > maxMoveDistance then
			maxMoveDistance = delta
		end
	end)

	if not boundPress then
		disconnectAll()
		return state
	end

	if button.AncestryChanged then
		connectSignal(button.AncestryChanged, function(_, parent)
			if not parent then
				Defer(disconnectAll)
			end
		end)
	end
	if button.Destroying then
		connectSignal(button.Destroying, disconnectAll)
	end

	return state
end

NAmanage.AttachMessageCopy = function(gui, rawMessage)
	if not (gui and gui.InputBegan and gui.InputEnded) then
		return
	end
	NAStuff._messageCopyHooks = NAmanage.ensureWeakKeyTable(NAStuff._messageCopyHooks)
	local hooks = NAStuff._messageCopyHooks

	local function buildResolver()
		if type(rawMessage) == "function" then
			return function()
				local ok, value = pcall(rawMessage, gui)
				if ok then
					return value
				end
				return nil
			end
		end
		return function()
			return rawMessage
		end
	end

	local existing = hooks[gui]
	if existing then
		existing.resolveMessage = buildResolver()
		return existing
	end

	local HOLD_TIME = 0.5
	local isHolding = false
	local holdToken = 0

	local state = {
		resolveMessage = buildResolver(),
	}
	hooks[gui] = state

	local function startHold()
		holdToken += 1
		local myToken = holdToken
		isHolding = true
		Delay(HOLD_TIME, function()
			if not isHolding or myToken ~= holdToken then
				return
			end
			local resolver = state.resolveMessage
			local msg = resolver and resolver() or nil
			if msg == nil then
				return
			end
			msg = tostring(msg)
			if msg == "" then
				return
			end
			if setclipboard then
				pcall(setclipboard, msg)
				if DoNotif then
					DoNotif("Message copied to clipboard.", 1.5)
				end
			elseif DoNotif then
				DoNotif("Clipboard unavailable", 1.5)
			end
		end)
	end

	local function stopHold()
		isHolding = false
	end

	state.beginConn = gui.InputBegan:Connect(function(input)
		if input.UserInputType == Enum.UserInputType.MouseButton1
			or input.UserInputType == Enum.UserInputType.Touch then
			startHold()
		end
	end)

	state.endConn = gui.InputEnded:Connect(function(input)
		if input.UserInputType == Enum.UserInputType.MouseButton1
			or input.UserInputType == Enum.UserInputType.Touch then
			stopHold()
		end
	end)

	local function cleanup()
		holdToken += 1
		isHolding = false
		local s = hooks[gui]
		if not s then
			return
		end
		hooks[gui] = nil
		if s.beginConn then
			pcall(function() s.beginConn:Disconnect() end)
			s.beginConn = nil
		end
		if s.endConn then
			pcall(function() s.endConn:Disconnect() end)
			s.endConn = nil
		end
		if s.ancestryConn then
			pcall(function() s.ancestryConn:Disconnect() end)
			s.ancestryConn = nil
		end
	end

	state.cleanup = cleanup
	state.ancestryConn = gui.AncestryChanged:Connect(function(_, parent)
		if not parent then
			cleanup()
		end
	end)

	return state
end


--[[ FUNCTION TO GET A PLAYER ]]--
local PlayerArgs = {
	["all"] = function()
		return __lt.cm("Players", "GetPlayers")
	end,

	["others"] = function()
		local Targets = {}

		Foreach(__lt.cm("Players", "GetPlayers"), function(Index, Player)
			if Player ~= LocalPlayer then
				Insert(Targets, Player)
			end
		end)

		return Targets
	end,

	["me"] = function()
		return { LocalPlayer }
	end,

	["random"] = function()
		local list = __lt.cm("Players", "GetPlayers")
		if LocalPlayer then
			local i = Discover(list, LocalPlayer)
			if i then table.remove(list, i) end
		end
		if #list == 0 then
			return {}
		end
		return { list[math.random(1, #list)] }
	end,

	["npc"] = function()
		local Targets = {}
		for _, model in ipairs(NAmanage.wsDescs()) do
			if CheckIfNPC(model) then
				Insert(Targets, model)
			end
		end
		return Targets
	end,

	["seated"] = function()
		local Targets = {}

		Foreach(__lt.cm("Players", "GetPlayers"), function(Index, Player)
			if getPlrHum(Player.Character).Sit then
				Insert(Targets, Player)
			end
		end)

		return Targets
	end,

	["stood"] = function()
		local Targets = {}

		Foreach(__lt.cm("Players", "GetPlayers"), function(Index, Player)
			if not getPlrHum(Player.Character).Sit then
				Insert(Targets, Player)
			end
		end)

		return Targets
	end,

	["nearest"] = function()
		if not LocalPlayer.Character or not getRoot(LocalPlayer.Character) then return {} end
		local lowest = math.huge
		local Targets = nil

		Foreach(__lt.cm("Players", "GetPlayers"), function(_, plr)
			if plr ~= LocalPlayer and plr.Character and getRoot(plr.Character) then
				local distance = (getRoot(plr.Character).Position - getRoot(LocalPlayer.Character).Position).Magnitude
				if distance < lowest then
					lowest = distance
					Targets = plr
				end
			end
		end)

		return Targets and {Targets} or {}
	end,

	["farthest"] = function()
		if not LocalPlayer.Character or not getRoot(LocalPlayer.Character) then return {} end
		local highest = 0
		local Targets = nil

		Foreach(__lt.cm("Players", "GetPlayers"), function(_, plr)
			if plr ~= LocalPlayer and plr.Character and getRoot(plr.Character) then
				local distance = (getRoot(plr.Character).Position - getRoot(LocalPlayer.Character).Position).Magnitude
				if distance > highest then
					highest = distance
					Targets = plr
				end
			end
		end)

		return Targets and {Targets} or {}
	end,

	["dead"] = function()
		local Targets = {}

		Foreach(__lt.cm("Players", "GetPlayers"), function(Index, Player)
			if getPlrHum(Player.Character).Health == 0 then
				Insert(Targets, Player)
			end
		end)

		return Targets
	end,

	["alive"] = function()
		local Targets = {}

		Foreach(__lt.cm("Players", "GetPlayers"), function(Index, Player)
			if getPlrHum(Player.Character).Health > 0 then
				Insert(Targets, Player)
			end
		end)

		return Targets
	end,

	["friends"] = function()
		local Targets = {}

		Foreach(__lt.cm("Players", "GetPlayers"), function(Index, Player)
			if Player:IsFriendsWith(LocalPlayer.UserId) and LocalPlayer ~= Player then
				Insert(Targets, Player)
			end
		end)

		return Targets
	end,

	["nonfriends"] = function()
		local Targets = {}

		Foreach(__lt.cm("Players", "GetPlayers"), function(Index, Player)
			if not Player:IsFriendsWith(LocalPlayer.UserId) and LocalPlayer ~= Player then
				Insert(Targets, Player)
			end
		end)

		return Targets
	end,

	["team"] = function()
		local Targets = {}

		Foreach(__lt.cm("Players", "GetPlayers"), function(_, Player)
			if Player.Team == LocalPlayer.Team and Player ~= LocalPlayer then
				Insert(Targets, Player)
			end
		end)

		return Targets
	end,

	["nonteam"] = function()
		local Targets = {}

		Foreach(__lt.cm("Players", "GetPlayers"), function(_, Player)
			if Player.Team ~= LocalPlayer.Team and Player ~= LocalPlayer then
				Insert(Targets, Player)
			end
		end)

		return Targets
	end,

	["r15"] = function()
		local Targets = {}

		Foreach(__lt.cm("Players", "GetPlayers"), function(_, Player)
			local Hum = getPlrHum(Player.Character)
			if Hum and Hum.RigType == Enum.HumanoidRigType.R15 then
				Insert(Targets, Player)
			end
		end)

		return Targets
	end,

	["r6"] = function()
		local Targets = {}

		Foreach(__lt.cm("Players", "GetPlayers"), function(_, Player)
			local Hum = getPlrHum(Player.Character)
			if Hum and Hum.RigType == Enum.HumanoidRigType.R6 then
				Insert(Targets, Player)
			end
		end)

		return Targets
	end,

	["invisible"] = function()
		local Targets = {}

		Foreach(__lt.cm("Players", "GetPlayers"), function(_, Player)
			local Char = Player.Character
			if Char then
				local isInvisible = true
				for _, part in ipairs(Char:GetChildren()) do
					if part:IsA("BasePart") and part.Transparency < 1 then
						isInvisible = false
						break
					end
				end
				if isInvisible then
					Insert(Targets, Player)
				end
			end
		end)

		return Targets
	end,

	["bacon"] = function()
		local Targets = {}

		Foreach(__lt.cm("Players", "GetPlayers"), function(_, Player)
			local Char = Player.Character
			if Char then
				for _, v in ipairs(Char:GetChildren()) do
					if v:IsA("Accessory") and v.Name:lower():find("pal") or v.Name:lower():find("kate") then
						Insert(Targets, Player)
						break
					end
				end
			end
		end)

		return Targets
	end,

	["slenders"] = function()
		local Targets = {}

		Foreach(__lt.cm("Players", "GetPlayers"), function(_, Player)
			local Hum = getPlrHum(Player.Character)
			if Hum and Hum.RigType == Enum.HumanoidRigType.R15 then
				local desc = Hum:GetAppliedDescription()
				if desc and tonumber(desc.BodyHeightScale) > 1.05 then
					Insert(Targets, Player)
				end
			end
		end)

		return Targets
	end,

	["short"] = function()
		local Targets = {}

		Foreach(__lt.cm("Players", "GetPlayers"), function(_, Player)
			local Hum = getPlrHum(Player.Character)
			if Hum and Hum.RigType == Enum.HumanoidRigType.R15 then
				local desc = Hum:GetAppliedDescription()
				if desc and tonumber(desc.BodyHeightScale) < 0.9 then
					Insert(Targets, Player)
				end
			end
		end)

		return Targets
	end,
	["#(%d+)"] = function(speaker, args, currentList)
		local returns = {}
		local randAmount = tonumber(args[1])
		local pool = { unpack(currentList or __lt.cm("Players", "GetPlayers")) }
		for i = 1, math.min(randAmount, #pool) do
			local idx = math.random(1, #pool)
			Insert(returns, pool[idx])
			table.remove(pool, idx)
		end
		return returns
	end,

	["%%(.+)"] = function(speaker, args)
		local returns = {}
		local teamPrefix = args[1]:lower()
		for _, plr in ipairs(__lt.cm("Players", "GetPlayers")) do
			if plr.Team
				and plr.Team.Name:lower():sub(1, #teamPrefix) == teamPrefix
			then
				Insert(returns, plr)
			end
		end
		return returns
	end,

	["allies"] = function()
		local Targets = {}

		Foreach(__lt.cm("Players", "GetPlayers"), function(_, Player)
			if Player.Team == LocalPlayer.Team and Player ~= LocalPlayer then
				Insert(Targets, Player)
			end
		end)

		return Targets
	end,

	["enemies"] = function()
		local Targets = {}

		Foreach(__lt.cm("Players", "GetPlayers"), function(_, Player)
			if Player.Team ~= LocalPlayer.Team and Player ~= LocalPlayer then
				Insert(Targets, Player)
			end
		end)

		return Targets
	end,

	["age(%d+)"] = function(speaker, args)
		local returns = {}
		local maxAge = tonumber(args[1])
		for _, plr in ipairs(__lt.cm("Players", "GetPlayers")) do
			if plr.AccountAge <= maxAge then
				Insert(returns, plr)
			end
		end
		return returns
	end,

	["group(%d+)"] = function(speaker, args)
		local returns = {}
		local groupID = tonumber(args[1])
		for _, plr in ipairs(__lt.cm("Players", "GetPlayers")) do
			if plr:IsInGroup(groupID) then
				Insert(returns, plr)
			end
		end
		return returns
	end,

	["rad(%d+)"] = function(speaker, args)
		local returns = {}
		local radius = tonumber(args[1])
		local origin = getRoot(speaker.Character)
		if not origin then return returns end
		for _, plr in ipairs(__lt.cm("Players", "GetPlayers")) do
			local root = getRoot(plr.Character)
			if root and (root.Position - origin.Position).Magnitude <= radius then
				Insert(returns, plr)
			end
		end
		return returns
	end,

	["cursor"] = function(speaker)
		local returns = {}
		local v = NAmanage.getPlrCursor()
		if v then Insert(returns, v) end
		return returns
	end,
}

originalIO.normalizePlayerQuery=function(query)
	if type(query) == "string" then
		return query:lower()
	end
	if type(query) == "table" and type(query.Name) == "string" then
		return query.Name:lower()
	end
	return ""
end

local function getPlr(a, b)
	local speaker, raw
	if b == nil then
		speaker = Players.LocalPlayer
		raw = originalIO.normalizePlayerQuery(a)
	else
		speaker = a
		raw = originalIO.normalizePlayerQuery(b)
	end

	if PlayerArgs[raw] then
		return PlayerArgs[raw](speaker)
	end

	local onlyDigits = raw:match("^%d+$")
	if onlyDigits then
		return PlayerArgs["#(%d+)"](speaker, {onlyDigits}, PlayerArgs["all"]())
	end

	for pat, fn in pairs(PlayerArgs) do
		local captures = { raw:match("^"..pat.."$") }
		if #captures > 0 then
			return fn(speaker, captures, PlayerArgs["all"]())
		end
	end

	local out = {}
	for _, plr in ipairs(__lt.cm("Players", "GetPlayers")) do
		local n = plr.Name:lower()
		local d = plr.DisplayName:lower()
		if n:sub(1,#raw) == raw or d:sub(1,#raw) == raw then
			Insert(out, plr)
		end
	end
	return out
end

