	return NAmanage.DrawingObjectSupported("Triangle", refresh)
end

NAmanage.DrawingLineSupported = function(refresh)
	return NAmanage.DrawingObjectSupported("Line", refresh)
end

NAmanage.DrawingTextSupported = function(refresh)
	return NAmanage.DrawingObjectSupported("Text", refresh)
end

NAmanage.DrawingCreateSquare = function(color, fillTransparency, options)
	if NAmanage.DrawingObjectSupported and not NAmanage.DrawingObjectSupported("Square") then
		return nil
	end
	local drawingLib = NAgui.getDrawingLibrary()
	if not drawingLib then
		return nil
	end
	local ok, square = pcall(function()
		return drawingLib.new("Square")
	end)
	if not ok or not square then
		if type(NAmanage._drawingObjectSupport) == "table" then
			NAmanage._drawingObjectSupport.Square = false
		end
		return nil
	end
	local alpha = NAgui.toDrawingTransparency(fillTransparency or 0.7)
	local thickness = math.max(1, tonumber(options and options.thickness) or 1)
	pcall(function()
		square.Visible = false
		square.Filled = false
		square.Thickness = thickness
		square.Color = color or Color3.new(1, 1, 1)
		square.Transparency = alpha
	end)
	return square
end

NAmanage.DrawingUpdateSquare = function(square, inst, color, fillTransparency, options)
	if not square then return false end
	local minX, minY, width, height = NAgui.getInstanceViewportBounds(inst)
	if not minX then
		pcall(function()
			square.Visible = false
		end)
		return true
	end
	local alpha = NAgui.toDrawingTransparency(fillTransparency or 0.7)
	local thickness = math.max(1, tonumber(options and options.thickness) or 1)
	local ok = pcall(function()
		square.Color = color or Color3.new(1, 1, 1)
		square.Transparency = alpha
		square.Filled = false
		square.Thickness = thickness
		square.Position = Vector2.new(minX, minY)
		square.Size = Vector2.new(width, height)
		square.Visible = true
	end)
	if not ok and type(NAmanage._drawingObjectSupport) == "table" then
		NAmanage._drawingObjectSupport.Square = false
	end
	return ok
end

NAmanage.DrawingCreateText = function(text, color, textSize, options)
	if NAmanage.DrawingObjectSupported and not NAmanage.DrawingObjectSupported("Text") then
		return nil
	end
	local drawingLib = NAgui.getDrawingLibrary()
	if not drawingLib then
		return nil
	end
	local ok, txt = pcall(function()
		return drawingLib.new("Text")
	end)
	if not ok or not txt then
		if type(NAmanage._drawingObjectSupport) == "table" then
			NAmanage._drawingObjectSupport.Text = false
		end
		return nil
	end
	local outlineEnabled
	if options and options.outlineEnabled ~= nil then
		outlineEnabled = options.outlineEnabled == true
	else
		outlineEnabled = NAStuff.ESP_DrawingTextOutline ~= false
	end
	pcall(function()
		txt.Visible = false
		txt.Center = true
		txt.Outline = outlineEnabled
		txt.Color = color or Color3.new(1, 1, 1)
		txt.Size = NAgui.sanitizeLabelSize(textSize or 12)
		txt.Text = tostring(text or "")
		txt.Transparency = 1
		txt.OutlineColor = Color3.new(0.05, 0.05, 0.05)
	end)
	return txt
end

NAmanage.DrawingUpdateText = function(txt, worldPos, text, color, textSize, options)
	if not txt then return false end
	local cam = workspace and workspace.CurrentCamera
	if not cam or not worldPos then
		pcall(function()
			txt.Visible = false
		end)
		return true
	end
	local viewportPoint, onScreen = cam:WorldToViewportPoint(worldPos)
	if viewportPoint.Z <= 0 or not onScreen then
		pcall(function()
			txt.Visible = false
		end)
		return true
	end
	local outlineEnabled
	if options and options.outlineEnabled ~= nil then
		outlineEnabled = options.outlineEnabled == true
	else
		outlineEnabled = NAStuff.ESP_DrawingTextOutline ~= false
	end
	local ok = pcall(function()
		txt.Text = tostring(text or "")
		txt.Color = color or Color3.new(1, 1, 1)
		txt.Size = NAgui.sanitizeLabelSize(textSize or 12)
		txt.Outline = outlineEnabled
		txt.OutlineColor = Color3.new(0.05, 0.05, 0.05)
		txt.Position = Vector2.new(viewportPoint.X, viewportPoint.Y)
		txt.Visible = true
	end)
	if not ok and type(NAmanage._drawingObjectSupport) == "table" then
		NAmanage._drawingObjectSupport.Text = false
	end
	return ok
end

NAmanage.DrawingCreateLine = function(color, alpha, thickness)
	if NAmanage.DrawingLineSupported and not NAmanage.DrawingLineSupported() then
		return nil
	end
	local drawingLib = NAgui.getDrawingLibrary()
	if not drawingLib then
		return nil
	end
	local ok, line = pcall(function()
		return drawingLib.new("Line")
	end)
	if not ok or not line then
		if type(NAmanage._drawingObjectSupport) == "table" then
			NAmanage._drawingObjectSupport.Line = false
		end
		return nil
	end
	pcall(function()
		line.Visible = false
		line.Color = color or Color3.new(1, 1, 1)
		line.Transparency = math.clamp(tonumber(alpha) or 1, 0, 1)
		line.Thickness = math.max(1, tonumber(thickness) or 1)
		line.From = Vector2.new(0, 0)
		line.To = Vector2.new(0, 0)
	end)
	return line
end

NAmanage.DrawingUpdateLine = function(line, fromPos, toPos, color, alpha, thickness)
	if not line then return false end
	if typeof(fromPos) ~= "Vector2" or typeof(toPos) ~= "Vector2" then
		pcall(function()
			line.Visible = false
		end)
		return true
	end
	local ok = pcall(function()
		line.From = fromPos
		line.To = toPos
		line.Color = color or Color3.new(1, 1, 1)
		line.Transparency = math.clamp(tonumber(alpha) or 1, 0, 1)
		line.Thickness = math.max(1, tonumber(thickness) or 1)
		line.Visible = true
	end)
	if not ok and type(NAmanage._drawingObjectSupport) == "table" then
		NAmanage._drawingObjectSupport.Line = false
	end
	return ok
end

NAmanage.DrawingCreateTriangle = function(color, alpha)
	if NAmanage.DrawingTriangleSupported and not NAmanage.DrawingTriangleSupported() then
		return nil
	end
	local drawingLib = NAgui.getDrawingLibrary()
	if not drawingLib then
		return nil
	end
	local ok, tri = pcall(function()
		return drawingLib.new("Triangle")
	end)
	if not ok or not tri then
		if type(NAmanage._drawingObjectSupport) == "table" then
			NAmanage._drawingObjectSupport.Triangle = false
		end
		return nil
	end
	pcall(function()
		tri.Visible = false
		tri.Filled = true
		tri.Thickness = 1
		tri.Color = color or Color3.new(1, 1, 1)
		tri.Transparency = math.clamp(tonumber(alpha) or 1, 0, 1)
	end)
	return tri
end

NAmanage.DrawingUpdateTriangle = function(tri, centerX, centerY, dirX, dirY, size, color, alpha)
	if not tri then
		return
	end
	local dx = tonumber(dirX) or 0
	local dy = tonumber(dirY) or -1
	local mag = math.sqrt((dx * dx) + (dy * dy))
	if mag <= 1e-4 then
		dx, dy = 0, -1
	else
		dx, dy = dx / mag, dy / mag
	end
	local arrowSize = math.clamp(tonumber(size) or 26, 8, 256)
	local tip = arrowSize * 0.5
	local tail = arrowSize * 0.36
	local halfWidth = arrowSize * 0.32
	local px = -dy
	local py = dx
	local ax = centerX + (dx * tip)
	local ay = centerY + (dy * tip)
	local baseX = centerX - (dx * tail)
	local baseY = centerY - (dy * tail)
	local bx = baseX + (px * halfWidth)
	local by = baseY + (py * halfWidth)
	local cx = baseX - (px * halfWidth)
	local cy = baseY - (py * halfWidth)
	local ok = pcall(function()
		tri.Color = color or Color3.new(1, 1, 1)
		tri.Transparency = math.clamp(tonumber(alpha) or 1, 0, 1)
		tri.PointA = Vector2.new(ax, ay)
		tri.PointB = Vector2.new(bx, by)
		tri.PointC = Vector2.new(cx, cy)
		tri.Visible = true
	end)
	if not ok and type(NAmanage._drawingObjectSupport) == "table" then
		NAmanage._drawingObjectSupport.Triangle = false
	end
	return ok
end

NAgui.updateLabelBounds=function(label)
	if not label then return end
	local billboard = label.Parent
	if not billboard or not billboard:IsA("BillboardGui") then return end
	local text = label.Text
	if text == "" then
		text = label.Name or " "
	end
	local targetSize = NAgui.sanitizeLabelSize(NAStuff.ESP_LabelTextSize)
	local success, bounds = pcall(TextService.GetTextSize, TextService, text, targetSize, label.Font, Vector2.new(1e4, 1e4))
	local width = 150
	local height = math.max(targetSize + 12, 30)
	if success and bounds then
		width = math.clamp(math.floor(bounds.X + 16), 80, 600)
		height = math.clamp(math.floor(bounds.Y + 12), 24, 200)
	end
	local size = billboard.Size
	if size.X.Offset ~= width or size.Y.Offset ~= height then
		billboard.Size = UDim2.new(0, width, 0, height)
	end
end

NAgui.applyLabelStyle=function(label)
	if not label then return end
	label.AutomaticSize = Enum.AutomaticSize.None
	label.TextScaled = NAStuff.ESP_LabelTextScaled
	label.TextWrapped = false
	label.ClipsDescendants = false
	label.TextStrokeTransparency = math.clamp(tonumber(NAStuff.ESP_LabelStrokeTransparency) or 0.5, 0, 1)
	label.TextSize = NAgui.sanitizeLabelSize(NAStuff.ESP_LabelTextSize)
	NAgui.updateLabelBounds(label)
end

NAgui.updateLabelForInstance=function(inst)
	if not inst or not inst.Parent then return end
	for _, child in ipairs(inst:GetChildren()) do
		if child:IsA("BillboardGui") and Sub(Lower(child.Name),-6) == "_label" then
			local lbl = child:FindFirstChildWhichIsA("TextLabel")
			if lbl then
				NAgui.applyLabelStyle(lbl)
			end
		end
	end
end

NAmanage.ESP_ApplyLabelStyles = function()
	local scaled = (NAStuff.ESP_LabelTextScaled == true)
	local size = NAgui.sanitizeLabelSize(NAStuff.ESP_LabelTextSize)
	local seen = {}
	if NAStuff.partESPEntries then
		for _, entry in pairs(NAStuff.partESPEntries) do
			if typeof(entry) == "table" and not seen[entry] then
				seen[entry] = true
				if entry.label then
					entry.label.TextScaled = scaled
					if not scaled then
						entry.label.TextSize = size
					end
				end
				if entry.drawingLabel then
					pcall(function()
						entry.drawingLabel.Size = size
						entry.drawingLabel.Outline = NAStuff.ESP_DrawingPartTextOutline ~= false
						entry.drawingLabel.OutlineColor = Color3.new(0.05, 0.05, 0.05)
					end)
				end
			end
		end
	end
	if NAStuff.partESPVisualMap then
		for _, entry in pairs(NAStuff.partESPVisualMap) do
			if typeof(entry) == "table" and not seen[entry] then
				seen[entry] = true
				if entry.label then
					entry.label.TextScaled = scaled
					if not scaled then
						entry.label.TextSize = size
					end
				end
				if entry.drawingLabel then
					pcall(function()
						entry.drawingLabel.Size = size
						entry.drawingLabel.Outline = NAStuff.ESP_DrawingPartTextOutline ~= false
						entry.drawingLabel.OutlineColor = Color3.new(0.05, 0.05, 0.05)
					end)
				end
			end
		end
	end
	if type(espCONS) == "table" then
		for _, data in pairs(espCONS) do
			if type(data) == "table" then
				if data.textLabel then
					data.textLabel.TextScaled = scaled
					if not scaled then
						data.textLabel.TextSize = size
					end
				end
				if data.drawingLabel then
					pcall(function()
						data.drawingLabel.Size = size
						data.drawingLabel.Outline = NAStuff.ESP_DrawingTextOutline ~= false
						data.drawingLabel.OutlineColor = Color3.new(0.05, 0.05, 0.05)
					end)
				end
			end
		end
	end
end

NAgui.adjustHighlightMaterialFor = function(target, enable)
	if not target then return end
	local originals = NAStuff.partESPGlassOriginal
	local counts = NAStuff.partESPGlassCount
	local ltOriginals = NAStuff.partESPLocalTransOriginal
	local ltCounts = NAStuff.partESPLocalTransCount
	if not originals then
		originals = {}
		NAStuff.partESPGlassOriginal = originals
	end
	if not counts then
		counts = {}
		NAStuff.partESPGlassCount = counts
	end
	if not ltOriginals then
		ltOriginals = {}
		NAStuff.partESPLocalTransOriginal = ltOriginals
	end
	if not ltCounts then
		ltCounts = {}
		NAStuff.partESPLocalTransCount = ltCounts
	end
	local function handlePart(base)
		if not base or not base:IsA("BasePart") then return end
		local gCount = counts[base] or 0
		local tCount = ltCounts[base] or 0
		if enable then
			if gCount == 0 then
				originals[base] = base.Material
			end
			counts[base] = gCount + 1
			if base.Material ~= Enum.Material.Glass then
				NAlib.setProperty(base, "Material", Enum.Material.Glass)
			end
			if tCount == 0 then
				ltOriginals[base] = base.LocalTransparencyModifier
			end
			ltCounts[base] = tCount + 1
			if base.Transparency >= 1 or base.LocalTransparencyModifier >= 1 then
				NAlib.setProperty(base, "LocalTransparencyModifier", 0.999)
			end
		else
			if gCount > 0 then
				gCount -= 1
				if gCount <= 0 then
					counts[base] = nil
					local original = originals[base]
					if original ~= nil then
						NAlib.setProperty(base, "Material", original)
						originals[base] = nil
					end
				else
					counts[base] = gCount
				end
			end
			if tCount > 0 then
				tCount -= 1
				if tCount <= 0 then
					ltCounts[base] = nil
					local lt = ltOriginals[base]
					if lt ~= nil then
						NAlib.setProperty(base, "LocalTransparencyModifier", lt)
						ltOriginals[base] = nil
					end
				else
					ltCounts[base] = tCount
				end
			end
		end
	end
	if target:IsA("BasePart") then
		handlePart(target)
	elseif target:IsA("Model") then
		for _, desc in ipairs(NAmanage.qDesc(target, "BasePart")) do
			handlePart(desc)
		end
	end
end

NAmanage.ESP_AdjustHighlightMaterial = function(target, enable)
	NAgui.adjustHighlightMaterialFor(target, enable)
end

NAStuff.partESPEntries = NAStuff.partESPEntries or {}
NAStuff.partESPVisualMap = NAStuff.partESPVisualMap or {}
NAStuff.partESPPartMap = NAStuff.partESPPartMap or {}
NAStuff.partESPQueueMap = NAStuff.partESPQueueMap or {}
NAStuff.partESPQueue = NAStuff.partESPQueue or {}
NAStuff.partESPQueueHead = tonumber(NAStuff.partESPQueueHead) or 1
NAStuff.partESPQueueTail = tonumber(NAStuff.partESPQueueTail) or 0
NAStuff.espScanTokens = NAStuff.espScanTokens or {}
NAStuff.espSweepCursor = NAStuff.espSweepCursor or {}

NAmanage.PartESP_QueueClear = function()
	NAStuff.partESPQueue = {}
	NAStuff.partESPQueueMap = {}
	NAStuff.partESPQueueHead = 1
	NAStuff.partESPQueueTail = 0
	NAlib.disconnect("esp_part_queue")
end

NAmanage.PartESP_QueueRun = function()
	if NAlib.isConnected("esp_part_queue") then
		return
	end
	NAlib.connect("esp_part_queue", RunService.Heartbeat:Connect(function()
		local queue = NAStuff.partESPQueue
		local qMap = NAStuff.partESPQueueMap
		local head = tonumber(NAStuff.partESPQueueHead) or 1
		local tail = tonumber(NAStuff.partESPQueueTail) or 0
		if head > tail then
			NAmanage.PartESP_QueueClear()
			return
		end

		local maxPerStep = tonumber(NAStuff.ESP_MaxPerStep) or 32
		if NAgui.espUsesDrawing("part") then
			maxPerStep = math.max(maxPerStep, tonumber(NAStuff.ESP_DrawingPartQueuePerStep) or 128)
		end
		maxPerStep = math.clamp(math.floor(maxPerStep), 1, 512)
		local processed = 0
		while processed < maxPerStep and head <= tail do
			local item = queue[head]
			queue[head] = nil
			head += 1
			processed += 1
			if item then
				local part = item.part
				if qMap[part] == item then
					qMap[part] = nil
				end
				if part and part.Parent and (part:IsA("BasePart") or part:IsA("Model")) then
					local canCreate = true
					if type(item.guard) == "function" then
						local ok, result = pcall(item.guard, part, item)
						canCreate = ok and result == true
					end
					if canCreate then
						NAmanage.CreateBox(part, item.color, item.transparency)
					end
				end
			end
		end

		NAStuff.partESPQueueHead = head
		NAStuff.partESPQueueTail = tail
		if head > tail then
			NAmanage.PartESP_QueueClear()
		end
	end))
end

NAmanage.PartESP_QueueCreate = function(part, color, transparency, guard)
	if not part or not part.Parent then
		return
	end
	if not (part:IsA("BasePart") or part:IsA("Model")) then
		return
	end
	local qMap = NAStuff.partESPQueueMap
	local existing = qMap[part]
	if existing then
		existing.color = color
		existing.transparency = transparency
		existing.guard = guard
		return
	end
	local queue = NAStuff.partESPQueue
	local tail = (tonumber(NAStuff.partESPQueueTail) or 0) + 1
	local item = {
		part = part,
		color = color,
		transparency = transparency,
		guard = guard,
	}
	queue[tail] = item
	qMap[part] = item
	NAStuff.partESPQueueTail = tail
	NAmanage.PartESP_QueueRun()
end

NAmanage.PartESP_QueueRemove = function(part)
	if not part then
		return false
	end
	local qMap = NAStuff.partESPQueueMap
	if type(qMap) ~= "table" then
		return false
	end
	local item = qMap[part]
	if not item then
		return false
	end
	qMap[part] = nil
	item.part = nil
	item.guard = nil
	return true
end

NAmanage.PartESP_StartSweep = function(key, predicate, budget)
	if type(key) ~= "string" or key == "" or type(predicate) ~= "function" then
		return
	end
	if NAlib.isConnected(key) then
		return
	end
	local cursorStore = NAStuff.espSweepCursor
	if type(cursorStore) ~= "table" then
		cursorStore = {}
		NAStuff.espSweepCursor = cursorStore
	end
	cursorStore[key] = tonumber(cursorStore[key]) or 1
	local stepBudget = tonumber(budget) or tonumber(NAStuff.ESP_RescanPerStep) or 90
	stepBudget = math.clamp(math.floor(stepBudget), 8, 400)
	NAlib.connect(key, RunService.Heartbeat:Connect(function()
		local list = NAmanage.wsDescs and NAmanage.wsDescs() or {}
		local total = #list
		if total <= 0 then
			cursorStore[key] = 1
			return
		end
		local idx = tonumber(cursorStore[key]) or 1
		if idx < 1 or idx > total then
			idx = 1
		end
		local scanned = 0
		local start = idx
		repeat
			local obj = list[idx]
			if obj then
				predicate(obj)
			end
			scanned += 1
			idx += 1
			if idx > total then
				idx = 1
			end
		until scanned >= stepBudget or idx == start
		cursorStore[key] = idx
	end))
end

NAmanage.PartESP_UpdateEntry = function(entry, force, rootPart)
	if not entry or entry.removed then return end
	local part = entry.part
	if not part or not part.Parent then
		NAmanage.PartESP_UnregisterEntry(entry)
		return
	end
	local billboard = entry.billboard
	local label = entry.label
	local drawingLabel = entry.drawingLabel
	local drawingSquare = entry.drawingSquare
	local drawingCornerLines = entry.drawingCornerLines
	local drawingCornerOutlineLines = entry.drawingCornerOutlineLines
	local visual = entry.visual
	local hasBillboard = billboard and billboard.Parent
	local hasDrawingLabel = drawingLabel ~= nil
	local hasDrawingSquare = drawingSquare ~= nil
	local hasDrawingCorners = type(drawingCornerLines) == "table" and #drawingCornerLines > 0
		or type(drawingCornerOutlineLines) == "table" and #drawingCornerOutlineLines > 0
	local hasVisual = visual and visual.Parent
	if not (hasBillboard or hasDrawingLabel or hasDrawingSquare or hasDrawingCorners or hasVisual) then
		NAmanage.PartESP_UnregisterEntry(entry)
		return
	end
	if billboard and ((not label) or label.Parent ~= billboard) then
		label = billboard:FindFirstChildWhichIsA("TextLabel")
		entry.label = label
	end
	if billboard and billboard.Parent then
		NAmanage.ESP_StoreVisual(billboard)
	end
	local baseName = entry.customName or part.Name or "Part"
	local display = baseName
	local showPartText = (NAStuff.ESP_ShowPartText ~= false)
	local showDistance = (NAStuff.ESP_ShowPartDistance == true)
	local root = rootPart
	if showDistance and not root then
		local plr = Players.LocalPlayer
		local char = plr and plr.Character
		root = char and getRoot(char)
	end
	if showDistance and root then
		local pos = NAgui.getInstanceWorldPosition(part)
		if pos then
			local dist = math.floor((root.Position - pos).Magnitude + 0.5)
			display = Format("%s | %d studs", baseName, dist)
		end
	end
	if label then
		if showPartText then
			if label.Text ~= display then
				label.Text = display
			end
			if not label.Visible then
				label.Visible = true
			end
			NAgui.applyLabelStyle(label)
		elseif label.Visible then
			label.Visible = false
		end
	end
	if drawingLabel then
		if showPartText then
			local textColor = entry.lightColor or entry.baseColor or Color3.new(1, 1, 1)
			local textPos = NAgui.getInstanceLabelWorldPosition(part, 0.2)
			if not NAmanage.DrawingUpdateText(drawingLabel, textPos, display, textColor, NAStuff.ESP_LabelTextSize, {
				outlineEnabled = NAStuff.ESP_DrawingPartTextOutline ~= false
			}) then
				NAmanage.ESP_RequestVisualRebuild()
				return
			end
		else
			pcall(function()
				drawingLabel.Visible = false
			end)
		end
	end
	local transparency = NAgui.sanitizeTransparency(NAStuff.ESP_PartTransparency or entry.transparency)
	local partDrawingStyle = NAgui.sanitizeESPDrawingBoxStyle(NAStuff.ESP_DrawingPartBoxStyle)
	if drawingSquare then
		local drawColor = entry.lightColor or entry.baseColor or Color3.new(1, 1, 1)
		if partDrawingStyle == "Corners" then
			pcall(function()
				drawingSquare.Visible = false
			end)
		elseif not NAmanage.DrawingUpdateSquare(drawingSquare, part, drawColor, transparency, {
			thickness = NAStuff.ESP_DrawingPartBoxThickness
		}) then
			NAmanage.ESP_RequestVisualRebuild()
			return
		end
	end
	if partDrawingStyle == "Corners" and type(drawingCornerLines) == "table" and type(drawingCornerOutlineLines) == "table" then
		local minX, minY, width, height = NAgui.getInstanceViewportBounds(part)
		if minX then
			local alpha = NAgui.toDrawingTransparency(transparency)
			local mainThickness = math.max(1, tonumber(NAStuff.ESP_DrawingPartBoxThickness) or 1)
			local outlineThickness = mainThickness + 2
			local segX = math.max(6, width * 0.25)
			local segY = math.max(6, height * 0.25)
			local points = {
				{ Vector2.new(minX, minY), Vector2.new(minX + segX, minY) },
				{ Vector2.new(minX + width, minY), Vector2.new(minX + width - segX, minY) },
				{ Vector2.new(minX, minY + height), Vector2.new(minX + segX, minY + height) },
				{ Vector2.new(minX + width, minY + height), Vector2.new(minX + width - segX, minY + height) },
				{ Vector2.new(minX, minY), Vector2.new(minX, minY + segY) },
				{ Vector2.new(minX + width, minY), Vector2.new(minX + width, minY + segY) },
				{ Vector2.new(minX, minY + height), Vector2.new(minX, minY + height - segY) },
				{ Vector2.new(minX + width, minY + height), Vector2.new(minX + width, minY + height - segY) },
			}
			for i = 1, 8 do
				local seg = points[i]
				if not NAmanage.DrawingUpdateLine(drawingCornerOutlineLines[i], seg[1], seg[2], Color3.new(0.1, 0.1, 0.1), math.min(1, alpha + 0.15), outlineThickness) then
					NAmanage.ESP_RequestVisualRebuild()
					return
				end
				if not NAmanage.DrawingUpdateLine(drawingCornerLines[i], seg[1], seg[2], entry.lightColor or entry.baseColor or Color3.new(1, 1, 1), alpha, mainThickness) then
					NAmanage.ESP_RequestVisualRebuild()
					return
				end
			end
		else
			for i = 1, #(drawingCornerLines or {}) do
				pcall(function()
					drawingCornerLines[i].Visible = false
				end)
			end
			for i = 1, #(drawingCornerOutlineLines or {}) do
				pcall(function()
					drawingCornerOutlineLines[i].Visible = false
				end)
			end
		end
	end
	if visual and visual.Parent then
		NAmanage.ESP_StoreVisual(visual)
		if visual:IsA("Highlight") then
			if visual.FillTransparency ~= transparency then
				visual.FillTransparency = transparency
			end
			local fill = entry.lightColor or entry.baseColor or Color3.new(1,1,1)
			local outline = entry.darkColor or fill
			local outlineTr = NAgui.sanitizeTransparency(NAStuff.ESP_OutlineTransparency or 0)
			if visual.FillColor ~= fill then
				visual.FillColor = fill
			end
			if visual.OutlineColor ~= outline then
				visual.OutlineColor = outline
			end
			if visual.OutlineTransparency ~= outlineTr then
				visual.OutlineTransparency = outlineTr
			end
		elseif visual:IsA("BoxHandleAdornment") then
			if entry.lightColor and visual.Color3 ~= entry.lightColor then
				visual.Color3 = entry.lightColor
			end
			if visual.Transparency ~= transparency then
				visual.Transparency = transparency
			end
			if part:IsA("BasePart") then
				local desired = part.Size + Vector3.new(0.1,0.1,0.1)
				if visual.Size ~= desired then
					visual.Size = desired
				end
			end
		end
	end
end

NAmanage.PartESP_UpdateTexts = function(force)
	local entries = NAStuff.partESPEntries
	if not entries then
		return
	end
	local interval = NAgui.espUsesDrawing("part") and 0.03 or 0.2
	if not force then
		local now = tick()
		local nextUpdate = NAStuff.partESPLastUpdate or 0
		if now < nextUpdate then
			return
		end
		NAStuff.partESPLastUpdate = now + interval
	else
		NAStuff.partESPLastUpdate = tick() + interval
	end
	local rootPart = nil
	if NAStuff.ESP_ShowPartDistance == true then
		local plr = Players.LocalPlayer
		local char = plr and plr.Character
		rootPart = char and getRoot(char)
	end
	local hasEntry = false
	for _, entry in pairs(entries) do
		if entry and not entry.removed then
			hasEntry = true
			NAmanage.PartESP_UpdateEntry(entry, force, rootPart)
		end
	end
	if not hasEntry then
		NAmanage.PartESP_StopHeartbeat()
	end
end

NAmanage.PartESP_StartHeartbeat = function()
	local useDrawingSignal = NAgui.espUsesDrawing("part")
	local desiredSignal = useDrawingSignal and "RenderStepped" or "Heartbeat"
	if NAlib.isConnected("esp_part_update") then
		if NAStuff.partESPUpdateSignal == desiredSignal then
			return
		end
		NAlib.disconnect("esp_part_update")
	end
	NAStuff.partESPUpdateSignal = desiredSignal
	NAStuff.partESPLastUpdate = 0
	local signal = useDrawingSignal and RunService.RenderStepped or RunService.Heartbeat
	NAlib.connect("esp_part_update", signal:Connect(function()
		NAmanage.PartESP_UpdateTexts(false)
	end))
end

NAmanage.PartESP_StopHeartbeat = function()
	local entries = NAStuff.partESPEntries
	if entries and next(entries) then return end
	NAlib.disconnect("esp_part_update")
	NAStuff.partESPUpdateSignal = nil
end

NAmanage.PartESP_RegisterEntry = function(entry)
	if not entry then return end
	entry.entryKey = entry.entryKey or entry.billboard or entry.visual or entry.drawingSquare or entry.drawingLabel or entry.part
	if not entry.entryKey then return end
	NAStuff.partESPEntries[entry.entryKey] = entry
	if entry.visual and typeof(entry.visual) == "Instance" then
		NAStuff.partESPVisualMap[entry.visual] = entry
	end
	if entry.part and typeof(entry.part) == "Instance" then
		local partMap = NAStuff.partESPPartMap
		if type(partMap) ~= "table" then
			partMap = {}
			NAStuff.partESPPartMap = partMap
		end
		local bucket = partMap[entry.part]
		if type(bucket) ~= "table" then
			bucket = {}
			partMap[entry.part] = bucket
		end
		bucket[entry.entryKey] = entry
	end
	if entry.billboardCleanup then
		entry.billboardCleanup:Disconnect()
	end
	if entry.visualCleanup then
		entry.visualCleanup:Disconnect()
	end
	if entry.partCleanup then
		entry.partCleanup:Disconnect()
		entry.partCleanup = nil
	end
	if entry.partDestroyingCleanup then
		entry.partDestroyingCleanup:Disconnect()
		entry.partDestroyingCleanup = nil
	end
	if entry.billboard then
		entry.billboardCleanup = entry.billboard.AncestryChanged:Connect(function(_, parent)
			if not parent then
				NAmanage.PartESP_UnregisterEntry(entry)
			end
		end)
	end
	if entry.visual then
		entry.visualCleanup = entry.visual.AncestryChanged:Connect(function(_, parent)
			if not parent then
				NAmanage.PartESP_UnregisterEntry(entry)
			end
		end)
	end
	if entry.part and typeof(entry.part) == "Instance" then
		entry.partCleanup = entry.part.AncestryChanged:Connect(function(_, parent)
			if not parent then
				NAmanage.PartESP_UnregisterEntry(entry)
			end
		end)
		pcall(function()
			entry.partDestroyingCleanup = entry.part.Destroying:Connect(function()
				NAmanage.PartESP_UnregisterEntry(entry)
			end)
		end)
	end
	NAmanage.PartESP_StartHeartbeat()
	NAmanage.PartESP_UpdateEntry(entry, true)
end

NAmanage.PartESP_UnregisterEntry = function(entry)
	if not entry or entry.removed then return end
	entry.removed = true
	NAmanage.ESP_LocatorRemoveArrow(entry)
	if entry.billboardCleanup then
		entry.billboardCleanup:Disconnect()
		entry.billboardCleanup = nil
	end
	if entry.visualCleanup then
		entry.visualCleanup:Disconnect()
		entry.visualCleanup = nil
	end
	if entry.partCleanup then
		entry.partCleanup:Disconnect()
		entry.partCleanup = nil
	end
	if entry.partDestroyingCleanup then
		entry.partDestroyingCleanup:Disconnect()
		entry.partDestroyingCleanup = nil
	end
	if entry.updateKey then
		NAlib.disconnect(entry.updateKey)
		entry.updateKey = nil
	end
	if entry.entryKey and NAStuff.partESPEntries then
		NAStuff.partESPEntries[entry.entryKey] = nil
	end
	if entry.visual and typeof(entry.visual) == "Instance" and NAStuff.partESPVisualMap then
		NAStuff.partESPVisualMap[entry.visual] = nil
	end
	if entry.part and typeof(entry.part) == "Instance" and type(NAStuff.partESPPartMap) == "table" then
		local bucket = NAStuff.partESPPartMap[entry.part]
		if type(bucket) == "table" and entry.entryKey then
			bucket[entry.entryKey] = nil
			if not next(bucket) then
				NAStuff.partESPPartMap[entry.part] = nil
			end
		end
	end
	if entry.drawingSquare then
		NAmanage.DrawingRemoveObject(entry.drawingSquare)
		entry.drawingSquare = nil
	end
	if type(entry.drawingCornerLines) == "table" then
		for i = 1, #entry.drawingCornerLines do
			NAmanage.DrawingRemoveObject(entry.drawingCornerLines[i])
		end
		entry.drawingCornerLines = nil
	end
	if type(entry.drawingCornerOutlineLines) == "table" then
		for i = 1, #entry.drawingCornerOutlineLines do
			NAmanage.DrawingRemoveObject(entry.drawingCornerOutlineLines[i])
		end
		entry.drawingCornerOutlineLines = nil
	end
	if entry.drawingLabel then
		NAmanage.DrawingRemoveObject(entry.drawingLabel)
		entry.drawingLabel = nil
	end
	if entry.visual and typeof(entry.visual) == "Instance" then
		pcall(function()
			entry.visual:Destroy()
		end)
	end
	entry.visual = nil
	if entry.billboard then
		pcall(function()
			entry.billboard:Destroy()
		end)
	end
	entry.billboard = nil
	entry.label = nil
	NAmanage.PartESP_StopHeartbeat()
end

NAmanage.PartESP_RebuildVisuals = function()
	local entries = NAStuff.partESPEntries
	if not entries or not next(entries) then
		return
	end
	local grouped = {}
	for _, entry in pairs(entries) do
		if entry and not entry.removed and entry.part and entry.part.Parent then
			local bucket = grouped[entry.part]
			if not bucket then
				bucket = {}
				grouped[entry.part] = bucket
			end
			bucket[#bucket+1] = {
				color = entry.baseColor or Color3.new(1,1,1),
				transparency = NAgui.sanitizeTransparency(NAStuff.ESP_PartTransparency or entry.transparency or 0.45),
			}
		end
	end
	for part, bucket in pairs(grouped) do
		NAmanage.RemoveEspFromPart(part)
		for _, info in ipairs(bucket) do
			NAmanage.CreateBox(part, info.color, info.transparency)
		end
	end
	NAmanage.PartESP_UpdateTexts(true)
end

NAmanage.ESP_RebuildVisuals = function()
	for model, data in pairs(espCONS) do
		if data then
			local wasEnabled = data.boxEnabled
			NAmanage.ESP_RemoveBoxes(model)
			if wasEnabled then
				NAmanage.ESP_AddBoxes(model)
			end
		end
	end
	NAmanage.PartESP_RebuildVisuals()
	NAmanage.PartESP_StartHeartbeat()
	if NAStuff.ESP_LocatorEnabled then
		NAmanage.ESP_LocatorEnable(true)
		NAmanage.ESP_LocatorApplyFlags()
	end
	if NAStuff.ESP_PlayerLocatorEnabled then
		NAmanage.ESP_PlayerLocatorEnable(true)
		NAmanage.ESP_PlayerLocatorApplyFlags()
	end
	NAmanage.ESP_ApplyLabelStyles()
end

function round(num,numDecimalPlaces)
	local mult=10^(numDecimalPlaces or 0)
	return math.floor(num*mult+0.5) / mult
end

function getPlaceInfo(forceRefresh)
	local cachedInfo = NAStuff and NAStuff._placeInfoCache
	if not forceRefresh and type(cachedInfo) == "table" then
		return cachedInfo
	end

	local success, result = pcall(function()
		return __lt.cm("MarketplaceService", "GetProductInfo", PlaceId)
	end)

	if not success or type(result) ~= "table" then
		return cachedInfo
	end

	if NAStuff then
		NAStuff._placeInfoCache = result
		NAStuff._placeInfoCacheAt = os.clock()
	end

	return result
end

function placeName()
	local info = getPlaceInfo()
	local name = info and NAlib.isProperty(info, "Name")
	return name or "unknown"
end

function placeIconAssetId()
	local info = getPlaceInfo()
	local icon = info and NAlib.isProperty(info, "IconImageAssetId")
	if typeof(icon) == "number" then
		return icon
	end
	if typeof(icon) == "string" then
		local digits = icon:match("(%d+)")
		if digits then
			local numeric = tonumber(digits)
			if numeric then
				return numeric
			end
		end
		local asNumber = tonumber(icon)
		if asNumber then
			return asNumber
		end
	end
	return nil
end

Defer(function()
	if NAmanage and NAmanage.btEnabled and NAmanage.btEnabled() then
		pcall(getPlaceInfo)
	end
end)

function SaveUIStroke(color)
	if typeof(color) ~= "Color3" then
		return
	end

	if NAStuff and NAStuff.AprilFoolsData then
		NAStuff.AprilFoolsData.originalColor = color
	end

	NAmanage.NASettingsSet("uiStroke", {
		R = color.R;
		G = color.G;
		B = color.B;
	})
end

function placeCreator()
	local info = getPlaceInfo()
	local creator = info and NAlib.isProperty(info, "Creator")
	local creatorName = creator and NAlib.isProperty(creator, "Name")
	return creatorName or "unknown"
end

NAmanage.ESP_Key = function(model)
	return tostring(model)
end

NAmanage.ESP_GetSecureHost = function()
	local host = (NAlib.huiGrabber and NAlib.huiGrabber())
		or COREGUI
		or (Players and Players.LocalPlayer and Players.LocalPlayer:FindFirstChildOfClass("PlayerGui"))
		or workspace.CurrentCamera
	if typeof(host) == "Instance" then
		return host
	end
	return nil
end

NAmanage.ESP_GetSecureAttrKey = function()
	local key = NAStuff.ESP_SecureAttrKey
	if type(key) == "string" and key ~= "" then
		return key
	end
	key = NAmanage.GenerateOpaqueSessionKey()
	NAStuff.ESP_SecureAttrKey = key
	return key
end

NAmanage.ESP_HardenVisual = function(inst)
	if typeof(inst) ~= "Instance" then
		return
	end
	pcall(function()
		inst.Archivable = false
	end)
	local secureAttrKey = NAmanage.ESP_GetSecureAttrKey()
	if NAmanage.GetAttr(inst, secureAttrKey) ~= true then
		NAmanage.SetAttr(inst, secureAttrKey, true)
		pcall(function()
			inst.Name = (NAgui.rStringgg and NAgui.rStringgg()) or "\0"
		end)
	end
	local hiddenSetter = (opt and opt.hiddenprop) or hiddenprop or sethiddenproperty or set_hidden_property or set_hidden_prop
	if hiddenSetter then
		pcall(function()
			hiddenSetter(inst, "RobloxLocked", true)
		end)
	end
end

NAmanage.ESP_EnsureSecureContainer = function()
	local host = NAmanage.ESP_GetSecureHost()
	if not host then
		return nil
	end
	local container = NAStuff.ESP_SecureContainer
	if container and not container.Parent then
		NAStuff.ESP_SecureContainer = nil
		container = nil
	end
	if not container then
		container = InstanceNew("Folder")
		NAStuff.ESP_SecureContainer = container
	end
	NAmanage.ESP_HardenVisual(container)
	if container.Parent ~= host then
		pcall(function()
			container.Parent = host
		end)
	end
	return container
end

NAmanage.ESP_StoreVisual = function(inst)
	if typeof(inst) ~= "Instance" then
		return nil
	end
	local container = NAmanage.ESP_EnsureSecureContainer()
	if not container then
		return nil
	end
	NAmanage.ESP_HardenVisual(inst)
	if inst.Parent ~= container then
		pcall(function()
			inst.Parent = container
		end)
	end
	return container
end

NAmanage.ESP_CollectTrackedBillboards = function(model, uid)
	local list = {}
	local seen = {}
	local function scan(root)
		if not (root and root.Parent) then
			return
		end
		for _, d in ipairs(NAmanage.qDesc(root, "BillboardGui")) do
			if not seen[d] and NAmanage.GetAttr(d, "NA_ESP_UID") == uid then
				seen[d] = true
				list[#list + 1] = d
			end
		end
	end
	scan(model)
	scan(NAStuff.ESP_SecureContainer)
	return list
end

