	bx.ClearTextOnFocus = false
	bx.Font = Enum.Font.Code
	bx.TextSize = 15
	bx.TextColor3 = tx
	bx.TextXAlignment = Enum.TextXAlignment.Left
	bx.PlaceholderText = ":cmd args"
