}

NAmanage.NAremoveShaderEffects=function(lighting)
	for _, name in ipairs(NA_SHADER_EFFECT_NAMES) do
		local inst = lighting:FindFirstChild(name)
		if inst then
			inst:Destroy()
		end
	end
