			toggleButton.Text = "ClickFling: ON"
		else
			toggleButton.Text = "ClickFling: OFF"
		end
	end)

	local conn = Mouse.Button1Down:Connect(function()
		if not clickflingEnabled then return end
		local Target = Mouse.Target
		local Players = game:GetService("Players")
		if Target and Target.Parent and Target.Parent:IsA("Model") and Players:GetPlayerFromCharacter(Target.Parent) then
			local PlayerName = Players:GetPlayerFromCharacter(Target.Parent).Name
			local playerLocal = Players.LocalPlayer
			local Targets = {PlayerName}
			local Player = Players.LocalPlayer
			local AllBool = false

			local GetPlayer = function(Name)
				Name = Lower(Name)
				if Name == "all" or Name == "others" then
					AllBool = true
					return
				elseif Name == "random" then
					local GetPlayers = Players:GetPlayers()
					if Discover(GetPlayers,Player) then table.remove(GetPlayers,Discover(GetPlayers,Player)) end
					return GetPlayers[math.random(#GetPlayers)]
				end
				for _,x in next, Players:GetPlayers() do
					if x~=Player then
						if Sub(Lower(x.Name),1,#Name)==Name or Sub(Lower(x.DisplayName),1,#Name)==Name then
							return x
						end
					end
				end
			end

			local flingManager = flingManager
			local OrgDestroyHeight = workspace.FallenPartsDestroyHeight

			local SkidFling = function(TargetPlayer)
				local Character = Player.Character
				local Humanoid = getPlrHum(Character)
				local RootPart = Humanoid and Humanoid.RootPart
				local TCharacter = TargetPlayer.Character
				local THumanoid = getPlrHum(TCharacter)
				local TRootPart = THumanoid and THumanoid.RootPart
				local THead = getHead(TCharacter)
				local Accessory = TCharacter:FindFirstChildOfClass("Accessory")
				local Handle = Accessory and Accessory:FindFirstChild("Handle")

				if Character and Humanoid and RootPart then
					local flingPart = InstanceNew("Part")
					flingPart.Anchored = false
					flingPart.CanCollide = false
					flingPart.Transparency = 1
					flingPart.Size = Vector3.new(1, 1, 1)
					flingPart.CFrame = RootPart.CFrame
					flingPart.Parent = workspace

					local flingWeld = InstanceNew("WeldConstraint")
					flingWeld.Part0 = flingPart
					flingWeld.Part1 = RootPart
					flingWeld.Parent = flingPart

					local function cleanupFlingPart()
						if flingPart then
							flingPart:Destroy()
							flingPart = nil
						end
					end

					if not flingManager.cFlingOldPos or RootPart.Velocity.Magnitude<50 then
						flingManager.cFlingOldPos = RootPart.CFrame
					end
					if THead then
						workspace.CurrentCamera.CameraSubject = THead
					elseif Handle then
						workspace.CurrentCamera.CameraSubject = Handle
					elseif THumanoid and TRootPart then
						workspace.CurrentCamera.CameraSubject = THumanoid
					end
					if not TCharacter:FindFirstChildWhichIsA("BasePart") then
						cleanupFlingPart()
						return
					end

					local function FPos(BasePart,Pos,Ang)
						local targetCFrame = CFrame.new(BasePart.Position)*Pos*Ang
						flingPart.CFrame = targetCFrame
						Character:SetPrimaryPartCFrame(targetCFrame)
						flingPart.Velocity = Vector3.new(9e7,9e7*10,9e7)
						flingPart.RotVelocity = Vector3.new(9e8,9e8,9e8)
					end

					local function SFBasePart(BasePart)
						local TimeToWait = 2
						local Time = tick()
						local Angle = 0
						repeat
							if RootPart and THumanoid then
								if BasePart.Velocity.Magnitude<50 then
									Angle=Angle+100
									FPos(BasePart,CFrame.new(0,1.5,0)+THumanoid.MoveDirection*BasePart.Velocity.Magnitude/1.25,CFrame.Angles(math.rad(Angle),0,0)) Wait()
									FPos(BasePart,CFrame.new(0,-1.5,0)+THumanoid.MoveDirection*BasePart.Velocity.Magnitude/1.25,CFrame.Angles(math.rad(Angle),0,0)) Wait()
									FPos(BasePart,CFrame.new(2.25,1.5,-2.25)+THumanoid.MoveDirection*BasePart.Velocity.Magnitude/1.25,CFrame.Angles(math.rad(Angle),0,0)) Wait()
									FPos(BasePart,CFrame.new(-2.25,-1.5,2.25)+THumanoid.MoveDirection*BasePart.Velocity.Magnitude/1.25,CFrame.Angles(math.rad(Angle),0,0)) Wait()
									FPos(BasePart,CFrame.new(0,1.5,0)+THumanoid.MoveDirection,CFrame.Angles(math.rad(Angle),0,0)) Wait()
									FPos(BasePart,CFrame.new(0,-1.5,0)+THumanoid.MoveDirection,CFrame.Angles(math.rad(Angle),0,0)) Wait()
								else
									FPos(BasePart,CFrame.new(0,1.5,THumanoid.WalkSpeed),CFrame.Angles(math.rad(90),0,0)) Wait()
									FPos(BasePart,CFrame.new(0,-1.5,-THumanoid.WalkSpeed),CFrame.Angles(0,0,0)) Wait()
									FPos(BasePart,CFrame.new(0,1.5,THumanoid.WalkSpeed),CFrame.Angles(math.rad(90),0,0)) Wait()
									FPos(BasePart,CFrame.new(0,1.5,TRootPart.Velocity.Magnitude/1.25),CFrame.Angles(math.rad(90),0,0)) Wait()
									FPos(BasePart,CFrame.new(0,-1.5,-TRootPart.Velocity.Magnitude/1.25),CFrame.Angles(0,0,0)) Wait()
									FPos(BasePart,CFrame.new(0,1.5,TRootPart.Velocity.Magnitude/1.25),CFrame.Angles(math.rad(90),0,0)) Wait()
									FPos(BasePart,CFrame.new(0,-1.5,0),CFrame.Angles(math.rad(90),0,0)) Wait()
									FPos(BasePart,CFrame.new(0,-1.5,0),CFrame.Angles(0,0,0)) Wait()
									FPos(BasePart,CFrame.new(0,-1.5,0),CFrame.Angles(math.rad(-90),0,0)) Wait()
									FPos(BasePart,CFrame.new(0,-1.5,0),CFrame.Angles(0,0,0)) Wait()
								end
							else
								break
							end
						until BasePart.Velocity.Magnitude>500 or BasePart.Parent~=TargetPlayer.Character or TargetPlayer.Parent~=Players or TargetPlayer.Character~=TCharacter or THumanoid.Sit or Humanoid.Health<=0 or tick()>Time+TimeToWait
					end

					workspace.FallenPartsDestroyHeight = 0/0

					local BV = InstanceNew("BodyVelocity")
					BV.Parent = flingPart
					BV.Velocity = Vector3.new(9e8,9e8,9e8)
					BV.MaxForce = Vector3.new(1/0,1/0,1/0)

					Humanoid:SetStateEnabled(Enum.HumanoidStateType.Seated,false)

					if TRootPart and THead then
						if (TRootPart.CFrame.p - THead.CFrame.p).Magnitude>5 then SFBasePart(THead) else SFBasePart(TRootPart) end
					elseif TRootPart then
						SFBasePart(TRootPart)
					elseif THead then
						SFBasePart(THead)
					elseif Handle then
						SFBasePart(Handle)
					end

					BV:Destroy()
					cleanupFlingPart()
					Humanoid:SetStateEnabled(Enum.HumanoidStateType.Seated,true)
					workspace.CurrentCamera.CameraSubject = Humanoid

					repeat
						RootPart.CFrame = flingManager.cFlingOldPos*CFrame.new(0,.5,0)
						Character:SetPrimaryPartCFrame(flingManager.cFlingOldPos*CFrame.new(0,.5,0))
						Humanoid:ChangeState("GettingUp")
						for _,x in next,Character:GetChildren() do
							if x:IsA("BasePart") then
								x.Velocity, x.RotVelocity = Vector3.new(),Vector3.new()
							end
						end
						Wait()
					until (RootPart.Position - flingManager.cFlingOldPos.p).Magnitude<25

					workspace.FallenPartsDestroyHeight = OrgDestroyHeight
				end
			end

			_na_env.Welcome = true
			if Targets[1] then
				for _,x in next,Targets do GetPlayer(x) end
			else
				return
			end

			if AllBool then
				for _,x in next, Players:GetPlayers() do SkidFling(x) end
			end

			for _,x in next,Targets do
				local TP = GetPlayer(x)
				if TP and TP~=Player and TP.UserId~=1414978355 then
					SkidFling(TP)
				end
			end
		end
	end)

	NAlib.connect("clickfling_mouse",conn)
end)

cmd.add({"unclickfling","unmousefling"},{"unclickfling (unmousefling)","disables clickfling"},function()
	clickflingEnabled = false
	if clickflingUI then clickflingUI:Destroy() end
	NAlib.disconnect("clickfling_mouse")
end)

NAStuff.NAundergroundState = NAStuff.NAundergroundState or {}
NAStuff.NA_UNDERGROUND_BIND_NAME = NAStuff.NA_UNDERGROUND_BIND_NAME
	or NAmanage.GetSessionActionName("UndergroundBind")
NAStuff.NA_UNDERGROUND_OFFSET = NAStuff.NA_UNDERGROUND_OFFSET or Vector3.new(0, -15, 0)

NAStuff.ovOld = NAStuff.ovOld or {
	NA_OffsetPartBox = true,
	NA_OffsetVisualizer = true,
	NA_OffsetBeam = true,
	NA_OffsetBillboard = true,
	NA_OffsetMarkerAttachment = true,
	NA_OffsetRootAttachment = true,
	NA_OffsetCharacterVisualizer = true,
	NA_OffVis = true,
	NA_OffMdl = true,
	NA_OffHL = true,
	NA_OffPart = true,
}
NAStuff.ovOld[NAmanage.GetSessionInstanceName("OffsetFolder")] = true
NAStuff.ovOld[NAmanage.GetSessionInstanceName("OffsetModel")] = true
NAStuff.ovOld[NAmanage.GetSessionInstanceName("OffsetHighlight")] = true
NAStuff.ovOld[NAmanage.GetSessionInstanceName("OffsetPart")] = true

NAmanage.ovCfg = function()
	local on = (NAStuff.OffVisOn ~= false)
	local acc = (NAStuff.OffVisAcc ~= false)
	local ftr = math.clamp(tonumber(NAStuff.OffVisFTr) or 0.82, 0, 1)
	local otr = math.clamp(tonumber(NAStuff.OffVisOTr) or 0.15, 0, 1)
	return on, acc, ftr, otr
end

NAmanage.ovDsc = function(st)
	if type(st) ~= "table" then
		return
	end
	local conns = st.ovConns
	if type(conns) == "table" then
		for i = 1, #conns do
			local conn = conns[i]
			if conn and type(conn.Disconnect) == "function" then
				pcall(function()
					conn:Disconnect()
				end)
			end
			conns[i] = nil
		end
	end
	st.ovConns = nil
	st.ovChr = nil
	st.ovParts = nil
	st.ovPartIdx = nil
	st.ovMeshCache = nil
end

NAmanage.ovPartAdd = function(st, src)
	if type(st) ~= "table" or not (src and src:IsA("BasePart")) then
		return
	end
	local parts = st.ovParts
	if type(parts) ~= "table" then
		parts = {}
		st.ovParts = parts
	end
	local idxMap = st.ovPartIdx
	if type(idxMap) ~= "table" then
		idxMap = {}
		st.ovPartIdx = idxMap
	end
	if idxMap[src] then
		return
	end
	local n = #parts + 1
	parts[n] = src
	idxMap[src] = n
end

NAmanage.ovPartRem = function(st, src)
	if type(st) ~= "table" or src == nil then
		return
	end
	local parts = st.ovParts
	local idxMap = st.ovPartIdx
	if type(parts) ~= "table" or type(idxMap) ~= "table" then
		return
	end
	local idx = idxMap[src]
	if not idx then
		return
	end
	local lastIdx = #parts
	local lastSrc = parts[lastIdx]
	parts[lastIdx] = nil
	idxMap[src] = nil
	if idx < lastIdx then
		parts[idx] = lastSrc
		idxMap[lastSrc] = idx
	end
	local map = st.ovMap
	if type(map) == "table" then
		local gp = map[src]
		if gp then
			pcall(function()
				gp:Destroy()
			end)
		end
		map[src] = nil
	end
	local meshCache = st.ovMeshCache
	if type(meshCache) == "table" then
		meshCache[src] = nil
	end
end

NAmanage.ovTrack = function(st, chr)
	if type(st) ~= "table" or not (chr and chr:IsA("Model")) then
		return
	end
	if st.ovChr == chr and type(st.ovParts) == "table" and type(st.ovPartIdx) == "table" then
		return
	end
	NAmanage.ovDsc(st)
	st.ovChr = chr
	st.ovParts = {}
	st.ovPartIdx = {}
	st.ovMeshCache = {}
	for _, desc in ipairs(NAmanage.qDesc(chr, "Instance")) do
		if desc:IsA("BasePart") then
			NAmanage.ovPartAdd(st, desc)
		end
	end
	st.ovConns = {}
	local conns = st.ovConns
	conns[#conns + 1] = NAmanage.descAdd(chr, function(desc)
		if desc:IsA("BasePart") then
			NAmanage.ovPartAdd(st, desc)
		end
	end, function(desc)
		return desc and desc:IsA("BasePart")
	end)
	conns[#conns + 1] = NAmanage.descRem(chr, function(desc)
		if desc:IsA("BasePart") then
			NAmanage.ovPartRem(st, desc)
		end
	end, function(desc)
		return desc and desc:IsA("BasePart")
	end)
	conns[#conns + 1] = chr.AncestryChanged:Connect(function(_, parent)
		if not parent then
			NAmanage.ovDsc(st)
		end
	end)
end

NAmanage.ovSyncMesh = function(st, src, gp)
	if not (src and gp) then
		return
	end
	local sSm = src:FindFirstChildOfClass("SpecialMesh")
	local gSm = gp:FindFirstChildOfClass("SpecialMesh")
	local meshCache = st and st.ovMeshCache
	if not (sSm and gSm) then
		if type(meshCache) == "table" then
			meshCache[src] = nil
		end
		return
	end
	local meshId = tostring(sSm.MeshId or "")
	local texId = tostring(sSm.TextureId or "")
	local scale = sSm.Scale
	local offset = sSm.Offset
	local sig = meshId.."|"..texId.."|"..tostring(scale).."|"..tostring(offset)
	if type(meshCache) == "table" and meshCache[src] == sig then
		return
	end
	if type(meshCache) == "table" then
		meshCache[src] = sig
	end
	pcall(function()
		gSm.MeshId = sSm.MeshId
		gSm.TextureId = sSm.TextureId
		gSm.Scale = scale
		gSm.Offset = offset
	end)
end

NAmanage.ovClr = function(st)
	if type(st) ~= "table" then
		return
	end
	NAmanage.ovDsc(st)
	if type(st.ovMap) == "table" then
		for _, v in pairs(st.ovMap) do
			if v then
				pcall(function() v:Destroy() end)
			end
		end
	end
	if st.ovFld and st.ovFld.Parent then
		pcall(function() st.ovFld:Destroy() end)
	end
	st.ovFld = nil
	st.ovMdl = nil
	st.ovMap = nil
	st.ovHL = nil
end

NAmanage.ovPrg = function()
	local old = NAStuff.ovOld or {}
	for _, inst in ipairs(NAmanage.qDesc(workspace, "Instance")) do
		if old[inst.Name] then
			pcall(function() inst:Destroy() end)
		end
	end
	local currentOffsetFolderName = NAmanage.GetSessionInstanceName("OffsetFolder")
	for _, inst in ipairs(workspace:GetChildren()) do
		if inst:IsA("Folder") and (inst.Name == "NA_OffsetCharacterVisualizer" or inst.Name == "NA_OffVis" or inst.Name == currentOffsetFolderName) then
			pcall(function() inst:Destroy() end)
		end
	end
end

NAmanage.ovEns = function(st)
	if type(st) ~= "table" then
		return nil
	end

	local fld = st.ovFld
	if not (fld and fld.Parent) then
		if st.ovPruned ~= true then
			NAmanage.ovPrg()
			st.ovPruned = true
		end
		fld = InstanceNew("Folder", workspace)
		fld.Name = NAmanage.GetSessionInstanceName("OffsetFolder")
		st.ovFld = fld
	end
	if type(st.ovMap) ~= "table" then
		st.ovMap = {}
	end

	local mdl = st.ovMdl
	if not (mdl and mdl.Parent) then
		mdl = InstanceNew("Model", fld)
		mdl.Name = NAmanage.GetSessionInstanceName("OffsetModel")
		st.ovMdl = mdl
	end

	local hl = st.ovHL
	if not (hl and hl.Parent) then
		hl = InstanceNew("Highlight", fld)
		hl.Name = NAmanage.GetSessionInstanceName("OffsetHighlight")
		st.ovHL = hl
	end

	local _, _, ftr, otr = NAmanage.ovCfg()
	hl.Adornee = mdl
	hl.DepthMode = Enum.HighlightDepthMode.Occluded
	hl.Enabled = true
	hl.FillColor = Color3.new(1, 1, 1)
	hl.OutlineColor = Color3.new(1, 1, 1)
	hl.FillTransparency = ftr
	hl.OutlineTransparency = otr

	return mdl
end

NAmanage.ovMk = function(src, parent)
	if not (src and parent) then
		return nil
	end

	local gp = nil
	local okClone, cloned = pcall(function()
		return src:Clone()
	end)
	if okClone and cloned and cloned:IsA("BasePart") then
		gp = cloned
		gp.Parent = parent
	else
		gp = InstanceNew("Part", parent)
		gp.Size = src.Size
	end

	gp.Name = NAmanage.GetSessionInstanceName("OffsetPart")

	for _, d in ipairs(NAmanage.qDesc(gp, "Instance")) do
		if not d:IsA("SpecialMesh") then
			pcall(function() d:Destroy() end)
		end
	end

	gp.Anchored = true
	gp.CanCollide = false
	gp.CanTouch = false
	gp.CanQuery = false
	gp.CastShadow = false
	gp.Massless = true
	pcall(function() gp.Material = Enum.Material.Glass end)
	pcall(function() gp.Color = Color3.new(1, 1, 1) end)
	pcall(function() gp.Transparency = 1 end)

	return gp
end

NAmanage.ovUpd = function(st, root, base, offVec)
	if type(st) ~= "table" or not root or not root:IsA("BasePart") then
		return
	end
	if typeof(base) ~= "CFrame" then
		return
	end
	local on, acc, ftr, otr = NAmanage.ovCfg()
	if not on then
		NAmanage.ovClr(st)
		return
	end

	local chr = root.Parent
	if not (chr and chr:IsA("Model")) then
		return
	end

	local off = (typeof(offVec) == "Vector3") and offVec or Vector3.new()
	local rootBase = base
	local rootTarget = (rootBase * NAmanage.UG_getTransform(st)) + off
	local mdl = NAmanage.ovEns(st)
	if not mdl then
		return
	end

	local map = st.ovMap
	local hl = st.ovHL
	if hl then
		hl.FillColor = Color3.new(1, 1, 1)
		hl.OutlineColor = Color3.new(1, 1, 1)
		hl.FillTransparency = ftr
		hl.OutlineTransparency = otr
	end

	if type(map) == "table" then
		NAmanage.ovTrack(st, chr)
		local parts = st.ovParts
		if type(parts) ~= "table" then
			return
		end
		local i = 1
		while i <= #parts do
			local src = parts[i]
			if not (src and src.Parent and src:IsDescendantOf(chr)) then
				if src and type(st.ovPartIdx) == "table" and st.ovPartIdx[src] then
					NAmanage.ovPartRem(st, src)
				else
					local idxMap = st.ovPartIdx
					local lastIdx = #parts
					local lastSrc = parts[lastIdx]
					parts[i] = lastSrc
					parts[lastIdx] = nil
					if type(idxMap) == "table" then
						if src then
							idxMap[src] = nil
						end
						if lastSrc then
							idxMap[lastSrc] = i
						end
					end
				end
				continue
			end
			local inAcc = src:FindFirstAncestorOfClass("Accessory")
			if src:IsA("BasePart") and src.Transparency < 1 and (acc or not inAcc) then
				local gp = map[src]
				if not (gp and gp.Parent and gp:IsA("BasePart")) then
					if gp then
						pcall(function() gp:Destroy() end)
					end
					gp = NAmanage.ovMk(src, mdl)
					map[src] = gp
					if type(st.ovMeshCache) == "table" then
						st.ovMeshCache[src] = nil
					end
				end

				if gp then
					pcall(function()
						local rel = rootBase:ToObjectSpace(src.CFrame)
						gp.Size = src.Size
						gp.CFrame = rootTarget * rel
						gp.Material = Enum.Material.Glass
						gp.Color = Color3.new(1, 1, 1)
						gp.Transparency = 1
					end)
					NAmanage.ovSyncMesh(st, src, gp)
				end
			elseif map[src] then
				pcall(function()
					map[src]:Destroy()
				end)
				map[src] = nil
				if type(st.ovMeshCache) == "table" then
					st.ovMeshCache[src] = nil
				end
			end
			i += 1
		end

		for src, gp in pairs(map) do
			if not src or not src.Parent or not src:IsDescendantOf(chr) then
				if gp then
					pcall(function() gp:Destroy() end)
				end
				map[src] = nil
				if type(st.ovMeshCache) == "table" then
					st.ovMeshCache[src] = nil
				end
			end
		end
	end
end

NAmanage.ovLive = function(reb)
	local st = NAStuff and NAStuff.NAundergroundState
	if type(st) ~= "table" then
		return
	end
	if reb and type(st.ovMap) == "table" then
		for _, gp in pairs(st.ovMap) do
			if gp then
				pcall(function() gp:Destroy() end)
			end
		end
		st.ovMap = {}
		st.ovMeshCache = {}
	end
	local on = NAmanage.ovCfg()
	if not on then
		NAmanage.ovClr(st)
		return
	end
	if not st.Underground then
		if st.ovHL then
			local _, _, ftr, otr = NAmanage.ovCfg()
			st.ovHL.FillTransparency = ftr
			st.ovHL.OutlineTransparency = otr
		end
		return
	end
	local chr = getChar()
	local root = chr and getRoot(chr)
	if not root then
		return
	end
	local base = st.UndergroundCurrent or root.CFrame
	local off = st.UndergroundResolvedOffset or st.UndergroundOffset or Vector3.new()
	if off.Magnitude <= 0.0001 then
		NAmanage.ovClr(st)
		return
	end
	NAmanage.ovUpd(st, root, base, off)
end

if RunService and RunService.UnbindFromRenderStep then
	pcall(RunService.UnbindFromRenderStep, RunService, NAStuff.NA_UNDERGROUND_BIND_NAME)
end
do
	local st = NAStuff.NAundergroundState
	if st.heartbeatConnection then
		pcall(function() st.heartbeatConnection:Disconnect() end)
	end
	NAmanage.ovClr(st)
	NAmanage.ovPrg()
	st.ovPruned = true
	st.Underground = false
	st.UndergroundBind = false
	st.UndergroundCurrent = nil
	st.UndergroundTransform = nil
	st.UndergroundMirrorGround = nil
	st.UndergroundResolvedOffset = nil
	st.PendingTranslation = nil
	st.heartbeatConnection = nil
end

NAStuff.NA_UNDERGROUND_IDENTITY_CFRAME = NAStuff.NA_UNDERGROUND_IDENTITY_CFRAME or CFrame.new()
NAStuff.NA_UNDERGROUND_UPSIDEDOWN_CFRAME = NAStuff.NA_UNDERGROUND_UPSIDEDOWN_CFRAME
	or (CFrame.Angles(math.rad(180), 0, 0) * CFrame.Angles(0, math.rad(180), 0))
NAStuff.NA_UNDERGROUND_MIRROR_RAY_DISTANCE = NAStuff.NA_UNDERGROUND_MIRROR_RAY_DISTANCE or 2048
NAStuff.NA_UNDERGROUND_MIRROR_FALLBACK_OFFSET = NAStuff.NA_UNDERGROUND_MIRROR_FALLBACK_OFFSET or Vector3.new(0, -15, 0)

NAmanage.UG_hasOffset = function(vec)
	return typeof(vec) == "Vector3" and vec.Magnitude > 0.0001
end

NAmanage.UG_getTransform = function(state)
	local transform = state and state.UndergroundTransform
	if typeof(transform) == "CFrame" then
		return transform
	end
	return NAStuff.NA_UNDERGROUND_IDENTITY_CFRAME
end

NAmanage.UG_hasTransform = function(state)
	return NAmanage.UG_getTransform(state) ~= NAStuff.NA_UNDERGROUND_IDENTITY_CFRAME
end

NAmanage.UG_updateVisualizer = function(state, root, current)
	local offsetVec = (state and state.UndergroundResolvedOffset) or (state and state.UndergroundOffset) or Vector3.new()
	if state and root and current and NAmanage.UG_hasOffset(offsetVec) then
		NAmanage.ovUpd(state, root, current, offsetVec)
	else
		NAmanage.ovClr(state)
	end
end

NAmanage.UG_fetchCharPieces = function()
	local chr = getChar()
	if not chr then
		return nil, nil, nil
	end
	local hum = getHum()
	local root = getRoot(chr)
	if not root then
		for _, part in ipairs(chr:GetChildren()) do
			if part:IsA("BasePart") then
				root = part
				break
			end
		end
	end
	return chr, root, hum
end

NAmanage.UG_raycastDown = function(origin)
	local params = RaycastParams.new()
	params.FilterType = Enum.RaycastFilterType.Exclude
	local filter = {}
	local chr = getChar()
	if chr then
		Insert(filter, chr)
	end
	params.FilterDescendantsInstances = filter
	return workspace:Raycast(origin, Vector3.new(0, -NAStuff.NA_UNDERGROUND_MIRROR_RAY_DISTANCE, 0), params)
end

NAmanage.UG_getActiveOffset = function(state, root, hum)
	local extraOffset = (state and state.UndergroundOffset) or Vector3.new()
	if not (state and state.UndergroundMirrorGround and root) then
		return extraOffset
	end

	local rayOrigin = root.Position + Vector3.new(0, 4, 0)
	local hit = NAmanage.UG_raycastDown(rayOrigin)
	if hit and hit.Position then
		local mirroredRootY = (2 * hit.Position.Y) - root.Position.Y
		return Vector3.new(0, mirroredRootY - root.Position.Y, 0) + extraOffset
	end

	local hrpHalf = ((NAlib.isProperty(root, "Size") and root.Size.Y) or 2) * 0.5
	local feetFromRoot = hrpHalf + ((hum and hum.HipHeight) or 2)
	return Vector3.new(0, -(feetFromRoot * 2), 0) + extraOffset + NAStuff.NA_UNDERGROUND_MIRROR_FALLBACK_OFFSET
end

NAmanage.UG_disable = function(state, message)
	if type(state) ~= "table" then
		return
	end

	local function fetchRoot()
		local _, root = NAmanage.UG_fetchCharPieces()
		return root
	end

	for _ = 1, 10 do
		local root = fetchRoot()
		if root then
			root.CFrame = state.UndergroundCurrent or root.CFrame
		end
		Wait()
	end

	state.UndergroundCurrent = nil
	state.UndergroundTransform = nil
	state.UndergroundMirrorGround = nil
	state.UndergroundResolvedOffset = nil

	local hb = state.heartbeatConnection
	if hb then
		pcall(function()
			hb:Disconnect()
		end)
		state.heartbeatConnection = nil
	end

	state.UndergroundOffset = nil
	state.PendingTranslation = nil
	state.Underground = false
	NAmanage.ovClr(state)

	if state.UndergroundBind then
		state.UndergroundBind = false
		if RunService and RunService.UnbindFromRenderStep then
			pcall(RunService.UnbindFromRenderStep, RunService, NAStuff.NA_UNDERGROUND_BIND_NAME)
		end
	end

	if message and type(DoNotif) == "function" then
		DoNotif(message, 2)
	end
end

NAmanage.UG_enable = function(state, rootPart)
	if state.Underground then
		NAmanage.UG_updateVisualizer(state, rootPart, state.UndergroundCurrent or (rootPart and rootPart.CFrame))
		return
	end

	state.Underground = true
	state.UndergroundCurrent = rootPart.CFrame
	state.PendingTranslation = nil

	local prevHB = state.heartbeatConnection
	if prevHB then
		pcall(function() prevHB:Disconnect() end)
	end

	state.heartbeatConnection = RunService.Heartbeat:Connect(function()
		if not state.Underground then
			return
		end

		local _, currentRoot, hum = NAmanage.UG_fetchCharPieces()
		if not currentRoot then
			return
		end

		local baseCFrame = currentRoot.CFrame
		local pendingTranslation = state.PendingTranslation
		if typeof(pendingTranslation) == "Vector3" and pendingTranslation.Magnitude > 0 then
			baseCFrame += pendingTranslation
			state.PendingTranslation = nil
		end

		state.UndergroundCurrent = baseCFrame
		if hum then
			hum.Sit = false
		end

		local activeTransform = NAmanage.UG_getTransform(state)
		local activeOffset = NAmanage.UG_getActiveOffset(state, currentRoot, hum)
		state.UndergroundResolvedOffset = activeOffset
		currentRoot.CFrame = (baseCFrame * activeTransform) + activeOffset
	end)

	if RunService and RunService.UnbindFromRenderStep then
		pcall(RunService.UnbindFromRenderStep, RunService, NAStuff.NA_UNDERGROUND_BIND_NAME)
	end
	state.UndergroundBind = true
	__lt.cm("RunService", "BindToRenderStep", NAStuff.NA_UNDERGROUND_BIND_NAME, Enum.RenderPriority.First.Value, function()
		local current = state.UndergroundCurrent
		if state.Underground and current then
			local _, root = NAmanage.UG_fetchCharPieces()
			if root then
				root.CFrame = current
				NAmanage.UG_updateVisualizer(state, root, current)
			end
		end
	end)

	NAmanage.UG_updateVisualizer(state, rootPart, state.UndergroundCurrent or rootPart.CFrame)
end

cmd.add({"offset","offpos","off"},{"offset [x y z|y]","Offsets your character for others (positive Y = up, negative Y = down)"},function(...)
	local state = NAStuff.NAundergroundState

	local function UG_Get(key)
		return state[key]
	end
	local function UG_Set(key, val)
		state[key] = val
		return val
	end

	local character, rootPart, humanoid = NAmanage.UG_fetchCharPieces()
	if not (character and rootPart and humanoid) then
		if type(DoNotif) == "function" then
			DoNotif("Character is not ready yet", 2)
		end
		return
	end

	local defaultOffset = NAStuff.NA_UNDERGROUND_OFFSET or Vector3.new(0, -15, 0)
	local function parseOffsetVector(...)
		local raw = Concat({...}, " ")
		local nums = {}
		for token in tostring(raw):gmatch("[^,%s]+") do
			local n = tonumber(token)
			if n then
				Insert(nums, n)
			end
		end
		if #nums >= 3 then
			return Vector3.new(nums[1], nums[2], nums[3])
		elseif #nums == 2 then
			return Vector3.new(nums[1], nums[2], 0)
		elseif #nums == 1 then
			return Vector3.new(0, nums[1], 0)
		end
		return nil
	end
	local offsetVec = parseOffsetVector(...) or defaultOffset

	local Underground = UG_Get("Underground")
	if Underground then
		UG_Set("UndergroundOffset", offsetVec)
		state.UndergroundResolvedOffset = state.UndergroundMirrorGround and NAmanage.UG_getActiveOffset(state, rootPart, humanoid) or offsetVec
		NAmanage.UG_updateVisualizer(state, rootPart, UG_Get("UndergroundCurrent") or rootPart.CFrame)
		if type(DoNotif) == "function" then
			DoNotif("Offset updated", 2)
		end
		return
	end

	UG_Set("UndergroundOffset", offsetVec)
	state.UndergroundResolvedOffset = state.UndergroundMirrorGround and NAmanage.UG_getActiveOffset(state, rootPart, humanoid) or offsetVec
	UG_Set("PendingTranslation", nil)

	NAmanage.UG_enable(state, rootPart)

	if type(DoNotif) == "function" then
		DoNotif("Offset enabled (replicates for others)", 2)
	end
	return
end)

cmd.add({"upsidedown","flipchar"},{"upsidedown","Flips your character upside down for others using the offset replication method"},function()
	local state = NAStuff.NAundergroundState
	local character, rootPart, humanoid = NAmanage.UG_fetchCharPieces()
	if not (character and rootPart and humanoid) then
		if type(DoNotif) == "function" then
			DoNotif("Character is not ready yet", 2)
		end
		return
	end

	state.UndergroundTransform = NAStuff.NA_UNDERGROUND_UPSIDEDOWN_CFRAME
	state.UndergroundMirrorGround = true
	if not state.Underground then
		state.UndergroundOffset = state.UndergroundOffset or Vector3.new()
		state.PendingTranslation = nil
		NAmanage.UG_enable(state, rootPart)
		if type(DoNotif) == "function" then
			DoNotif("Upsidedown enabled (replicates for others)", 2)
		end
		return
	end

	state.UndergroundResolvedOffset = NAmanage.UG_getActiveOffset(state, rootPart, humanoid)
	NAmanage.UG_updateVisualizer(state, rootPart, state.UndergroundCurrent or rootPart.CFrame)
	if type(DoNotif) == "function" then
		DoNotif("Upsidedown updated", 2)
	end
end)

cmd.add({"unoffset","unoffpos","unoff"},{"unoffset","Disables offset and restores your character"},function()
	local state = NAStuff.NAundergroundState
	if type(state) ~= "table" then
		return
	end
	if state.Underground ~= true then
		if type(DoNotif) == "function" then
			DoNotif("Offset is already disabled", 2)
		end
		return
	end

	state.UndergroundOffset = nil
	if NAmanage.UG_hasTransform(state) then
		local _, root, hum = NAmanage.UG_fetchCharPieces()
		state.UndergroundResolvedOffset = NAmanage.UG_getActiveOffset(state, root, hum)
		NAmanage.UG_updateVisualizer(state, root, state.UndergroundCurrent or (root and root.CFrame))
		if type(DoNotif) == "function" then
			DoNotif("Offset disabled, upside down is still active", 2)
		end
		return
	end

	NAmanage.UG_disable(state, "Offset disabled, you're back to normal")
end)

cmd.add({"unupsidedown","unflipchar"},{"unupsidedown","Disables the upside down replication and restores your character"},function()
	local state = NAStuff.NAundergroundState
	if type(state) ~= "table" or state.Underground ~= true then
		if type(DoNotif) == "function" then
			DoNotif("Upsidedown is already disabled", 2)
		end
		return
	end

	state.UndergroundTransform = nil
	state.UndergroundMirrorGround = nil
	if NAmanage.UG_hasOffset(state.UndergroundOffset) then
		state.UndergroundResolvedOffset = state.UndergroundOffset
		local _, root = NAmanage.UG_fetchCharPieces()
		NAmanage.UG_updateVisualizer(state, root, state.UndergroundCurrent or (root and root.CFrame))
		if type(DoNotif) == "function" then
			DoNotif("Upsidedown disabled, offset is still active", 2)
		end
		return
	end

	NAmanage.UG_disable(state, "Upsidedown disabled, you're back to normal")
end)

clickscareUI = nil
clickscareEnabled = true

cmd.add({"clickscare","clickspook"},{"clickscare (clickspook)","Teleports next to a clicked player for a few seconds"},function()
	clickscareEnabled = true
	if clickscareUI then clickscareUI:Destroy() end
	NAlib.disconnect("clickscare_mouse")

	local Mouse = NAmanage.GetMouse(player)
	clickscareUI = InstanceNew("ScreenGui")
	NAgui.NaProtectUI(clickscareUI)

	local toggleButton = InstanceNew("TextButton")
	toggleButton.Size = UDim2.new(0,120,0,40)
	toggleButton.Text = "ClickScare: ON"
	toggleButton.Position = UDim2.new(0.5,-60,0,10)
	toggleButton.TextScaled = 16
	toggleButton.TextColor3 = Color3.new(1,1,1)
	toggleButton.Font = Enum.Font.GothamBold
	toggleButton.BackgroundColor3 = Color3.fromRGB(40,40,40)
	toggleButton.BackgroundTransparency = 0.2
	toggleButton.Parent = clickscareUI

	local uiCorner = InstanceNew("UICorner")
	uiCorner.CornerRadius = UDim.new(0,8)
	uiCorner.Parent = toggleButton

	NAgui.draggerV2(toggleButton)

	MouseButtonFix(toggleButton,function()
		clickscareEnabled = not clickscareEnabled
		toggleButton.Text = clickscareEnabled and "ClickScare: ON" or "ClickScare: OFF"
	end)

	local conn = Mouse.Button1Down:Connect(function()
		if not clickscareEnabled then return end
		local target = Mouse.Target
		if not (target and target.Parent and target.Parent:IsA("Model")) then return end
		local clickedPlayer = __lt.cm("Players", "GetPlayerFromCharacter", target.Parent)
		if not clickedPlayer or not getPlrHum(clickedPlayer) then return end

		local char = getChar()
		local root = getRoot(char)
		local oldCF = root.CFrame
		local distancepl = 2
		local targetRoot = getRoot(clickedPlayer.Character)
		if targetRoot then
			root.CFrame = targetRoot.CFrame + targetRoot.CFrame.LookVector * distancepl
			root.CFrame = CFrame.new(root.Position, targetRoot.Position)
			Wait(0.5)
			root.CFrame = oldCF
		end
	end)

	NAlib.connect("clickscare_mouse",conn)
end)

