	return box, valueLabel, bar
end

NAmanage._fpsTracker = NAmanage._fpsTracker or nil

NAmanage.getRealFPS = NAmanage.getRealFPS or function()
	local tracker = NAmanage._fpsTracker
	if not tracker then
		tracker = {
			times = {},
			head = 1,
			tail = 0,
			value = 0,
			conn = nil,
		}
		tracker.conn = RunService.RenderStepped:Connect(function()
			local now = os.clock()
			tracker.tail += 1
			tracker.times[tracker.tail] = now
			local cutoff = now - 1
			while tracker.head <= tracker.tail and tracker.times[tracker.head] < cutoff do
				tracker.times[tracker.head] = nil
				tracker.head += 1
			end
			local frameCount = tracker.tail - tracker.head + 1
			if frameCount <= 1 then
				tracker.value = frameCount
			else
				local firstTime = tracker.times[tracker.head]
				local span = now - (tonumber(firstTime) or now)
				if span > 0 then
					tracker.value = (frameCount - 1) / span
				else
					tracker.value = frameCount
				end
			end
			if tracker.head > 2048 then
				local compact = {}
				local n = 0
				for i = tracker.head, tracker.tail do
					n += 1
					compact[n] = tracker.times[i]
				end
				tracker.times = compact
				tracker.head = 1
				tracker.tail = n
			end
		end)
		NAmanage._fpsTracker = tracker
	end
	return math.max(0, math.floor((tonumber(tracker.value) or 0) + 0.5))
end

cmd.add({ "ping" }, { "ping", "Shows your network latency" }, function()
	local T = NAstatsUI.Theme
	NAstatsUI.createStatCommand({
		key = "Ping",
		title = "Ping",
		subtitle = "Network latency",
		position = UDim2.new(0.5, 0, 0.22, 0),
		updateFn = function()
			local rawPing = tonumber(NAmanage.GetDataPingMs and NAmanage.GetDataPingMs()) or 0
			return tostring(rawPing).." ms", rawPing
		end,
		colorFn = function(ping)
			if ping <= 50 then
				return T.Colors.Good
			end
			if ping <= 100 then
				return T.Colors.Warn
			end
			return T.Colors.Bad
		end,
	})
end)

cmd.add({ "fps" }, { "fps", "Shows your frames per second" }, function()
	local T = NAstatsUI.Theme

	NAstatsUI.createStatCommand({
		key = "FPS",
		title = "FPS",
		subtitle = "Frames per second",
		position = UDim2.new(0.5, 0, 0.36, 0),
		updateFn = function()
			local fps = NAmanage.getRealFPS()
			return tostring(fps), fps
		end,
		colorFn = function(fps)
			if fps >= 55 then
				return T.Colors.Good
			end
			if fps >= 30 then
				return T.Colors.Warn
			end
			return T.Colors.Bad
		end,
	})
end)

cmd.add({ "stats" }, { "stats", "Shows both FPS and ping" }, function()
	local existing = windowRegistry["Stats"]
	if existing and existing.screenGui and existing.screenGui.Parent then
		NAlib.disconnect("UI:Stats")
		existing.screenGui:Destroy()
		windowRegistry["Stats"] = nil
	end

	local T = NAstatsUI.Theme
	local height = IsOnMobile and 180 or 150
	local width = IsOnMobile and 300 or 270
	local ui = NAstatsUI.createWindow(UDim2.new(0.5, 0, 0.32, 0), UDim2.new(0, width, 0, height), "Stats")

	windowRegistry["Stats"] = ui

	local grid = NAstatsUI.createInstance("Frame", {
		BackgroundTransparency = 1,
		Size = UDim2.new(1, 0, 1, 0),
		Parent = ui.content
	})

	local layout = NAstatsUI.createInstance("UIListLayout", {
		FillDirection = IsOnMobile and Enum.FillDirection.Vertical or Enum.FillDirection.Horizontal,
		HorizontalAlignment = Enum.HorizontalAlignment.Center,
		VerticalAlignment = Enum.VerticalAlignment.Top,
		SortOrder = Enum.SortOrder.LayoutOrder,
		Padding = UDim.new(0, IsOnMobile and 8 or 10),
		Parent = grid,
	})

	local pingBox, pingValue, pingBar = NAstatsUI.createStatBox(grid, "Ping")
	local fpsBox, fpsValue, fpsBar = NAstatsUI.createStatBox(grid, "FPS")

	pingBox.LayoutOrder = 1
	fpsBox.LayoutOrder = 2

	local lastUpdate = 0
	local updateInterval = 0.5

	local pingColorFn = function(p)
		if p <= 50 then
			return T.Colors.Good
		end
		if p <= 100 then
			return T.Colors.Warn
		end
		return T.Colors.Bad
	end

	local fpsColorFn = function(f)
		if f >= 55 then
			return T.Colors.Good
		end
		if f >= 30 then
			return T.Colors.Warn
		end
		return T.Colors.Bad
	end

	local conn = RunService.RenderStepped:Connect(function()
		local t = os.clock()
		if t - lastUpdate < updateInterval then
			return
		end

		local fps = NAmanage.getRealFPS()

		local p = tonumber(NAmanage.GetDataPingMs and NAmanage.GetDataPingMs()) or 0

		pingValue.Text = "<b>"..tostring(p).." ms</b>"
		pingValue.TextColor3 = pingColorFn(p)
		fpsValue.Text = "<b>"..tostring(fps).."</b>"
		fpsValue.TextColor3 = fpsColorFn(fps)

		local pingRatio = math.clamp(p == 0 and 0 or 1 - (p / 300), 0, 1)
		local fpsRatio = math.clamp(fps / 120, 0, 1)

		pingBar.Size = UDim2.new(pingRatio, 0, 1, 0)
		pingBar.BackgroundColor3 = pingColorFn(p)
		fpsBar.Size = UDim2.new(fpsRatio, 0, 1, 0)
		fpsBar.BackgroundColor3 = fpsColorFn(fps)

		local collapsedTitle = Format(
			"Stats: <font color='%s'>%d ms</font> | <font color='%s'>%d FPS</font>",
			NAstatsUI.colorToHex(pingColorFn(p)),
			p,
			NAstatsUI.colorToHex(fpsColorFn(fps)),
			fps
		)
		ui.setCollapsedTitle(collapsedTitle)
		lastUpdate = t
	end)
	NAlib.connect("UI:Stats", conn)

	MouseButtonFix(ui.closeButton, function()
		NAlib.disconnect("UI:Stats")
		if windowRegistry["Stats"] == ui then
			windowRegistry["Stats"] = nil
		end
		ui.screenGui:Destroy()
	end)
end)

NAmanage.CloseSpeedometerUI = NAmanage.CloseSpeedometerUI or function()
	local existing = windowRegistry["Speedometer"]
	NAlib.disconnect("UI:Speedometer")
	if existing and existing.screenGui then
		existing.screenGui:Destroy()
	end
	windowRegistry["Speedometer"] = nil
end

cmd.add({"speedometer", "sps", "speedo"}, {"speedometer (sps,speedo)", "Toggles a NA-themed speedometer"}, function()
	local existing = windowRegistry["Speedometer"]
	if existing and existing.screenGui and existing.screenGui.Parent then
		NAmanage.CloseSpeedometerUI()
		return
	end

	local T = NAstatsUI.Theme
	local ui = NAstatsUI.createWindow(UDim2.new(0.5, 0, 0.82, 0), UDim2.new(0, IsOnMobile and 230 or 210, 0, IsOnMobile and 120 or 110), "Speedometer")
	windowRegistry["Speedometer"] = ui

	local statDisplay = NAstatsUI.createStatDisplay(ui.content, "Speed", "Studs / sec")
	local lastUpdate = 0
	local updateInterval = 0.08

	local function speedColor(speed)
		if speed >= 100 then
			return T.Colors.Bad
		end
		if speed >= 50 then
			return T.Colors.Warn
		end
		return T.Colors.Accent
	end

	local conn = RunService.RenderStepped:Connect(function()
		local now = os.clock()
		if now - lastUpdate < updateInterval then
			return
		end
		lastUpdate = now

		local char = getChar()
		local root = char and getRoot(char)
		local velocity = root and (root.AssemblyLinearVelocity or root.Velocity)
		local speed = velocity and Vector3.new(velocity.X, 0, velocity.Z).Magnitude or 0
		local text = Format("%.2f", speed)
		local color = speedColor(speed)

		statDisplay.value.Text = "<b>"..text.."</b>"
		statDisplay.value.TextColor3 = color
		ui.setCollapsedTitle(Format("Speed: <font color='%s'>%s</font>", NAstatsUI.colorToHex(color), text))
	end)
	NAlib.connect("UI:Speedometer", conn)

	MouseButtonFix(ui.closeButton, function()
		NAmanage.CloseSpeedometerUI()
	end)
end)

