	if NAStuff.auraConn then NAStuff.auraConn:Disconnect() NAStuff.auraConn=nil end
	if NAStuff.auraViz then NAStuff.auraViz:Destroy() NAStuff.auraViz=nil end
	DebugNotif("Aura disabled",1.2)
end,true)

