cmd.add({"cartornado", "ctornado"}, {"cartornado (ctornado)", "Tornados a car just sit in the car"}, function()
	NAStuff = NAStuff or {}
	local CONN_KEY = "cartornado"
	local ACTIVE_KEY = "cartornado_active"
	NAlib.disconnect(CONN_KEY)
	NAlib.disconnect(ACTIVE_KEY)
	if NAStuff._cartornadoPart then
		pcall(function() NAStuff._cartornadoPart:Destroy() end)
		NAStuff._cartornadoPart = nil
	end
	if NAStuff._cartornadoHelper then
		pcall(function() NAStuff._cartornadoHelper:Destroy() end)
		NAStuff._cartornadoHelper = nil
	end

	local Player = Players.LocalPlayer

	repeat RunService.RenderStepped:Wait() until Player.Character
	local Character = Player.Character

	local SPart = InstanceNew("Part")
	SPart.Anchored = true
	SPart.CanCollide = true
	SPart.Size = Vector3.new(1, 100, 1)
	SPart.Transparency = 0.4
	SPart.Parent = workspace
	NAStuff._cartornadoPart = SPart
	NAlib.connect(CONN_KEY, SPart.AncestryChanged:Connect(function(_, parent)
		if not parent then
			NAStuff._cartornadoPart = nil
			Defer(function()
				NAlib.disconnect(CONN_KEY)
			end)
		end
	end))

	NAlib.connect(CONN_KEY, RunService.PreSimulation:Connect(function()
		if not SPart or not SPart.Parent then return end
		local hum = Character and getHum()
		if hum and Character.PrimaryPart then
			local rayOrigin = Character.PrimaryPart.Position + Character.PrimaryPart.CFrame.LookVector * 6
			local rayDir = Vector3.new(0, -4, 0)
			local ray = Ray.new(rayOrigin, rayDir)
			local part = workspace:FindPartOnRayWithIgnoreList(ray, {Character})
			if part then
				SPart.CFrame = Character.PrimaryPart.CFrame + Character.PrimaryPart.CFrame.LookVector * 6
			end
		end
	end))

	NAlib.connect(CONN_KEY, SPart.Touched:Connect(function(hit)
		if not hit:IsA("Seat") then return end
		NAlib.disconnect(CONN_KEY)
		NAStuff._cartornadoPart = nil

		local torso = getTorso(Character)
		if not torso then
			SPart:Destroy()
			return
		end

		local hum = getHum()
		if not hum then
			SPart:Destroy()
			return
		end

		local motionBase = Character.PrimaryPart or torso
		if not motionBase then
			SPart:Destroy()
			return
		end

		local helperPart = InstanceNew("Part")
		helperPart.Anchored = false
		helperPart.CanCollide = false
		helperPart.Transparency = 1
		helperPart.Size = Vector3.new(1, 1, 1)
		helperPart.CFrame = motionBase.CFrame
		helperPart.Parent = workspace
		NAStuff._cartornadoHelper = helperPart

		local helperWeld = InstanceNew("WeldConstraint")
		helperWeld.Part0 = helperPart
		helperWeld.Part1 = motionBase
		helperWeld.Parent = helperPart

		local isFlying = true
		local function cleanupHelperPart()
			isFlying = false
			if helperPart then
				helperPart:Destroy()
				helperPart = nil
			end
			if NAStuff._cartornadoHelper then
				NAStuff._cartornadoHelper = nil
			end
			NAlib.disconnect(ACTIVE_KEY)
		end

		local flyv = InstanceNew("BodyVelocity")
		local flyg = InstanceNew("BodyGyro")
		local speed = 50
		local lastSpeed = speed
		local maxSpeed = 100
		local isRunning = false
		local f = 0

		flyv.Parent = helperPart
		flyv.MaxForce = Vector3.new(math.huge, math.huge, math.huge)

		flyg.Parent = helperPart
		flyg.MaxTorque = Vector3.new(9e9, 9e9, 9e9)
		flyg.P = 1000
		flyg.D = 50

		hum.PlatformStand = true

		NAlib.connect(ACTIVE_KEY, hum.Changed:Connect(function()
			isRunning = hum.MoveDirection.Magnitude > 0
		end))
		NAlib.connect(ACTIVE_KEY, hum.Died:Connect(cleanupHelperPart))
		NAlib.connect(ACTIVE_KEY, Character.AncestryChanged:Connect(function(_, parent)
			if not parent then
				cleanupHelperPart()
			end
		end))
		NAlib.connect(ACTIVE_KEY, helperPart.AncestryChanged:Connect(function(_, parent)
			if not parent then
				isFlying = false
				if NAStuff._cartornadoHelper then
					NAStuff._cartornadoHelper = nil
				end
				Defer(function()
					NAlib.disconnect(ACTIVE_KEY)
				end)
			end
		end))

		SpawnCall(function()
			while isFlying do
				flyg.CFrame = workspace.CurrentCamera.CFrame * CFrame.Angles(-math.rad(f * 50 * speed / maxSpeed), 0, 0)
				flyv.Velocity = workspace.CurrentCamera.CFrame.LookVector * speed
				Wait(0.1)

				if speed < 0 then
					speed = 0
					f = 0
				end

				if isRunning then
					speed = lastSpeed
				else
					if speed ~= 0 then
						lastSpeed = speed
					end
					speed = 0
				end
			end
		end)

		Wait(0.3)
		hit:Sit(hum)
		SPart:Destroy()

		local seat = hum.SeatPart
		if not seat then
			cleanupHelperPart()
			return
		end

		local vehicleModel = seat.Parent
		while vehicleModel and not vehicleModel:IsA("Model") do
			vehicleModel = vehicleModel.Parent
		end

		if vehicleModel then
			for _, v in pairs(NAmanage.qDesc(vehicleModel, "BasePart")) do
				if v.CanCollide then
					v.CanCollide = false
				end
			end
		end

		Wait(0.2)
		speed = 80

		local spin = InstanceNew("BodyAngularVelocity")
		spin.MaxTorque = Vector3.new(0, math.huge, 0)
		spin.AngularVelocity = Vector3.new(0, 2000, 0)
		spin.Parent = helperPart
	end))
end)

