cmd.add({"oldroblox"},{"oldroblox","Old skybox and studs"},function()
	if NAmanage.GetAttr(Lighting, "NAOldRbx_Enabled") then return end
	NAmanage.SetAttr(Lighting, "NAOldRbx_Enabled", true)

	local studTex = NAmanage.getNAImageAsset("Stud", "rbxassetid://48715260")
	local inletTex = NAmanage.getNAImageAsset("Inlet", "rbxassetid://20299774")
	local skyA = {
		bk = NAmanage.getNAImageAsset("bk", "rbxassetid://161781263"),
		dn = NAmanage.getNAImageAsset("dn", "rbxassetid://161781258"),
		ft = NAmanage.getNAImageAsset("ft", "rbxassetid://161781261"),
		lf = NAmanage.getNAImageAsset("lf", "rbxassetid://161781267"),
		rt = NAmanage.getNAImageAsset("rt", "rbxassetid://161781268"),
		up = NAmanage.getNAImageAsset("up", "rbxassetid://161781260"),
	}

	local function ensureSky()
		local s = __lt.cm("Lighting", "FindFirstChild", "NAOldRobloxSky")
		if s then return s end
		local sky = InstanceNew("Sky")
		sky.Name = "NAOldRobloxSky"
		sky.SkyboxBk = skyA.bk
		sky.SkyboxDn = skyA.dn
		sky.SkyboxFt = skyA.ft
		sky.SkyboxLf = skyA.lf
		sky.SkyboxRt = skyA.rt
		sky.SkyboxUp = skyA.up
		sky.Parent = Lighting
		return sky
	end

	local function applyToPart(v)
		if not v or not v.Parent or not v:IsA("BasePart") then return end
		if NAmanage.GetAttr(v, "NAOldRbx_Applied") then return end
		NAmanage.SetAttr(v, "NAOldRbx_Applied", true)
		if NAmanage.GetAttr(v, "NAOldRbx_OrigMatName") == nil then
			local ok, name = pcall(function() return v.Material.Name end)
			if ok then NAmanage.SetAttr(v, "NAOldRbx_OrigMatName", name) end
		end

		local stud = v:FindFirstChild("NAOldRobloxStud")
		if not stud then
			stud = InstanceNew("Texture")
			stud.Name = "NAOldRobloxStud"
			stud.Parent = v
		end
		stud.Texture = studTex
		stud.Face = Enum.NormalId.Top
		stud.StudsPerTileU = 1
		stud.StudsPerTileV = 1
		stud.Transparency = v.Transparency

		local inlet = v:FindFirstChild("NAOldRobloxInlet")
		if not inlet then
			inlet = InstanceNew("Texture")
			inlet.Name = "NAOldRobloxInlet"
			inlet.Parent = v
		end
		inlet.Texture = inletTex
		inlet.Face = Enum.NormalId.Bottom
		inlet.StudsPerTileU = 1
		inlet.StudsPerTileV = 1
		inlet.Transparency = v.Transparency

		v.Material = Enum.Material.Plastic
	end

	NAmanage.SetAttr(Lighting, "NAOldRbx_PrevClockTime", Lighting.ClockTime)
	NAmanage.SetAttr(Lighting, "NAOldRbx_PrevGlobalShadows", Lighting.GlobalShadows)
	local ok,outlines = pcall(function() return Lighting.Outlines end)
	if ok then NAmanage.SetAttr(Lighting, "NAOldRbx_HadOutlines", true) NAmanage.SetAttr(Lighting, "NAOldRbx_PrevOutlines", outlines) end

	local stash = workspace:FindFirstChild("NAOldRbx_SkyStash") or InstanceNew("Folder")
	stash.Name = "NAOldRbx_SkyStash"
	stash.Parent = workspace
	for _,v in ipairs(__lt.cm("Lighting", "GetChildren")) do
		if v:IsA("Sky") then
			local c = v:Clone()
			c.Parent = stash
			v:Destroy()
		end
	end

	Lighting.ClockTime = 12
	pcall(function() Lighting.GlobalShadows = false end)
	pcall(function() Lighting.Outlines = false end)
	ensureSky()

	local RS = SafeGetService("RunService")

	local q = {head = 1, tail = 0, data = {}}
	local function qpush(x) q.tail += 1; q.data[q.tail] = x end
	local function qpop() local i = q.head; if i > q.tail then return nil end; local x = q.data[i]; q.data[i] = nil; q.head = i + 1; return x end
	for _,child in ipairs(workspace:GetChildren()) do qpush(child) end

	NAlib.disconnect("oldrbx_tick")
	NAlib.connect("oldrbx_tick", RS.Heartbeat:Connect(function()
		if not NAmanage.GetAttr(Lighting, "NAOldRbx_Enabled") then return end
		local budgetNodes = 200
		local i = 0
		while i < budgetNodes do
			local node = qpop()
			if not node then break end
			if node.Parent then
				if node:IsA("BasePart") then
					applyToPart(node)
					i += 1
				end
				for _,c in ipairs(node:GetChildren()) do
					qpush(c)
				end
			end
		end
	end))

	NAlib.disconnect("oldrbx_desc")
	NAlib.connect("oldrbx_desc", NAmanage.wsAdd(function(obj)
		if not NAmanage.GetAttr(Lighting, "NAOldRbx_Enabled") then return end
		if obj:IsA("BasePart") then
			qpush(obj)
		end
	end))

	NAlib.disconnect("oldrbx_skywatch")
	NAlib.connect("oldrbx_skywatch", NAmanage.childAdd(Lighting, function(obj)
		if not NAmanage.GetAttr(Lighting, "NAOldRbx_Enabled") then return end
		if obj:IsA("Sky") and obj.Name ~= "NAOldRobloxSky" then
			local c = obj:Clone()
			c.Parent = stash
			obj:Destroy()
			ensureSky()
		end
	end, function(obj)
		return obj and obj:IsA("Sky")
	end))

	NAlib.disconnect("oldrbx_skyguard")
	NAlib.connect("oldrbx_skyguard", NAmanage.childRem(Lighting, function(obj)
		if not NAmanage.GetAttr(Lighting, "NAOldRbx_Enabled") then return end
		if obj:IsA("Sky") and not __lt.cm("Lighting", "FindFirstChild", "NAOldRobloxSky") then
			ensureSky()
		end
	end, function(obj)
		return obj and obj:IsA("Sky")
	end))
end)

cmd.add({"unoldroblox"},{"unoldroblox","Restore skybox and studs"},function()
	if not NAmanage.GetAttr(Lighting, "NAOldRbx_Enabled") then return end

	NAlib.disconnect("oldrbx_desc")
	NAlib.disconnect("oldrbx_skywatch")
	NAlib.disconnect("oldrbx_skyguard")
	NAlib.disconnect("oldrbx_tick")

	local RS = SafeGetService("RunService")

	local rq = {head = 1, tail = 0, data = {}}
	local function rpush(x) rq.tail += 1; rq.data[rq.tail] = x end
	local function rpop() local i = rq.head; if i > rq.tail then return nil end; local x = rq.data[i]; rq.data[i] = nil; rq.head = i + 1; return x end
	for _,child in ipairs(workspace:GetChildren()) do rpush(child) end

	NAlib.disconnect("oldrbx_untick")
	NAlib.connect("oldrbx_untick", RS.Heartbeat:Connect(function()
		local budgetNodes = 200
		local i = 0
		while i < budgetNodes do
			local node = rpop()
			if not node then break end
			if node.Parent then
				if node:IsA("BasePart") and NAmanage.GetAttr(node, "NAOldRbx_Applied") then
					local a = node:FindFirstChild("NAOldRobloxStud"); if a then a:Destroy() end
					local b = node:FindFirstChild("NAOldRobloxInlet"); if b then b:Destroy() end
					local matName = NAmanage.GetAttr(node, "NAOldRbx_OrigMatName")
					if typeof(matName) == "string" then
						local mat = Enum.Material[matName]
						if mat then pcall(function() node.Material = mat end) end
					end
					NAmanage.SetAttr(node, "NAOldRbx_Applied", nil)
					NAmanage.SetAttr(node, "NAOldRbx_OrigMatName", nil)
					i += 1
				end
				for _,c in ipairs(node:GetChildren()) do
					rpush(c)
				end
			end
		end

		if rq.head > rq.tail then
			NAlib.disconnect("oldrbx_untick")

			for _,v in ipairs(__lt.cm("Lighting", "GetChildren")) do
				if v:IsA("Sky") and v.Name == "NAOldRobloxSky" then
					v:Destroy()
				end
			end
			local stash = workspace:FindFirstChild("NAOldRbx_SkyStash")
			if stash then
				for _,c in ipairs(stash:GetChildren()) do
					if c:IsA("Sky") then
						c.Parent = Lighting
					end
				end
				stash:Destroy()
			end

			local prevClock = NAmanage.GetAttr(Lighting, "NAOldRbx_PrevClockTime")
			local prevShadows = NAmanage.GetAttr(Lighting, "NAOldRbx_PrevGlobalShadows")
			if typeof(prevClock) == "number" then pcall(function() Lighting.ClockTime = prevClock end) end
			if typeof(prevShadows) == "boolean" then pcall(function() Lighting.GlobalShadows = prevShadows end) end
			if NAmanage.GetAttr(Lighting, "NAOldRbx_HadOutlines") then
				local prevOut = NAmanage.GetAttr(Lighting, "NAOldRbx_PrevOutlines")
				pcall(function() Lighting.Outlines = prevOut end)
			end

			NAmanage.SetAttr(Lighting, "NAOldRbx_Enabled", nil)
			NAmanage.SetAttr(Lighting, "NAOldRbx_PrevClockTime", nil)
			NAmanage.SetAttr(Lighting, "NAOldRbx_PrevGlobalShadows", nil)
			NAmanage.SetAttr(Lighting, "NAOldRbx_HadOutlines", nil)
			NAmanage.SetAttr(Lighting, "NAOldRbx_PrevOutlines", nil)
		end
	end))
end)

