originalIO.setWorkspaceLocked=function(flag)
	local root = workspace
	if not root then
		return
	end

	Spawn(function()
		local q = { root }
		local qi, qn = 1, 1
		local step = 256
		local n = 0

		while qi <= qn do
			local inst = q[qi]
			qi += 1

			if NAlib.isProperty(inst, "Locked") ~= nil then
				NAlib.setProperty(inst, "Locked", flag)
			end

			local ch = inst:GetChildren()
			for i = 1, #ch do
				qn += 1
				q[qn] = ch[i]
			end

			n += 1
			if n >= step then
				n = 0
				Wait()
			end
		end
	end)
end

