	if not FakeLag and not NAlib.isConnected("FakeLag") then return end
	FakeLag = false
	NAlib.disconnect("FakeLag")
	local r = getRoot(getChar())
	if r then NAlib.setProperty(r, "Anchored", false) end
end)

