NAmanage.toolCache = NAmanage.ensureWeakKeyTable(NAmanage.toolCache or {})
NAmanage.toolGrabCol = NAmanage.ensureWeakKeyTable(NAmanage.toolGrabCol or {})
NAmanage.grabBusy = NAmanage.ensureWeakKeyTable(NAmanage.grabBusy or {})
NAmanage.toolCacheReady = NAmanage.toolCacheReady or false

NAmanage.isOwnPackTool = NAmanage.isOwnPackTool or function(tool)
	if typeof(tool) ~= "Instance" or not tool:IsA("Tool") then
		return false
	end

	local char = getChar()
	local bp = getBp()
	return (char and tool:IsDescendantOf(char)) or (bp and tool:IsDescendantOf(bp))
end

NAmanage.isCharTool = NAmanage.isCharTool or function(tool)
	if typeof(tool) ~= "Instance" or not tool:IsA("Tool") then
		return false
	end

	if NAmanage.isOwnPackTool(tool) then
		return false
	end

	local inst = tool.Parent
	while inst and inst ~= workspace do
		if inst:IsA("Model") then
			local okPlr, plr = pcall(function()
				return Players:GetPlayerFromCharacter(inst)
			end)
			if okPlr and plr then
				return true
			end
			if inst:FindFirstChildOfClass("Humanoid") then
				return true
			end
		end
		inst = inst.Parent
	end

	return false
end

NAmanage.isDroppedTool = NAmanage.isDroppedTool or function(tool)
	if typeof(tool) ~= "Instance" or not tool:IsA("Tool") then
		return false
	end
	if not tool:IsDescendantOf(workspace) then
		return false
	end
	if NAmanage.isOwnPackTool(tool) then
		return false
	end
	if NAmanage.isCharTool(tool) then
		return false
	end
	return true
end

NAmanage.toolPart = NAmanage.toolPart or function(tool)
	if typeof(tool) ~= "Instance" then
		return nil
	end

	local handle = tool:FindFirstChild("Handle")
	if handle and handle:IsA("BasePart") then
		return handle
	end

	for _, d in ipairs(tool:GetDescendants()) do
		if d:IsA("BasePart") then
			return d
		end
	end

	return nil
end

NAmanage.toolParts=function(tool)
	local parts = {}
	if typeof(tool) ~= "Instance" then
		return parts
	end

	local handle = tool:FindFirstChild("Handle")
	if handle and handle:IsA("BasePart") then
		parts[#parts + 1] = handle
	end

	for _, d in ipairs(tool:GetDescendants()) do
		if d:IsA("BasePart") and d ~= handle then
			parts[#parts + 1] = d
		end
	end

	return parts
end

NAmanage.toolPrompts = NAmanage.toolPrompts or function(tool)
	local prompts = {}
	if typeof(tool) ~= "Instance" then
		return prompts
	end

	for _, inst in ipairs(tool:GetDescendants()) do
		if inst:IsA("ProximityPrompt") and inst.Parent then
			prompts[#prompts + 1] = inst
		end
	end

	return prompts
end

NAmanage.toolHasPrompt = NAmanage.toolHasPrompt or function(tool)
	return #NAmanage.toolPrompts(tool) > 0
end

NAmanage.fireToolPrompts = NAmanage.fireToolPrompts or function(tool, waitTime, attempts)
	if typeof(tool) ~= "Instance" or typeof(fireproximityprompt) ~= "function" then
		return false, false
	end

	local prompts = NAmanage.toolPrompts(tool)
	if #prompts == 0 then
		return false, false
	end

	local fired = false
	local tries = math.max(1, tonumber(attempts) or 1)
	for attempt = 1, tries do
		for _, inst in ipairs(prompts) do
			if inst and inst.Parent then
				fired = true
				local holdDuration = inst.HoldDuration
				local maxDistance = inst.MaxActivationDistance

				NACaller(function()
					if holdDuration > 0 then
						inst.HoldDuration = 0
					end
					if maxDistance < 32 then
						inst.MaxActivationDistance = 32
					end
				end)

				pcall(fireproximityprompt, inst)

				NACaller(function()
					if inst and inst.Parent then
						if inst.HoldDuration ~= holdDuration then
							inst.HoldDuration = holdDuration
						end
						if inst.MaxActivationDistance ~= maxDistance then
							inst.MaxActivationDistance = maxDistance
						end
					end
				end)
			end
		end

		if NAmanage.isOwnPackTool(tool) then
			break
		end

		local settleBetween = tonumber(waitTime)
		if settleBetween and settleBetween > 0 and attempt < tries then
			Wait(settleBetween)
		end
	end

	local settle = tonumber(waitTime)
	if settle and settle > 0 then
		Wait(settle)
	end

	return fired, NAmanage.isOwnPackTool(tool)
end

NAmanage.fireToolPromptsFromCharacter = NAmanage.fireToolPromptsFromCharacter or function(tool)
	if typeof(tool) ~= "Instance" or typeof(fireproximityprompt) ~= "function" then
		return false, false
	end

	local prompts = NAmanage.toolPrompts(tool)
	if #prompts == 0 then
		return false, false
	end

	local char = getChar()
	local root = char and getRoot(char)
	if not (char and root) then
		return false, false
	end

	local oldCF = root.CFrame
	local moved = false
	local firedAny = false

	for _, pp in ipairs(prompts) do
		if pp and pp.Parent then
			local part = (NAindex and NAindex.getPromptPart and NAindex.getPromptPart(pp)) or nil
			if part and part.Parent then
				local offset = math.max(3, math.min(6, (pp.MaxActivationDistance or 0) * 0.6))
				local targetPos = part.Position + Vector3.new(0, 0, offset)
				local targetCF = CFrame.new(targetPos, part.Position)
				NAmanage.safePivotModel(char, targetCF)
				moved = true
				Wait(0.2)

				local fired = false
				fired, _ = NAmanage.fireToolPrompts(tool, 0.12, 3)
				firedAny = firedAny or fired
				if NAmanage.isOwnPackTool(tool) then
					break
				end
			end
		end
	end

	if moved and char and char.Parent and root and root.Parent then
		NAmanage.safePivotModel(char, oldCF)
	end

	return firedAny, NAmanage.isOwnPackTool(tool)
end

NAmanage.touchEquipTool = NAmanage.touchEquipTool or function(tool, root, hum, settleTime)
	if not (tool and root) then
		return false
	end

	NAmanage.touchTool(tool, root)
	local settle = tonumber(settleTime) or 0.05
	if settle > 0 then
		Wait(settle)
	end

	if NAmanage.isOwnPackTool(tool) then
		return true
	end

	if hum then
		NACaller(function()
			hum:EquipTool(tool)
		end)
		if settle > 0 then
			Wait(settle)
		end
	end

	return NAmanage.isOwnPackTool(tool)
end

NAmanage.addToolCache=function(tool)
	if typeof(tool) == "Instance" and tool:IsA("Tool") then
		NAmanage.toolCache[tool] = true
	end
end

NAmanage.scanToolBranch=function(inst)
	if typeof(inst) ~= "Instance" then
		return
	end

	if inst:IsA("Tool") then
		NAmanage.addToolCache(inst)
		return
	end

	if inst:IsA("Folder") or inst:IsA("Model") then
		for _, d in ipairs(inst:GetDescendants()) do
			if d:IsA("Tool") then
				NAmanage.addToolCache(d)
			end
		end
	end
end

NAmanage.dropToolCache=function(tool)
	if typeof(tool) == "Instance" and tool:IsA("Tool") then
		NAmanage.toolCache[tool] = nil
		NAmanage.grabBusy[tool] = nil
		NAmanage.restoreToolCollision(tool)
	end
end

NAmanage.initToolCache=function()
	if NAmanage.toolCacheStarted then
		return
	end

	NAmanage.toolCacheStarted = true
	NAmanage.toolCache = NAmanage.ensureWeakKeyTable(NAmanage.toolCache)
	NAmanage.grabBusy = NAmanage.ensureWeakKeyTable(NAmanage.grabBusy)
	NAmanage.toolGrabCol = NAmanage.ensureWeakKeyTable(NAmanage.toolGrabCol)

	for _, ch in ipairs(workspace:GetChildren()) do
		NAmanage.scanToolBranch(ch)
	end

	NAlib.connect("grabtools_cache_add", workspace.DescendantAdded:Connect(function(inst)
		NAmanage.scanToolBranch(inst)
		if inst:IsA("Folder") or inst:IsA("Model") then
			Defer(function()
				if inst and inst.Parent then
					NAmanage.scanToolBranch(inst)
				end
			end)
		end
	end))

	NAlib.connect("grabtools_cache_rem", workspace.DescendantRemoving:Connect(function(inst)
		if inst:IsA("Tool") then
			NAmanage.dropToolCache(inst)
		end
	end))

	Spawn(function()
		local scanned = 0
		for _, inst in ipairs(workspace:GetDescendants()) do
			if inst:IsA("Tool") then
				NAmanage.addToolCache(inst)
			end
			scanned += 1
			if scanned % 2500 == 0 then
				Wait()
			end
		end
		NAmanage.toolCacheReady = true
	end)
end

NAmanage.toolList=function()
	NAmanage.initToolCache()

	local list = {}
	local seen = {}
	for tool in pairs(NAmanage.toolCache) do
		if NAmanage.isDroppedTool(tool) then
			if not seen[tool] then
				seen[tool] = true
				list[#list + 1] = tool
			end
		else
			NAmanage.toolCache[tool] = nil
			NAmanage.grabBusy[tool] = nil
			NAmanage.restoreToolCollision(tool)
		end
	end

	if #list > 0 or NAmanage.toolCacheReady then
		return list
	end

	if type(NAmanage.fastDesc) == "function" then
		for _, tool in ipairs(NAmanage.fastDesc(workspace, "Tool")) do
			NAmanage.addToolCache(tool)
			if NAmanage.isDroppedTool(tool) and not seen[tool] then
				seen[tool] = true
				list[#list + 1] = tool
			end
		end
		if #list > 0 then
			return list
		end
	end

	for _, ch in ipairs(workspace:GetChildren()) do
		NAmanage.scanToolBranch(ch)
	end

	for tool in pairs(NAmanage.toolCache) do
		if NAmanage.isDroppedTool(tool) and not seen[tool] then
			seen[tool] = true
			list[#list + 1] = tool
		end
	end

	return list
end

NAmanage.saveToolCollision=function(tool)
	if not tool or NAmanage.toolGrabCol[tool] then
		return
	end

	local saved = setmetatable({}, { __mode = "k" })
	for _, part in ipairs(NAmanage.toolParts(tool)) do
		local ok, val = pcall(function()
			return part.CanCollide
		end)
		if ok then
			saved[part] = val
			if val ~= false then
				NACaller(function()
					part.CanCollide = false
				end)
			end
		end
	end
	NAmanage.toolGrabCol[tool] = saved
end

NAmanage.restoreToolCollision=function(tool)
	local saved = tool and NAmanage.toolGrabCol[tool]
	if not saved then
		return
	end

	for part, val in pairs(saved) do
		if part and part.Parent then
			NACaller(function()
				part.CanCollide = val
			end)
		end
	end
	NAmanage.toolGrabCol[tool] = nil
end

NAmanage.touchTool=function(tool, root)
	if not tool or not root then
		return
	end

	for _, part in ipairs(NAmanage.toolParts(tool)) do
		if part and part.Parent and firetouchinterest then
			NACaller(function()
				firetouchinterest(root, part, 0)
				firetouchinterest(part, root, 0)
				firetouchinterest(root, part, 1)
				firetouchinterest(part, root, 1)
			end)
		end
	end
end

NAmanage.pullTool=function(tool, root)
	if not tool or not root then
		return
	end

	local cf = root.CFrame
	local n = 0
	for _, part in ipairs(NAmanage.toolParts(tool)) do
		if part and part.Parent then
			n += 1
			NACaller(function()
				part.AssemblyLinearVelocity = Vector3.zero
				part.AssemblyAngularVelocity = Vector3.zero
				part.CFrame = cf * CFrame.new((n % 3 - 1) * 0.35, 0, -0.7 - (n * 0.03))
			end)
		end
	end
end

NAmanage.grabTool=function(tool, tries)
	if not NAmanage.isDroppedTool(tool) then
		return false
	end
	if NAmanage.grabBusy[tool] then
		return false
	end

	NAmanage.grabBusy[tool] = true
	local wantsPrompt = NAmanage.toolHasPrompt(tool)
	if not wantsPrompt then
		NAmanage.saveToolCollision(tool)
	end

	local ok = false
	tries = tonumber(tries) or 6

	for _ = 1, tries do
		local char = getChar()
		local hum = char and getHum(char)
		local root = char and getRoot(char)

		if not (char and hum and root) then
			break
		end

		if not NAmanage.isDroppedTool(tool) then
			ok = NAmanage.isOwnPackTool(tool)
			break
		end

		if wantsPrompt then
			local fired, picked = NAmanage.fireToolPrompts(tool, 0.12, 2)
			if picked then
				ok = true
				break
			end

			if fired and not picked then
				_, picked = NAmanage.fireToolPromptsFromCharacter(tool)
				if picked then
					ok = true
					break
				end
			end

			if NAmanage.touchEquipTool(tool, root, hum, 0.08) then
				ok = true
				break
			end
		else
			NAmanage.pullTool(tool, root)
			NAmanage.touchTool(tool, root)
		end

		if NAmanage.isOwnPackTool(tool) then
			ok = true
			break
		end

		NACaller(function()
			hum:EquipTool(tool)
		end)

		if NAmanage.isOwnPackTool(tool) then
			ok = true
			break
		end

		Defer(function()
			local c = getChar()
			local r = c and getRoot(c)
			local h = c and getHum(c)
			if tool and r and NAmanage.isDroppedTool(tool) then
				if wantsPrompt then
					local fired, picked = NAmanage.fireToolPrompts(tool, 0.12, 2)
					if not picked then
						if fired then
							NAmanage.fireToolPromptsFromCharacter(tool)
						end
						NAmanage.touchEquipTool(tool, r, h, 0.08)
					end
				else
					NAmanage.pullTool(tool, r)
					NAmanage.touchTool(tool, r)
				end
			end
		end)

		Defer(function()
			local c = getChar()
			local h = c and getHum(c)
			local r = c and getRoot(c)
			if tool and h and r and NAmanage.isDroppedTool(tool) then
				if wantsPrompt then
					local fired, picked = NAmanage.fireToolPrompts(tool, 0.12, 2)
					if not picked then
						if fired then
							NAmanage.fireToolPromptsFromCharacter(tool)
						end
						NAmanage.touchEquipTool(tool, r, h, 0.08)
					end
				else
					NAmanage.pullTool(tool, r)
					NAmanage.touchTool(tool, r)
				end
			end
		end)

		Wait(0.01)
	end

	ok = ok or NAmanage.isOwnPackTool(tool)
	NAmanage.grabBusy[tool] = nil
	NAmanage.restoreToolCollision(tool)

	if ok then
		NAmanage.toolCache[tool] = nil
	end

	return ok
end

NAmanage.grabAllTools=function(range)
	local char = getChar()
	local hum = char and getHum(char)
	local root = char and getRoot(char)
	if not hum or not root then return 0 end

	range = tonumber(range)
	local useRange = range and range > 0

	local count = 0
	for _, tool in ipairs(NAmanage.qDesc(workspace, "Tool")) do
		if useRange then
			local handle = tool:FindFirstChild("Handle") or tool:FindFirstChildWhichIsA("BasePart")
			if handle and (handle.Position - root.Position).Magnitude <= range then
				if NACaller(function() hum:EquipTool(tool) end) then
					count += 1
				end
			end
		else
			if NACaller(function() hum:EquipTool(tool) end) then
				count += 1
			end
		end
	end
	return count
end

cmd.add({"grabtools","gtools","gtls"},{"grabtools [range]","Grabs dropped tools"},function(...)
	local firstArg = ...
	local range = tonumber(firstArg)

	local count = NAmanage.grabAllTools(range)
	if count > 0 then
		if range and range > 0 then
			DebugNotif(("Grabbed %d tools within %d studs"):format(count, range), 2)
		else
			DebugNotif(("Grabbed %d tools"):format(count), 2)
		end
	else
		DebugNotif("No tools to grab", 2)
	end
end)

cmd.add({"loopgrabtools","loopgrab","lgtools","lgtls","lgrab","lg"},{"loopgrabtools [range]","Loop grabs dropped tools"},function(...)
