			elseif w < 900 then
				cols = 2
			else
				cols = 3
			end
			local padScale = 0.02
			local widthScale = (1 - padScale * (cols - 1)) / cols
			gridLayout.CellPadding = UDim2.new(padScale,0,0,8)
			gridLayout.CellSize = UDim2.new(widthScale,0,0,200)
		end
