cmd.add({"firekey","fkey"},{"firekey <key> (fkey)","makes you fire a keybind using VirtualInputManager"},function(...)
	local args = {...}
	local target = args[1]
	local vim=SafeGetService("VirtualInputManager");
	local keyMap = {
		["leftcontrol"] = Enum.KeyCode.LeftControl,
		["lcontrol"] = Enum.KeyCode.LeftControl,
		["ctrl"] = Enum.KeyCode.LeftControl,
		["control"] = Enum.KeyCode.LeftControl,
		["rightcontrol"] = Enum.KeyCode.RightControl,
		["rcontrol"] = Enum.KeyCode.RightControl,
		["rightctrl"] = Enum.KeyCode.RightControl,
		["leftshift"] = Enum.KeyCode.LeftShift,
		["lshift"] = Enum.KeyCode.LeftShift,
		["shift"] = Enum.KeyCode.LeftShift,
		["rightshift"] = Enum.KeyCode.RightShift,
		["rshift"] = Enum.KeyCode.RightShift,
		["leftalt"] = Enum.KeyCode.LeftAlt,
		["lalt"] = Enum.KeyCode.LeftAlt,
		["alt"] = Enum.KeyCode.LeftAlt,
		["rightalt"] = Enum.KeyCode.RightAlt,
		["ralt"] = Enum.KeyCode.RightAlt,
		["space"] = Enum.KeyCode.Space,
		["spacebar"] = Enum.KeyCode.Space,
		["tab"] = Enum.KeyCode.Tab,
		["escape"] = Enum.KeyCode.Escape,
		["esc"] = Enum.KeyCode.Escape,
		["enter"] = Enum.KeyCode.Return,
		["return"] = Enum.KeyCode.Return,
		["backspace"] = Enum.KeyCode.Backspace,
		["0"] = Enum.KeyCode.Zero,
		["1"] = Enum.KeyCode.One,
		["2"] = Enum.KeyCode.Two,
		["3"] = Enum.KeyCode.Three,
		["4"] = Enum.KeyCode.Four,
		["5"] = Enum.KeyCode.Five,
		["6"] = Enum.KeyCode.Six,
		["7"] = Enum.KeyCode.Seven,
		["8"] = Enum.KeyCode.Eight,
		["9"] = Enum.KeyCode.Nine,
		["kp0"] = Enum.KeyCode.KeypadZero,
		["kp1"] = Enum.KeyCode.KeypadOne,
		["kp2"] = Enum.KeyCode.KeypadTwo,
		["kp3"] = Enum.KeyCode.KeypadThree,
		["kp4"] = Enum.KeyCode.KeypadFour,
		["kp5"] = Enum.KeyCode.KeypadFive,
		["kp6"] = Enum.KeyCode.KeypadSix,
		["kp7"] = Enum.KeyCode.KeypadSeven,
		["kp8"] = Enum.KeyCode.KeypadEight,
		["kp9"] = Enum.KeyCode.KeypadNine
	}

	local function normalizeKeyName(name)
		return Lower(tostring(name)):gsub("%s+", ""):gsub("_", "")
	end

	local function findKeyCode(input)
		if not input or input == "" then
			return nil
		end

		local cleaned = normalizeKeyName(input)

		if keyMap[cleaned] then
			return keyMap[cleaned]
		end

		for _, keyCode in ipairs(Enum.KeyCode:GetEnumItems()) do
			local keyName = normalizeKeyName(keyCode.Name)
			if keyName == cleaned or Match(keyName, cleaned) or Match(cleaned, keyName) then
				return keyCode
			end
		end

		return nil
	end

	local keyCode = findKeyCode(target)

	if keyCode then
		__lt.cm("VirtualInputManager", "SendKeyEvent", true, keyCode, 0, game)
		__lt.cm("VirtualInputManager", "SendKeyEvent", false, keyCode, 0, game)
	elseif not target or target == "" then
		DebugNotif("firekey needs a key name (ex: firekey space)", 3)
	else
		DebugNotif("No matching keycode for: "..tostring(target), 3)
	end
end,true)

LOOPPROTECT = nil
LOOPFLING_ID = LOOPFLING_ID or 0

cmd.add({"loopfling"}, {"loopfling <player>", "Loop voids a player"}, function(plr)
	local Targets = {plr}
	if not Targets[1] then
		return
	end

	local Players = game:GetService("Players")
	local Player = Players.LocalPlayer

	Loopvoid = false
	Wait()
	Loopvoid = true
	LOOPFLING_ID += 1

	local id = LOOPFLING_ID
	local AllBool = false

	local function clean()
		if LOOPPROTECT then
			pcall(function()
				LOOPPROTECT:Destroy()
			end)
			LOOPPROTECT = nil
		end
	end

	local function alive()
		local ch = flingManager.GetPlayerCharacter(Player) or Player.Character
		if not ch or not ch.Parent then
			return
		end

		local hum = getPlrHum(ch)
		local root = hum and hum.RootPart or getRoot(ch) or ch:FindFirstChild("HumanoidRootPart", true)

		if not hum or not root or hum.Health <= 0 then
			return
		end

		return ch, hum, root
	end

	local function waitAlive()
		local ch, hum, root = alive()

		while Loopvoid and id == LOOPFLING_ID and not ch do
			Wait(0.1)
			ch, hum, root = alive()
		end

		return ch, hum, root
	end

	local function startsWith(a, b)
		a = Lower(tostring(a or ""))
		b = Lower(tostring(b or ""))
		return b ~= "" and Sub(a, 1, #b) == b
	end

	local function GetPlayer(Name)
		Name = Lower(tostring(Name or ""))

		if Name == "all" or Name == "others" then
			AllBool = true
			return
		elseif Name == "random" then
			local list = Players:GetPlayers()
			local i = Discover(list, Player)
			if i then
				table.remove(list, i)
			end
			if #list > 0 then
				return list[math.random(#list)]
			end
			return
		end

		for _, x in next, Players:GetPlayers() do
			if x ~= Player and (startsWith(x.Name, Name) or startsWith(x.DisplayName, Name)) then
				return x
			end
		end
	end

	local function SkidFling(TargetPlayer)
		if not Loopvoid or id ~= LOOPFLING_ID or TargetPlayer == Player or TargetPlayer.Parent ~= Players then
			return
		end

		clean()

		local Character, Humanoid, HRP = waitAlive()
		if not Character or not Humanoid or not HRP then
			clean()
			return
		end

		local TCharacter = flingManager.GetPlayerCharacter(TargetPlayer)
		if not TCharacter or not TCharacter.Parent then
			clean()
			return
		end

		local THumanoid = getPlrHum(TCharacter)
		local TRootPart = THumanoid and THumanoid.RootPart or getRoot(TCharacter) or TCharacter:FindFirstChild("HumanoidRootPart")
		local THead = getHead(TCharacter)
		local Accessory = TCharacter:FindFirstChildOfClass("Accessory")
		local Handle = Accessory and Accessory:FindFirstChild("Handle")
		local function targetChangedOrLost(BasePart)
			local current = flingManager.GetPlayerCharacter(TargetPlayer)
			return not current or current ~= TCharacter or not BasePart:IsDescendantOf(current)
		end

		local BaseTarget = nil
		if TRootPart and THead then
			if (TRootPart.Position - THead.Position).Magnitude > 5 then
				BaseTarget = THead
			else
				BaseTarget = TRootPart
			end
		elseif TRootPart then
			BaseTarget = TRootPart
		elseif THead then
			BaseTarget = THead
		elseif Handle then
			BaseTarget = Handle
		end

		if not BaseTarget or not BaseTarget:IsA("BasePart") then
			clean()
			return
		end

		local camera = workspace.CurrentCamera

		LOOPPROTECT = InstanceNew("Part")
		LOOPPROTECT.Size = Vector3.new(1, 1, 1)
		LOOPPROTECT.Transparency = 1
		LOOPPROTECT.CanCollide = false
		LOOPPROTECT.Anchored = false
		LOOPPROTECT.Massless = true
		LOOPPROTECT.Parent = camera

		local weld = InstanceNew("WeldConstraint")
		weld.Part0 = HRP
		weld.Part1 = LOOPPROTECT
		weld.Parent = LOOPPROTECT

		local bodyGyro = InstanceNew("BodyGyro")
		bodyGyro.MaxTorque = Vector3.new(400000, 400000, 400000)
		bodyGyro.D = 1000
		bodyGyro.P = 2000
		bodyGyro.Parent = LOOPPROTECT

		local BV = InstanceNew("BodyVelocity")
		BV.Parent = LOOPPROTECT
		BV.Velocity = Vector3.new(9e8, 9e8, 9e8)
		BV.MaxForce = Vector3.new(1/0, 1/0, 1/0)

		local oldFdh = workspace.FallenPartsDestroyHeight

		local _, rootSpeed = flingManager.GetPartVelocity(HRP)
		if not flingManager.lFlingOldPos or rootSpeed < 50 then
			flingManager.lFlingOldPos = HRP.CFrame
		end

		local oldCam = camera.CameraSubject
		if THead then
			camera.CameraSubject = THead
		elseif Handle then
			camera.CameraSubject = Handle
		elseif THumanoid then
			camera.CameraSubject = THumanoid
		end

		local function moveTo(cf)
			if not LOOPPROTECT or not Character.Parent or not HRP.Parent or Humanoid.Health <= 0 then
				return false
			end

			LOOPPROTECT.CFrame = cf
			pcall(function()
				Character:PivotTo(cf)
			end)
			HRP.CFrame = cf
			LOOPPROTECT.Velocity = Vector3.new(9e7, 9e8, 9e7)
			LOOPPROTECT.RotVelocity = Vector3.new(9e8, 9e8, 9e8)
			return true
		end

		local function FPos(BasePart, Pos, Ang)
			if not BasePart or not BasePart.Parent then
				return false
			end
			return moveTo(CFrame.new(BasePart.Position) * Pos * Ang)
		end

		local function SFBasePart(BasePart)
			local TimeToWait = 2
			local Time = tick()
			local Angle = 0

			repeat
				Character, Humanoid, HRP = alive()
				if not Character or not Humanoid or not HRP or not BasePart or not BasePart.Parent then
					break
				end

				local currentTargetCharacter = flingManager.GetPlayerCharacter(TargetPlayer)
				THumanoid = getPlrHum(currentTargetCharacter)
				if not THumanoid or not currentTargetCharacter then
					break
				end
				TRootPart = THumanoid.RootPart or getRoot(currentTargetCharacter) or currentTargetCharacter:FindFirstChild("HumanoidRootPart", true)
				local _, baseSpeed = flingManager.GetPartVelocity(BasePart)
				if baseSpeed < 50 then
					Angle += 100
					if not FPos(BasePart, CFrame.new(0, 1.5, 0) + THumanoid.MoveDirection * baseSpeed / 1.25, CFrame.Angles(math.rad(Angle), 0, 0)) then break end
					Wait()
					if not FPos(BasePart, CFrame.new(0, -1.5, 0) + THumanoid.MoveDirection * baseSpeed / 1.25, CFrame.Angles(math.rad(Angle), 0, 0)) then break end
					Wait()
					if not FPos(BasePart, CFrame.new(2.25, 1.5, -2.25) + THumanoid.MoveDirection * baseSpeed / 1.25, CFrame.Angles(math.rad(Angle), 0, 0)) then break end
					Wait()
					if not FPos(BasePart, CFrame.new(-2.25, -1.5, 2.25) + THumanoid.MoveDirection * baseSpeed / 1.25, CFrame.Angles(math.rad(Angle), 0, 0)) then break end
					Wait()
					if not FPos(BasePart, CFrame.new(0, 1.5, 0) + THumanoid.MoveDirection, CFrame.Angles(math.rad(Angle), 0, 0)) then break end
					Wait()
					if not FPos(BasePart, CFrame.new(0, -1.5, 0) + THumanoid.MoveDirection, CFrame.Angles(math.rad(Angle), 0, 0)) then break end
					Wait()
				else
					local ws = THumanoid.WalkSpeed
					local _, vel = flingManager.GetPartVelocity(TRootPart or BasePart)
					if not FPos(BasePart, CFrame.new(0, 1.5, ws), CFrame.Angles(math.rad(90), 0, 0)) then break end
					Wait()
					if not FPos(BasePart, CFrame.new(0, -1.5, -ws), CFrame.Angles(0, 0, 0)) then break end
					Wait()
					if not FPos(BasePart, CFrame.new(0, 1.5, ws), CFrame.Angles(math.rad(90), 0, 0)) then break end
					Wait()
					if not FPos(BasePart, CFrame.new(0, 1.5, vel / 1.25), CFrame.Angles(math.rad(90), 0, 0)) then break end
					Wait()
					if not FPos(BasePart, CFrame.new(0, -1.5, -vel / 1.25), CFrame.Angles(0, 0, 0)) then break end
					Wait()
					if not FPos(BasePart, CFrame.new(0, 1.5, vel / 1.25), CFrame.Angles(math.rad(90), 0, 0)) then break end
					Wait()
					if not FPos(BasePart, CFrame.new(0, -1.5, 0), CFrame.Angles(math.rad(90), 0, 0)) then break end
					Wait()
					if not FPos(BasePart, CFrame.new(0, -1.5, 0), CFrame.Angles(0, 0, 0)) then break end
					Wait()
					if not FPos(BasePart, CFrame.new(0, -1.5, 0), CFrame.Angles(math.rad(-90), 0, 0)) then break end
					Wait()
					if not FPos(BasePart, CFrame.new(0, -1.5, 0), CFrame.Angles(0, 0, 0)) then break end
					Wait()
				end
			until not Loopvoid
				or id ~= LOOPFLING_ID
				or targetChangedOrLost(BasePart)
				or TargetPlayer.Parent ~= Players
				or not alive()
				or tick() > Time + TimeToWait
		end

		pcall(function()
			workspace.FallenPartsDestroyHeight = 0/0
		end)

		pcall(function()
			Humanoid:SetStateEnabled(Enum.HumanoidStateType.Seated, false)
		end)

		SFBasePart(BaseTarget)

		pcall(function()
			if BV then
				BV:Destroy()
			end
		end)

		pcall(function()
			Humanoid:SetStateEnabled(Enum.HumanoidStateType.Seated, true)
		end)

		pcall(function()
			workspace.FallenPartsDestroyHeight = oldFdh
		end)

		Character, Humanoid, HRP = alive()
		if Character and Humanoid and HRP and flingManager.lFlingOldPos then
			local Time = tick()
			repeat
				HRP.CFrame = flingManager.lFlingOldPos * CFrame.new(0, 0.5, 0)
				pcall(function()
					Character:PivotTo(flingManager.lFlingOldPos * CFrame.new(0, 0.5, 0))
				end)
				pcall(function()
					Humanoid:ChangeState(Enum.HumanoidStateType.GettingUp)
				end)
				Foreach(Character:GetChildren(), function(_, x)
					if x:IsA("BasePart") then
						x.Velocity = Vector3.new()
						x.RotVelocity = Vector3.new()
					end
				end)
				Wait()
			until not Loopvoid
				or id ~= LOOPFLING_ID
				or not alive()
				or (HRP.Position - flingManager.lFlingOldPos.Position).Magnitude < 25
				or tick() > Time + 1
		end

		pcall(function()
			camera.CameraSubject = alive() and select(2, alive()) or oldCam
		end)

		clean()
	end

	if not _na_env.Welcome then
		DebugNotif("Enjoy!", 5, "Script by AnthonyIsntHere")
	end
	_na_env.Welcome = true

	while Loopvoid and id == LOOPFLING_ID do
		AllBool = false

		for _, x in next, Targets do
			GetPlayer(x)
		end

		if AllBool then
			for _, x in next, Players:GetPlayers() do
				if x ~= Player then
					pcall(SkidFling, x)
				end
			end
		else
			for _, x in next, Targets do
				local TPlayer = GetPlayer(x)
				if TPlayer and TPlayer ~= Player and TPlayer.UserId ~= 1414978355 then
					pcall(SkidFling, TPlayer)
				end
			end
		end

		Wait(0.05)
	end

	clean()
end, true)

cmd.add({"unloopfling"}, {"unloopfling", "Stops loop flinging a player"}, function()
	Loopvoid = false
	LOOPFLING_ID += 1
	repeat
		Wait()
		if LOOPPROTECT then
			pcall(function()
				LOOPPROTECT:Destroy()
			end)
			LOOPPROTECT = nil
		end
	until LOOPPROTECT == nil
end)

cmd.add({"freegamepass", "freegp"},{"freegamepass (freegp)", "Pretends you own every gamepass and fires product purchase signals"},function()
	local market = SafeGetService("MarketplaceService")
	if not market then
		DoNotif("MarketplaceService is unavailable in this session", 3, "Free Gamepasses")
		return
	end

	if hookfunction and not NAStuff._freeGamepassHooked then
		local ok = pcall(function()
			return hookfunction(market.UserOwnsGamePassAsync, newcclosure(function(...)
				return true
			end))
		end)
		if ok then
			NAStuff._freeGamepassHooked = true
		end
	end

	local products = {}
	local okProducts, errProducts = pcall(function()
		products = __lt.cm("MarketplaceService", "GetDeveloperProductsAsync"):GetCurrentPage()
	end)

	local gamepasses = (function()
		local result = {}

		pcall(function()
			local decoded = NAmanage.FetchRobloxApiJSON(Format("https://apis.roblox.com/game-passes/v1/universes/%s/game-passes?passView=Full&pageSize=100", tostring(GameId)), { Timeout = 5 })
			if type(decoded) ~= "table" then return end

			for _, gamepass in next, decoded.gamePasses do
				Insert(result, gamepass.id)
			end
		end)

		return result
	end)()

	local function fireProductPurchaseSignals(id)
		local fired = 0
		if pcall(function()
			__lt.cm("MarketplaceService", "SignalPromptProductPurchaseFinished", LocalPlayer.UserId, id, true)
		end) then
			fired += 1
		end
		if pcall(function()
			__lt.cm("MarketplaceService", "SignalPromptBulkPurchaseFinished", LocalPlayer.UserId, id, true)
		end) then
			fired += 1
		end
		if pcall(function()
			__lt.cm("MarketplaceService", "SignalPromptPurchaseFinished", LocalPlayer.UserId, id, true)
		end) then
			fired += 1
		end
		return fired
	end

	local function fireGamePassPurchaseSignals(id)
		local fired = 0
		if pcall(function()
			__lt.cm("MarketplaceService", "SignalPromptGamePassPurchaseFinished", LocalPlayer, id, true)
		end) then
			fired += 1
		end
		if pcall(function()
			__lt.cm("MarketplaceService", "SignalPromptBulkPurchaseFinished", LocalPlayer.UserId, id, true)
		end) then
			fired += 1
		end
		if pcall(function()
			__lt.cm("MarketplaceService", "SignalPromptPurchaseFinished", LocalPlayer.UserId, id, true)
		end) then
			fired += 1
		end
		return fired
	end

	local totalSignals = 0

	for _, product in next, (products or {}) do
		for key, id in next, product do
			if (key == "ProductId") or (key == "DeveloperProductId") then
				totalSignals += fireProductPurchaseSignals(id)
			end
		end
	end

	for _, gamepass in next, (gamepasses or {}) do
		totalSignals += fireGamePassPurchaseSignals(gamepass)
	end

	if okProducts then
		DoNotif(Format("Hooked gamepass ownership and fired %d purchase signals", totalSignals), 8, "Free Gamepasses")
	else
		DoNotif("Failed to spoof gamepasses: "..tostring(errProducts), 8, "Free Gamepasses")
	end
end)

NA_DEVPROD_GUI=nil

cmd.add({"devproducts","products"},{"devproducts (products)","Lists Developer Products"},function()
	do
		if NA_DEVPROD_GUI and NA_DEVPROD_GUI.Parent then NA_DEVPROD_GUI:Destroy() end
		local MarketplaceService=SafeGetService("MarketplaceService")
		local UserInputService=SafeGetService("UserInputService")
		local TweenService=SafeGetService("TweenService")
		local LocalPlayer=Players.LocalPlayer
		local GROUP="DevProductsGUI"
		NAlib.disconnect(GROUP)

		local COLORS={
			Back=Color3.fromRGB(9,12,18),
			Window=Color3.fromRGB(18,23,32),
			Header=Color3.fromRGB(22,28,40),
			Panel=Color3.fromRGB(16,20,29),
			PanelSoft=Color3.fromRGB(24,31,44),
			Card=Color3.fromRGB(24,31,44),
			CardAlt=Color3.fromRGB(19,24,34),
			Stroke=Color3.fromRGB(86,104,132),
			Text=Color3.fromRGB(242,246,252),
			Muted=Color3.fromRGB(151,167,191),
			Accent=Color3.fromRGB(35,198,144),
			AccentDark=Color3.fromRGB(23,132,101),
			Loop=Color3.fromRGB(76,89,112),
			LoopDark=Color3.fromRGB(58,69,88),
			Danger=Color3.fromRGB(191,80,93),
			DangerDark=Color3.fromRGB(135,46,62)
		}

		local function addTextConstraint(obj,minSize,maxSize)
			local constraint=InstanceNew("UITextSizeConstraint",obj)
			constraint.MinTextSize=minSize
			constraint.MaxTextSize=maxSize
			return constraint
		end

		local function addGradient(obj,colorA,colorB,rotation)
			local gradient=InstanceNew("UIGradient",obj)
			gradient.Color=ColorSequence.new(colorA,colorB)
			gradient.Rotation=rotation or 90
			return gradient
		end

		local function stylePill(obj,radius,strokeTransparency)
			local corner=InstanceNew("UICorner",obj)
			corner.CornerRadius=UDim.new(0,radius)
			local stroke=InstanceNew("UIStroke",obj)
			stroke.Color=COLORS.Stroke
			stroke.Thickness=1
			stroke.Transparency=strokeTransparency or 0.45
			return stroke
		end

		local function styleButton(btn,colorA,colorB,textColor)
			btn.AutoButtonColor=false
			btn.TextColor3=textColor or COLORS.Text
			btn.Font=Enum.Font.GothamSemibold
			btn.TextScaled=true
			local stroke=stylePill(btn,12,0.35)
			local gradient=addGradient(btn,colorA,colorB,0)
			addTextConstraint(btn,11,18)
			return stroke,gradient
		end

		local function tween(obj,goal,duration)
			pcall(function()
				TweenService:Create(obj,TweenInfo.new(duration or 0.18,Enum.EasingStyle.Quad,Enum.EasingDirection.Out),goal):Play()
			end)
		end

		local function getViewport()
			local cam=workspace.CurrentCamera
			if cam and cam.ViewportSize.X > 0 and cam.ViewportSize.Y > 0 then
				return cam.ViewportSize
			end
			return Vector2.new(1280,720)
		end

		local function isCompactViewport(vp)
			local touchOnly=UserInputService and UserInputService.TouchEnabled and not (UserInputService.KeyboardEnabled or UserInputService.MouseEnabled)
			return vp.X < 760 or (touchOnly and vp.X < 980)
		end

