		local list=InstanceNew("ScrollingFrame",body)
		list.Active=true
		list.BackgroundTransparency=1
		list.BorderSizePixel=0
		list.Position=UDim2.fromOffset(10,10)
		list.Size=UDim2.new(1,-20,1,-20)
		list.ScrollBarThickness=6
