bringc = {}

NAmanage.parseBringDistance=function(args, defaultDistance)
	local distance = tonumber(args[#args])
	if distance then
		table.remove(args, #args)
		return math.clamp(distance, 0, 1000)
	end
	return defaultDistance or 0
end

NAmanage.bringOffsetCFrame=function(cf, distance)
	if not cf then return nil end
	distance = tonumber(distance) or 0
	return cf + cf.LookVector * distance
end

cmd.add({"cbring", "clientbring", "clientb"}, {"cbring <player> [distance]", "Brings the player once on your client"}, function(...)
	local args = {...}
	local distance = NAmanage.parseBringDistance(args, 3)
	local username = args[1]
	local target = getPlr(username)
	if #target == 0 then return end
	local localChar = getChar()
	if not localChar then return end
	local localRoot = getRoot(localChar)
	if not localRoot then return end
	for _, plr in next, target do
		local targetChar = getPlrChar(plr)
		if targetChar then
			local targetRoot = getRoot(targetChar)
			if targetRoot then
				targetRoot.CFrame = NAmanage.bringOffsetCFrame(localRoot.CFrame, distance)
			end
		end
	end
end, true)

cmd.add({"loopcbring", "loopclientb", "loppclientb", "loopclientbring", "lcbring", "lclientb"}, {"loopcbring <player> [distance]", "Continuously brings the player on your client"}, function(...)
	local args = {...}
	local distance = NAmanage.parseBringDistance(args, 3)
	local username = args[1]
	local target = getPlr(username)
	if #target == 0 then return end
	for _, conn in ipairs(bringc) do
		conn:Disconnect()
	end
	bringc = {}
	if NAlib.isConnected("cbnoclip") then
		NAlib.disconnect("cbnoclip")
	end
	NAlib.connect("cbnoclip", RunService.RenderStepped:Connect(function()
		local char = getChar()
		if not char then return end
		for _, descendant in pairs(NAmanage.qDesc(char, "BasePart")) do
			descendant.CanCollide = false
		end
	end))
	for _, plr in next, target do
		if not plr then return end
		local conn = RunService.RenderStepped:Connect(function()
			local targetChar = getPlrChar(plr)
			local localChar = getChar()
			if targetChar and localChar then
				local targetRoot = getRoot(targetChar)
				local localRoot = getRoot(localChar)
				if targetRoot and localRoot then
					targetRoot.CFrame = NAmanage.bringOffsetCFrame(localRoot.CFrame, distance)
				end
			end
		end)
		Insert(bringc, conn)
	end
end, true)

cmd.add({"unloopcbring", "unloopclientb", "unloopcientb", "unlcbring", "unlclientb", "uncbring", "unclientb"}, {"unloopcbring", "Disable looped client bring"}, function()
	for _, conn in ipairs(bringc) do
		conn:Disconnect()
	end
	bringc = {}
	if NAlib.isConnected("cbnoclip") then
		NAlib.disconnect("cbnoclip")
	end
end)

cmd.add({"mute", "muteboombox"}, {"mute <player> (muteboombox)", "Mutes the player's boombox"}, function(...)
	local uuuu = ...
