TPWalk = false

cmd.add({"tpwalk", "tpwalk"}, {"tpwalk <number>", "More undetectable walkspeed script"}, function(...)
	if TPWalk then
		TPWalk = false
		NAlib.disconnect("TPWalkingConnection")
	end

	TPWalk = true
	local Speed = tonumber(...) or 1
	local stepRate = 1 / 60
	local maxSteps = 3
	local accumulator = 0

	NAlib.connect("TPWalkingConnection", RunService.Heartbeat:Connect(function(deltaTime)
		if not TPWalk then
			return
		end
		accumulator = math.min(accumulator + (tonumber(deltaTime) or 0), stepRate * maxSteps)
		local humanoid = getHum()
		local char = getChar()
		if not humanoid or not char or humanoid.MoveDirection.Magnitude <= 0 then
			return
		end
		local moveDirection = humanoid.MoveDirection
		local steps = 0
		while accumulator >= stepRate and steps < maxSteps do
			local stepDelta = moveDirection * Speed * stepRate * 10
			local undergroundState = NAStuff and NAStuff.NAundergroundState
			if undergroundState and undergroundState.Underground then
				undergroundState.PendingTranslation = (undergroundState.PendingTranslation or Vector3.new()) + stepDelta
			else
				char:TranslateBy(stepDelta)
			end
			accumulator -= stepRate
			steps += 1
		end
	end))
end, true)

cmd.add({"untpwalk"}, {"untpwalk", "Stops the tpwalk command"}, function()
	TPWalk = false
	NAlib.disconnect("TPWalkingConnection")
end)

muteLOOP = {}

cmd.add({"loopmute", "loopmuteboombox"}, {"loopmute <player> (loopmuteboombox)", "Loop mutes the player's boombox"}, function(...)
	local u = ...
	local pls = getPlr(u)
	if #pls == 0 then return end

	local function mute(p)
		if p and p.Character then
			for _, d in ipairs(NAmanage.qDesc(p.Character, "Sound")) do
				if d.Playing then
					d.Playing = false
				end
			end
		end
		local bp = p:FindFirstChildOfClass("Backpack")
		if bp then
			for _, d in ipairs(NAmanage.qDesc(bp, "Sound")) do
				if d.Playing then
					d.Playing = false
				end
			end
		end
	end

	for _, p in ipairs(pls) do
		local id = p.UserId
		if not muteLOOP[id] then
			muteLOOP[id] = Spawn(function()
				while p and p.Parent do
					mute(p)
					Wait(1)
				end
				muteLOOP[id] = nil
			end)
			DebugNotif("Loopmuted "..p.Name)
		else
			DebugNotif(p.Name.." already loopmuted")
		end
	end
end, true)

cmd.add({"unloopmute", "unloopmuteboombox"}, {"unloopmute <player> (unloopmuteboombox)", "Unloop mutes the player's boombox"}, function(...)
	local u = ...
	local pls = getPlr(u)
	if #pls == 0 then return end

	for _, p in ipairs(pls) do
		local id = p.UserId
		local t = muteLOOP[id]
		if t then
			coroutine.close(t)
			muteLOOP[id] = nil
			DebugNotif("Unloopmuted "..p.Name)
		else
			DebugNotif(p.Name.." not loopmuted")
		end
	end
end, true)

