					local targetPart = part
					SpawnCall(function()
						local orig = targetPart.CFrame
						targetPart.CFrame = root.CFrame
						firetouchinterest(targetPart,root,1)
						Wait()
						firetouchinterest(targetPart,root,0)
						Delay(0.1,function()
							if targetPart and targetPart.Parent then
								targetPart.CFrame = orig
							end
						end)
					end)
				end
			end
		end
	end
	if found == 0 then
		DebugNotif(("No TouchInterests found matching \"%s\""):format(targetText),2)
	else
		DebugNotif(("Fired %d TouchInterests"):format(found),2)
	end
end,true)

NAutil.parseInterval = function(defaultInterval, ...)
	local args = { ... }
	local n1 = tonumber(args[1])
	if n1 then
		return n1, (args[2] and Lower(Concat(args, " ", 2)) or nil)
	else
		return defaultInterval, (args[1] and Lower(Concat(args, " ", 1)) or nil)
	end
end

NAmanage.getAutoInteractDefaultInterval = function()
	return math.clamp(tonumber(NAStuff.AutoInteractDefaultInterval) or 0.1, 0, 1)
end

local promptPartCache = {}
local carPartCache = {}
local promptNamesCache = {}
local clickNamesCache = {}
local partNamesCache = {}

NAindex.lc = function(s)
	if s then
		return Lower(s)
	end
	return ""
end

NAindex.carPart = function(inst)
	if not inst then
		return nil
	end
	local c = carPartCache[inst]
	if c ~= nil then
		if c == false then
			return nil
		end
		return c
	end
	local part
	if inst:IsA("BasePart") then
		part = inst
	elseif inst:IsA("Attachment") then
		local p = inst.Parent
		if p and p:IsA("BasePart") then
			part = p
		end
	end
	if not part then
		if inst:IsA("Model") then
			part = inst.PrimaryPart or inst:FindFirstChildWhichIsA("BasePart", true)
		else
			local parent = inst.Parent
			if parent and parent:IsA("Model") then
				part = parent.PrimaryPart or parent:FindFirstChildWhichIsA("BasePart", true)
			end
		end
	end
	if not part then
		part = inst:FindFirstAncestorWhichIsA("BasePart")
	end
	carPartCache[inst] = part or false
	return part
end

NAindex.getPromptPart = function(pp)
	if not pp then
		return nil
	end
	local c = promptPartCache[pp]
	if c ~= nil then
		if c == false then
			return nil
		end
		return c
	end
	local parent = pp.Parent
	local part
	if parent then
		if parent:IsA("Attachment") then
			local p = parent.Parent
			if p and p:IsA("BasePart") then
				part = p
			end
		elseif parent:IsA("BasePart") then
			part = parent
		end
	end
	if not part then
		local model = pp:FindFirstAncestorWhichIsA("Model")
		if model then
			if model.PrimaryPart then
				part = model.PrimaryPart
			else
				part = model:FindFirstChildWhichIsA("BasePart", true)
			end
		end
	end
	if not part then
		part = pp:FindFirstAncestorWhichIsA("BasePart")
	end
	promptPartCache[pp] = part or false
	return part
end

NAindex.namesForPrompt = function(p)
	local cached = promptNamesCache[p]
	if cached then
		return cached
	end
	local names = {}
	if p.Name then
		Insert(names, p.Name)
	end
	if p.ObjectText then
		Insert(names, p.ObjectText)
	end
	if p.ActionText then
		Insert(names, p.ActionText)
	end
	local parent = p.Parent
	if parent and parent.Name then
		Insert(names, parent.Name)
	end
	local part = NAindex.getPromptPart(p)
	if part then
		Insert(names, part.Name)
		local m = part:FindFirstAncestorWhichIsA("Model")
		while m do
			Insert(names, m.Name)
			m = m:FindFirstAncestorWhichIsA("Model")
		end
	else
		local m = p:FindFirstAncestorWhichIsA("Model")
		while m do
			Insert(names, m.Name)
			m = m:FindFirstAncestorWhichIsA("Model")
		end
	end
	for i = 1, #names do
		names[i] = NAindex.lc(names[i])
	end
	promptNamesCache[p] = names
	return names
end

NAindex.namesForClick = function(d)
	local cached = clickNamesCache[d]
	if cached then
		return cached
	end
	local names = {}
	if d.Name then
		Insert(names, d.Name)
	end
	local parent = d.Parent
	if parent and parent.Name then
		Insert(names, parent.Name)
	end
	local part = NAindex.carPart(parent or d)
	if part then
		Insert(names, part.Name)
		local m = part:FindFirstAncestorWhichIsA("Model")
		while m do
			Insert(names, m.Name)
			m = m:FindFirstAncestorWhichIsA("Model")
		end
	end
	for i = 1, #names do
		names[i] = NAindex.lc(names[i])
	end
	clickNamesCache[d] = names
	return names
end

NAindex.namesForPart = function(part)
	if not part then
		return {}
	end
	local cached = partNamesCache[part]
	if cached then
		return cached
	end
	local names = {}
	Insert(names, NAindex.lc(part.Name))
	local m = part:FindFirstAncestorWhichIsA("Model")
	while m do
		Insert(names, NAindex.lc(m.Name))
		m = m:FindFirstAncestorWhichIsA("Model")
	end
	partNamesCache[part] = names
	return names
end

NAindex.matchAny = function(names, target)
	target = NAindex.lc(target)
	if not target or target == "" then
		return true
	end
	for i = 1, #names do
		if names[i] == target then
			return true
		end
	end
	return false
end

NAindex.matchAnyFind = function(names, target)
	target = NAindex.lc(target)
	if not target or target == "" then
		return true
	end
	for i = 1, #names do
		local n = names[i]
		if n == target or Find(n, target, 1, true) then
			return true
		end
	end
	return false
end

NAindex.promptTarget = function(pp)
	local part = NAindex.getPromptPart(pp)
	return part, part and part.Position or nil
end

NAindex.clickTarget = function(cd)
	local part = NAindex.carPart(cd.Parent or cd)
	return part, part and part.Position or nil
end

NAindex.inRangePrompt = function(pp, rootPos, extra)
	local part, pos = NAindex.promptTarget(pp)
	if not pos then
		return false, math.huge, part
	end
	local dist = (pos - rootPos).Magnitude
	local maxd = (pp.MaxActivationDistance or 0) + (extra or 0)
	return dist <= maxd, dist, part
end

NAindex.inRangeClick = function(cd, rootPos, extra)
	local part, pos = NAindex.clickTarget(cd)
	if not pos then
		return false, math.huge, part
	end
	local dist = (pos - rootPos).Magnitude
	local maxd = (cd.MaxActivationDistance or 0) + (extra or 0)
	return dist <= maxd, dist, part
end

NAindex.init = function()
	if NAindex._init then return end
	NAindex._init = true
end

NAsuppress._acquire = function(pp)
	local r = NAsuppress.ref[pp] or 0
	if r == 0 then
		NAsuppress.snap[pp] = pp.Enabled
		pp.Enabled = false
	end
	NAsuppress.ref[pp] = r + 1
end

NAsuppress._release = function(pp)
	local r = NAsuppress.ref[pp]
	if not r then return end
	r -= 1
	if r <= 0 then
		local prev = NAsuppress.snap[pp]
		if prev ~= nil and pp and pp.Parent then
			pp.Enabled = prev
		end
		NAsuppress.ref[pp] = nil
		NAsuppress.snap[pp] = nil
	else
		NAsuppress.ref[pp] = r
	end
end

NAsuppress.collectAndAcquire = function(centerPos, radius, allowSet)
	local list = {}
	if InstancesTbl and type(InstancesTbl.proxy) == "table" then
		for _, p in ipairs(InstancesTbl.proxy) do
			if p and p.Parent and p.Enabled and not (allowSet and allowSet[p]) then
				local _, pos = NAindex.promptTarget(p)
				if pos and (pos - centerPos).Magnitude <= radius then
					NAsuppress._acquire(p)
					Insert(list, p)
				end
			end
		end
	end
	return list
end

NAsuppress.releaseList = function(list)
	for _, p in ipairs(list) do
		NAsuppress._release(p)
	end
end

NAjobs._tracked = NAjobs._tracked or {
	prompt = { list = {}, idx = {} },
	click = { list = {}, idx = {} }
}

NAjobs._trackedAdd = function(kind, inst)
	if not inst then
		return
	end
	local bucket = NAjobs._tracked[kind]
	if not bucket then
		return
	end
	if bucket.idx[inst] then
		return
	end
	local list = bucket.list
	local n = #list + 1
	list[n] = inst
	bucket.idx[inst] = n
end

NAjobs._trackedRemove = function(kind, inst)
	if not inst then
		return
	end
	local bucket = NAjobs._tracked[kind]
	if not bucket then
		return
	end
	local idx = bucket.idx[inst]
	if not idx then
		return
	end
	local list = bucket.list
	local last = #list
	local repl = list[last]
	list[last] = nil
	if idx ~= last then
		list[idx] = repl
		if repl then
			bucket.idx[repl] = idx
		end
	end
	bucket.idx[inst] = nil
	if kind == "prompt" and type(NAjobs._lastPromptFire) == "table" then
		NAjobs._lastPromptFire[inst] = nil
	elseif kind == "click" and type(NAjobs._lastClickFire) == "table" then
		NAjobs._lastClickFire[inst] = nil
	end
	if #list <= 0 then
		if kind == "prompt" then
			NAjobs._promptCursor = 0
		elseif kind == "click" then
			NAjobs._clickCursor = 0
		end
	end
end

NAjobs._ensureTracked = function()
	if NAjobs._trackedReady then
		return
	end
	NAjobs._trackedReady = true
	for _, inst in ipairs(NAmanage.qDesc(workspace, "Instance")) do
		if inst:IsA("ProximityPrompt") then
			NAjobs._trackedAdd("prompt", inst)
		elseif inst:IsA("ClickDetector") then
			NAjobs._trackedAdd("click", inst)
		end
	end
	NAlib.connect("NAjobs_track_add", NAmanage.descAdd(workspace, function(inst)
		if inst:IsA("ProximityPrompt") then
			NAjobs._trackedAdd("prompt", inst)
		elseif inst:IsA("ClickDetector") then
			NAjobs._trackedAdd("click", inst)
		end
	end, function(inst)
		return inst and (inst:IsA("ProximityPrompt") or inst:IsA("ClickDetector"))
	end))
	NAlib.connect("NAjobs_track_rem", NAmanage.descRem(workspace, function(inst)
		if inst:IsA("ProximityPrompt") then
			NAjobs._trackedRemove("prompt", inst)
		elseif inst:IsA("ClickDetector") then
			NAjobs._trackedRemove("click", inst)
		end
	end))
end

NAjobs._resolvePromptPart = function(pp)
	if not (pp and pp.Parent) then
		return nil
	end
	local parent = pp.Parent
	if parent:IsA("Attachment") then
		local p = parent.Parent
		if p and p:IsA("BasePart") then
			return p
		end
	elseif parent:IsA("BasePart") then
		return parent
	end
	local model = pp:FindFirstAncestorWhichIsA("Model")
	if model then
		return model.PrimaryPart or model:FindFirstChildWhichIsA("BasePart", true)
	end
	return pp:FindFirstAncestorWhichIsA("BasePart")
end

NAjobs._resolveClickPart = function(cd)
	if not (cd and cd.Parent) then
		return nil
	end
	local src = cd.Parent
	if src:IsA("BasePart") then
		return src
	end
	if src:IsA("Model") then
		return src.PrimaryPart or src:FindFirstChildWhichIsA("BasePart", true)
	end
	local model = cd:FindFirstAncestorWhichIsA("Model")
	if model then
		return model.PrimaryPart or model:FindFirstChildWhichIsA("BasePart", true)
	end
	return cd:FindFirstAncestorWhichIsA("BasePart")
end

NAjobs._collectNames = function(kind, inst, part)
	local names = {}
	local function add(v)
		if not v then
			return
		end
		local s = Lower(tostring(v))
		if s ~= "" then
			names[#names + 1] = s
		end
	end
	if kind == "prompt" then
		add(inst.Name)
		add(inst.ObjectText)
		add(inst.ActionText)
		local parent = inst.Parent
		if parent then
			add(parent.Name)
		end
	else
		add(inst.Name)
		local parent = inst.Parent
		if parent then
			add(parent.Name)
		end
	end
	if part then
		add(part.Name)
		local m = part:FindFirstAncestorWhichIsA("Model")
		while m do
			add(m.Name)
			m = m:FindFirstAncestorWhichIsA("Model")
		end
	end
	return names
end

NAjobs._matchNames = function(matcher, names, target)
	if not target or target == "" then
		return true
	end
	return matcher(names, target)
end

NAjobs._claim = function(key)
	if not key then return true end
	if NAjobs._claimed[key] == NAjobs._frame then return false end
	NAjobs._claimed[key] = NAjobs._frame
	return true
end

NAjobs._restoreTouchDue = function()
	local now = time()
	for part, st in pairs(NAjobs._touchState) do
		if st.moved and st.restoreAt and now >= st.restoreAt then
			if part and part.Parent then
				part.CFrame = st.orig
			end
			st.moved = false
			st.orig = nil
			st.restoreAt = nil
			NAjobs._touchState[part] = nil
		end
	end
end

NAjobs._effectiveInterval = function(job, zeroCount)
	local ivl = tonumber(job and job.interval) or 0
	if ivl > 0 then
		return ivl
	end
	local minIvl = math.max(0.01, tonumber(NAjobs._zeroMinInterval) or 0.03)
	local targetTPS = math.max(1, tonumber(NAjobs._zeroTargetTicksPerSecond) or 45)
	return math.max(minIvl, (tonumber(zeroCount) or 1) / targetTPS)
end

NAjobs._enqueue = function(job)
	local tail = (NAjobs._qTail or 0) + 1
	NAjobs._qTail = tail
	NAjobs._q[tail] = job
end

NAjobs._dequeue = function()
	local head = NAjobs._qHead or 1
	local tail = NAjobs._qTail or 0
	if head > tail then
		return nil
	end
	local job = NAjobs._q[head]
	NAjobs._q[head] = nil
	head += 1
	if head > tail then
		NAjobs._qHead = 1
		NAjobs._qTail = 0
	else
		NAjobs._qHead = head
	end
	return job
end

NAjobs._buildTargetPlan = function(dueJobs)
	local plan = {
		all = false,
		exact = {},
		findList = {},
	}
	local findSeen = {}
	for i = 1, #dueJobs do
		local job = dueJobs[i]
		local target = job and job.target
		if not target or target == "" then
			plan.all = true
		elseif job.useFind then
			if not findSeen[target] then
				findSeen[target] = true
				Insert(plan.findList, target)
			end
		else
			plan.exact[target] = true
		end
	end
	return plan
end

NAjobs._matchesTargetPlan = function(names, plan)
	if plan.all then
		return true
	end
	for i = 1, #names do
		if plan.exact[names[i]] then
			return true
		end
	end
	local findList = plan.findList
	for i = 1, #findList do
		local target = findList[i]
		for j = 1, #names do
			local name = names[j]
			if name == target or Find(name, target, 1, true) then
				return true
			end
		end
	end
	return false
end

NAjobs._batchInterval = function(dueJobs, zeroCount, floor)
	local minInterval = nil
	for i = 1, #dueJobs do
		local job = dueJobs[i]
		if job and NAjobs.jobs[job.id] == job then
			local ivl = NAjobs._effectiveInterval(job, zeroCount)
			if not minInterval or ivl < minInterval then
				minInterval = ivl
			end
		end
	end
	if not minInterval then
		minInterval = 0.1
	end
	local minFloor = tonumber(floor) or 0
	if minInterval < minFloor then
		minInterval = minFloor
	end
	return minInterval
end

NAjobs._canRefire = function(lastMap, inst, now, cooldown)
	if type(lastMap) ~= "table" or not inst then
		return true
	end
	local cd = tonumber(cooldown) or 0
	if cd <= 0 then
		return true
	end
	local last = tonumber(lastMap[inst]) or 0
	return (now - last) >= cd
end

NAjobs._runPromptBatch = function(dueJobs)
	local char = getChar()
	local root = char and (getRoot(char) or char:FindFirstChildWhichIsA("BasePart"))
	if not root then
		return
	end
	local rootPos = root.Position
	local useRange = NAStuff.AutoInteractDistanceEnabled ~= false
	local extraRange = tonumber(NAStuff.AutoInteractExtraRange) or 5
	local tracked = (NAjobs._tracked.prompt and NAjobs._tracked.prompt.list) or {}
	local trackedCount = #tracked
	if trackedCount <= 0 then
		NAjobs._promptCursor = 0
		return
	end
	local plan = NAjobs._buildTargetPlan(dueJobs)
	local needsNames = not plan.all and (next(plan.exact) ~= nil or #plan.findList > 0)
	local maxFires = math.max(1, math.floor(tonumber(NAjobs._promptMaxFiresPerBatch) or 18))
	local scanBudget = math.max(1, math.floor(tonumber(NAjobs._promptScanPerBatch) or trackedCount))
	if scanBudget < maxFires then
		scanBudget = maxFires
	end
	if scanBudget > trackedCount then
		scanBudget = trackedCount
	end
	local cursor = tonumber(NAjobs._promptCursor) or 0
	local cooldown = tonumber(NAjobs._promptRefireFloor) or 0
	local dynamicFloor = NAjobs._batchInterval(dueJobs, 0, 0)
	if dynamicFloor > cooldown then
		cooldown = dynamicFloor
	end
	local now = time()
	local stale = {}
	local fired = 0
	local lastMap = NAjobs._lastPromptFire
	if type(lastMap) ~= "table" then
		lastMap = {}
		NAjobs._lastPromptFire = lastMap
	end
	for step = 1, scanBudget do
		if fired >= maxFires then
			break
		end
		local idx = ((cursor + step - 1) % trackedCount) + 1
		local inst = tracked[idx]
		if not (inst and inst.Parent) then
			if inst then
				Insert(stale, inst)
			end
		else
			local part = NAjobs._resolvePromptPart(inst)
			if part and inst.Enabled then
				local ok = true
				if needsNames then
					local names = NAjobs._collectNames("prompt", inst, part)
					ok = NAjobs._matchesTargetPlan(names, plan)
				end
				if ok and useRange then
					local dist = (part.Position - rootPos).Magnitude
					ok = dist <= ((inst.MaxActivationDistance or 0) + extraRange)
				end
				if ok and NAjobs._claim(inst) and NAjobs._canRefire(lastMap, inst, now, cooldown) then
					local okFire = pcall(fireproximityprompt, inst)
					if okFire then
						lastMap[inst] = now
						fired += 1
					end
				end
			end
		end
	end
	NAjobs._promptCursor = (cursor + scanBudget) % trackedCount
	for i = 1, #stale do
		NAjobs._trackedRemove("prompt", stale[i])
	end
end

NAjobs._runClickBatch = function(dueJobs)
	local char = getChar()
	local root = char and (getRoot(char) or char:FindFirstChildWhichIsA("BasePart"))
	if not root then
		return
	end
	local rootPos = root.Position
	local useRange = NAStuff.AutoInteractDistanceEnabled ~= false
	local extraRange = tonumber(NAStuff.AutoInteractExtraRange) or 5
	local tracked = (NAjobs._tracked.click and NAjobs._tracked.click.list) or {}
	local trackedCount = #tracked
	if trackedCount <= 0 then
		NAjobs._clickCursor = 0
		return
	end
	local plan = NAjobs._buildTargetPlan(dueJobs)
	local needsNames = not plan.all and (next(plan.exact) ~= nil or #plan.findList > 0)
	local maxFires = math.max(1, math.floor(tonumber(NAjobs._clickMaxFiresPerBatch) or 18))
	local scanBudget = math.max(1, math.floor(tonumber(NAjobs._clickScanPerBatch) or trackedCount))
	if scanBudget < maxFires then
		scanBudget = maxFires
	end
	if scanBudget > trackedCount then
		scanBudget = trackedCount
	end
	local cursor = tonumber(NAjobs._clickCursor) or 0
	local cooldown = tonumber(NAjobs._clickRefireFloor) or 0
	local dynamicFloor = NAjobs._batchInterval(dueJobs, 0, 0)
	if dynamicFloor > cooldown then
		cooldown = dynamicFloor
	end
	local now = time()
	local stale = {}
	local fired = 0
	local lastMap = NAjobs._lastClickFire
	if type(lastMap) ~= "table" then
		lastMap = {}
		NAjobs._lastClickFire = lastMap
	end
	for step = 1, scanBudget do
		if fired >= maxFires then
			break
		end
		local idx = ((cursor + step - 1) % trackedCount) + 1
		local inst = tracked[idx]
		if not (inst and inst.Parent) then
			if inst then
				Insert(stale, inst)
			end
		else
			local part = NAjobs._resolveClickPart(inst)
			if part then
				local ok = true
				if needsNames then
					local names = NAjobs._collectNames("click", inst, part)
					ok = NAjobs._matchesTargetPlan(names, plan)
				end
				if ok and useRange then
					local dist = (part.Position - rootPos).Magnitude
					ok = dist <= ((inst.MaxActivationDistance or 0) + extraRange)
				end
				if ok and NAjobs._claim(inst) and NAjobs._canRefire(lastMap, inst, now, cooldown) then
					local okFire = pcall(fireclickdetector, inst)
					if okFire then
						lastMap[inst] = now
						fired += 1
					end
				end
			end
		end
	end
	NAjobs._clickCursor = (cursor + scanBudget) % trackedCount
	for i = 1, #stale do
		NAjobs._trackedRemove("click", stale[i])
	end
end

NAjobs._runStep = function()
	NAjobs._frame = (NAjobs._frame or 0) + 1
	NAjobs._claimed = {}
	local now = time()
	local zeroCount = 0
	local duePrompt = {}
	local dueClick = {}
	local dueOther = {}
	for _, job in pairs(NAjobs.jobs) do
		if job.interval <= 0 then
			zeroCount += 1
		end
		if now >= (job.next or 0) then
			if job.kind == "prompt" then
				Insert(duePrompt, job)
			elseif job.kind == "click" then
				Insert(dueClick, job)
			else
				Insert(dueOther, job)
			end
		end
	end

	local ranPromptBatch = false
	local ranClickBatch = false
	if #duePrompt > 0 then
		local nextAt = tonumber(NAjobs._promptBatchNext) or 0
		if now >= nextAt then
			NAjobs._runPromptBatch(duePrompt)
			ranPromptBatch = true
			NAjobs._promptBatchNext = now + NAjobs._batchInterval(duePrompt, zeroCount, NAjobs._promptBatchFloor)
		end
	end
	if #dueClick > 0 then
		local nextAt = tonumber(NAjobs._clickBatchNext) or 0
		if now >= nextAt then
			NAjobs._runClickBatch(dueClick)
			ranClickBatch = true
			NAjobs._clickBatchNext = now + NAjobs._batchInterval(dueClick, zeroCount, NAjobs._clickBatchFloor)
		end
	end
	if ranPromptBatch then
		for i = 1, #duePrompt do
			local job = duePrompt[i]
			if NAjobs.jobs[job.id] == job then
				job.next = now + NAjobs._effectiveInterval(job, zeroCount)
			end
		end
	end
	if ranClickBatch then
		for i = 1, #dueClick do
			local job = dueClick[i]
			if NAjobs.jobs[job.id] == job then
				job.next = now + NAjobs._effectiveInterval(job, zeroCount)
			end
		end
	end

	local budget = math.max(1, math.floor(tonumber(NAjobs._maxTicksPerStep) or 2))
	local ran = 0
	for i = 1, #dueOther do
		if ran >= budget then
			break
		end
		local job = dueOther[i]
		if NAjobs.jobs[job.id] == job then
			job.next = now + NAjobs._effectiveInterval(job, zeroCount)
			pcall(job.tick, job)
			ran += 1
		end
	end
	NAjobs._restoreTouchDue()
end

NAjobs._schedule = function()
	if NAjobs.hb then return end
	NAjobs._accum = 0
	NAjobs.hb = NAlib.connect("NAjobs_stp", RunService.Heartbeat:Connect(function(dt)
		local step = tonumber(NAjobs._stepInterval) or (1 / 120)
		if step <= 0 then
			step = 1 / 120
		end
		local maxCatch = math.max(1, math.floor(tonumber(NAjobs._maxCatchUpSteps) or 6))
		local delta = tonumber(dt) or 0
		if delta < 0 then
			delta = 0
		end
		NAjobs._accum = (tonumber(NAjobs._accum) or 0) + delta

		local loops = 0
		while NAjobs._accum >= step and loops < maxCatch do
			NAjobs._accum -= step
			loops += 1
			NAjobs._runStep()
		end

		local maxAccum = step * maxCatch
		if NAjobs._accum > maxAccum then
			NAjobs._accum = maxAccum
		end
	end))
end

NAjobs._maybeStop = function()
	if not next(NAjobs.jobs) then
		if NAjobs.hb then
			NAlib.disconnect("NAjobs_stp")
			NAjobs.hb = nil
		end
		NAjobs._q = {}
		NAjobs._qHead = 1
		NAjobs._qTail = 0
		NAjobs._accum = 0
		NAjobs._promptBatchNext = 0
		NAjobs._clickBatchNext = 0
		NAjobs._promptCursor = 0
		NAjobs._clickCursor = 0
		NAjobs._lastPromptFire = {}
		NAjobs._lastClickFire = {}
		NAjobs._claimed = {}
	end
end

NAjobs._findExisting = function(kind, target, useFind)
	local findMode = useFind and true or false
	for id, job in pairs(NAjobs.jobs) do
		if job.kind == kind and (job.target or nil) == target and (job.useFind and true or false) == findMode then
			return id, job
		end
	end
	return nil
end

NAjobs._nextIdForKind = function(kind)
	local used = {}
	for id, job in pairs(NAjobs.jobs) do
		if job.kind == kind then
			local n = tonumber(tostring(id):match("^"..kind.."#(%d+)$"))
			if n then used[n] = true end
		end
	end
	local i = 1
	while used[i] do i += 1 end
	return kind.."#"..tostring(i)
end

NAjobs.start = function(kind, interval, target, useFind)
	NAindex.init()
	if kind == "prompt" or kind == "click" then
		NAjobs._ensureTracked()
	end
	local tgt = target and Lower(target) or nil
	local ivl = interval or 0.1
	local ivlClamped = math.max(0, ivl)
	local staggerCap = math.max(0, tonumber(NAjobs._staggerCap) or 0.003)
	local stagger = ivlClamped > 0 and math.min(staggerCap, ivlClamped / 48) or 0
	local matcher = useFind and NAindex.matchAnyFind or NAindex.matchAny
	local existingId, existingJob = NAjobs._findExisting(kind, tgt, useFind)
	if existingJob then
		existingJob.interval = ivlClamped
		existingJob.target = tgt
		existingJob.m = matcher
		existingJob.useFind = useFind and true or false
		existingJob.stagger = stagger
		existingJob.next = time()
		return existingId, true
	end
	local id = NAjobs._nextIdForKind(kind)
	local job = {
		id = id,
		kind = kind,
		interval = ivlClamped,
		target = tgt,
		next = time(),
		stagger = stagger,
		m = matcher,
		useFind = useFind and true or false
	}
	if kind == "prompt" then
		job.tick = function(self)
			local char = getChar()
			local root = char and (getRoot(char) or char:FindFirstChildWhichIsA("BasePart"))
			if not root then
				return
			end
			local rootPos = root.Position
			local useRange = NAStuff.AutoInteractDistanceEnabled ~= false
			local extraRange = tonumber(NAStuff.AutoInteractExtraRange) or 5
			local tracked = (NAjobs._tracked.prompt and NAjobs._tracked.prompt.list) or {}
			local hasTarget = self.target ~= nil and self.target ~= ""
			for i = #tracked, 1, -1 do
				local inst = tracked[i]
				if not (inst and inst.Parent) then
					NAjobs._trackedRemove("prompt", inst)
				else
					local part = NAjobs._resolvePromptPart(inst)
					if not part then
						continue
					end
					local ok = true
					if hasTarget then
						local names = NAjobs._collectNames("prompt", inst, part)
						ok = NAjobs._matchNames(self.m, names, self.target)
					end
					if ok and useRange then
						local dist = (part.Position - rootPos).Magnitude
						ok = dist <= ((inst.MaxActivationDistance or 0) + extraRange)
					end
					if ok and part and inst.Enabled then
						pcall(fireproximityprompt, inst)
					end
				end
			end
		end
	elseif kind == "click" then
		job.tick = function(self)
			local char = getChar()
			local root = char and (getRoot(char) or char:FindFirstChildWhichIsA("BasePart"))
			if not root then
				return
			end
			local rootPos = root.Position
			local useRange = NAStuff.AutoInteractDistanceEnabled ~= false
			local extraRange = tonumber(NAStuff.AutoInteractExtraRange) or 5
			local tracked = (NAjobs._tracked.click and NAjobs._tracked.click.list) or {}
			local hasTarget = self.target ~= nil and self.target ~= ""
			for i = #tracked, 1, -1 do
				local inst = tracked[i]
				if not (inst and inst.Parent) then
					NAjobs._trackedRemove("click", inst)
				else
					local part = NAjobs._resolveClickPart(inst)
					if not part then
						continue
					end
					local ok = true
					if hasTarget then
						local names = NAjobs._collectNames("click", inst, part)
						ok = NAjobs._matchNames(self.m, names, self.target)
					end
					if ok and useRange then
						local dist = (part.Position - rootPos).Magnitude
						ok = dist <= ((inst.MaxActivationDistance or 0) + extraRange)
					end
					if ok and part then
						pcall(fireclickdetector, inst)
					end
				end
			end
		end
	elseif kind == "touch" then
		job.tick = function(self)
			if not InstancesTbl or type(InstancesTbl.touch) ~= "table" then
				return
			end
			local char = getChar()
			local root = char and (getRoot(char) or char:FindFirstChildWhichIsA("BasePart"))
			if not root or (not root:IsDescendantOf(workspace)) then
				return
			end
			local list = {}
			local touchTbl = InstancesTbl.touch
			local hasTarget = self.target ~= nil and self.target ~= ""
			for i = 1, #touchTbl do
				local ti = touchTbl[i]
				if ti then
					local container = ti.Parent
					if container and container.Parent then
						local part = NAindex.carPart(container)
						if part then
							local ok = false
							if hasTarget then
								local names = NAindex.namesForPart(part)
								if self.m(names, self.target) then
									ok = true
								end
							else
								ok = true
							end
							if ok then
								local asm = part.AssemblyRootPart or part
								if asm then
									local n = #list + 1
									list[n] = {
										part = asm
									}
								end
							end
						end
					end
				end
			end
			for _, it in ipairs(list) do
				if NAjobs._claim(it.part) then
					Spawn(function()
						local asm = it.part
						if not asm or (not asm.Parent) or (not asm:IsDescendantOf(workspace)) then
							return
						end
						local st = NAjobs._touchState[asm]
						if not st or (not st.moved) then
							st = st or {}
							st.orig = asm.CFrame
							st.moved = true
							NAjobs._touchState[asm] = st
						end
						local char2 = getChar()
						local root2 = char2 and (getRoot(char2) or char2:FindFirstChildWhichIsA("BasePart"))
						if not root2 or (not root2:IsDescendantOf(workspace)) then
							return
						end
						asm:PivotTo(root2.CFrame)
						pcall(firetouchinterest, asm, root2, 1)
						Wait()
						pcall(firetouchinterest, asm, root2, 0)
						st.restoreAt = time() + 0.05
					end)
				end
			end
		end
	end
	NAjobs.jobs[id] = job
	NAjobs._schedule()
	return id
end

NAjobs._restoreAllTouch = function()
	for part, st in pairs(NAjobs._touchState) do
		if st.moved and st.orig and part and part.Parent then
			part.CFrame = st.orig
		end
		NAjobs._touchState[part] = nil
	end
end

NAjobs.stopByKind = function(kind)
	for id, job in pairs(NAjobs.jobs) do
		if job.kind == kind then NAjobs.jobs[id] = nil end
	end
	if kind == "touch" then NAjobs._restoreAllTouch() end
	NAjobs._maybeStop()
end

NAjobs.stopById = function(id)
	local job = NAjobs.jobs[id]
	if not job then return end
	NAjobs.jobs[id] = nil
	if job.kind == "touch" then NAjobs._restoreAllTouch() end
	NAjobs._maybeStop()
end

NAjobs.stopAll = function()
	for id in pairs(NAjobs.jobs) do NAjobs.jobs[id] = nil end
	NAjobs._restoreAllTouch()
	NAjobs._maybeStop()
end

NAjobs.setAutoIntervalLink = function(id, linked)
	local job = NAjobs.jobs[id]
	if not job then
		return false
	end
	job.autoIntervalLinked = linked == true
	return true
end

NAjobs.applyLinkedAutoInteractInterval = function(interval)
	local n = tonumber(interval)
	if not n then
		return 0
	end
	local ivl = math.max(0, n)
	local changed = 0
	for _, job in pairs(NAjobs.jobs) do
		if job and (job.kind == "prompt" or job.kind == "click" or job.kind == "touch") and job.autoIntervalLinked == true then
			job.interval = ivl
			job.next = time()
			changed += 1
		end
	end
	return changed
end

NAmanage._sortedJobs = function(kind, useFind)
	local list = {}
	local findMode = useFind and true or false
	for _, job in pairs(NAjobs.jobs) do
		if job.kind == kind and (job.useFind and true or false) == findMode then
			Insert(list, job)
		end
	end
	table.sort(list, function(a, b)
		local ai = tonumber(tostring(a.id):match("#(%d+)$")) or math.huge
		local bi = tonumber(tostring(b.id):match("#(%d+)$")) or math.huge
		if ai == bi then
			return (a.target or "") < (b.target or "")
		end
		return ai < bi
	end)
	return list
end

local function buildStopWindow(kind, titleText, useFind)
	local buttons = {}
	for _, job in ipairs(NAmanage._sortedJobs(kind, useFind)) do
		local label = job.id..(job.target and (" • "..job.target) or "")
		Insert(buttons, {
			Text = label,
			Callback = function()
				NAjobs.stopById(job.id)
				DebugNotif("stopped "..label, 2)
			end
		})
	end
	Insert(buttons, {
		Text = "All",
		Callback = function()
			for jid, j in pairs(NAjobs.jobs) do
				if j.kind == kind and (j.useFind and true or false) == (useFind and true or false) then
					NAjobs.stopById(jid)
				end
			end
			local suffix = useFind and " (find)" or ""
			DebugNotif("all "..kind..suffix.." stopped", 2)
		end
	})
	Window({
		Title = titleText,
		Buttons = buttons
	})
end

NAmanage._windowStopKind=function(kind, titleText)
	buildStopWindow(kind, titleText, false)
end

NAmanage._windowStopKindFind=function(kind, titleText)
	buildStopWindow(kind, titleText, true)
end

cmd.add({"autofireproxi","afp"},{"autofireproxi <interval> [target]","Automatically fires ProximityPrompts matching [target] every <interval> seconds"}, function(...)
	local args = {...}
	local interval, target
	local defaultInterval = NAmanage.getAutoInteractDefaultInterval()
	local useDefaultInterval = args[1] == nil or not tonumber(args[1])
	if args[1] and not tonumber(args[1]) then
		interval = defaultInterval
		target = Lower(Concat(args, " ", 1))
	else
		interval, target = NAutil.parseInterval(defaultInterval, ...)
	end
	local id, reused = NAjobs.start("prompt", interval, target)
	NAjobs.setAutoIntervalLink(id, useDefaultInterval)
	local action = reused and "updated" or "started"
	DebugNotif(target and ("afp %s (%s) → %s"):format(action, target, id) or ("afp %s → %s"):format(action, id), 2)
end, true)

