NAmanage.fastWorkspaceMatches=function(className, needle, mode)
	local query = type(needle) == "string" and Lower(needle) or ""
	if query == "" then
		return {}
	end

	return NAmanage.fastDesc(workspace, className, {
		match = function(inst)
			if mode == "class" then
				return Lower(inst.ClassName) == query
			end

			local instName = Lower(inst.Name)
			if mode == "exact" then
				return instName == query
			end

			return Find(instName, query, 1, true) ~= nil
		end
	})
end

cmd.add({"gotopart", "topart", "toprt"}, {"gotopart {partname}", "Teleports you to each matching part by name once"}, function(...)
	local partName = Concat({...}, " "):lower()
	local commandKey = "gotopart"

	if NAStuff.activeTeleports[commandKey] then
		NAStuff.activeTeleports[commandKey].active = false
	end

	local taskState = {active = true}
	NAStuff.activeTeleports[commandKey] = taskState

	SpawnCall(function()
		local partDelay = NAmanage.tpDelay()
		for _, part in ipairs(NAmanage.fastWorkspaceMatches("BasePart", partName, "exact")) do
			if not taskState.active then return end
			if part.Name:lower() == partName then
				if getHum() then getHum().Sit = false Wait(0.1) end
				if getChar() then getChar():PivotTo(part:GetPivot()) end
				Wait(partDelay)
			end
		end
	end)
end, true)

cmd.add({"tweengotopart","tgotopart","ttopart","ttoprt"},{"tweengotopart <partName>","Tween to each matching part by name once"},function(...)
	local partName = Concat({...}," "):lower()
	local key      = "tweengotopart"
	if NAStuff.activeTeleports[key] then NAStuff.activeTeleports[key].active = false end
	local state    = {active = true}
	NAStuff.activeTeleports[key] = state
	local tweenAttrActive = "NATweenGoToPartActive"
	local tweenAttrStart = "NATweenGoToPartStartCF"
	local tweenAttrTarget = "NATweenGoToPartTargetCF"
	local tweenAttrCurrent = "NATweenGoToPartCurrentCF"
	SpawnCall(function()
		local partDelay = NAmanage.tpDelay()
		for _,obj in ipairs(NAmanage.fastWorkspaceMatches("BasePart", partName, "exact")) do
			if not state.active then return end
			if obj.Name:lower() == partName then
				local hum = getHum()
				if hum then hum.Sit = false end
				local char = getChar()
				if char then
					local duration = NAmanage.resolveTweenDuration()
					local startCF = char:GetPivot()
					local targetCF = obj:GetPivot()
					local elapsed = 0
					local done = false
					local hbConn
					NAmanage.SetAttr(char, tweenAttrActive, true)
					NAmanage.SetAttr(char, tweenAttrStart, startCF)
					NAmanage.SetAttr(char, tweenAttrTarget, targetCF)
					hbConn = RunService.Heartbeat:Connect(function(dt)
						if not state.active or not char.Parent then
							NAmanage.SetAttr(char, tweenAttrCurrent, nil)
							NAmanage.SetAttr(char, tweenAttrActive, false)
							done = true
							if hbConn then
								hbConn:Disconnect()
								hbConn = nil
							end
							return
						end
						elapsed += dt
						local alpha = duration <= 0 and 1 or math.clamp(elapsed / duration, 0, 1)
						local currentCF = startCF:Lerp(targetCF, alpha)
						NAmanage.SetAttr(char, tweenAttrCurrent, currentCF)
						char:PivotTo(currentCF)
						if alpha >= 1 then
							NAmanage.SetAttr(char, tweenAttrCurrent, nil)
							NAmanage.SetAttr(char, tweenAttrActive, false)
							done = true
							if hbConn then
								hbConn:Disconnect()
								hbConn = nil
							end
						end
					end)
					while state.active and not done do
						Wait()
					end
					Wait(partDelay)
				end
			end
		end
	end)
end,true)


cmd.add({"gotopartfind", "topartfind", "toprtfind"}, {"gotopartfind {name}", "Teleports to each part containing name once"}, function(...)
	local name = Concat({...}, " "):lower()
