cmd.add({"unfolderesp","unfesp"},{"unfolderesp [folderName]","Disables folder ESP for a folder or all"},function(...)
	local members = NAStuff.folderESPMembers
	if type(members) ~= "table" then
		DoNotif("No folder ESP entries are active.", 2)
		return
	end

	local function detachFolder(folder)
		return NAmanage.FolderESP_Disable(folder)
	end

	local function collectTrackedFolders()
		local tracked = {}
		for folder, _ in pairs(members) do
			if typeof(folder) == "Instance" then
				tracked[#tracked + 1] = folder
			else
				members[folder] = nil
			end
		end
		table.sort(tracked, function(a, b)
			return Lower(a.Name) < Lower(b.Name)
		end)
		return tracked
	end

	local function removeAllFolders()
		local tracked = collectTrackedFolders()
		local removed = 0
		for _, folder in ipairs(tracked) do
			if detachFolder(folder) then
				removed += 1
			end
		end
		if removed > 0 then
			DoNotif(Format("Stopped folder ESP for %d folder(s).", removed), 2)
		else
			DoNotif("No folder ESP entries were active.", 2)
		end
	end

	local trackedFolders = collectTrackedFolders()

	local rawInput = Concat({...}, " ")
	rawInput = (type(rawInput) == "string") and rawInput:gsub("^%s+", ""):gsub("%s+$", "") or ""
	local loweredInput = Lower(rawInput)

	if loweredInput ~= "" then
		if loweredInput == "all" or loweredInput == "*" then
			removeAllFolders()
			return
		end

		local picked = nil
		for _, folder in ipairs(trackedFolders) do
			if Lower(folder.Name) == loweredInput then
				picked = folder
				break
			end
		end

		if not picked then
			for _, folder in ipairs(trackedFolders) do
				if Find(Lower(folder.Name), loweredInput, 1, true) then
					picked = folder
					break
				end
			end
		end

		if picked and detachFolder(picked) then
			DoNotif(Format("Stopped folder ESP for '%s'.", picked.Name), 2)
		else
			DoNotif(Format("No folder ESP entry matching '%s'.", rawInput ~= "" and rawInput or loweredInput), 3)
		end
		return
	end

	if #trackedFolders == 0 then
		DoNotif("No folder ESP entries are active.", 2)
		return
	end

	local buttons = {
		{
			Text = "All",
			Callback = removeAllFolders
		}
	}

	for _, folder in ipairs(trackedFolders) do
		local folderRef = folder
		buttons[#buttons + 1] = {
			Text = folderRef.Name,
			Callback = function()
				if detachFolder(folderRef) then
					DoNotif(Format("Stopped folder ESP for '%s'.", folderRef.Name), 2)
				else
					DoNotif("Folder ESP entry was not active.", 2)
				end
			end
		}
	end

	Window({
		Title = "Folder ESP",
		Description = "Select a folder ESP entry to disable.",
		Buttons = buttons
	})
end,true)

cmd.add({"unmodelesp","unmesp"},{"unmodelesp [modelName]","Disables model ESP for a model or all"},function(...)
	local models = NAStuff.modelESPModels
	local map = NAStuff.modelESPMap
	if type(models) ~= "table" or #models == 0 then
		DoNotif("No model ESP entries are active.", 2)
		return
	end

	local function detachModel(model)
		if typeof(model) ~= "Instance" then
			return false
		end
		return NAmanage.ModelESP_Disable(model)
	end

	local function collectTrackedModels()
		local tracked = {}
		for i = #models, 1, -1 do
			local model = models[i]
			if typeof(model) == "Instance" and model:IsA("Model") and model.Parent and model:FindFirstChildWhichIsA("BasePart", true) then
				tracked[#tracked + 1] = model
			else
				NAmanage.ModelESP_Disable(model)
			end
		end
		table.sort(tracked, function(a, b)
			return Lower(a.Name) < Lower(b.Name)
		end)
		return tracked
	end

	local function removeAllModels()
		local tracked = collectTrackedModels()
		local removed = 0
		for _, model in ipairs(tracked) do
			if detachModel(model) then
				removed += 1
			end
		end
		if removed > 0 then
			DoNotif(Format("Stopped model ESP for %d model(s).", removed), 2)
		else
			DoNotif("No model ESP entries were active.", 2)
		end
	end

	local trackedModels = collectTrackedModels()
	local rawInput = Concat({...}, " ")
	rawInput = (type(rawInput) == "string") and rawInput:gsub("^%s+", ""):gsub("%s+$", "") or ""
	local loweredInput = Lower(rawInput)

	if loweredInput ~= "" then
		if loweredInput == "all" or loweredInput == "*" then
			removeAllModels()
			return
		end

		local picked = nil
		for _, model in ipairs(trackedModels) do
			if Lower(model.Name) == loweredInput then
				picked = model
				break
			end
		end
		if not picked then
			for _, model in ipairs(trackedModels) do
				if Find(Lower(model.Name), loweredInput, 1, true) then
					picked = model
					break
				end
			end
		end

		if picked and detachModel(picked) then
			DoNotif(Format("Stopped model ESP for '%s'.", picked.Name), 2)
		else
			DoNotif(Format("No model ESP entry matching '%s'.", rawInput ~= "" and rawInput or loweredInput), 3)
		end
		return
	end

	if #trackedModels == 0 then
		DoNotif("No model ESP entries are active.", 2)
		return
	end

	local buttons = {
		{
			Text = "All",
			Callback = removeAllModels
		}
	}

	for _, model in ipairs(trackedModels) do
		local modelRef = model
		buttons[#buttons + 1] = {
			Text = modelRef.Name,
			Callback = function()
				if detachModel(modelRef) then
					DoNotif(Format("Stopped model ESP for '%s'.", modelRef.Name), 2)
				else
					DoNotif("Model ESP entry was not active.", 2)
				end
			end
		}
	end

	Window({
		Title = "Model ESP",
		Description = "Select a model ESP entry to disable.",
		Buttons = buttons
	})
end,true)

cmd.add({"viewpart", "viewp", "vpart"}, {"viewpart {partName} (viewp, vpart)", "Focuses camera on a part, model, or folder"},function(...)
