NAmanage.HB_Defaults=function()
	return {
		size = 10;
		transparency = 0.9;
		color = { R = 0; G = 0; B = 0 };
		material = "Neon";
		noCollide = true;
		massless = true;
	}
end

NAmanage.HB_Coerce=function(opts)
	local base = NAmanage.HB_Defaults()
	if type(opts) ~= "table" then
		return base
	end
	if typeof(opts.color) == "Color3" then
		base.color = { R = opts.color.R; G = opts.color.G; B = opts.color.B }
	elseif type(opts.color) == "table" then
		base.color = {
			R = math.clamp(opts.color.R or opts.color.r or opts.color[1] or base.color.R, 0, 1);
			G = math.clamp(opts.color.G or opts.color.g or opts.color[2] or base.color.G, 0, 1);
			B = math.clamp(opts.color.B or opts.color.b or opts.color[3] or base.color.B, 0, 1);
		}
	end
	base.size = math.clamp(tonumber(opts.size) or base.size, 0.1, 200)
	base.transparency = math.clamp(tonumber(opts.transparency) or base.transparency, 0, 1)
	if opts.material ~= nil then
		base.material = NAmanage.HB_ResolveMaterial(opts.material)
	end
	base.noCollide = opts.noCollide ~= false
	base.massless = opts.massless ~= false
	return base
end

NAmanage.HB_ColorFromOpt=function(opt)
	if typeof(opt) == "Color3" then
		return opt
	end
	if type(opt) == "table" then
		local r = tonumber(opt.R or opt.r or opt[1])
		local g = tonumber(opt.G or opt.g or opt[2])
		local b = tonumber(opt.B or opt.b or opt[3])
		if r and g and b then
			return Color3.new(math.clamp(r, 0, 1), math.clamp(g, 0, 1), math.clamp(b, 0, 1))
		end
	end
	return BrickColor.new("Really black").Color
end

NAmanage.HB_ResolveMaterial=function(matName)
	local items = Enum.Material:GetEnumItems()
	local defaultMat = "Neon"
	if matName == nil then return defaultMat end
	local input = tostring(matName)
	if input == "" then return defaultMat end
	local lowerInput = input:lower()

	local bestName = nil
	local bestScore = math.huge

	local function score(name)
		local lname = name:lower()
		if lname == lowerInput then return 0 end
		if lname:sub(1, #lowerInput) == lowerInput then return 1 end
		if lname:find(lowerInput, 1, true) then return 2 end
		return 3
	end

	for _, item in ipairs(items) do
		local s = score(item.Name)
		if s < bestScore or (s == bestScore and #item.Name < #(bestName or item.Name)) then
			bestScore = s
			bestName = item.Name
			if s == 0 then
				break
			end
		end
	end

	return bestName or defaultMat
end

NAStuff.HitboxOptions = NAmanage.HB_Coerce(NAStuff.HitboxOptions or (NAmanage.NASettingsGet and NAmanage.NASettingsGet("hitboxOptions")))

function NAmanage.GetHitboxOpts()
	NAStuff.HitboxOptions = NAmanage.HB_Coerce(NAStuff.HitboxOptions)
	return NAStuff.HitboxOptions
end

function NAmanage.SetHitboxOpt(key, value)
	local opts = NAmanage.HB_Coerce(NAStuff.HitboxOptions)
	opts[key] = value
	opts = NAmanage.HB_Coerce(opts)
	NAStuff.HitboxOptions = opts
	if NAmanage.NASettingsSet then
		pcall(NAmanage.NASettingsSet, "hitboxOptions", opts)
	end
	if NAmanage.HitboxUpdateActive then
		NAmanage.HitboxUpdateActive(opts)
	end
	return opts
end

function NAmanage.HitboxUpdateActive(newOpts)
	local opts = NAmanage.HB_Coerce(newOpts or NAmanage.GetHitboxOpts())
	local function rescan(D)
		if not (D and D.ps) then return end
		for key,_ in pairs(D.ps) do
			local ch = nil
			if typeof(key) == "Instance" and key:IsA("Player") then
				ch = getPlrChar(key)
			elseif typeof(key) == "Instance" and key:IsA("Model") then
				ch = key
			end
			if ch and ch.Parent then
				for _,bp in ipairs(ch:GetChildren()) do
					if bp:IsA("BasePart") then
						D.ps[key] = D.ps[key] or {}
						D.ps[key][bp] = true
					end
				end
			end
		end
	end
	local function updateCfg(D)
		if not (D and D.cfg) then return end
		rescan(D)
		D.cfg.sz = Vector3.new(opts.size, opts.size, opts.size)
		D.cfg.tr = opts.transparency
		D.cfg.bc = BrickColor.new(NAmanage.HB_ColorFromOpt(opts.color))
		D.cfg.mat = Enum.Material[NAmanage.HB_ResolveMaterial(opts.material or "Neon")] or Enum.Material.Neon
		D.cfg.noCollide = opts.noCollide ~= false
		D.cfg.massless = opts.massless ~= false
		local function match(bp)
			if not bp then return false end
			if D.cfg.limb == "All" then return true end
			return Lower(bp.Name) == D.cfg.limbL
		end
		for key, set in pairs(D.ps or {}) do
			for bp,_ in pairs(set) do
				if bp and bp.Parent and match(bp) then
					D.og[key] = D.og[key] or {}
					if not D.og[key][bp] then
						D.og[key][bp] = {
							Size=bp.Size, Transparency=bp.Transparency, BrickColor=bp.BrickColor,
							Material=bp.Material, CanCollide=bp.CanCollide, Massless=bp.Massless
						}
					end
					if bp.Size ~= D.cfg.sz then bp.Size = D.cfg.sz end
					if bp.Transparency ~= D.cfg.tr then bp.Transparency = D.cfg.tr end
					if bp.BrickColor ~= D.cfg.bc then bp.BrickColor = D.cfg.bc end
					if bp.Material ~= D.cfg.mat then bp.Material = D.cfg.mat end
					if D.cfg.noCollide then
						if bp.CanCollide then bp.CanCollide = false end
					else
						local og = D.og[key][bp]
						if og and bp.CanCollide ~= og.CanCollide then
							bp.CanCollide = og.CanCollide
						end
					end
					if D.cfg.massless then
						if not bp.Massless then bp.Massless = true end
					else
						local og = D.og[key][bp]
						if og and bp.Massless ~= og.Massless then
							bp.Massless = og.Massless
						end
					end
				end
			end
		end
	end
	updateCfg(NAStuff.HB and NAStuff.HB.P)
	updateCfg(NAStuff.HB and NAStuff.HB.N)
end

cmd.add({"hitbox","hbox"}, {"hitbox <player> {size}",""}, function(pArg, sArg)
	NAStuff.HB = NAStuff.HB or {};
	NAStuff.HB.P = NAStuff.HB.P or {
		ps = {},
		og = {},
		ca = {},
		da = {},
		ac = {},
		addConn = nil,
		remConn = nil,
		run = nil,
		cfg = nil
	};
	NAStuff.HB.N = NAStuff.HB.N or {
		ps = {},
		og = {},
		md = {},
		ac = {},
		wc = nil,
		run = nil,
		cfg = nil
	};
	local targets = getPlr(pArg);
	local hbOpts = NAmanage.GetHitboxOpts();
	local n = tonumber(sArg) or hbOpts.size or 10;
	local argL = Lower(pArg);
	local npc = argL == "npc";
	local glb = argL == "all" or argL == "others";
	local allowEmpty = npc or glb;
	if #targets == 0 and (not allowEmpty) then
		DoNotif("No targets found", 2);
		return;
	end;
	local defaultTransparency = math.clamp(tonumber(hbOpts.transparency) or 0.9, 0, 1);
	local defaultColor = NAmanage.HB_ColorFromOpt(hbOpts.color);
	local defaultMaterial = Enum.Material[NAmanage.HB_ResolveMaterial(hbOpts.material or "Neon")] or Enum.Material.Neon;
	local defaultNoCollide = hbOpts.noCollide ~= false;
	local defaultMassless = hbOpts.massless ~= false;
	local function GetChar(t)
		if typeof(t) == "Instance" and t:IsA("Player") then
			return getPlrChar(t);
		elseif typeof(t) == "Instance" and t:IsA("Model") then
			return t;
		end;
	end;
	local partSet = {
		All = true
	};
	if #targets == 0 then
		local defaults = {
			"Head",
			"UpperTorso",
			"LowerTorso",
			"Torso",
			"LeftUpperArm",
			"LeftLowerArm",
			"LeftHand",
			"RightUpperArm",
			"RightLowerArm",
			"RightHand",
			"LeftUpperLeg",
			"LeftLowerLeg",
			"LeftFoot",
			"RightUpperLeg",
			"RightLowerLeg",
			"RightFoot"
		};
		for _, limb in ipairs(defaults) do
			partSet[limb] = true;
		end;
	end;
	for _, t in ipairs(targets) do
		local c = GetChar(t);
		if c then
			for _, p in ipairs(c:GetChildren()) do
				if p:IsA("BasePart") then
					partSet[p.Name] = true;
				end;
			end;
		end;
	end;
	local btns = {};
	for limb, _ in pairs(partSet) do
		Insert(btns, {
			Text = limb,
			Callback = function()
				local sz = Vector3.new(n, n, n);
				local bc = BrickColor.new(defaultColor);
				local mat = defaultMaterial;
				local limbL = Lower(limb);
				local isAll = limb == "All";
				local function MatchBp(bp)
					if isAll then
						return true;
					end;
					return Lower(bp.Name) == limbL;
				end;
				local function Cache(D, key, bp)
					D.og[key] = D.og[key] or {};
					if not D.og[key][bp] then
						D.og[key][bp] = {
							Size = bp.Size,
							Transparency = bp.Transparency,
							BrickColor = bp.BrickColor,
							Material = bp.Material,
							CanCollide = bp.CanCollide,
							Massless = bp.Massless
						};
					end;
					if not NAmanage.GetAttr(bp, "NAHB_HasOrig") then
						local c = bp.BrickColor.Color;
						NAmanage.SetAttr(bp, "NAHB_HasOrig", true);
						NAmanage.SetAttr(bp, "NAHB_OSizeX", bp.Size.X);
						NAmanage.SetAttr(bp, "NAHB_OSizeY", bp.Size.Y);
						NAmanage.SetAttr(bp, "NAHB_OSizeZ", bp.Size.Z);
						NAmanage.SetAttr(bp, "NAHB_OTransparency", bp.Transparency);
						NAmanage.SetAttr(bp, "NAHB_OColorR", c.R);
						NAmanage.SetAttr(bp, "NAHB_OColorG", c.G);
						NAmanage.SetAttr(bp, "NAHB_OColorB", c.B);
						NAmanage.SetAttr(bp, "NAHB_OMaterial", bp.Material.Name);
						NAmanage.SetAttr(bp, "NAHB_OCanCollide", bp.CanCollide);
						NAmanage.SetAttr(bp, "NAHB_OMassless", bp.Massless);
					end;
				end;
				local function ApplyBp(D, key, bp)
					Cache(D, key, bp);
					local og = D.og[key] and D.og[key][bp] or nil;
					if bp.Size ~= D.cfg.sz then
						bp.Size = D.cfg.sz;
					end;
					if bp.Transparency ~= D.cfg.tr then
						bp.Transparency = D.cfg.tr;
					end;
					if bp.BrickColor ~= D.cfg.bc then
						bp.BrickColor = D.cfg.bc;
					end;
					if bp.Material ~= D.cfg.mat then
						bp.Material = D.cfg.mat;
					end;
					if D.cfg.noCollide then
						if bp.CanCollide then
							bp.CanCollide = false;
						end;
					elseif og and bp.CanCollide ~= og.CanCollide then
						bp.CanCollide = og.CanCollide;
					end;
					if D.cfg.massless then
						if not bp.Massless then
							bp.Massless = true;
						end;
					elseif og and bp.Massless ~= og.Massless then
						bp.Massless = og.Massless;
					end;
				end;
				if npc then
					local D = NAStuff.HB.N;
					if D.run then
						D.run:Disconnect();
						D.run = nil;
					end;
					if D.wc then
						D.wc:Disconnect();
						D.wc = nil;
					end;
					for m, c in pairs(D.md) do
						if c then
							c:Disconnect();
						end;
						D.md[m] = nil;
					end;
					for m, c in pairs(D.ac) do
						if c then
							c:Disconnect();
						end;
						D.ac[m] = nil;
					end;
					for m, _ in pairs(D.ps) do
						D.ps[m] = nil;
					end;
					D.cfg = {
						limb = limb,
						limbL = limbL,
						sz = sz,
						bc = bc,
						mat = mat,
						tr = defaultTransparency,
						noCollide = defaultNoCollide,
						massless = defaultMassless
					};
					local function Track(m, bp)
						if not (bp and bp.Parent) then
							return;
						end;
						if not bp:IsA("BasePart") then
							return;
						end;
						if not MatchBp(bp) then
							return;
						end;
						D.ps[m] = D.ps[m] or {};
						D.ps[m][bp] = true;
						ApplyBp(D, m, bp);
					end;
					local function Scan(m)
						if not (m and m.Parent) then
							return;
						end;
						for _, c in ipairs(m:GetChildren()) do
							if c:IsA("BasePart") then
								Track(m, c);
							end;
						end;
					end;
					local function Setup(m)
						if not (m and m.Parent) then
							return;
						end;
						if D.md[m] then
							D.md[m]:Disconnect();
						end;
						D.md[m] = NAmanage.descAdd(m, function(inst)
							if inst and inst:IsA("BasePart") then
								Track(m, inst);
							end;
						end, function(inst)
							return inst and inst:IsA("BasePart")
						end);
						if D.ac[m] then
							D.ac[m]:Disconnect();
						end;
						D.ac[m] = m.AncestryChanged:Connect(function(_, parent)
							if not D.cfg then
								return;
							end;
							if parent and workspace and m:IsDescendantOf(workspace) then
								Defer(function()
									Scan(m);
								end);
							end;
						end);
						Scan(m);
					end;
					local function IsNPC(inst)
						if inst and inst:IsA("Model") and CheckIfNPC(inst) then
							return inst;
						end;
						local m = inst and inst:FindFirstAncestorWhichIsA("Model") or nil;
						if m and CheckIfNPC(m) then
							return m;
						end;
						return nil;
					end;
					for _, t in ipairs(targets) do
						local m = GetChar(t);
						if m then
							Setup(m);
						end;
					end;
					D.wc = NAmanage.wsAdd(function(inst)
						local m = IsNPC(inst);
						if m then
							Defer(function()
								if not D.md[m] then
									Setup(m);
								end;
							end);
						end;
					end);
					local acc = 0;
					local acc2 = 0;
					D.run = RunService.Heartbeat:Connect(function(dt)
						acc += dt;
						acc2 += dt;
						if acc >= 0.12 then
							acc = 0;
							for m, c in pairs(D.md) do
								if not (m and m.Parent) then
									if c then
										c:Disconnect();
									end;
									D.md[m] = nil;
									if D.ac[m] then
										D.ac[m]:Disconnect();
										D.ac[m] = nil;
									end;
									D.ps[m] = nil;
									D.og[m] = nil;
								end;
							end;
							for m, set in pairs(D.ps) do
								if not (m and m.Parent) then
									D.ps[m] = nil;
									D.og[m] = nil;
									if D.md[m] then
										D.md[m]:Disconnect();
										D.md[m] = nil;
									end;
									if D.ac[m] then
										D.ac[m]:Disconnect();
										D.ac[m] = nil;
									end;
								else
									for bp, _ in pairs(set) do
										if not (bp and bp.Parent) then
											set[bp] = nil;
										elseif MatchBp(bp) then
											ApplyBp(D, m, bp);
										end;
									end;
								end;
							end;
						end;
						if acc2 >= 0.35 then
							acc2 = 0;
							for _, ch in ipairs(workspace:GetChildren()) do
								if ch:IsA("Model") and CheckIfNPC(ch) and (not D.md[ch]) then
									Setup(ch);
								end;
							end;
						end;
					end);
				else
					local D = NAStuff.HB.P;
					if D.run then
						D.run:Disconnect();
						D.run = nil;
					end;
					if D.addConn then
						D.addConn:Disconnect();
						D.addConn = nil;
					end;
					if D.remConn then
						D.remConn:Disconnect();
						D.remConn = nil;
					end;
					for k, c in pairs(D.ca) do
						if c then
							c:Disconnect();
						end;
						D.ca[k] = nil;
					end;
					for k, c in pairs(D.da) do
						if c then
							c:Disconnect();
						end;
						D.da[k] = nil;
					end;
					for k, c in pairs(D.ac) do
						if c then
							c:Disconnect();
						end;
						D.ac[k] = nil;
					end;
					for k, _ in pairs(D.ps) do
						D.ps[k] = nil;
					end;
					D.cfg = {
						limb = limb,
						limbL = limbL,
						sz = sz,
						bc = bc,
						mat = mat,
						tr = defaultTransparency,
						noCollide = defaultNoCollide,
						massless = defaultMassless
					};
					local function Track(k, bp)
						if not (bp and bp.Parent) then
							return;
						end;
						if not bp:IsA("BasePart") then
							return;
						end;
						if not MatchBp(bp) then
							return;
						end;
						D.ps[k] = D.ps[k] or {};
						D.ps[k][bp] = true;
						ApplyBp(D, k, bp);
					end;
					local function Scan(k, ch)
						if not (ch and ch.Parent) then
							return;
						end;
						for _, c in ipairs(ch:GetChildren()) do
							if c:IsA("BasePart") then
								Track(k, c);
							end;
						end;
					end;
					local function SetupChar(k, ch)
						if D.da[k] then
							D.da[k]:Disconnect();
						end;
						D.da[k] = NAmanage.descAdd(ch, function(inst)
							if inst and inst:IsA("BasePart") then
								Track(k, inst);
							end;
						end, function(inst)
							return inst and inst:IsA("BasePart")
						end);
						if D.ac[k] then
							D.ac[k]:Disconnect();
						end;
						D.ac[k] = ch.AncestryChanged:Connect(function(_, parent)
							if not D.cfg then
								return;
							end;
							if parent and workspace and ch:IsDescendantOf(workspace) then
								Defer(function()
									local cc = GetChar(k);
									if cc then
										Scan(k, cc);
									end;
								end);
							end;
						end);
						Scan(k, ch);
					end;
					local function SetupKey(k)
						local ch = GetChar(k);
						if ch then
							SetupChar(k, ch);
						end;
						if typeof(k) == "Instance" and k:IsA("Player") and k.CharacterAdded then
							if D.ca[k] then
								D.ca[k]:Disconnect();
							end;
							D.ca[k] = k.CharacterAdded:Connect(function(c)
								Defer(function()
									if c then
										SetupChar(k, c);
									end;
								end);
							end);
						end;
						Defer(function()
							local cc = GetChar(k);
							if cc then
								Scan(k, cc);
							end;
						end);
					end;
					for _, t in ipairs(targets) do
						SetupKey(t);
					end;
					if glb then
						D.addConn = Players.PlayerAdded:Connect(function(plr)
							SetupKey(plr);
						end);
						D.remConn = Players.PlayerRemoving:Connect(function(plr)
							if D.ca[plr] then
								D.ca[plr]:Disconnect();
								D.ca[plr] = nil;
							end;
							if D.da[plr] then
								D.da[plr]:Disconnect();
								D.da[plr] = nil;
							end;
							if D.ac[plr] then
								D.ac[plr]:Disconnect();
								D.ac[plr] = nil;
							end;
							D.ps[plr] = nil;
							D.og[plr] = nil;
						end);
					end;
					local acc = 0;
					D.run = RunService.Heartbeat:Connect(function(dt)
						acc += dt;
						if acc < 0.12 then
							return;
						end;
						acc = 0;
						for k, set in pairs(D.ps) do
							local ch = GetChar(k);
							if not (ch and ch.Parent) then
								D.ps[k] = nil;
							else
								for bp, _ in pairs(set) do
									if not (bp and bp.Parent) then
										set[bp] = nil;
									elseif MatchBp(bp) then
										ApplyBp(D, k, bp);
									end;
								end;
							end;
						end;
					end);
				end;
			end
		});
	end;
	Window({
		Title = "Hitbox Menu",
		Description = "Choose limb to resize",
		Buttons = btns
	});
end, true);

cmd.add({"unhitbox","unhbox"}, {"unhitbox <player>",""}, function(pArg)
	NAStuff.HB = NAStuff.HB or {}
	NAStuff.HB.P = NAStuff.HB.P or {
		ps = {},
		og = {},
		ca = {},
		da = {},
		ac = {},
		addConn = nil,
		remConn = nil,
		run = nil,
		cfg = nil
	}
	NAStuff.HB.N = NAStuff.HB.N or {
		ps = {},
		og = {},
		md = {},
		ac = {},
		wc = nil,
		run = nil,
		cfg = nil
	}

	local argL = pArg and Lower(pArg) or ""
	local targets = getPlr(pArg)
	local npc = argL == "npc"
	local glb = argL == "" or argL == "all" or argL == "others"
	local allowEmpty = npc or glb

	if #targets == 0 and not allowEmpty then
		DoNotif("No targets found", 2)
		return
	end

	local function RestorePart(bp, pr)
		if not (bp and bp.Parent) then
			return
		end

		local sx = NAmanage.GetAttr(bp, "NAHB_OSizeX")
		local sy = NAmanage.GetAttr(bp, "NAHB_OSizeY")
		local sz = NAmanage.GetAttr(bp, "NAHB_OSizeZ")
		if sx and sy and sz then
			bp.Size = Vector3.new(sx, sy, sz)
		elseif pr and pr.Size then
			bp.Size = pr.Size
		end

		local tr = NAmanage.GetAttr(bp, "NAHB_OTransparency")
		if tr ~= nil then
			bp.Transparency = tr
		elseif pr and pr.Transparency ~= nil then
			bp.Transparency = pr.Transparency
		end

		local cr = NAmanage.GetAttr(bp, "NAHB_OColorR")
		local cg = NAmanage.GetAttr(bp, "NAHB_OColorG")
		local cb = NAmanage.GetAttr(bp, "NAHB_OColorB")
		if cr and cg and cb then
			bp.BrickColor = BrickColor.new(Color3.new(cr, cg, cb))
		elseif pr and pr.BrickColor then
			bp.BrickColor = pr.BrickColor
		end

		local matName = NAmanage.GetAttr(bp, "NAHB_OMaterial")
		if matName then
			local em = Enum.Material[matName]
			if em then
				bp.Material = em
			end
		elseif pr and pr.Material then
			bp.Material = pr.Material
		end

		local cc = NAmanage.GetAttr(bp, "NAHB_OCanCollide")
		if cc ~= nil then
			bp.CanCollide = cc
		elseif pr and pr.CanCollide ~= nil then
			bp.CanCollide = pr.CanCollide
		end

		local ml = NAmanage.GetAttr(bp, "NAHB_OMassless")
		if ml ~= nil then
			bp.Massless = ml
		elseif pr and pr.Massless ~= nil then
			bp.Massless = pr.Massless
		end

		NAmanage.SetAttr(bp, "NAHB_HasOrig", nil)
		NAmanage.SetAttr(bp, "NAHB_OSizeX", nil)
		NAmanage.SetAttr(bp, "NAHB_OSizeY", nil)
		NAmanage.SetAttr(bp, "NAHB_OSizeZ", nil)
		NAmanage.SetAttr(bp, "NAHB_OTransparency", nil)
		NAmanage.SetAttr(bp, "NAHB_OColorR", nil)
		NAmanage.SetAttr(bp, "NAHB_OColorG", nil)
		NAmanage.SetAttr(bp, "NAHB_OColorB", nil)
		NAmanage.SetAttr(bp, "NAHB_OMaterial", nil)
		NAmanage.SetAttr(bp, "NAHB_OCanCollide", nil)
		NAmanage.SetAttr(bp, "NAHB_OMassless", nil)
	end

	local function RestoreMap(mp)
		for bp, pr in pairs(mp) do
			RestorePart(bp, pr)
		end
	end

	local function GetChar(t)
		if typeof(t) == "Instance" and t:IsA("Player") then
			return getPlrChar(t)
		elseif typeof(t) == "Instance" and t:IsA("Model") then
			return t
		end
	end

	local function restoreEntryPlayer(D, k)
		local ch = GetChar(k)
		if ch and ch.Parent then
			local mp = D.og[k]
			for _, bp in ipairs(NAmanage.qDesc(ch, "BasePart")) do
				local pr = mp and mp[bp] or nil
				RestorePart(bp, pr)
			end
		elseif D.og[k] then
			RestoreMap(D.og[k])
		end
		D.og[k] = nil
		D.ps[k] = nil
		if D.ca[k] then
			D.ca[k]:Disconnect()
			D.ca[k] = nil
		end
		if D.da[k] then
			D.da[k]:Disconnect()
			D.da[k] = nil
		end
		if D.ac[k] then
			D.ac[k]:Disconnect()
			D.ac[k] = nil
		end
	end

	local function restoreEntryNPC(D, k)
		local ch = GetChar(k)
		if ch and ch.Parent then
			local mp = D.og[k]
			for _, bp in ipairs(NAmanage.qDesc(ch, "BasePart")) do
				local pr = mp and mp[bp] or nil
				RestorePart(bp, pr)
			end
		elseif D.og[k] then
			RestoreMap(D.og[k])
		end
		D.og[k] = nil
		D.ps[k] = nil
	end

	local function cleanupPlayers(D)
		local any = false
		for _ in pairs(D.ps) do
			any = true
			break
		end
		if any then
			return
		end
		for _, c in pairs(D.ca) do
			if c then
				c:Disconnect()
			end
		end
		for _, c in pairs(D.da) do
			if c then
				c:Disconnect()
			end
		end
		for _, c in pairs(D.ac) do
			if c then
				c:Disconnect()
			end
		end
		D.ca = {}
		D.da = {}
		D.ac = {}
		if D.addConn then
			D.addConn:Disconnect()
			D.addConn = nil
		end
		if D.remConn then
			D.remConn:Disconnect()
			D.remConn = nil
		end
		if D.run then
			D.run:Disconnect()
			D.run = nil
		end
		D.cfg = nil
	end

	local function cleanupNPC(D)
		local any = false
		for _ in pairs(D.ps) do
			any = true
			break
		end
		if any then
			return
		end
		for _, c in pairs(D.md) do
			if c then
				c:Disconnect()
			end
		end
		for _, c in pairs(D.ac) do
			if c then
				c:Disconnect()
			end
		end
		D.md = {}
		D.ac = {}
		if D.wc then
			D.wc:Disconnect()
			D.wc = nil
		end
		if D.run then
			D.run:Disconnect()
			D.run = nil
		end
		D.cfg = nil
	end

	if npc then
		local D = NAStuff.HB.N
		for k in pairs(D.og) do
			restoreEntryNPC(D, k)
		end
		for _, t in ipairs(targets) do
			restoreEntryNPC(D, t)
		end
		cleanupNPC(D)
		return
	end

	local D = NAStuff.HB.P
	local lp = Players.LocalPlayer

	if glb then
		if argL == "others" then
			for _, plr in ipairs(__lt.cm("Players", "GetPlayers")) do
				if plr ~= lp then
					restoreEntryPlayer(D, plr)
				end
			end
		else
			for _, plr in ipairs(__lt.cm("Players", "GetPlayers")) do
				restoreEntryPlayer(D, plr)
			end
		end
		cleanupPlayers(D)
		return
	end

	for _, t in ipairs(targets) do
		restoreEntryPlayer(D, t)
	end
	cleanupPlayers(D)
end, true)

NAStuff.PST = {
	orig   = {},
	exact  = {},
	partial= {},
	sizeE  = {},
	sizeP  = {},
}
PST = NAStuff.PST

NAmanage.cachePart = function(p)
	NAStuff.PST.orig[p] = {
		Size         = p.Size,
		Transparency = p.Transparency,
		CanCollide   = p.CanCollide,
	}
end

NAmanage.resizePart = function(p, sizeVec, store)
	if not NAStuff.PST.orig[p] then NAmanage.cachePart(p) end
	p.Size         = sizeVec
	p.Transparency = 0.5
	p.CanCollide   = false
	Insert(store, p)
end

cmd.add({"partsize","psize","sizepart"},{"partsize {name} {size}", "Grow a part or model named exactly <name> to the cube size you choose."},function(nameArg, sizeArg)
	local term, n = Lower(nameArg), tonumber(sizeArg)
	if not n then DoNotif("Invalid size",2) return end
	local sizeVec = Vector3.new(n,n,n)
	NAStuff.PST.sizeE[term] = sizeVec

	local parts, elser = {}, {}
	for _, obj in ipairs(NAmanage.wsDescs()) do
		local nm = Lower(obj.Name)
		if obj:IsA("BasePart") and nm == term then
			Insert(parts, obj)
		elseif nm == term then
			Insert(elser, obj)
		end
	end

	for _, p in ipairs(parts) do
		NAmanage.resizePart(p, sizeVec, NAStuff.PST.exact)
	end
	for _, m in ipairs(elser) do
		for _, d in ipairs(NAmanage.qDesc(m, "BasePart")) do
			NAmanage.resizePart(d, sizeVec, NAStuff.PST.exact)
		end
	end

	if not NAlib.isConnected("partsizeExact") then
		NAlib.connect("partsizeExact", NAmanage.wsAdd(function(obj)
			if obj:IsA("BasePart") then
				local nm = Lower(obj.Name)
				local sz = NAStuff.PST.sizeE[nm]
				if sz then
					NAmanage.resizePart(obj, sz, NAStuff.PST.exact)
					return
				end
			else
				local sz = NAStuff.PST.sizeE[Lower(obj.Name)]
				if sz then
					for _, d in ipairs(NAmanage.qDesc(obj, "BasePart")) do
						NAmanage.resizePart(d, sz, NAStuff.PST.exact)
					end
				end
			end
		end))
	end
end, true)

cmd.add({"partsizefind","psizefind","sizefind","partsizef"},{"partsizefind {term} {size}", "Grow every part or model whose name contains <term> to the cube size you choose."},function(termArg, sizeArg)
	local term, n = Lower(termArg), tonumber(sizeArg)
	if not n then DoNotif("Invalid size",2) return end
	local sizeVec = Vector3.new(n,n,n)
	PST.sizeP[term] = sizeVec

	local parts, elser = {}, {}
	for _, obj in ipairs(NAmanage.wsDescs()) do
		local nm = Lower(obj.Name)
		if obj:IsA("BasePart") and nm:find(term) then
			Insert(parts, obj)
		elseif nm:find(term) then
			Insert(elser, obj)
		end
	end

	for _, p in ipairs(parts) do
		NAmanage.resizePart(p, sizeVec, PST.partial)
	end
	for _, m in ipairs(elser) do
		for _, d in ipairs(NAmanage.qDesc(m, "BasePart")) do
			NAmanage.resizePart(d, sizeVec, PST.partial)
		end
	end

	if not NAlib.isConnected("partsizeFind") then
		NAlib.connect("partsizeFind", NAmanage.wsAdd(function(obj)
			if obj:IsA("BasePart") then
				local nm = Lower(obj.Name)
				for t, sz in pairs(PST.sizeP) do
					if nm:find(t) then
						NAmanage.resizePart(obj, sz, PST.partial)
						return
					end
				end
			else
				for t, sz in pairs(PST.sizeP) do
					if Lower(obj.Name):find(t) then
						for _, d in ipairs(NAmanage.qDesc(obj, "BasePart")) do
							NAmanage.resizePart(d, sz, PST.partial)
						end
						return
					end
				end
			end
		end))
	end
end, true)

cmd.add({"unpartsize","unsizepart","unpsize"},{"unpartsize", "Undo partsize—return those parts back to their original size and collision."},function()
	local parts = PST.exact
	local sizeMap = PST.sizeE

	local terms = {}
	for term, _ in pairs(sizeMap) do
		Insert(terms, term)
	end

	local function restorePart(p)
		local pr = PST.orig[p]
		if pr then
			p.Size         = pr.Size
			p.Transparency = pr.Transparency
			p.CanCollide   = pr.CanCollide
			PST.orig[p] = nil
		end
	end

	local function termMatchesPart(term, part)
		local obj = part
		while obj do
			if Lower(obj.Name) == term then
				return true
			end
			obj = obj.Parent
		end
		return false
	end

	local function removeAll()
		for _, p in ipairs(parts) do
			restorePart(p)
		end
		table.clear(parts)
		table.clear(sizeMap)
		NAlib.disconnect("partsizeExact")
		DoNotif("Cleared all exact-name partsize changes.", 2)
	end

	if #terms == 0 then
		if #parts == 0 then
			DoNotif("No exact-name partsize changes are active.", 2)
		else
			removeAll()
		end
		return
	end

	local function removeByTerm(term)
		for i = #parts, 1, -1 do
			local p = parts[i]
			if p and p.Parent and termMatchesPart(term, p) then
				restorePart(p)
				table.remove(parts, i)
			end
		end
		sizeMap[term] = nil
		if not next(sizeMap) then
			NAlib.disconnect("partsizeExact")
		end
		DoNotif("Reverted partsize for exact name '"..term.."'.", 2)
	end

	local buttons = {}
	Insert(buttons, { Text = "All", Callback = removeAll })
	for _, t in ipairs(terms) do
		Insert(buttons, { Text = t, Callback = function() removeByTerm(t) end })
	end

	Window({
		Title = "Undo Exact Partsize",
		Description = "Select a name to restore original size (future spawns included).",
		Buttons = buttons
	})
end, true)

cmd.add({"unpartsizefind","unsizefind","unpsizefind"},{"unpartsizefind", "Undo partsizefind—return those resized parts back to their original size and collision."},function()
	local parts = PST.partial
	local sizeMap = PST.sizeP

	local terms = {}
	for term, _ in pairs(sizeMap) do
		Insert(terms, term)
	end

	local function restorePart(p)
		local pr = PST.orig[p]
		if pr then
			p.Size         = pr.Size
			p.Transparency = pr.Transparency
			p.CanCollide   = pr.CanCollide
			PST.orig[p] = nil
		end
	end

	local function termMatchesPart(term, part)
		local obj = part
		while obj do
			if Find(Lower(obj.Name), term) ~= nil then
				return true
			end
			obj = obj.Parent
		end
		return false
	end

	local function removeAll()
		for _, p in ipairs(parts) do
			restorePart(p)
		end
		table.clear(parts)
		table.clear(sizeMap)
		NAlib.disconnect("partsizeFind")
		DoNotif("Cleared all partial-name partsize changes.", 2)
	end

	if #terms == 0 then
		if #parts == 0 then
			DoNotif("No partial-name partsize changes are active.", 2)
		else
			removeAll()
		end
		return
	end

	local function removeByTerm(term)
		for i = #parts, 1, -1 do
			local p = parts[i]
			if p and p.Parent and termMatchesPart(term, p) then
				restorePart(p)
				table.remove(parts, i)
			end
		end
		sizeMap[term] = nil
		if not next(sizeMap) then
			NAlib.disconnect("partsizeFind")
		end
		DoNotif("Reverted partsizefind for term '"..term.."'.", 2)
	end

	local buttons = {}
	Insert(buttons, { Text = "All", Callback = removeAll })
	for _, t in ipairs(terms) do
		Insert(buttons, { Text = t, Callback = function() removeByTerm(t) end })
	end

	Window({
		Title = "Undo Partial Partsize",
		Description = "Select a term to restore original size (future spawns included).",
		Buttons = buttons
	})
end, true)

cmd.add({"breakcars", "bcars"}, {"breakcars (bcars)", "Breaks any car"}, function()
	NAStuff = NAStuff or {}
	local CONN_KEY = "breakcars"
	if NAStuff._breakcarsEnabled then
		NAStuff._breakcarsEnabled = false
		NAlib.disconnect(CONN_KEY)
		if NAStuff._breakcarsFolder then
			pcall(function() NAStuff._breakcarsFolder:Destroy() end)
		end
		NAStuff._breakcarsFolder = nil
		DoNotif("Breakcars disabled", 2, "BreakCars")
		return
	end
	NAStuff._breakcarsEnabled = true
	NAlib.disconnect(CONN_KEY)
	if NAStuff._breakcarsFolder then
		pcall(function() NAStuff._breakcarsFolder:Destroy() end)
		NAStuff._breakcarsFolder = nil
	end

	DebugNotif("Car breaker loaded, sit on a vehicle and be the driver")

	local Player = Players.LocalPlayer
	local Mouse = NAmanage.GetMouse(Player)

	local Folder = InstanceNew("Folder")
	Folder.Parent = workspace
	NAStuff._breakcarsFolder = Folder
	NAlib.connect(CONN_KEY, Folder.AncestryChanged:Connect(function(_, parent)
		if not parent then
			NAStuff._breakcarsEnabled = false
			NAStuff._breakcarsFolder = nil
			Defer(function()
				NAlib.disconnect(CONN_KEY)
			end)
		end
	end))

	local Part = InstanceNew("Part")
	Part.Anchored = true
	Part.CanCollide = false
	Part.Transparency = 1
	Part.Size = Vector3.new(1, 1, 1)
	Part.Parent = Folder

	local Attachment1 = InstanceNew("Attachment")
	Attachment1.Parent = Part

	local UpdatedPosition = Mouse.Hit + Vector3.new(0, 5, 0)

	SpawnCall(function()
		while NAStuff._breakcarsEnabled and Wait() do
			for _, player in ipairs(__lt.cm("Players", "GetPlayers")) do
				if player ~= Player then
					pcall(function() player.MaximumSimulationRadius = 0 end)
					pcall(function() if opt and opt.hiddenprop then opt.hiddenprop(player, "SimulationRadius", 0) end end)
				end
			end
			pcall(function() Player.MaximumSimulationRadius = math.pow(math.huge, math.huge) end)
			pcall(function() if setsimulationradius then setsimulationradius(math.huge) end end)
		end
	end)

	local function applyForceToPart(part)
		if not part:IsA("BasePart") or part.Anchored then return end
		if part.Name == "Handle" then return end
		local parent = part.Parent
		if getPlrHum(parent) or getHead(parent) then return end

		Mouse.TargetFilter = part

		for _, v in ipairs(part:GetChildren()) do
			if v:IsA("BodyAngularVelocity") or v:IsA("BodyForce") or v:IsA("BodyGyro")
				or v:IsA("BodyPosition") or v:IsA("BodyThrust") or v:IsA("BodyVelocity")
				or v:IsA("RocketPropulsion") or v:IsA("Torque") or v:IsA("AlignPosition")
				or v:IsA("Attachment") then
				v:Destroy()
			end
		end

		part.CanCollide = false

		local torque = InstanceNew("Torque")
		torque.Torque = Vector3.new(100000, 100000, 100000)
		torque.Parent = part

		local alignPosition = InstanceNew("AlignPosition")
		alignPosition.MaxForce = math.huge
		alignPosition.MaxVelocity = math.huge
		alignPosition.Responsiveness = 200
		alignPosition.Parent = part

		local attachment2 = InstanceNew("Attachment")
		attachment2.Parent = part

		torque.Attachment0 = attachment2
		alignPosition.Attachment0 = attachment2
		alignPosition.Attachment1 = Attachment1
	end

	for _, descendant in ipairs(NAmanage.wsDescs()) do
		applyForceToPart(descendant)
	end

	NAlib.connect(CONN_KEY, NAmanage.wsAdd(applyForceToPart))

	NAlib.connect(CONN_KEY, UserInputService.InputBegan:Connect(function(input, isChatting)
		if input.KeyCode == Enum.KeyCode.E and not isChatting then
			UpdatedPosition = Mouse.Hit + Vector3.new(0, 5, 0)
		end
	end))

	SpawnCall(function()
		while NAStuff._breakcarsEnabled and Wait() do
			pcall(function()
				Attachment1.WorldCFrame = UpdatedPosition
			end)
		end
		pcall(function()
			if Folder and Folder.Parent then
				Folder:Destroy()
			end
		end)
	end)
end)

cmd.add({"setsimradius", "ssr", "simrad"},{"setsimradius <number>","Set sim radius using available methods. Usage: setsimradius <radius>"},function(...)
	local r = tonumber(...)
	if not r then
		return DoNotif("Invalid input. Usage: setsimradius <number>")
	end

	local ok = false

	if setsimulationradius then
		NACaller(function()
			setsimulationradius(r)
			ok = true
			DebugNotif("SimRadius set with setsimulationradius: "..r)
		end)
	end

	if not ok and opt.hiddenprop then
		if NACaller(function()
				opt.hiddenprop(LocalPlayer, "SimulationRadius", r)
			end) then
			ok = true
			DebugNotif("SimRadius set with sethiddenproperty: "..r)
		end
	end

	if not ok then
		if NACaller(function()
				LocalPlayer.SimulationRadius = r
			end) then
			ok = true
			DebugNotif("SimRadius set directly: "..r)
		end
	end

	if not ok then
		DebugNotif("No supported method to set sim radius.")
	end
end,true)

cmd.add({"infjump", "infinitejump"}, {"infjump (infinitejump)", "Enables infinite jumping"}, function()
	Wait()
	DebugNotif("Infinite Jump Enabled", 2)

	local function doINFJUMPY()
		NAlib.disconnect("infjump_jump")

		local debounce = false
		local humanoid = nil

		while not humanoid do Wait(.1) humanoid = getHum() end

		NAlib.connect("infjump_jump", UserInputService.JumpRequest:Connect(function()
			if not debounce and humanoid:GetState() ~= Enum.HumanoidStateType.Dead then
				debounce = true
				NAmanage.LaunchHumanoid(humanoid)

				Delay(0.25, function()
					debounce = false
				end)
			end
		end))
	end

	NAlib.disconnect("infjump_char")
	NAlib.connect("infjump_char", plr.CharacterAdded:Connect(function()
		doINFJUMPY()
	end))

	doINFJUMPY()
end)

