				st.safeSet(Lighting,"FogEnd",st.nb.baseline.FogEnd)
				st.safeSet(Lighting,"GlobalShadows",st.nb.baseline.GlobalShadows)
				st.safeSet(Lighting,"Ambient",st.nb.baseline.Ambient)
