cmd.add({"fireremotes", "fremotes", "frem"}, {"fireremotes (fremotes, frem)", "Fires every remote with arguments"}, function()
	local remoteList = {}
	local remoteCount = 0
	local failedCount = 0

	local q = {game}
	local qi, qn = 1, 1
	local step = 120
	local n = 0

	while qi <= qn do
		local inst = q[qi]
		qi += 1

		if inst ~= COREGUI then
			if inst:IsA("RemoteEvent") or inst:IsA("RemoteFunction") then
				remoteList[#remoteList + 1] = inst
			end

			local ch = inst:GetChildren()
			for i = 1, #ch do
				local c = ch[i]
				if c ~= COREGUI then
					qn += 1
					q[qn] = c
				end
			end
		end

		n += 1
		if n >= step then
			n = 0
			Wait()
		end
	end

	for i = 1, #remoteList do
		local obj = remoteList[i]
		if obj:IsA("RemoteEvent") then
			local ok = pcall(function()
				obj:FireServer()
			end)
			if ok then
				remoteCount = remoteCount + 1
			else
				failedCount = failedCount + 1
			end
		elseif obj:IsA("RemoteFunction") then
			SpawnCall(function()
				local ok = pcall(function()
					obj:InvokeServer()
				end)
				if ok then
					remoteCount = remoteCount + 1
				else
					failedCount = failedCount + 1
				end
			end)
		end

		if i % 25 == 0 then
			Wait()
		end
	end

	Delay(2, function()
		DebugNotif("Fired " .. remoteCount .. " remotes\nFailed: " .. failedCount .. " remotes")
	end)
end)

