	originalIO.bodyModsApplyPP = function(length)
		local character = originalIO.bodyModsGetCharacter(true)
		local humanoid = originalIO.bodyModsGetHumanoid(true)
		if not character or not humanoid then
			return
		end
		local torso = originalIO.bodyModsGetTorso(false)
		if not torso then
			return
		end

		for _, part in ipairs(character:GetChildren()) do
			if part:IsA("BasePart") and (part.Name == "Balls" or part.Name == "penis") then
				part:Destroy()
			end
		end

		local value = tonumber(length) or state.pp.len or 1
		value = math.clamp(value, 0.5, 6)
		state.pp.len = value

		local skin = originalIO.bodyModsGetSkinColor()
		local shaftLength = 1.42 + value * 0.85
		local shaftRadius = math.clamp(0.34 + value * 0.042, 0.35, 0.58)
		local ballRadius = math.clamp(0.49 + value * 0.042, 0.50, 0.78)
		local tipRadius = math.clamp(shaftRadius * 1.24, 0.39, 0.65)

		local function createPart(shape, size, color, name)
			local part = InstanceNew("Part")
			part.Shape = shape
			part.Size = size
			part.Color = color
			part.Material = Enum.Material.SmoothPlastic
			part.Anchored = false
			part.CanCollide = false
			part.CanTouch = false
			part.CanQuery = false
			part.Massless = true
			part.Name = name
			part.Parent = character
			return part
		end

		local function weldConstraint(part0, part1)
			local weld = InstanceNew("WeldConstraint")
			weld.Part0 = part0
			weld.Part1 = part1
			weld.Parent = part0
		end

		local offsetY = (humanoid.RigType == Enum.HumanoidRigType.R15) and -0.98 or -1.40
		local scrotumSpread = math.clamp(ballRadius * 0.44, 0.21, 0.36)
		local leftBall = createPart(Enum.PartType.Ball, Vector3.new(ballRadius * 2, ballRadius * 2.08, ballRadius * 1.98), skin, "Balls")
		local rightBall = createPart(Enum.PartType.Ball, Vector3.new(ballRadius * 2, ballRadius * 2.08, ballRadius * 1.98), skin, "Balls")
		local shaft = createPart(Enum.PartType.Cylinder, Vector3.new(shaftLength, shaftRadius * 2, shaftRadius * 2), skin, "penis")
		local tip = createPart(Enum.PartType.Ball, Vector3.new(tipRadius * 2.15, tipRadius * 2.05, tipRadius * 2.05), pinkColor, "penis")

		leftBall.CFrame = torso.CFrame * CFrame.new(-scrotumSpread, offsetY, -0.74 - shaftRadius * 0.46)
		rightBall.CFrame = torso.CFrame * CFrame.new(scrotumSpread, offsetY, -0.74 - shaftRadius * 0.46)
		local shaftBaseOffset = (humanoid.RigType == Enum.HumanoidRigType.R15) and 0.46 or 0.62
		local shaftBaseZ = -(torso.Size.Z * 0.5 + shaftRadius * 0.11)
		local shaftForwardBias = math.max(0, shaftLength * 0.5 - shaftRadius * 0.88)
		shaft.CFrame = torso.CFrame
			* CFrame.new(0.00, offsetY + shaftBaseOffset, shaftBaseZ)
			* CFrame.Angles(0, math.rad(270), 0)
			* CFrame.new(-shaftForwardBias, 0, 0)
		tip.CFrame = shaft.CFrame * CFrame.new(-shaftLength * 0.5, 0, 0)

		weldConstraint(tip, shaft)

		local leftBallWeld = InstanceNew("Weld")
		leftBallWeld.Part0 = torso
		leftBallWeld.Part1 = leftBall
		leftBallWeld.C0 = torso.CFrame:ToObjectSpace(leftBall.CFrame)
		leftBallWeld.C1 = CFrame.new()
		leftBallWeld.Parent = leftBall

		local rightBallWeld = InstanceNew("Weld")
		rightBallWeld.Part0 = torso
		rightBallWeld.Part1 = rightBall
		rightBallWeld.C0 = torso.CFrame:ToObjectSpace(rightBall.CFrame)
		rightBallWeld.C1 = CFrame.new()
		rightBallWeld.Parent = rightBall

		local shaftWeld = InstanceNew("Weld")
		shaftWeld.Part0 = torso
		shaftWeld.Part1 = shaft
		shaftWeld.C0 = torso.CFrame:ToObjectSpace(shaft.CFrame)
		shaftWeld.C1 = CFrame.new()
		shaftWeld.Parent = shaft

		state.pp.active = true
		state.pp.sh = shaft
		state.pp.dr = tip
		state.pp.wS = shaftWeld
		state.pp.wBL = leftBallWeld
		state.pp.wBR = rightBallWeld
		state.pp.sy = 0
		state.pp.vy = 0
		state.pp.sz = 0
		state.pp.vz = 0
		state.pp.sx = 0
		state.pp.vx = 0
		state.pp.rx = 0
		state.pp.vrx = 0
		state.pp.ry = 0
		state.pp.vry = 0
		state.pp.bsy = 0
		state.pp.bvy = 0
		state.pp.bsz = 0
		state.pp.bvz = 0
		state.pp.bsx = 0
		state.pp.bvx = 0
		state.pp.brx = 0
		state.pp.bvrx = 0
		state.pp.bry = 0
		state.pp.bvry = 0
		state.pp.baseC0 = shaftWeld.C0
		state.pp.baseBL = leftBallWeld.C0
		state.pp.baseBR = rightBallWeld.C0
		state.pp.llv = state.pp.llv or Vector3.zero

		state.pp.animConn = originalIO.bodyModsDisconnectConnection(state.pp.animConn)
		state.pp.animConn = RunService.RenderStepped:Connect(function(dt)
			local currentChar = originalIO.bodyModsGetCharacter()
			if not currentChar or not currentChar.Parent then
				return
			end
			local hrp = currentChar:FindFirstChild("HumanoidRootPart")
			if not hrp or not state.pp.wS or not state.pp.baseC0 then
				return
			end

			local velocity = hrp.AssemblyLinearVelocity or hrp.Velocity
			local localVel = hrp.CFrame:VectorToObjectSpace(velocity)
			local angular = hrp.AssemblyAngularVelocity or Vector3.zero
			local localAng = hrp.CFrame:VectorToObjectSpace(angular)
			local accel = (localVel - state.pp.llv) / math.max(dt, 1/240)
			state.pp.llv = localVel
			local planarSpeed = Vector3.new(localVel.X, 0, localVel.Z).Magnitude
			local lengthScale = math.clamp(value / 2, 0.45, 3)
			local softness = math.clamp((planarSpeed + math.abs(localVel.Y) * 0.45) / 19, 0, 1)
			local gait = math.sin(os.clock() * (5.4 + planarSpeed * 0.16)) * math.clamp((planarSpeed - 1.5) / 10, 0, 1)
			local settleY = -0.013 * lengthScale
			local settleZ = -0.042 * lengthScale

			local targetY = math.clamp(settleY + (-localVel.Y * 0.016) - (accel.Y * 0.007) + math.abs(gait) * 0.012, -0.13, 0.11)
			local targetZ = math.clamp(settleZ + (-localVel.Z * (0.019 + 0.0028 * value)) - (accel.Z * 0.011) - math.abs(gait) * 0.014, -0.27, 0.13)
			local targetX = math.clamp((-localVel.X * 0.015) - (accel.X * 0.007), -0.15, 0.15)
			local targetPitch = math.clamp((localAng.Z * 0.020) - (localVel.Y * 0.006) - (accel.Y * 0.0025), -0.18, 0.18)
			local targetRoll = math.clamp((localAng.X * 0.020) + (localVel.X * 0.010) + (accel.X * 0.003), -0.18, 0.18)

			local kTrans = (39 - 11 * softness) / math.max(0.65 + lengthScale * 0.35, 0.7)
			local dTrans = 4.9 + lengthScale * 0.36 - 0.55 * softness
			local kRot = (34 - 9 * softness) / math.max(0.70 + lengthScale * 0.30, 0.7)
			local dRot = 4.3 + lengthScale * 0.26 - 0.45 * softness

			state.pp.sy, state.pp.vy = originalIO.bodyModsSpring(state.pp.sy, state.pp.vy, targetY, kTrans, dTrans, dt)
			state.pp.sz, state.pp.vz = originalIO.bodyModsSpring(state.pp.sz, state.pp.vz, targetZ, kTrans, dTrans, dt)
			state.pp.sx, state.pp.vx = originalIO.bodyModsSpring(state.pp.sx, state.pp.vx, targetX, kTrans, dTrans, dt)
			state.pp.rx, state.pp.vrx = originalIO.bodyModsSpring(state.pp.rx, state.pp.vrx, targetPitch, kRot, dRot, dt)
			state.pp.ry, state.pp.vry = originalIO.bodyModsSpring(state.pp.ry, state.pp.vry, targetRoll, kRot, dRot, dt)

			state.pp.sy = math.clamp(state.pp.sy, -0.12, 0.10)
			state.pp.sz = math.clamp(state.pp.sz, -0.26, 0.12)
			state.pp.sx = math.clamp(state.pp.sx, -0.14, 0.14)
			state.pp.rx = math.clamp(state.pp.rx, -0.18, 0.18)
			state.pp.ry = math.clamp(state.pp.ry, -0.18, 0.18)

			local sway = CFrame.new(state.pp.sx, state.pp.sy, state.pp.sz) * CFrame.Angles(state.pp.rx, 0, state.pp.ry)
			state.pp.wS.C0 = state.pp.baseC0 * sway

			if state.pp.wBL and state.pp.wBR and state.pp.baseBL and state.pp.baseBR then
				local ballTargetY = math.clamp((-0.020 * lengthScale) + (-localVel.Y * 0.020) - (accel.Y * 0.010) + math.abs(gait) * 0.024, -0.16, 0.14)
				local ballTargetZ = math.clamp((-0.028 * lengthScale) + (-localVel.Z * 0.010) - (accel.Z * 0.012) - math.abs(gait) * 0.018, -0.14, 0.08)
				local ballTargetX = math.clamp((-localVel.X * 0.018) - (accel.X * 0.008), -0.10, 0.10)
				local ballTargetPitch = math.clamp((-localVel.Y * 0.010) - (accel.Y * 0.004), -0.16, 0.16)
				local ballTargetRoll = math.clamp((localVel.X * 0.018) + gait * 0.055, -0.18, 0.18)

				local kBallTrans = (28 - 9 * softness) / math.max(0.75 + lengthScale * 0.22, 0.8)
				local dBallTrans = 4.7 + lengthScale * 0.26 - 0.35 * softness
				local kBallRot = (23 - 7 * softness) / math.max(0.80 + lengthScale * 0.18, 0.8)
				local dBallRot = 4.1 + lengthScale * 0.21 - 0.25 * softness

				state.pp.bsy, state.pp.bvy = originalIO.bodyModsSpring(state.pp.bsy, state.pp.bvy, ballTargetY, kBallTrans, dBallTrans, dt)
				state.pp.bsz, state.pp.bvz = originalIO.bodyModsSpring(state.pp.bsz, state.pp.bvz, ballTargetZ, kBallTrans, dBallTrans, dt)
				state.pp.bsx, state.pp.bvx = originalIO.bodyModsSpring(state.pp.bsx, state.pp.bvx, ballTargetX, kBallTrans, dBallTrans, dt)
				state.pp.brx, state.pp.bvrx = originalIO.bodyModsSpring(state.pp.brx, state.pp.bvrx, ballTargetPitch, kBallRot, dBallRot, dt)
				state.pp.bry, state.pp.bvry = originalIO.bodyModsSpring(state.pp.bry, state.pp.bvry, ballTargetRoll, kBallRot, dBallRot, dt)

				state.pp.bsy = math.clamp(state.pp.bsy, -0.16, 0.14)
				state.pp.bsz = math.clamp(state.pp.bsz, -0.14, 0.08)
				state.pp.bsx = math.clamp(state.pp.bsx, -0.10, 0.10)
				state.pp.brx = math.clamp(state.pp.brx, -0.16, 0.16)
				state.pp.bry = math.clamp(state.pp.bry, -0.18, 0.18)

				local spreadJiggle = math.abs(gait) * math.clamp(0.010 + ballRadius * 0.015, 0.010, 0.024)
				local leftBallSway = CFrame.new(-spreadJiggle - state.pp.bsx, state.pp.bsy, state.pp.bsz) * CFrame.Angles(state.pp.brx, 0, state.pp.bry)
				local rightBallSway = CFrame.new(spreadJiggle + state.pp.bsx, state.pp.bsy, state.pp.bsz) * CFrame.Angles(state.pp.brx, 0, -state.pp.bry)
				state.pp.wBL.C0 = state.pp.baseBL * leftBallSway
				state.pp.wBR.C0 = state.pp.baseBR * rightBallSway
			end
		end)

		originalIO.bodyModsEnsureColorWatcher()
		originalIO.bodyModsConnectAppearanceLoaded(Players.LocalPlayer, originalIO.bodyModsOnAppearanceLoaded)
		originalIO.bodyModsEnsureSpawnConnection()
		DebugNotif("penis "..tostring(value),1.5)
	end

	originalIO.bodyModsRemovePP = function()
		local character = originalIO.bodyModsGetCharacter()
		if not character then
			return
		end

		local toRemove = {}
		for _, part in ipairs(character:GetChildren()) do
			if part:IsA("BasePart") and (part.Name == "Balls" or part.Name == "penis") then
				Insert(toRemove, part)
			end
		end
		for _, part in ipairs(toRemove) do
			part.CanCollide = false
			part.CanTouch = false
			part.CanQuery = false
			__lt.cm("TweenService", "Create", part, TweenInfo.new(0.25, Enum.EasingStyle.Quad, Enum.EasingDirection.Out), { Transparency = 1 }):Play()
		end
		Delay(0.27, function()
			for _, part in ipairs(toRemove) do
				if part and part.Parent then
					part:Destroy()
				end
			end
		end)

		state.pp.animConn = originalIO.bodyModsDisconnectConnection(state.pp.animConn)
		state.pp.active = false
		state.pp.wS = nil
		state.pp.wTip = nil
		state.pp.wBL = nil
		state.pp.wBR = nil
		state.pp.sh = nil
		state.pp.dr = nil
		state.pp.baseC0 = nil
		state.pp.baseBL = nil
		state.pp.baseBR = nil
		state.pp.llv = Vector3.zero
		state.pp.sy = 0
		state.pp.sz = 0
		state.pp.sx = 0
		state.pp.rx = 0
		state.pp.ry = 0
		state.pp.bsy = 0
		state.pp.bsz = 0
		state.pp.bsx = 0
		state.pp.brx = 0
		state.pp.bry = 0

		originalIO.bodyModsEnsureColorWatcher()
		DebugNotif("PP Removed",1.5)
	end

	originalIO.bodyModsReapplyOnSpawn = function(newCharacter)
		Spawn(function()
			local humanoid = newCharacter:WaitForChild("Humanoid", 10)
			if state.boobs.active then
				Spawn(function()
					if originalIO.bodyModsWaitFor({ "UpperTorso", "Torso" }, 10) then
						originalIO.bodyModsApplyBoobs(state.boobs.size or 1)
					end
				end)
			end
			if state.ass.active then
				Spawn(function()
					if humanoid and humanoid.RigType == Enum.HumanoidRigType.R15 then
						if originalIO.bodyModsWaitFor({ "LowerTorso" }, 10) then
							originalIO.bodyModsApplyAss(state.ass.size or 1)
						end
					else
						if originalIO.bodyModsWaitFor({ "Torso" }, 10) then
							originalIO.bodyModsApplyAss(state.ass.size or 1)
						end
					end
				end)
			end
			if state.pp.active then
				Spawn(function()
					if humanoid and humanoid.RigType == Enum.HumanoidRigType.R15 then
						if originalIO.bodyModsWaitFor({ "LowerTorso" }, 10) then
							originalIO.bodyModsApplyPP(state.pp.len or 1)
						end
					else
						if originalIO.bodyModsWaitFor({ "Torso" }, 10) then
							originalIO.bodyModsApplyPP(state.pp.len or 1)
						end
					end
				end)
			end
		end)
	end

	originalIO.bodyModsEnsureSpawnConnection = function()
		if state.spawnConn and state.spawnConn.Connected then
			return
		end
		state.spawnConn = Players.LocalPlayer.CharacterAdded:Connect(originalIO.bodyModsReapplyOnSpawn)
	end

	originalIO.bodyModsEnsurePlayerAppearanceHook = function()
		state.apConn = originalIO.bodyModsDisconnectConnection(state.apConn)
		state.apConn = originalIO.bodyModsConnectAppearanceLoaded(Players.LocalPlayer, originalIO.bodyModsOnAppearanceLoaded)
	end

	originalIO.bodyModsEnsurePlayerAppearanceHook()
	originalIO.bodyModsEnsureSpawnConnection()

	cmd.add({"boobs","boobies"},{"boobs <size> (boobies)","Boobs"},function(arg)
		local value = tonumber(arg) or state.boobs.size or 1
		value = math.clamp(value, 1, 8)
		originalIO.bodyModsApplyBoobs(value)
	end,true)

	cmd.add({"unboobs","unboobies","noboobs","noboobies"},{"unboobs (unboobies,noboobs,noboobies)","Boobs"},function()
		originalIO.bodyModsRemoveBoobs()
	end)

	cmd.add({"ass","booty"},{"ass <size> (booty)","Ass"},function(arg)
		local value = tonumber(arg) or state.ass.size or 1
		value = math.clamp(value, 1, 8)
		originalIO.bodyModsApplyAss(value)
	end,true)

	cmd.add({"unass","noass"},{"unass (noass)","Ass"},function()
		originalIO.bodyModsRemoveAss()
	end)

	cmd.add({"penis","pp"},{"penis <length> (pp)","penis"},function(arg)
		local value = tonumber(arg) or state.pp.len or 1
		value = math.clamp(value, 0.5, 6)
		originalIO.bodyModsApplyPP(value)
	end,true)

	cmd.add({"unpenis","unpp","nopenis","nopp"},{"unpenis (unpp,nopenis,nopp)","penis"},function()
		originalIO.bodyModsRemovePP()
	end)
end

