NAmanage.stripChar = function(text, trimWhitespace)
	if not text then
		return ""
	end
	local cleaned = text:gsub("\t", "")
	if trimWhitespace ~= false then
		cleaned = cleaned:gsub("^%s*(.-)%s*$", "%1")
	end
	return cleaned
end

