local patchedCommandColor = Color3.fromRGB(255, 115, 115)
local pluginCommandColor = Color3.fromRGB(255, 196, 125)
local cmdIntegrationColor = Color3.fromRGB(120, 180, 255)

NAgui.addPatchedLabel=function(text)
	if not text then return text end
	if Lower(text):find("patched", 1, true) then
		return text
	end
	return "[PATCHED] "..text
end

NAgui.txtSize=function(ui,x,y)
	local textService = TextService
	if not (textService and ui) then
		return Vector2.new(0, 0)
	end

	local font = ui.Font
	if font == nil or font == Enum.Font.Unknown then
		font = Enum.Font.SourceSans
	end

	local text = ui.Text or ""
	local size = tonumber(ui.TextSize) or 14
	local bounds = Vector2.new(tonumber(x) or 100, tonumber(y) or 100)

	local ok, result = pcall(textService.GetTextSize, textService, text, size, font, bounds)
	if ok and result then
		return result
	end

	return Vector2.new(0, 0)
end
NAmanage.cmdYield=function(i, budget)
	budget = tonumber(budget) or 120
	if budget > 0 and i > 0 and i % budget == 0 then
		Wait()
	end
end

NAStuff.CommandBuildRevision = tonumber(NAStuff.CommandBuildRevision) or 0
NAStuff.CommandBuildSignatureApplied = NAStuff.CommandBuildSignatureApplied or nil

NAmanage.invalidateCommandBuild = NAmanage.invalidateCommandBuild or function()
	NAStuff.CommandBuildRevision = (tonumber(NAStuff.CommandBuildRevision) or 0) + 1
	return NAStuff.CommandBuildRevision
end

NAmanage.getCommandBuildSignature = NAmanage.getCommandBuildSignature or function()
	local cmdCount = countDictNA(cmds.Commands)
	local aliasCount = countDictNA(cmds.Aliases)
	local savedAliasCount = countDictNA(cmds.NASAVEDALIASES)
	local integrationCount = type(NAStuff.CmdIntegrationCommands) == "table" and #NAStuff.CmdIntegrationCommands or 0
	local revision = tonumber(NAStuff.CommandBuildRevision) or 0
	return table.concat({
		tostring(revision),
		tostring(cmdCount),
		tostring(aliasCount),
		tostring(savedAliasCount),
		tostring(integrationCount),
	}, ":")
end

NAmanage.isCommandDataStale = NAmanage.isCommandDataStale or function()
	local currentSignature = NAmanage.getCommandBuildSignature and NAmanage.getCommandBuildSignature() or nil
	return currentSignature ~= (NAStuff.CommandBuildSignatureApplied or nil)
end

NAmanage.buildCommandDataPackage = function()
	local signature = NAmanage.getCommandBuildSignature and NAmanage.getCommandBuildSignature() or nil
	local entries = {}
	local metaByName = {}
	local used = {}
	local aliasByFunc = {}
	local dataToName = {}
	local aliasOwnerMap = {}
	local savedOwnerMap = {}
	local aliasStep = 0
	local cmdMapStep = 0
	for name, data in pairs(cmds.Commands or {}) do
		cmdMapStep += 1
		if name then
			dataToName[data] = tostring(name)
		end
		NAmanage.cmdYield(cmdMapStep, 220)
	end
	for alias, data in pairs(cmds.Aliases or {}) do
		aliasStep += 1
		NAmanage.cmdYield(aliasStep, 180)
		local lowerAlias = Lower(tostring(alias or ""))
		if lowerAlias ~= "" then
			local owner = dataToName[data]
			if owner then
				aliasOwnerMap[lowerAlias] = owner
			end
		end
		local func = type(data) == "table" and data[1]
		if func then
			local bucket = aliasByFunc[func]
			if not bucket then
				bucket = {}
				aliasByFunc[func] = bucket
			end
			bucket[Lower(tostring(alias))] = true
		end
	end
	for alias, original in pairs(cmds.NASAVEDALIASES or {}) do
		local lowerAlias = Lower(tostring(alias or ""))
		local lowerOriginal = Lower(tostring(original or ""))
		if lowerAlias ~= "" and lowerOriginal ~= "" then
			savedOwnerMap[lowerAlias] = lowerOriginal
		end
	end
	local function resolveCommandDisplay(name, data)
		local dInfo = data and data[2] and data[2][1] or ""
		local func = data and data[1]
		local aliasSet = {}
		local fromFunc = func and aliasByFunc[func]
		if fromFunc then
			for alias in pairs(fromFunc) do
				aliasSet[alias] = true
			end
		end
		local main = name and Lower(name)
		local prefix, aliasBlock = dInfo:match("^(.-)%s*%((.-)%)$")
		if aliasBlock then
			for a in aliasBlock:gmatch("[^,%s]+") do
				aliasSet[Lower(a)] = true
			end
		end
		local final = {}
		for alias in pairs(aliasSet) do
			if alias ~= main then
				Insert(final, alias)
			end
		end
		table.sort(final)
		local updatedText
		if prefix then
			updatedText = prefix.." ("..Concat(final, ", ")..")"
		else
			updatedText = dInfo
			if #final > 0 then
				updatedText = updatedText.." ("..Concat(final, ", ")..")"
			end
		end
		return updatedText, final
	end

	local function addNACommand(name, data)
		if not name or name == "" then return end
		local displayText, extraAliases = resolveCommandDisplay(name, data)
		if displayText and displayText ~= "" then
			if type(data[2]) == "table" then
				data[2][1] = displayText
			end
		else
			displayText = (type(data[2]) == "table" and data[2][1]) or name
		end
		local aliasList = {}
		for _, alias in ipairs(extraAliases or {}) do
			Insert(aliasList, alias:lower())
		end
		local commandMeta = (type(data[4]) == "table") and data[4] or {}
		local isPatched = commandMeta.patched == true
		local isPluginCmd, pluginType = NAmanage.IsPluginCommand and NAmanage.IsPluginCommand(name)
		local pluginTag = nil
		if isPluginCmd then
			pluginTag = pluginType or true -- keep a marker even if type is unknown so coloring works
		end
		local finalText = displayText
		if isPluginCmd then
			finalText = finalText.." ["..(pluginType and (pluginType.." plugin") or "plugin").."]"
		end
		if isPatched then
			finalText = NAgui.addPatchedLabel(finalText)
		end
		if isAprilFools() then
			finalText = maybeMock(finalText)
		end
		local desc = ""
		if type(data[2]) == "table" then
			desc = data[2][2] or ""
		end
		if isPatched then
			if desc == "" then
				desc = "Patched / may not work"
			elseif not Lower(desc):find("patched", 1, true) then
				desc = desc.." (patched)"
			end
		end
		used[Lower(name)] = true
		local searchable = NAmanage.stripMarkup(Lower(finalText or displayText or name))
		if #aliasList > 0 then
			searchable = searchable.." "..Concat(aliasList, " ")
		end
		if desc ~= "" then
			searchable = searchable.." "..NAmanage.stripMarkup(Lower(desc))
		end
		if isPatched then
			searchable = searchable.." patched"
		end
		metaByName[name] = {
			origin = "na";
			displayText = finalText;
			searchable = searchable;
			aliases = aliasList;
			pluginType = pluginTag;
			desc = desc;
			patched = isPatched;
		}
		entries[#entries + 1] = {
			name = name;
			display = finalText;
			meta = metaByName[name];
			sortKey = Lower(tostring(finalText or name));
		}
	end

	local cmdStep = 0
	for name, data in pairs(cmds.Commands) do
		cmdStep += 1
		addNACommand(name, data)
		NAmanage.cmdYield(cmdStep, 120)
	end

	local cmdList = NAStuff.CmdIntegrationCommands
	if type(cmdList) == "table" then
		for cmdInfoIndex, info in ipairs(cmdList) do
			NAmanage.cmdYield(cmdInfoIndex, 120)
			local baseName = info and info.name
			if baseName then
				baseName = tostring(baseName)
			end
			if baseName and baseName ~= "" then
				local key = baseName
				local duplicate = used[Lower(baseName)] == true
				if duplicate then
					key = "cmd:"..baseName
				end
				local aliases = {}
				local displayAliases = {}
				local seenDisplayAliases = {}
				local function addDisplayAlias(alias)
					if type(alias) ~= "string" then return end
					local str = tostring(alias)
					if str == "" then return end
					local lowerStr = str:lower()
					if lowerStr == "" then return end
					if lowerStr ~= key:lower() and lowerStr ~= baseName:lower() and not seenDisplayAliases[lowerStr] then
						seenDisplayAliases[lowerStr] = true
						Insert(displayAliases, str)
					end
				end
				if type(info.aliases) == "table" then
					for _, a in ipairs(info.aliases) do
						local aa = tostring(a or "")
						if aa ~= "" then
							Insert(aliases, aa:lower())
							addDisplayAlias(aa)
						end
					end
				end
				Insert(aliases, key:lower())
				if duplicate then
					Insert(aliases, baseName:lower())
				end
				local displayName = tostring(baseName)
				local desc = ""
				if type(info.desc) == "string" then
					desc = info.desc
				end
				local finalText = "[Cmd] "..displayName
				if duplicate then
					finalText = "[Cmd] "..displayName.." (use cmd:"..baseName..")"
				end
				if #displayAliases > 0 then
					finalText = finalText.." ("..Concat(displayAliases, ", ")..")"
				end
				local searchable = NAmanage.stripMarkup(Lower(displayName))
				if #aliases > 0 then
					searchable = searchable.." "..Concat(aliases, " ")
				end
				if desc ~= "" then
					searchable = searchable.." "..NAmanage.stripMarkup(Lower(desc))
				end
				used[Lower(key)] = true
				metaByName[key] = {
					origin = "cmd";
					displayText = finalText;
					searchable = searchable;
					aliases = aliases;
					sourceName = baseName;
					duplicate = duplicate;
					desc = desc;
				}
				entries[#entries + 1] = {
					name = key;
					display = finalText;
					meta = metaByName[key];
					sortKey = Lower(tostring(finalText or key));
				}
			end
		end
	end

	table.sort(entries, function(a, b)
		return tostring(a.sortKey or a.display or a.name) < tostring(b.sortKey or b.display or b.name)
	end)

	local searchEntries = {}
	local defaultEntryMap = {}
	local defaultTargets = {}
	for _, cmdName in ipairs(defaultBarCommands or {}) do
		local lowerCmd = Lower(tostring(cmdName or ""))
		if lowerCmd ~= "" then
			defaultTargets[lowerCmd] = true
		end
	end
	for i = 1, #entries do
		NAmanage.cmdYield(i, 180)
		local entry = entries[i]
		local cmdName = entry and entry.name
		if cmdName then
			local meta = entry.meta or metaByName[cmdName] or {}
			local lowerName = Lower(tostring(cmdName))
			local extraAliases = {}
			if type(meta.aliases) == "table" then
				for j = 1, #meta.aliases do
					local aliasText = Lower(tostring(meta.aliases[j] or ""))
					if aliasText ~= "" then
						extraAliases[#extraAliases + 1] = aliasText
						if defaultTargets[aliasText] and not defaultEntryMap[aliasText] then
							defaultEntryMap[aliasText] = entry
						end
					end
				end
			end
			if defaultTargets[lowerName] and not defaultEntryMap[lowerName] then
				defaultEntryMap[lowerName] = entry
			end
			searchEntries[#searchEntries + 1] = {
				name = cmdName,
				lowerName = lowerName,
				searchable = meta.searchable or NAmanage.stripMarkup(Lower(tostring(entry.display or cmdName))),
				extraAliases = extraAliases,
				display = entry.display,
				meta = meta,
			}
		end
	end

	return {
		signature = signature;
		totalCount = NAmanage.totalCommandCount and NAmanage.totalCommandCount() or #entries;
		entries = entries;
		metaByName = metaByName;
		searchEntries = searchEntries;
		aliasOwnerMap = aliasOwnerMap;
		savedOwnerMap = savedOwnerMap;
		defaultEntryMap = defaultEntryMap;
	}
end

NAmanage.buildCommandEntries=function()
	local package = NAmanage.buildCommandDataPackage()
	NAStuff.AutofillMetaByName = package and package.metaByName or {}
	return package and package.entries or {}, package and package.metaByName or {}
end

NAmanage.totalCommandCount=function()
	local count = countDictNA(cmds.Commands)
	if type(NAStuff.CmdIntegrationCommands) == "table" then
		count = count + #NAStuff.CmdIntegrationCommands
	end
	return count
end
local COMMAND_LIST_TOP_PADDING = 5
local COMMAND_OVERSCAN_ROWS = 8

NAmanage.cmdStatic = function()
	return false
end

NAmanage.vpSize = function()
	local sg = NAStuff and NAStuff.NASCREENGUI
	local vp = nil
	if sg and sg.AbsoluteSize then
		vp = sg.AbsoluteSize
	end
	if (not vp or vp.X <= 0 or vp.Y <= 0) and workspace.CurrentCamera then
		vp = workspace.CurrentCamera.ViewportSize
	end
	vp = vp or Vector2.new(1280, 720)

	local scale = 1
	local scaler = NAUIMANAGER and NAUIMANAGER.AUTOSCALER
	if scaler then
		scale = tonumber(scaler.Scale) or 1
	end
	if not scale or scale <= 0 then
		scale = 1
	end

	return Vector2.new(math.max(1, vp.X / scale), math.max(1, vp.Y / scale))
end

NAmanage.virtView = function(sf, viewH, totalH, minH)
	if not viewH or viewH <= 0 then
		local vp = NAmanage.vpSize and NAmanage.vpSize() or Vector2.new(1280, 720)
		viewH = math.max(tonumber(minH) or 1, vp.Y * 0.25)
	end

	local y = sf and sf.CanvasPosition and sf.CanvasPosition.Y or 0
	local maxY = math.max(0, (tonumber(totalH) or 0) - viewH)
	if sf and y > maxY + (tonumber(minH) or 1) then
		y = maxY
		sf.CanvasPosition = Vector2.new(sf.CanvasPosition.X, y)
	end

	return viewH, y
end

NAmanage.cmdResp = function(center)
	local frame = NAUIMANAGER and NAUIMANAGER.commandsFrame
	if not (frame and frame:IsA("GuiObject")) then
		return
	end

	local vp = NAmanage.vpSize()
	local margin = (vp.X < 420 or vp.Y < 260) and 8 or 16
	local maxW = math.max(180, vp.X - margin)
	local maxH = math.max(118, vp.Y - margin)
	local minW = math.min(260, math.max(180, maxW))
	local minH = math.min(180, math.max(118, maxH))
	local curW = tonumber(frame.Size.X.Offset) or 300
	local curH = tonumber(frame.Size.Y.Offset) or 320
	local nextW = math.clamp(curW, minW, maxW)
	local nextH = math.clamp(curH, minH, maxH)

	if nextW ~= curW or nextH ~= curH then
		frame.Size = UDim2.new(0, math.floor(nextW + 0.5), 0, math.floor(nextH + 0.5))
	end

	local compact = nextH <= 190 or nextW <= 235
	local container = frame:FindFirstChild("Container")
	if container and container:IsA("GuiObject") then
		container.Size = compact and UDim2.new(1, -10, 1, -42) or UDim2.new(1, -15, 1, -50)
		container.Position = compact and UDim2.new(0.5, 0, 1, -6) or UDim2.new(0.5, 0, 1, -10)

		local filter = container:FindFirstChild("Filter")
		if filter and filter:IsA("GuiObject") then
			filter.Size = compact and UDim2.new(1, -8, 0, 20) or UDim2.new(1, -10, 0, 24)
			filter.Position = compact and UDim2.new(0.5, 0, 0, 4) or UDim2.new(0.5, 0, 0, 5)
			if NAlib and NAlib.isProperty and NAlib.isProperty(filter, "TextSize") then
				filter.TextSize = compact and 14 or 16
			end
		end

		local list = container:FindFirstChild("List")
		if list and list:IsA("GuiObject") then
			list.Position = compact and UDim2.new(0, 4, 0, 27) or UDim2.new(0, 5, 0, 30)
			list.Size = compact and UDim2.new(1, -24, 1, -31) or UDim2.new(1, -28, 1, -35)
		end

		local scrollBar = container:FindFirstChild("CustomScrollBar")
		if scrollBar and scrollBar:IsA("GuiObject") then
			scrollBar.Position = compact and UDim2.new(1, -17, 0, 27) or UDim2.new(1, -18, 0, 30)
			scrollBar.Size = compact and UDim2.new(0, 14, 1, -31) or UDim2.new(0, 16, 1, -35)
		end
	end

	if center and NAmanage.centerFrame then
		NAmanage.centerFrame(frame)
	end
end

function NAmanage.cmdYield(i, budget)
	budget = tonumber(budget) or 120
	if budget > 0 and i > 0 and i % budget == 0 then
		Wait()
	end
end

local function createCommandListLabel(state)
	local label = NAUIMANAGER.commandExample:Clone()
	label.MouseEnter:Connect(function()
		local desc = NAmanage.GetAttr(label, "CmdDesc")
		if type(desc) == "string" and desc ~= "" then
			NAUIMANAGER.description.Visible = true
			NAUIMANAGER.description.Text = desc
		else
			NAUIMANAGER.description.Visible = false
			NAUIMANAGER.description.Text = ""
		end
	end)
	label.MouseLeave:Connect(function()
		NAUIMANAGER.description.Visible = false
		NAUIMANAGER.description.Text = ""
	end)
	return label
end

local function releaseCommandListLabel(state, label)
	if not label then
		return
	end
	label.Visible = false
	label.Parent = nil
	Insert(state.pooledLabels, label)
end

local function acquireCommandListLabel(state)
	local label = table.remove(state.pooledLabels)
	while label do
		if typeof(label) == "Instance" and label.Parent ~= state.virtualCanvas then
			local ok = pcall(function()
				label.Parent = state.virtualCanvas
			end)
			if ok then
				return label
			end
		end
		label = table.remove(state.pooledLabels)
	end

	label = createCommandListLabel(state)
	label.Parent = state.virtualCanvas
	return label
end

local function applyCommandListEntry(state, label, entry, index)
	local meta = entry.meta or {}
	local cmdName = entry.name
	local finalText = meta.displayText or entry.display or cmdName
	local isPatched = meta.patched == true
	local isCmdIntegration = meta.origin == "cmd"
	local isPluginCmd = meta.pluginType ~= nil

	if isPatched then
		label.TextColor3 = patchedCommandColor
	elseif isCmdIntegration then
		label.TextColor3 = cmdIntegrationColor
	elseif isPluginCmd then
		label.TextColor3 = pluginCommandColor
	elseif state.defaultCmdColor then
		label.TextColor3 = state.defaultCmdColor
	end

	local desc = meta.desc
	if desc ~= nil then
		desc = tostring(desc)
	end
	desc = desc or ""
	if desc ~= "" and isAprilFools() then
		desc = maybeMock(desc)
	end

	if label.SetAttribute then
		NAmanage.SetAttr(label, "CmdDesc", desc)
		NAmanage.SetAttr(label, "IsPluginCommand", isPluginCmd)
		NAmanage.SetAttr(label, "IsPatchedCommand", isPatched)
		NAmanage.SetAttr(label, "IsCmdIntegration", isCmdIntegration)
	end

	label.Name = cmdName
	label.Text = " "..finalText
	label.Size = state.templateSize or label.Size
	if state.staticMode then
		label.LayoutOrder = index
		label.Position = UDim2.new(0, 0, 0, 0)
	else
		local rowStep = state.rowStep or 20
		label.Position = UDim2.new(0, 0, 0, COMMAND_LIST_TOP_PADDING + ((index - 1) * rowStep))
	end
	label.Visible = true
end

local function clearStaticCommandLabels(state)
	if type(state.staticLabels) ~= "table" then
		state.staticLabels = {}
		return
	end
	for i = 1, #state.staticLabels do
		local label = state.staticLabels[i]
		if typeof(label) == "Instance" then
			pcall(function()
				label:Destroy()
			end)
		end
	end
	state.staticLabels = {}
end

local function rebuildStaticCommandLabels(state)
	if not state then
		return
	end
	local cList = state.list
	if not cList then
		return
	end

	if state.virtualCanvas and state.virtualCanvas.Parent == cList then
		state.virtualCanvas.Parent = nil
	end
	while #state.visibleLabels > 0 do
		releaseCommandListLabel(state, table.remove(state.visibleLabels))
	end
	clearStaticCommandLabels(state)

	local entries = state.entries or {}
	state.staticLabels = state.staticLabels or {}
	for i = 1, #entries do
		local entry = entries[i]
		local label = createCommandListLabel(state)
		label.Parent = cList
		applyCommandListEntry(state, label, entry, i)
		state.staticLabels[i] = label
	end

	updateCanvasSize(cList, NAUIMANAGER and NAUIMANAGER.AUTOSCALER and NAUIMANAGER.AUTOSCALER.Scale or nil)
	if NAmanage.CustomScroll and NAmanage.CustomScroll.refreshByTarget then
		NAmanage.CustomScroll.refreshByTarget(cList)
	end
end

local function requestCommandListSync(state)
	if not state or state.syncQueued == true then
		return
	end
	state.syncQueued = true
	Defer(function()
		if not state then
			return
		end
		state.syncQueued = false
		if type(NAmanage.syncVisibleCommandRows) == "function" then
			NAmanage.syncVisibleCommandRows(state)
		end
	end)
end

local function getCommandTemplateHeight()
	local template = NAUIMANAGER and NAUIMANAGER.commandExample
	if not template then
		return 18
	end

	local size = template.Size
	if size and size.Y then
		local offset = tonumber(size.Y.Offset) or 0
		if offset > 0 then
			return offset
		end
	end

	local logicalSize = NAmanage.GetLogicalAbsoluteSize and NAmanage.GetLogicalAbsoluteSize(template) or nil
	local absY = logicalSize and logicalSize.Y or (template.AbsoluteSize and template.AbsoluteSize.Y or 0)
	if absY and absY > 0 then
		return math.floor(absY + 0.5)
	end

	return 18
end

NAmanage.ensureCommandListState=function()
	local cList = NAUIMANAGER and NAUIMANAGER.commandsList
	if not (cList and NAUIMANAGER and NAUIMANAGER.commandExample) then
		return nil
	end
	local staticMode = NAmanage.cmdStatic and NAmanage.cmdStatic() or false

	local state = NAStuff.CommandListState
	if type(state) == "table" and state.list == cList and state.staticMode == staticMode then
		if staticMode then
			return state
		end
		if state.virtualCanvas and state.virtualCanvas.Parent == cList then
			return state
		end
	end

	if type(state) == "table" and state.list == cList and state.staticMode ~= staticMode then
		clearStaticCommandLabels(state)
		while #state.visibleLabels > 0 do
			releaseCommandListLabel(state, table.remove(state.visibleLabels))
		end
		if state.virtualCanvas then
			pcall(function()
				state.virtualCanvas:Destroy()
			end)
		end
		NAStuff.CommandListState = nil
		state = nil
	end

	local virtualCanvas = nil
	if not staticMode then
		virtualCanvas = cList:FindFirstChild("VirtualCanvas")
		if not virtualCanvas then
			virtualCanvas = InstanceNew("Frame")
			virtualCanvas.Name = "VirtualCanvas"
			virtualCanvas.BackgroundTransparency = 1
			virtualCanvas.BorderSizePixel = 0
			virtualCanvas.Size = UDim2.new(1, 0, 0, 0)
			virtualCanvas.Position = UDim2.new(0, 0, 0, 0)
			virtualCanvas.Parent = cList
		end
	else
		virtualCanvas = cList:FindFirstChild("VirtualCanvas")
		if virtualCanvas then
			virtualCanvas.Parent = nil
		end
	end

	if type(state) == "table" and state.list == cList and state.staticMode == staticMode then
		return state
	end

	local pooled = {}
	for _, label in pairs(NAStuff.CommandLabelPool or {}) do
		if typeof(label) == "Instance" then
			Insert(pooled, label)
		end
	end
	NAStuff.CommandLabelPool = pooled

	local templateHeight = getCommandTemplateHeight()
	local rowGap = math.max(2, math.floor(templateHeight * 0.15 + 0.5))
	local rowStep = templateHeight + rowGap

	state = {
		list = cList;
		virtualCanvas = virtualCanvas;
		entries = {};
		filteredEntries = {};
		visibleLabels = {};
		pooledLabels = pooled;
		defaultCmdColor = NAUIMANAGER.commandExample.TextColor3;
		templateSize = NAUIMANAGER.commandExample.Size;
		templateHeight = templateHeight;
		rowGap = rowGap;
		rowStep = rowStep;
		syncQueued = false;
		staticMode = staticMode;
		staticLabels = {};
	}
	NAStuff.CommandListState = state

	if NAUIMANAGER.description then
		NAUIMANAGER.description.Visible = false
		NAUIMANAGER.description.Text = ""
	end

	NAlib.disconnect("NA_CommandListCanvasPos")
	NAlib.disconnect("NA_CommandListAbsSize")
	if not staticMode then
		NAlib.connect("NA_CommandListCanvasPos", cList:GetPropertyChangedSignal("CanvasPosition"):Connect(function()
			requestCommandListSync(state)
		end))
		NAlib.connect("NA_CommandListAbsSize", cList:GetPropertyChangedSignal("AbsoluteSize"):Connect(function()
			requestCommandListSync(state)
		end))
	end

	return state
end

NAmanage.syncVisibleCommandRows=function(state)
	state = state or NAmanage.ensureCommandListState()
	if not state then
		return
	end

	local cList = state.list
	local virtualCanvas = state.virtualCanvas
	local filteredEntries = state.filteredEntries or {}
	local count = #filteredEntries

	if state.staticMode then
		updateCanvasSize(cList, NAUIMANAGER and NAUIMANAGER.AUTOSCALER and NAUIMANAGER.AUTOSCALER.Scale or nil)
		if NAmanage.CustomScroll and NAmanage.CustomScroll.refreshByTarget then
			NAmanage.CustomScroll.refreshByTarget(cList)
		end
		return
	end

	if NAUIMANAGER.description then
		NAUIMANAGER.description.Visible = false
		NAUIMANAGER.description.Text = ""
	end

	if count <= 0 then
		while #state.visibleLabels > 0 do
			releaseCommandListLabel(state, table.remove(state.visibleLabels))
		end
		if virtualCanvas then
			virtualCanvas.Size = UDim2.new(1, 0, 0, 0)
		end
		cList.CanvasSize = UDim2.new(0, 0, 0, 0)
		if NAmanage.CustomScroll and NAmanage.CustomScroll.refreshByTarget then
			NAmanage.CustomScroll.refreshByTarget(cList)
		end
		return
	end

	local rowStep = state.rowStep or 20
	local totalHeight = COMMAND_LIST_TOP_PADDING + (count * rowStep)
	virtualCanvas.Size = UDim2.new(1, 0, 0, totalHeight)
	cList.CanvasSize = UDim2.new(0, 0, 0, totalHeight)
	if NAmanage.CustomScroll and NAmanage.CustomScroll.refreshByTarget then
		NAmanage.CustomScroll.refreshByTarget(cList)
	end

	local overscanPx = COMMAND_OVERSCAN_ROWS * rowStep
	local scrollY = cList.CanvasPosition.Y
	local logicalListSize = NAmanage.GetLogicalAbsoluteSize and NAmanage.GetLogicalAbsoluteSize(cList) or nil
	local viewHeight = logicalListSize and logicalListSize.Y or cList.AbsoluteSize.Y
	if NAmanage.virtView then
		viewHeight, scrollY = NAmanage.virtView(cList, viewHeight, totalHeight, rowStep * 3)
	end
	local firstIndex = math.min(count, math.max(1, math.floor((math.max(0, scrollY - COMMAND_LIST_TOP_PADDING - overscanPx)) / rowStep) + 1))
	local lastIndex = math.min(count, math.ceil((math.max(0, scrollY + viewHeight - COMMAND_LIST_TOP_PADDING + overscanPx)) / rowStep))
	if lastIndex < firstIndex then
		lastIndex = firstIndex
	end

	local needed = math.max(0, lastIndex - firstIndex + 1)
	while #state.visibleLabels > needed do
		releaseCommandListLabel(state, table.remove(state.visibleLabels))
	end

	for offset = 1, needed do
		local entryIndex = firstIndex + offset - 1
		local entry = filteredEntries[entryIndex]
		if entry then
			local label = state.visibleLabels[offset]
			if not label then
				label = acquireCommandListLabel(state)
				state.visibleLabels[offset] = label
			elseif label.Parent ~= virtualCanvas then
				label.Parent = virtualCanvas
			end
			applyCommandListEntry(state, label, entry, entryIndex)
		end
	end
end
NAgui.commands = function()
	local cFrame, cList = NAUIMANAGER.commandsFrame, NAUIMANAGER.commandsList
	if not (cFrame and cList and NAUIMANAGER.commandExample) then
		return
	end

	if not cFrame.Visible then
		cFrame.Visible = true
		cList.CanvasSize = UDim2.new(0, 0, 0, 0)
	end
	if NAmanage.cmdResp then
		NAmanage.cmdResp(false)
	end
	NAmanage.centerFrame(cFrame)

	local state = NAmanage.ensureCommandListState()
	if not state then
		return
	end

	local entries = NAStuff.AutofillEntries
	if type(entries) ~= "table" then
		entries = {}
	end
	if type(NAmanage.isCommandDataStale) == "function" and NAmanage.isCommandDataStale() then
		if type(NAmanage.queueCommandDataBuild) == "function" then
			pcall(NAmanage.queueCommandDataBuild, { force = (#entries <= 0) })
		elseif type(NAgui.loadCMDS) == "function" then
			pcall(NAgui.loadCMDS, { force = (#entries <= 0) })
		end
	end
	state.entries = entries
	state.filteredEntries = entries
	NAStuff.CommandFilterEntries = nil

	Defer(function()
		if NAgui.filterCommandList then
			NAgui.filterCommandList(NAUIMANAGER.commandsFilter and NAUIMANAGER.commandsFilter.Text or "")
		else
			NAmanage.syncVisibleCommandRows(state)
		end
	end)
end
