NAgui.tween = function(obj, style, direction, duration, goal, callback)
	style = style or "Sine"
	direction = direction or "Out"
	local tweenInfo = TweenInfo.new(duration, Enum.EasingStyle[style], Enum.EasingDirection[direction])
	local tween = __lt.cm("TweenService", "Create", obj, tweenInfo, goal)
	if callback then
		local completedConn
		completedConn = tween.Completed:Connect(function(...)
			if completedConn then
				pcall(function() completedConn:Disconnect() end)
				completedConn = nil
			end
			callback(...)
		end)
	end
	tween:Play()
	return tween
end

NAgui._resizeCleanup = NAgui._resizeCleanup or {}
NAgui.resizeable = function(ui, min, max)
	if not ui or not ui:IsA("GuiObject") then return function() end end
	local prevCleanup = NAgui._resizeCleanup[ui]
	if prevCleanup then
		pcall(prevCleanup)
		NAgui._resizeCleanup[ui] = nil
	end
	pcall(function()
		NAmanage.SetAttr(ui, "NAResizeActive", nil)
	end)
	local function getUiScale()
		local s = (NAUIMANAGER and NAUIMANAGER.AUTOSCALER and tonumber(NAUIMANAGER.AUTOSCALER.Scale)) or 1
		if not s or s <= 0 then
			s = 1
		end
		return s
	end
	local function getLogicalSize()
		local size = ui.Size
		local lx = tonumber(size.X.Offset) or 0
		local ly = tonumber(size.Y.Offset) or 0
		if size.X.Scale ~= 0 or size.Y.Scale ~= 0 then
			local s = getUiScale()
			local abs = ui.AbsoluteSize
			if size.X.Scale ~= 0 then
				lx = (abs.X or 0) / s
			end
			if size.Y.Scale ~= 0 then
				ly = (abs.Y or 0) / s
			end
		end
		return Vector2.new(lx, ly)
	end

	if not min then
		local baseMin = getLogicalSize()
		min = Vector2.new(
			math.max(1, math.floor(baseMin.X * 0.5 + 0.5)),
			math.max(1, math.floor(baseMin.Y * 0.5 + 0.5))
		)
	end
	max = max or Vector2.new(5000, 5000)

	local screenGui = ui:FindFirstAncestorWhichIsA("ScreenGui") or ui:FindFirstAncestorWhichIsA("LayerCollector") or ui.Parent
	local mouse
	pcall(function()
		if Players and Players.LocalPlayer then
			mouse = NAmanage.GetMouse(Players.LocalPlayer)
		end
	end)

	local rgui = NAUIMANAGER.resizeFrame and NAUIMANAGER.resizeFrame:Clone()
	if not rgui then return function() end end
	rgui.Parent = screenGui
	rgui.BackgroundTransparency = 1
	rgui.ClipsDescendants = false
	NAgui.NAProtection(rgui)

	local function updateOverlay()
		local ok = pcall(function()
			if not ui or not ui.Parent or not rgui or not rgui.Parent or not screenGui then
				return
			end
			local s = getUiScale()
			local absPos = ui.AbsolutePosition
			local absSize = ui.AbsoluteSize
			local rootPos = screenGui.AbsolutePosition or Vector2.new(0, 0)
			local relPos = absPos - rootPos
			rgui.Position = UDim2.new(0, math.floor((relPos.X / s) + 0.5), 0, math.floor((relPos.Y / s) + 0.5))
			rgui.Size = UDim2.new(0, math.floor((absSize.X / s) + 0.5), 0, math.floor((absSize.Y / s) + 0.5))
		end)
		if not ok then end
	end

	local function updateVisibility()
		local ok = pcall(function()
			if not ui or not ui.Parent or not rgui or not rgui.Parent then
				return
			end
			rgui.Visible = ui.Visible
		end)
		if not ok then end
	end

	updateOverlay()
	updateVisibility()

	local overlayConns = {}
	pcall(function()
		Insert(overlayConns, ui:GetPropertyChangedSignal("AbsoluteSize"):Connect(updateOverlay))
	end)
	pcall(function()
		Insert(overlayConns, ui:GetPropertyChangedSignal("AbsolutePosition"):Connect(updateOverlay))
	end)
	pcall(function()
		Insert(overlayConns, ui:GetPropertyChangedSignal("Visible"):Connect(updateVisibility))
	end)
	pcall(function()
		if NAUIMANAGER and NAUIMANAGER.AUTOSCALER and NAUIMANAGER.AUTOSCALER.GetPropertyChangedSignal then
			Insert(overlayConns, NAUIMANAGER.AUTOSCALER:GetPropertyChangedSignal("Scale"):Connect(updateOverlay))
		end
	end)

	local dragging = false
	local mode
	local UIPos
	local lastSize
	local lastPos = Vector2.new()
	local dragInput
	local dragEndedConn
	local cursorSaved
	local cursorActive = false
	local touchGestureLocked = false

	local function isMenuMinimized()
		return ui and ui.GetAttribute and NAmanage.GetAttr(ui, "NAMenuMinimized") == true
	end

	local function ensureMouse()
		if mouse then return mouse end
		pcall(function()
			if Players and Players.LocalPlayer then
				mouse = NAmanage.GetMouse(Players.LocalPlayer)
			end
		end)
		return mouse
	end

	local function setCursor(icon)
		if not ensureMouse() then return end
		if not mouse then return end
		if not cursorActive then
			cursorSaved = mouse.Icon
			cursorActive = true
		end
		mouse.Icon = icon or ""
	end

	local function restoreCursor()
		if not mouse then return end
		if cursorActive then
			mouse.Icon = cursorSaved or ""
			cursorSaved = nil
			cursorActive = false
		elseif mouse.Icon ~= "" then
			mouse.Icon = ""
		end
	end

	local function endDrag()
		if touchGestureLocked then
			NAgui.releaseTouchGesture(ui, "resize", dragInput)
			touchGestureLocked = false
		end
		pcall(function()
			if ui then
				NAmanage.SetAttr(ui, "NAResizeActive", nil)
			end
		end)
		dragging = false
		mode = nil
		dragInput = nil
		if dragEndedConn then dragEndedConn:Disconnect() dragEndedConn = nil end
		restoreCursor()
	end

	local function updateResize(currentPos)
		local ok, err = pcall(function()
			if isMenuMinimized() then return end
			if not dragging or not mode or not screenGui or not screenGui.AbsoluteSize then return end
			local map = resizeXY and resizeXY[mode.Name]
			if not map then return end

			local s = getUiScale()
			local delta = (currentPos - lastPos) / s

			local resizeDelta = Vector2.new(delta.X * map[1].X, delta.Y * map[1].Y)
			local newSize = Vector2.new(
				math.clamp(lastSize.X + resizeDelta.X, min.X, max.X),
				math.clamp(lastSize.Y + resizeDelta.Y, min.Y, max.Y)
			)

			ui.Size = UDim2.new(0, newSize.X, 0, newSize.Y)

			local ox = UIPos.X.Offset
			local oy = UIPos.Y.Offset
			if map[1].X < 0 then
				ox = ox + (lastSize.X - newSize.X)
			end
			if map[1].Y < 0 then
				oy = oy + (lastSize.Y - newSize.Y)
			end

			ui.Position = UDim2.new(UIPos.X.Scale, ox, UIPos.Y.Scale, oy)
		end)
		if not ok then warn("Resize update failed:", err) end
	end

	local uisChangedConn, uisEndedConn
	pcall(function()
		uisChangedConn = UserInputService.InputChanged:Connect(function(input)
			pcall(function()
				if dragging and (input.UserInputType == Enum.UserInputType.MouseMovement or input.UserInputType == Enum.UserInputType.Touch) then
					if input.UserInputType == Enum.UserInputType.Touch and input ~= dragInput then
						return
					end
					updateResize(Vector2.new(input.Position.X, input.Position.Y))
				end
			end)
		end)
	end)

	pcall(function()
		uisEndedConn = UserInputService.InputEnded:Connect(function(input)
			pcall(function()
				if not dragging then return end
				if input.UserInputType == Enum.UserInputType.MouseButton1 then
					endDrag()
				elseif input.UserInputType == Enum.UserInputType.Touch and input == dragInput then
					endDrag()
				end
			end)
		end)
	end)

	for _, button in ipairs(rgui:GetChildren()) do
		if button:IsA("GuiObject") then
			button.Active = true
			pcall(function()
				Insert(overlayConns, button.InputBegan:Connect(function(input)
					pcall(function()
						if input.UserInputType == Enum.UserInputType.MouseButton1 or input.UserInputType == Enum.UserInputType.Touch then
							if input.UserInputType == Enum.UserInputType.Touch then
								if not (NAgui.tryLockTouchGesture and NAgui.tryLockTouchGesture(ui, "resize", input)) then
									return
								end
								touchGestureLocked = true
							end
							mode = button
							dragging = true
							pcall(function()
								if ui then
									NAmanage.SetAttr(ui, "NAResizeActive", true)
								end
							end)
							local p = input.Position
							lastPos = Vector2.new(p.X, p.Y)
							lastSize = getLogicalSize()
							UIPos = ui.Position
							dragInput = input
							if dragEndedConn then dragEndedConn:Disconnect() end
							dragEndedConn = input.Changed:Connect(function()
								if input.UserInputState == Enum.UserInputState.End then
									endDrag()
								end
							end)
						end
					end)
				end))
			end)

			pcall(function()
				Insert(overlayConns, button.InputEnded:Connect(function(input)
					pcall(function()
						if not dragging or mode ~= button or input.UserInputState ~= Enum.UserInputState.End then return end
						if input.UserInputType == Enum.UserInputType.MouseButton1 then
							endDrag()
						elseif input.UserInputType == Enum.UserInputType.Touch and input == dragInput then
							endDrag()
						end
					end)
				end))
			end)

			pcall(function()
				Insert(overlayConns, button.MouseEnter:Connect(function()
					pcall(function()
						local map = resizeXY and resizeXY[button.Name]
						if map then setCursor(map[3]) end
					end)
				end))
			end)

			pcall(function()
				Insert(overlayConns, button.MouseLeave:Connect(function()
					pcall(function()
						if not dragging then restoreCursor() end
					end)
				end))
			end)
		end
	end

	local cleaned = false
	local ancestryConn
	pcall(function()
		ancestryConn = ui.AncestryChanged:Connect(function(_, parent)
			if not parent then
				pcall(function()
					if NAgui._resizeCleanup[ui] then
						NAgui._resizeCleanup[ui]()
					end
				end)
			end
		end)
	end)

	local function cleanup()
		if cleaned then return end
		cleaned = true
		NAgui._resizeCleanup[ui] = nil
		pcall(endDrag)
		for _, conn in ipairs(overlayConns) do
			pcall(function() conn:Disconnect() end)
		end
		pcall(function() if ancestryConn then ancestryConn:Disconnect() end end)
		pcall(function() if uisChangedConn then uisChangedConn:Disconnect() end end)
		pcall(function() if uisEndedConn then uisEndedConn:Disconnect() end end)
		pcall(function() if dragEndedConn then dragEndedConn:Disconnect() end end)
		pcall(restoreCursor)
		pcall(function() rgui:Destroy() end)
	end
	NAgui._resizeCleanup[ui] = cleanup
	return cleanup
end
NAmanage.UpdateWaypointList=function()
	local list = NAUIMANAGER.WaypointList
	local rawFilter = NAUIMANAGER.filterBox and NAUIMANAGER.filterBox.Text or ""
	local filterText = rawFilter:lower()
	for _, child in ipairs(list:GetChildren()) do
		if not child:IsA("UIListLayout") then
			child:Destroy()
		end
	end
	for name, entry in pairs(Waypoints) do
		if filterText == "" or name:lower():find(filterText, 1, true) then
			local row = NAUIMANAGER.WPFrame:Clone()
			row.Name = name
			row.Parent = list
			local nameBtn = row:FindFirstChildWhichIsA("TextButton")
			if nameBtn then nameBtn.Text = name end
			local actionFrame = row:FindFirstChildWhichIsA("Frame")
			if actionFrame then
				local copyBtn = actionFrame:FindFirstChild("CopyBtn")
				local delBtn = actionFrame:FindFirstChild("DelBtn")
				local tpBtn = actionFrame:FindFirstChild("TPBtn")
				if copyBtn then
					MouseButtonFix(copyBtn, function()
						local comps = entry.Components
						if type(comps) ~= "table" then
							return DebugNotif("Waypoint data missing", 3)
						end
						local posX, posY, posZ = comps[1], comps[2], comps[3]
						if type(posX) ~= "number" or type(posY) ~= "number" or type(posZ) ~= "number" then
							return DebugNotif("Waypoint position is invalid", 3)
						end
						local copyText = Format("%f, %f, %f", posX, posY, posZ)
						if setclipboard then
							pcall(setclipboard, copyText)
							DebugNotif("Copied "..name)
						else
							DebugNotif("Copy not supported")
						end
					end)
				end
				if delBtn then
					MouseButtonFix(delBtn, function()
						Waypoints[name] = nil
						NAmanage.SaveWaypoints()
						NAmanage.UpdateWaypointList()
						DebugNotif("Removed '"..name.."'")
					end)
				end
				if tpBtn then
					MouseButtonFix(tpBtn, function()
						local comps = entry.Components
						local cf = CFrame.new(unpack(comps))
						local char = getChar()
						if char then
							char:PivotTo(cf)
						end
					end)
				end
			end
		end
	end
	updateCanvasSize(list, NAUIMANAGER and NAUIMANAGER.AUTOSCALER and NAUIMANAGER.AUTOSCALER.Scale or nil)
end

NAgui.atchSettings = function(row, hoverKey, strength)
	if not (row and row:IsA("GuiObject")) then
		return
	end
	if not (TweenService and NAlib and NAlib.connect and NAlib.disconnect) then
		return
	end

	local key = "NAgui_row_hover:"..tostring(hoverKey or row.Name or "row")
	local baseRowColor = row.BackgroundColor3
	local hoverRowColor = baseRowColor:Lerp(Color3.new(1, 1, 1), strength or 0.08)

	local function tw(color)
		pcall(function()
			__lt.cm("TweenService", "Create", row, TweenInfo.new(0.22, Enum.EasingStyle.Exponential, Enum.EasingDirection.Out), {
				BackgroundColor3 = color
			}):Play()
		end)
	end

	NAlib.disconnect(key)
	NAlib.connect(key, row.MouseEnter:Connect(function()
		tw(hoverRowColor)
	end))
	NAlib.connect(key, row.MouseLeave:Connect(function()
		tw(baseRowColor)
	end))
	NAlib.connect(key, row:GetPropertyChangedSignal("Parent"):Connect(function()
		if not row.Parent then
			Defer(function()
				NAlib.disconnect(key)
			end)
		end
	end))
end

NAgui.addButton = function(label, callback)
	if not NAUIMANAGER.SettingsList then return end
	local button = templates.Button:Clone()
	button.Title.Text = label
	NAmanage.SetSearch.tag(button, label)
	button.Parent = NAUIMANAGER.SettingsList
	button.LayoutOrder = NAgui._nextLayoutOrder()
	NAmanage.registerElementForCurrentTab(button)
	if NAgui.RegisterStrokesFrom then
		NAgui.RegisterStrokesFrom(button)
	end
	NAgui.atchSettings(button, "button:"..tostring(label)..":"..tostring(button.LayoutOrder), 0.08)

	MouseButtonFix(button.Interact,function()
		pcall(callback)
	end)
	return button
end

NAgui.addSection = function(titleText)
	if not NAUIMANAGER.SettingsList then return end
	local section = templates.SectionTitle:Clone()
	section.Title.Text = titleText
	pcall(function()
		NAmanage.SetAttr(section, "NASettingsSection", true)
	end)
	NAmanage.SetSearch.tag(section, titleText)
	section.Parent = NAUIMANAGER.SettingsList
	section.LayoutOrder = NAgui._nextLayoutOrder()
	NAmanage.registerElementForCurrentTab(section)
	if NAgui.RegisterStrokesFrom then
		NAgui.RegisterStrokesFrom(section)
	end
end

NAgui.getInputMinWidth=function(frame, fallback)
	fallback = fallback or 32
	if not (frame and frame.GetAttribute) then
		return fallback
	end
	local ok, attr = pcall(function()
		return NAmanage.GetAttr(frame, "NAMinWidth")
	end)
	local minAttr = tonumber(ok and attr or nil)
	if not minAttr then
		return fallback
	end
	return math.max(fallback, minAttr)
end

NAgui.getInputMeasureText=function(box)
	if not box then
		return ""
	end

	local text = tostring(box.Text or "")
	local okContent, contentText = pcall(function()
		return box.ContentText
	end)
	if okContent and type(contentText) == "string" and contentText ~= "" then
		local focused = false
		local okFocused, isFocused = pcall(function()
			return box:IsFocused()
		end)
		if okFocused and isFocused == true then
			focused = true
		end
		if focused or text == "" then
			text = contentText
		end
	end

	return text
end

NAgui.getInputTextWidth=function(box, padding)
	padding = padding or 24
	if not box then
		return padding
	end
	local measureText = NAgui.getInputMeasureText(box)

	if box.TextScaled and TextService then
		local okScaled, sizeScaled = pcall(function()
			local fontSize = tonumber(box.TextSize) or 14
			return __lt.cm("TextService", "GetTextSize", measureText, fontSize, box.Font or Enum.Font.SourceSans, Vector2.new(1e4, 1e3))
		end)
		if okScaled and sizeScaled and type(sizeScaled.X) == "number" then
			return sizeScaled.X + padding
		end
	end

	local okBounds, bounds = pcall(function()
		return box.TextBounds
	end)
	if okBounds and bounds and type(bounds.X) == "number" then
		return bounds.X + padding
	end

	if TextService then
		local okSize, size = pcall(function()
			return __lt.cm("TextService", "GetTextSize", measureText, box.TextSize or 14, box.Font or Enum.Font.SourceSans, Vector2.new(1e4, 1e3))
		end)
		if okSize and size and type(size.X) == "number" then
			return size.X + padding
		end
	end

	return 56
end

NAgui.addInfo = function(label, value, opts)
	if not NAUIMANAGER.SettingsList then return nil end
	opts = type(opts) == "table" and opts or {}

	local info = templates.Input:Clone()
	info.Name = "Info"
	info.Title.Text = label
	NAmanage.SetSearch.tag(info, label)

	info.LayoutOrder = NAgui._nextLayoutOrder()
	info.Parent = NAUIMANAGER.SettingsList
	NAmanage.registerElementForCurrentTab(info)
	if NAgui.RegisterStrokesFrom then
		NAgui.RegisterStrokesFrom(info)
	end
	NAgui.atchSettings(info, "info:"..tostring(label)..":"..tostring(info.LayoutOrder), 0.06)

	local frame = info.InputFrame
	if not frame then
		return nil
	end

	local box = frame.InputBox
	if not box then
		return nil
	end

	box.Text = value or ""
	box.PlaceholderText = ""
	box.ClearTextOnFocus = false
	pcall(function()
		box.TextEditable = false
	end)
	pcall(function()
		box.Interactable = false
	end)
	box.Active = false
	box.Selectable = false

	box.TextXAlignment = Enum.TextXAlignment.Center
	box.TextWrapped = false
	box.TextTruncate = Enum.TextTruncate.None
	local textScaledEnabled = opts.textScaled ~= false
	box.TextScaled = textScaledEnabled
	box.ClipsDescendants = true
	frame.ClipsDescendants = true
	local baseTextSize = tonumber(opts.textSize) or tonumber(box.TextSize) or 14
	local minTextSize = tonumber(opts.minTextSize) or 10
	if minTextSize > baseTextSize then
		minTextSize = baseTextSize
	end
	local clampAlignLeft = opts.clampAlignLeft ~= false
	local autoShrink = opts.autoShrink ~= false

	local lastW

	local function resize()
		if not (info and frame and box) then
			return
		end
		local textW = NAgui.getInputTextWidth(box)
		local minW = NAgui.getInputMinWidth(frame)
		local maxW

		local cw = info.AbsoluteSize.X
		if (not cw or cw <= 0) and info.Parent then
			cw = info.Parent.AbsoluteSize.X
		end
		if (not cw or cw <= 0) and NAUIMANAGER and NAUIMANAGER.SettingsList then
			cw = NAUIMANAGER.SettingsList.AbsoluteSize.X
		end

		if cw and cw > 0 then
			local tw = (info.Title and info.Title.TextBounds.X or 0)
			local gap = 32
			maxW = cw - tw - gap
		end

		local w = math.max(textW, minW)
		local hit = false
		if maxW then
			local clamped = math.max(minW, math.min(w, maxW))
			hit = clamped >= (maxW - 0.5)
			w = clamped
		end

		box.TextXAlignment = (hit and clampAlignLeft) and Enum.TextXAlignment.Left or Enum.TextXAlignment.Center

		if not textScaledEnabled then
			local targetTextSize = baseTextSize
			if hit and autoShrink then
				local avail = math.max(1, w - 14)
				local rawWidth = math.max(1, NAgui.getInputTextWidth(box, 0))
				if rawWidth > avail then
					targetTextSize = math.max(minTextSize, math.floor(baseTextSize * (avail / rawWidth)))
				end
			end
			if box.TextSize ~= targetTextSize then
				box.TextSize = targetTextSize
			end
		end

		if type(w) ~= "number" then
			return
		end

		if not lastW or math.abs(lastW - w) > 0.5 then
			lastW = w
			frame.Size = UDim2.new(0, w, 0, 30)
		end
	end

	box:GetPropertyChangedSignal("TextBounds"):Connect(resize)
	box:GetPropertyChangedSignal("Text"):Connect(resize)
	info:GetPropertyChangedSignal("AbsoluteSize"):Connect(resize)
	resize()

	local interact = frame:FindFirstChild("Interact")
	if interact then
		interact.Visible = false
	end

	return box, info
end

NAgui._toggleRegistry = NAgui._toggleRegistry or {}
NAgui._colorPickerRegistry = NAgui._colorPickerRegistry or {}
NAgui._sliderRegistry = NAgui._sliderRegistry or {}
NAgui._inputRegistry = NAgui._inputRegistry or {}
NAgui._dropdownRegistry = NAgui._dropdownRegistry or {}
NAgui._keybindRegistry = NAgui._keybindRegistry or {}

NAgui.addToggle = function(lbl, def, cb, opt)
	if not NAUIMANAGER.SettingsList then return end
	opt = opt or {}
	cb = type(cb) == "function" and cb or function() end

	local tgl = templates.Toggle:Clone()
	local sw = tgl:FindFirstChild("Switch")
	local ind = sw and sw:FindFirstChild("Indicator")
	local st = ind and ind:FindFirstChildWhichIsA("UIStroke")
	local swStroke = sw and sw:FindFirstChildWhichIsA("UIStroke")
	local rowStroke = tgl:FindFirstChild("UIStroke")
	local title = tgl:FindFirstChild("Title")

	if sw then
		pcall(function() sw.Active = false end)
		pcall(function() sw.Selectable = false end)
	end

	local it = tgl:FindFirstChild("Interact")
	if it then
		it:Destroy()
	end

	it = InstanceNew("ImageButton")
	it.Name = "Interact"
	it.BackgroundTransparency = 1
	it.ImageTransparency = 1
	it.AutoButtonColor = false
	it.Active = true
	it.Selectable = false
	it.ZIndex = 999999
	it.AnchorPoint = Vector2.new(1, 0.5)
	it.Position = UDim2.new(1, -15, 0.5, 0)
	it.Size = UDim2.new(0, 45, 0, 22)
	it.Parent = tgl

	local cbtn
	if opt.sideChip and sw then
		local chip = sw:Clone()
		chip.Name = "SideSwitch"
		chip.Parent = tgl

		local w = sw.Size.X.Offset
		if w <= 0 then w = 45 end

		sw.AnchorPoint = Vector2.new(1, 0.5)
		sw.Position = UDim2.new(1, -15, 0.5, 0)

		chip.AnchorPoint = Vector2.new(1, 0.5)
		chip.Position = UDim2.new(1, -15 - w - 6, 0.5, 0)
		chip.Size = UDim2.new(0, w, 0, sw.Size.Y.Offset)

		it.AnchorPoint = Vector2.new(1, 0.5)
		it.Position = UDim2.new(1, -15, 0.5, 0)
		it.Size = UDim2.new(0, 45, 0, 22)

		local cind = chip:FindFirstChild("Indicator")
		local cst = chip:FindFirstChildWhichIsA("UIStroke", true)
		local con = false

		local function cupd()
			if cind then
				local onx = chip.AbsoluteSize.X - cind.AbsoluteSize.X - 4
				local offx = 2
				local toPos = UDim2.new(0, con and onx or offx, 0.5, 0)
				pcall(function()
					__lt.cm("TweenService", "Create", cind, TweenInfo.new(0.35, Enum.EasingStyle.Quart, Enum.EasingDirection.Out), {
						Position = toPos
					}):Play()
				end)
				cind.Visible = false
			end
			if cst then
				pcall(function()
					__lt.cm("TweenService", "Create", cst, TweenInfo.new(0.4, Enum.EasingStyle.Exponential, Enum.EasingDirection.Out), {
						Color = con and Color3.fromRGB(155, 100, 255) or Color3.fromRGB(72, 72, 72)
					}):Play()
				end)
			end
		end

		if type(opt.sideGet) == "function" then
			local ok, v = pcall(opt.sideGet)
			if ok then con = v and true or false end
		end
		cupd()

		cbtn = InstanceNew("TextButton")
		cbtn.Name = "ChipInteract"
		cbtn.BackgroundTransparency = 1
		cbtn.Text = "Use"
		cbtn.TextColor3 = Color3.new(1, 1, 1)
		cbtn.AutoButtonColor = false
		cbtn.Size = UDim2.new(1, 0, 1, 0)
		cbtn.Parent = chip

		chip.ZIndex = it.ZIndex + 1
		for _, d in ipairs(NAmanage.qDesc(chip, "GuiObject")) do
			d.ZIndex = it.ZIndex + 2
		end
		cbtn.ZIndex = it.ZIndex + 3

		MouseButtonFix(cbtn, function()
			con = not con
			cupd()
			if type(opt.sideSet) == "function" then
				pcall(opt.sideSet, con)
			end
		end)
	end

	tgl.Title.Text = lbl
	NAmanage.SetSearch.tag(tgl, lbl)
	tgl.Parent = NAUIMANAGER.SettingsList
	tgl.ZIndex = 1
	for _, d in ipairs(NAmanage.qDesc(tgl, "GuiObject")) do
		d.ZIndex = d == it and 999999 or d.ZIndex
	end
	tgl.LayoutOrder = NAgui._nextLayoutOrder()
	NAmanage.registerElementForCurrentTab(tgl)

	local baseRowColor = tgl.BackgroundColor3
	local hoverRowColor = baseRowColor:Lerp(Color3.new(1, 1, 1), 0.08)
	local on = def and true or false
	local busy = false

	local function tw(obj, info, goal)
		if not obj then return nil end
		local ok, tween = pcall(function()
			return __lt.cm("TweenService", "Create", obj, info, goal)
		end)
		if ok and tween then
			tween:Play()
			return tween
		end
		return nil
	end

	local function animateRowHover(show)
		local rowColor = show and hoverRowColor or baseRowColor
		tw(tgl, TweenInfo.new(0.25, Enum.EasingStyle.Exponential, Enum.EasingDirection.Out), {
			BackgroundColor3 = rowColor
		})
	end

	local function applyToggleVisual(state, opts2)
		opts2 = opts2 or {}
		local animate = opts2.animate ~= false
		local pulse = opts2.pulse == true

		if not ind then
			return
		end

		local onPos = UDim2.new(1, -20, 0.5, 0)
		local offPos = UDim2.new(1, -40, 0.5, 0)
		local toPos = state and onPos or offPos
		local toColor = state and Color3.fromRGB(60, 200, 80) or Color3.fromRGB(111, 111, 121)
		local toStroke = state and Color3.fromRGB(50, 255, 80) or Color3.fromRGB(80, 80, 80)
		local toOuterStroke = state and Color3.fromRGB(84, 208, 102) or Color3.fromRGB(72, 72, 72)

		if animate then
			animateRowHover(true)
			if rowStroke then
				tw(rowStroke, TweenInfo.new(0.45, Enum.EasingStyle.Exponential, Enum.EasingDirection.Out), {
					Transparency = 1
				})
			end
			tw(ind, TweenInfo.new(state and 0.5 or 0.45, Enum.EasingStyle.Quart, Enum.EasingDirection.Out), {
				Position = toPos
			})
			tw(ind, TweenInfo.new(0.8, Enum.EasingStyle.Exponential, Enum.EasingDirection.Out), {
				BackgroundColor3 = toColor
			})
			if st then
				tw(st, TweenInfo.new(0.55, Enum.EasingStyle.Exponential, Enum.EasingDirection.Out), {
					Color = toStroke
				})
			end
			if swStroke then
				tw(swStroke, TweenInfo.new(0.55, Enum.EasingStyle.Exponential, Enum.EasingDirection.Out), {
					Color = toOuterStroke
				})
			end
			if pulse then
				local mini = UDim2.new(0, 12, 0, 12)
				local resetSize = UDim2.new(0, 17, 0, 17)
				local down = tw(ind, TweenInfo.new(0.15, Enum.EasingStyle.Quart, Enum.EasingDirection.Out), { Size = mini })
				if down then
					pcall(function()
						down.Completed:Connect(function()
							tw(ind, TweenInfo.new(0.22, Enum.EasingStyle.Quart, Enum.EasingDirection.Out), { Size = resetSize })
						end)
					end)
				else
					ind.Size = resetSize
				end
			end
			Delay(0.05, function()
				animateRowHover(false)
				if rowStroke then
					tw(rowStroke, TweenInfo.new(0.45, Enum.EasingStyle.Exponential, Enum.EasingDirection.Out), {
						Transparency = 0
					})
				end
			end)
		else
			ind.Position = toPos
			ind.BackgroundColor3 = toColor
			if st then st.Color = toStroke end
			if swStroke then swStroke.Color = toOuterStroke end
		end
	end

	local function flashToggleError(message)
		tw(tgl, TweenInfo.new(0.25, Enum.EasingStyle.Exponential, Enum.EasingDirection.Out), {
			BackgroundColor3 = Color3.fromRGB(85, 0, 0)
		})
		if rowStroke then
			tw(rowStroke, TweenInfo.new(0.25, Enum.EasingStyle.Exponential, Enum.EasingDirection.Out), {
				Transparency = 1
			})
		end
		local prevTitle = title and title.Text or nil
		if title then
			title.Text = "Callback Error"
		end
		warn("[NA] Toggle callback error ("..tostring(lbl).."): "..tostring(message))
		Delay(0.5, function()
			if not tgl.Parent then
				return
			end
			if title and prevTitle ~= nil then
				title.Text = prevTitle
			end
			tw(tgl, TweenInfo.new(0.35, Enum.EasingStyle.Exponential, Enum.EasingDirection.Out), {
				BackgroundColor3 = baseRowColor
			})
			if rowStroke then
				tw(rowStroke, TweenInfo.new(0.35, Enum.EasingStyle.Exponential, Enum.EasingDirection.Out), {
					Transparency = 0
				})
			end
		end)
	end

	local function set(v, o)
		o = o or {}
		local want = v and true or false
		if not o.force and on == want then
			if o.fire then
				local ok, err = pcall(cb, on)
				if not ok then
					flashToggleError(err)
				end
			end
			return
		end
		on = want
		applyToggleVisual(on, {
			animate = o.animate ~= false,
			pulse = o.pulse == true
		})
		if o.fire ~= false then
			local ok, err = pcall(cb, on)
			if not ok then
				flashToggleError(err)
			end
		end
	end

	if rowStroke then
		rowStroke.Transparency = 1
		tw(rowStroke, TweenInfo.new(0.7, Enum.EasingStyle.Exponential, Enum.EasingDirection.Out), { Transparency = 0 })
	end
	if title then
		title.TextTransparency = 1
		tw(title, TweenInfo.new(0.7, Enum.EasingStyle.Exponential, Enum.EasingDirection.Out), { TextTransparency = 0 })
	end
	tgl.BackgroundTransparency = 1
	tw(tgl, TweenInfo.new(0.7, Enum.EasingStyle.Exponential, Enum.EasingDirection.Out), { BackgroundTransparency = 0 })

	set(on, { force = true, fire = false, animate = false, pulse = false })

	NAlib.connect("NAgui_toggle_hover:"..tostring(lbl)..":"..tostring(tgl.LayoutOrder), tgl.MouseEnter:Connect(function()
		animateRowHover(true)
	end))
	NAlib.connect("NAgui_toggle_hover:"..tostring(lbl)..":"..tostring(tgl.LayoutOrder), tgl.MouseLeave:Connect(function()
		animateRowHover(false)
	end))

	local function clk()
		if busy then return end
		busy = true
		set(not on, { force = true, fire = true, animate = true, pulse = true })
		Defer(function()
			busy = false
		end)
	end

	MouseButtonFix(it, clk)

	local ent = {
		button = tgl;
		get = function() return on end;
		set = function(v, o)
			o = o or {}
			if o.force == nil then o.force = true end
			if o.animate == nil then o.animate = true end
			set(v, o)
		end;
	}
	NAgui._toggleRegistry[lbl] = ent

	tgl:GetPropertyChangedSignal("Parent"):Connect(function()
		if not tgl.Parent and NAgui._toggleRegistry[lbl] == ent then
			NAgui._toggleRegistry[lbl] = nil
		end
	end)

	return tgl
end

NAgui.setToggleState = function(label, value, opts)
	local entry = NAgui._toggleRegistry and NAgui._toggleRegistry[label]
	if not entry then return end
	entry.set(value, opts)
end

NAgui.addColorPicker = function(label, defaultColor, callback, opts)
	if not NAUIMANAGER.SettingsList then return end
	callback = type(callback) == "function" and callback or function() end

	local cfg = opts or {}

	local picker = templates.ColorPicker:Clone()
	picker.Title.Text = label
	NAmanage.SetSearch.tag(picker, label)
	picker.Parent = NAUIMANAGER.SettingsList
	picker.LayoutOrder = NAgui._nextLayoutOrder()
	NAmanage.registerElementForCurrentTab(picker)

	local bg = picker.CPBackground
	local disp = bg.Display
	local main = bg.MainCP
	local sl = picker.ColorSlider
	local rgb = picker.RGB
	local hex = picker.HexInput
	local rowStroke = picker:FindFirstChild("UIStroke")
	local title = picker:FindFirstChild("Title")
	local interact = picker:FindFirstChild("Interact")
	local baseRowColor = picker.BackgroundColor3
	local hoverRowColor = baseRowColor:Lerp(Color3.new(1, 1, 1), 0.08)
	local opened = false

	local rgbTog = picker:FindFirstChild("RGBToggle")
	local rgbBtn, rgbSw, rgbDot, rgbTit

	if rgbTog and rgbTog:IsA("GuiObject") then
		rgbBtn = rgbTog:FindFirstChild("Interact")
		rgbSw = rgbTog:FindFirstChild("Switch")
		if rgbSw then
			rgbDot = rgbSw:FindFirstChild("Indicator")
		end
		rgbTit = rgbTog:FindFirstChild("Title")
	end

	if not (rgbTog and rgbBtn and rgbSw and rgbDot and rgbTit) then
		rgbTog, rgbBtn, rgbSw, rgbDot, rgbTit = NAgui.MakeSwitchRow(picker, "RGBToggle", "RGB Cycle")
	end

	if not (interact and interact:IsA("GuiButton")) then
		interact = InstanceNew("TextButton")
		interact.Name = "Interact"
		interact.BackgroundTransparency = 1
		interact.BorderSizePixel = 0
		interact.Text = ""
		interact.AutoButtonColor = false
		interact.AnchorPoint = Vector2.new(0.5, 0.5)
		interact.Position = UDim2.new(0.5, 0, 0.5, 0)
		interact.Size = UDim2.new(1, 0, 1, 0)
		interact.Parent = picker
	end

	local function tw(obj, info, goal)
		if not obj then return nil end
		local ok, tween = pcall(function()
			return __lt.cm("TweenService", "Create", obj, info, goal)
		end)
		if ok and tween then
			tween:Play()
			return tween
		end
		return nil
	end

	local function flashColorPickerError(message)
		tw(picker, TweenInfo.new(0.25, Enum.EasingStyle.Exponential, Enum.EasingDirection.Out), {
			BackgroundColor3 = Color3.fromRGB(85, 0, 0)
		})
		if rowStroke then
			tw(rowStroke, TweenInfo.new(0.25, Enum.EasingStyle.Exponential, Enum.EasingDirection.Out), {
				Transparency = 1
			})
		end
		local prevTitle = title and title.Text or nil
		if title then
			title.Text = "Callback Error"
		end
		warn("[NA] ColorPicker callback error ("..tostring(label).."): "..tostring(message))
		Delay(0.5, function()
			if not picker.Parent then
				return
			end
			if title and prevTitle ~= nil then
				title.Text = prevTitle
			end
			tw(picker, TweenInfo.new(0.35, Enum.EasingStyle.Exponential, Enum.EasingDirection.Out), {
				BackgroundColor3 = baseRowColor
			})
			if rowStroke then
				tw(rowStroke, TweenInfo.new(0.35, Enum.EasingStyle.Exponential, Enum.EasingDirection.Out), {
					Transparency = 0
				})
			end
		end)
	end

	local function runColorCallback(col, optPack)
		local ok, err = pcall(callback, col, optPack)
		if not ok then
			flashColorPickerError(err)
		end
	end

	local function getSaved()
		if type(label) ~= "string" then return nil end
		if not (NAmanage and type(NAmanage.NASettingsGet) == "function") then return nil end
		local st = NAmanage.NASettingsGet("colorPickerAutoRGB")
		if type(st) ~= "table" then return nil end
		local v = st[label]
		if type(v) == "boolean" then return v end
		return nil
	end

	local function saveState(sta)
		if type(label) ~= "string" then return end
		if not (NAmanage and type(NAmanage.NASettingsGet) == "function" and type(NAmanage.NASettingsSet) == "function") then return end
		local st = NAmanage.NASettingsGet("colorPickerAutoRGB")
		if type(st) ~= "table" then st = {} end
		local nxt = {}
		for k,v in pairs(st) do nxt[k] = v end
		nxt[label] = sta and true or false
		NAmanage.NASettingsSet("colorPickerAutoRGB", nxt)
	end

	rgbTit = rgbTog:FindFirstChild("Title")

	rgbBtn = rgbTog:FindFirstChild("Interact")
	if not (rgbBtn and rgbBtn:IsA("GuiButton")) then
		rgbBtn = InstanceNew("TextButton")
		rgbBtn.Name = "Interact"
		rgbBtn.BackgroundTransparency = 1
		rgbBtn.AutoButtonColor = false
		rgbBtn.BorderSizePixel = 0
		rgbBtn.Text = ""
		rgbBtn.Size = UDim2.new(1, 0, 1, 0)
		rgbBtn.ZIndex = (rgbTog.ZIndex or 1) + 1
		rgbBtn.Parent = rgbTog
	end

	rgbSw = rgbTog:FindFirstChild("Switch")
	if not (rgbSw and rgbSw:IsA("GuiObject")) then
		rgbSw = InstanceNew("Frame")
		rgbSw.Name = "Switch"
		rgbSw.BorderSizePixel = 0
		rgbSw.AnchorPoint = Vector2.new(1, 0.5)
		rgbSw.Position = UDim2.new(1, -12, 0.5, 0)
		rgbSw.Size = UDim2.new(0, 45, 0, 22)
		rgbSw.BackgroundColor3 = Color3.fromRGB(49, 49, 54)
		rgbSw.Parent = rgbTog

		local c = InstanceNew("UICorner")
		c.CornerRadius = UDim.new(0, 12)
		c.Parent = rgbSw

		local st = InstanceNew("UIStroke")
		st.Color = Color3.fromRGB(71, 71, 71)
		st.Parent = rgbSw
	end

	rgbDot = rgbSw:FindFirstChild("Indicator")
	if not (rgbDot and rgbDot:IsA("GuiObject")) then
		rgbDot = InstanceNew("Frame")
		rgbDot.Name = "Indicator"
		rgbDot.BorderSizePixel = 0
		rgbDot.AnchorPoint = Vector2.new(0, 0.5)
		rgbDot.Position = UDim2.new(0, 2, 0.5, 0)
		rgbDot.Size = UDim2.new(0, 18, 0, 18)
		rgbDot.BackgroundColor3 = Color3.fromRGB(114, 114, 124)
		rgbDot.Parent = rgbSw

		local c = InstanceNew("UICorner")
		c.CornerRadius = UDim.new(1, 0)
		c.Parent = rgbDot

		local st = InstanceNew("UIStroke")
		st.Color = Color3.fromRGB(83, 83, 83)
		st.Parent = rgbDot
	end

	local pickerConns = {}
	local pickerDestroyed = false
	local rgbLoopConn = nil
	local startRgbLoop = nil
	local dM, dS = false, false
	local inM, inS
	local dragChangedConn, dragEndedConn = nil, nil

	local function trackPickerConn(conn)
		if conn then
			Insert(pickerConns, conn)
		end
		return conn
	end

	local function stopRgbLoop()
		if rgbLoopConn then
			rgbLoopConn:Disconnect()
			rgbLoopConn = nil
		end
	end

	local function stopDragListeners()
		if dragChangedConn then
			dragChangedConn:Disconnect()
			dragChangedConn = nil
		end
		if dragEndedConn then
			dragEndedConn:Disconnect()
			dragEndedConn = nil
		end
	end

	local function cleanupPickerConnections()
		if pickerDestroyed then
			return
		end
		pickerDestroyed = true
		stopRgbLoop()
		stopDragListeners()
		for i = 1, #pickerConns do
			local conn = pickerConns[i]
			if conn then
				pcall(function()
					conn:Disconnect()
				end)
			end
		end
		for i = #pickerConns, 1, -1 do
			pickerConns[i] = nil
		end
		dM, dS = false, false
		inM, inS = nil, nil
	end

	local pickerOpenSize = picker.Size
	local bgOpenSize = bg.Size
	local bgOpenTr = bg.BackgroundTransparency
	local dispOpenTr = 1
	local interactOpenSize = interact.Size
	local interactOpenPos = interact.Position
	local bgOpenPos = UDim2.new(1, -15, bg.Position.Y.Scale, bg.Position.Y.Offset)
	local slOpenPos = UDim2.new(1, -15, sl.Position.Y.Scale, sl.Position.Y.Offset)
	local rgbOpenPos = rgb.Position
	local hexOpenPos = hex.Position
	local mainOpenTr = main.ImageTransparency
	local pointOpenTr = main.MainPoint.ImageTransparency

	local pickerClosedSize = UDim2.new(pickerOpenSize.X.Scale, pickerOpenSize.X.Offset, pickerOpenSize.Y.Scale, 45)
	local bgClosedSize = UDim2.new(0, 39, 0, 22)
	local bgClosedTr = 1
	local dispClosedTr = disp.BackgroundTransparency
	local interactClosedSize = UDim2.new(1, 0, 1, 0)
	local interactClosedPos = UDim2.new(0.5, 0, 0.5, 0)
	local rgbClosedPos = UDim2.new(rgbOpenPos.X.Scale, rgbOpenPos.X.Offset, rgbOpenPos.Y.Scale, rgbOpenPos.Y.Offset + 30)
	local hexClosedPos = UDim2.new(hexOpenPos.X.Scale, hexOpenPos.X.Offset, hexOpenPos.Y.Scale, hexOpenPos.Y.Offset + 17)
	local mainClosedTr = 1
	local pointClosedTr = 1

	bg.Position = bgOpenPos
	sl.Position = slOpenPos

	local function animateRowHover(show)
		tw(picker, TweenInfo.new(0.25, Enum.EasingStyle.Exponential, Enum.EasingDirection.Out), {
			BackgroundColor3 = show and hoverRowColor or baseRowColor
		})
	end

	local function setPickerOpen(state, animate)
		opened = state == true
		local fast = TweenInfo.new(0.2, Enum.EasingStyle.Exponential, Enum.EasingDirection.Out)
		local mid = TweenInfo.new(0.6, Enum.EasingStyle.Exponential, Enum.EasingDirection.Out)
		local bgInfo = TweenInfo.new(0.45, Enum.EasingStyle.Exponential, Enum.EasingDirection.Out)
		local useAnim = animate ~= false

		local pickerSize = opened and pickerOpenSize or pickerClosedSize
		local bgSize = opened and bgOpenSize or bgClosedSize
		local displayTr = opened and dispOpenTr or dispClosedTr
		local interactSize = opened and interactOpenSize or interactClosedSize
		local interactPos = opened and interactOpenPos or interactClosedPos
		local rgbPos = opened and rgbOpenPos or rgbClosedPos
		local hexPos = opened and hexOpenPos or hexClosedPos
		local mainTr = opened and mainOpenTr or mainClosedTr
		local pointTr = opened and pointOpenTr or pointClosedTr
		local bgTr = opened and bgOpenTr or bgClosedTr

		if useAnim then
			tw(picker, mid, { Size = pickerSize })
			tw(bg, bgInfo, { Size = bgSize, BackgroundTransparency = bgTr, Position = bgOpenPos })
			tw(disp, mid, { BackgroundTransparency = displayTr })
			tw(interact, mid, { Size = interactSize, Position = interactPos })
			tw(rgb, mid, { Position = rgbPos })
			tw(hex, TweenInfo.new(0.5, Enum.EasingStyle.Exponential, Enum.EasingDirection.Out), { Position = hexPos })
			pcall(function()
				tw(main.MainPoint, fast, { ImageTransparency = pointTr })
			end)
			pcall(function()
				tw(main, fast, { ImageTransparency = mainTr })
			end)
		else
			picker.Size = pickerSize
			bg.Size = bgSize
			bg.BackgroundTransparency = bgTr
			bg.Position = bgOpenPos
			disp.BackgroundTransparency = displayTr
			interact.Size = interactSize
			interact.Position = interactPos
			sl.Position = slOpenPos
			rgb.Position = rgbPos
			hex.Position = hexPos
			pcall(function() main.MainPoint.ImageTransparency = pointTr end)
			pcall(function() main.ImageTransparency = mainTr end)
		end
	end

	picker.ClipsDescendants = true
	if rowStroke then
		rowStroke.Transparency = 1
		tw(rowStroke, TweenInfo.new(0.7, Enum.EasingStyle.Exponential, Enum.EasingDirection.Out), { Transparency = 0 })
	end
	if title then
		title.TextTransparency = 1
		tw(title, TweenInfo.new(0.7, Enum.EasingStyle.Exponential, Enum.EasingDirection.Out), { TextTransparency = 0 })
	end
	picker.BackgroundTransparency = 1
	tw(picker, TweenInfo.new(0.7, Enum.EasingStyle.Exponential, Enum.EasingDirection.Out), { BackgroundTransparency = 0 })

	trackPickerConn(picker.MouseEnter:Connect(function()
		animateRowHover(true)
	end))
	trackPickerConn(picker.MouseLeave:Connect(function()
		animateRowHover(false)
	end))
	trackPickerConn(interact.MouseButton1Click:Connect(function()
		animateRowHover(true)
		if rowStroke then
			tw(rowStroke, TweenInfo.new(0.25, Enum.EasingStyle.Exponential, Enum.EasingDirection.Out), { Transparency = 1 })
		end
		Delay(0.2, function()
			if picker.Parent then
				animateRowHover(false)
				if rowStroke then
					tw(rowStroke, TweenInfo.new(0.25, Enum.EasingStyle.Exponential, Enum.EasingDirection.Out), { Transparency = 0 })
				end
			end
		end)
		setPickerOpen(not opened, true)
	end))

	setPickerOpen(false, false)

	local rgbOn = false
	local rgbSpd = 0.1

	local function updTog()
		if rgbSw then
			rgbSw.BackgroundColor3 = rgbOn and Color3.fromRGB(70, 49, 104) or Color3.fromRGB(49, 49, 54)
		end
		if rgbDot then
			local w = rgbDot.Size.X.Offset
			if w == 0 then w = math.max(rgbDot.AbsoluteSize.X, 18) end
			local pad = 2
			rgbDot.Position = rgbOn and UDim2.new(1, -w - pad, 0.5, 0) or UDim2.new(0, pad, 0.5, 0)
			rgbDot.BackgroundColor3 = rgbOn and Color3.fromRGB(154, 99, 255) or Color3.fromRGB(114, 114, 124)
		end
		if rgbTit and rgbTit:IsA("TextLabel") then
			rgbTit.Text = rgbOn and "RGB Cycle (ON)" or "RGB Cycle"
			rgbTit.TextColor3 = rgbOn and Color3.fromRGB(194, 194, 255) or Color3.fromRGB(244, 244, 249)
		end
	end

	local function setRGB(sta, opt)
		opt = opt or {}
		local ns = sta and true or false
		if rgbOn == ns then
			if not opt.skipVis then updTog() end
			return
		end
		rgbOn = ns
		if not opt.skipSave then
			saveState(rgbOn)
		end
		updTog()
		if rgbOn then
			if startRgbLoop then
				startRgbLoop()
			end
		else
			stopRgbLoop()
		end
	end

	local sv = getSaved()
	if type(sv) == "boolean" then
		setRGB(sv, { skipVis = true, skipSave = true })
	end
	updTog()

	if rgbBtn then
		MouseButtonFix(rgbBtn, function()
			setRGB(not rgbOn)
		end)
	end

	if typeof(defaultColor) ~= "Color3" then
		defaultColor = Color3.fromRGB(255, 255, 255)
	end

	local h, s, v = defaultColor:ToHSV()

	local function updUI(push, opt)
		opt = opt or {}
		local col = Color3.fromHSV(h, s, v)
		disp.BackgroundColor3 = col
		bg.BackgroundColor3 = Color3.fromHSV(h, 1, 1)
		main.MainPoint.Position = UDim2.new(s, 0, 1 - v, 0)
		sl.SliderPoint.Position = UDim2.new(h, 0, 0.5, 0)

		local r = math.floor(col.R * 255 + 0.5)
		local g = math.floor(col.G * 255 + 0.5)
		local b = math.floor(col.B * 255 + 0.5)

		if push then
			rgb.RInput.InputBox.Text = tostring(r)
			rgb.GInput.InputBox.Text = tostring(g)
			rgb.BInput.InputBox.Text = tostring(b)
			hex.InputBox.Text = Format("#%02X%02X%02X", r, g, b)
		end

		if opt.fire ~= false then
			runColorCallback(col, opt)
		end
	end

	local function parseRGB()
		setRGB(false)
		local r = tonumber(rgb.RInput.InputBox.Text) or 0
		local g = tonumber(rgb.GInput.InputBox.Text) or 0
		local b = tonumber(rgb.BInput.InputBox.Text) or 0
		r = math.clamp(r, 0, 255)
		g = math.clamp(g, 0, 255)
		b = math.clamp(b, 0, 255)
		h, s, v = Color3.fromRGB(r, g, b):ToHSV()
		updUI(false)
	end

	trackPickerConn(rgb.RInput.InputBox.FocusLost:Connect(parseRGB))
	trackPickerConn(rgb.GInput.InputBox.FocusLost:Connect(parseRGB))
	trackPickerConn(rgb.BInput.InputBox.FocusLost:Connect(parseRGB))

	trackPickerConn(hex.InputBox.FocusLost:Connect(function()
		setRGB(false)
		local txt = (hex.InputBox.Text or ""):gsub("#", ""):upper()
		if txt:match("^[0-9A-F]+$") and #txt == 6 then
			local r = tonumber(txt:sub(1, 2), 16)
			local g = tonumber(txt:sub(3, 4), 16)
			local b = tonumber(txt:sub(5, 6), 16)
			if r and g and b then
				h, s, v = Color3.fromRGB(r, g, b):ToHSV()
				updUI(true)
				return
			end
		end
		local col = Color3.fromHSV(h, s, v)
		hex.InputBox.Text = Format("#%02X%02X%02X",
			math.floor(col.R * 255 + 0.5),
			math.floor(col.G * 255 + 0.5),
			math.floor(col.B * 255 + 0.5)
		)
	end))

	pcall(function() main.MainPoint.AnchorPoint = Vector2.new(0.5, 0.5) end)
	pcall(function() sl.SliderPoint.AnchorPoint = Vector2.new(0.5, 0.5) end)

	local UIS = SafeGetService("UserInputService")
	local RS = SafeGetService("RunService")

	startRgbLoop = function()
		if pickerDestroyed or rgbLoopConn or not RS then
			return
		end
		rgbLoopConn = trackPickerConn(RS.RenderStepped:Connect(function(dt)
			if pickerDestroyed then
				return
			end
			if rgbOn and not dM and not dS then
				local step = math.clamp(dt or 0.016, 0.001, 0.1)
				h = (h + step * rgbSpd) % 1
				updUI(true)
			end
		end))
	end
	if rgbOn then
		startRgbLoop()
	end

	local function v2(p)
		if typeof(p) == "Vector2" then return p end
		if typeof(p) == "Vector3" then return Vector2.new(p.X, p.Y) end
		return UIS and __lt.cm("UserInputService", "GetMouseLocation") or Vector2.new(0, 0)
	end

	local function updMain(pos)
		local sz = main.AbsoluteSize
		if sz.X <= 0 or sz.Y <= 0 then return end
		local ap = main.AbsolutePosition
		local rx = math.clamp(pos.X - ap.X, 0, sz.X)
		local ry = math.clamp(pos.Y - ap.Y, 0, sz.Y)
		s = rx / sz.X
		v = 1 - (ry / sz.Y)
		updUI(true)
	end

	local function updSl(pos)
		local sz = sl.AbsoluteSize
		if sz.X <= 0 then return end
		local ap = sl.AbsolutePosition
		local rx = math.clamp(pos.X - ap.X, 0, sz.X)
		h = rx / sz.X
		updUI(true)
	end

	local function startDragListeners()
		if not UIS or pickerDestroyed then
			return
		end
		if dragChangedConn or dragEndedConn then
			return
		end

		dragChangedConn = UIS.InputChanged:Connect(function(input)
			if not dM and not dS then
				return
			end
			if dM then
				if inM and inM.UserInputType == Enum.UserInputType.Touch then
					if input == inM then
						updMain(v2(input.Position))
					end
				elseif input.UserInputType == Enum.UserInputType.MouseMovement then
					updMain(v2(input.Position))
				end
			end
			if dS then
				if inS and inS.UserInputType == Enum.UserInputType.Touch then
					if input == inS then
						updSl(v2(input.Position))
					end
				elseif input.UserInputType == Enum.UserInputType.MouseMovement then
					updSl(v2(input.Position))
				end
			end
		end)

		dragEndedConn = UIS.InputEnded:Connect(function(input)
			if input.UserInputType == Enum.UserInputType.MouseButton1 then
				dM, dS = false, false
				inM, inS = nil, nil
				stopDragListeners()
				return
			end
			if input.UserInputType == Enum.UserInputType.Touch then
				if inM == input then dM, inM = false, nil end
				if inS == input then dS, inS = false, nil end
				if not dM and not dS then
					stopDragListeners()
				end
			end
		end)
	end

	local function hit(obj)
		if obj:IsA("GuiButton") then
			pcall(function() obj.Active = true end)
			return obj
		end
		pcall(function() obj.Active = true end)
		local b = obj:FindFirstChild("__Hit")
		if not (b and b:IsA("TextButton")) then
			b = InstanceNew("TextButton")
			b.Name = "__Hit"
			b.BackgroundTransparency = 1
			b.AutoButtonColor = false
			b.BorderSizePixel = 0
			b.Text = ""
			b.Size = UDim2.new(1, 0, 1, 0)
			b.ZIndex = (obj.ZIndex or 1) + 20
			b.Parent = obj
		end
		return b
	end

	local mHit = hit(main)
	local sHit = hit(sl)
	pcall(function() main.MainPoint.Interactable = false end)
	pcall(function() sl.SliderPoint.Interactable = false end)
	pcall(function() interact.Interactable = true end)

	local function beg(t, input)
		if input.UserInputType ~= Enum.UserInputType.MouseButton1 and input.UserInputType ~= Enum.UserInputType.Touch then
			return
		end
		if not opened then
			return
		end
		setRGB(false)
		if t == "m" then
			dM = true
			inM = input
			updMain(v2(input.Position))
		else
			dS = true
			inS = input
			updSl(v2(input.Position))
		end
		startDragListeners()
	end

	trackPickerConn(mHit.InputBegan:Connect(function(i) beg("m", i) end))
	trackPickerConn(sHit.InputBegan:Connect(function(i) beg("s", i) end))

	local entry = {
		get = function()
			return Color3.fromHSV(h, s, v)
		end,
		set = function(col, opt)
			if typeof(col) ~= "Color3" then return end
			h, s, v = col:ToHSV()
			updUI(true, opt or {})
		end,
		getAutoRGB = function()
			return rgbOn
		end,
		setAutoRGB = function(sta)
			setRGB(sta)
		end,
	}

	NAgui._colorPickerRegistry[label] = entry

	trackPickerConn(picker:GetPropertyChangedSignal("Parent"):Connect(function()
		if not picker.Parent then
			if NAgui._colorPickerRegistry[label] == entry then
				NAgui._colorPickerRegistry[label] = nil
			end
			cleanupPickerConnections()
		end
	end))

	local initOpts = {
		fire = cfg.fireOnInit ~= false;
		context = "init";
	}
	updUI(true, initOpts)

	return picker
end

NAgui.setColorPickerValue = function(label, color, opts)
	local entry = NAgui._colorPickerRegistry and NAgui._colorPickerRegistry[label]
	if not entry then return end
	entry.set(color, opts or { fire = false })
end

NAgui.setColorPickerAutoRGB = function(label, enabled)
	local entry = NAgui._colorPickerRegistry and NAgui._colorPickerRegistry[label]
	if not entry or not entry.setAutoRGB then return end
	entry.setAutoRGB(enabled)
end

NAgui.getColorPickerAutoRGB = function(label)
	local entry = NAgui._colorPickerRegistry and NAgui._colorPickerRegistry[label]
	if not entry or not entry.getAutoRGB then return nil end
	return entry.getAutoRGB()
end

NAgui.addInput = function(label, placeholder, defaultText, callback, opts)
	if not NAUIMANAGER.SettingsList then return end
	opts = opts or {}

	local input = templates.Input:Clone()
	local frame = input.InputFrame
	local box = frame.InputBox
	local chipRow, chipBtn
	local sideOn = true
	local function updChip()
		if not chipRow then return end
		local t = sideOn and 0.15 or 0.8
		chipRow.BackgroundTransparency = t
	end
	if opts.sideChip then
		local tgl = templates.Toggle:Clone()
		local sw = tgl:FindFirstChild("Switch")
		if sw then
			local chip = sw:Clone()
			chip.Name = "SideSwitch"
			chip.Parent = input
			tgl:Destroy()

			local swW = chip.Size.X.Offset
			if swW <= 0 then
				swW = 45
			end

			chip.AnchorPoint = Vector2.new(1, 0.5)
			chip.Position = UDim2.new(1, -15, 0.5, 0)
			chip.Size = UDim2.new(0, swW, 0, chip.Size.Y.Offset)

			chipRow = chip

			frame.AnchorPoint = Vector2.new(1, 0.5)
			frame.Position = UDim2.new(1, -15, 0.5, 0)

			local chipInd = chip:FindFirstChild("Indicator")
			local chipStroke = chip:FindFirstChildWhichIsA("UIStroke", true)
			local chipOn = false

			local function updChip2()
				if chipInd then
					local onX = chip.AbsoluteSize.X - chipInd.AbsoluteSize.X - 4
					local offX = 2
					chipInd.Position = UDim2.new(0, chipOn and onX or offX, 0.5, 0)
					chipInd.Visible = false
				end
				if chipStroke then
					chipStroke.Color = chipOn and Color3.fromRGB(155, 100, 255) or Color3.fromRGB(72, 72, 72)
				end
			end

			if type(opts.sideGet) == "function" then
				local ok, v = pcall(opts.sideGet)
				if ok then
					chipOn = v and true or false
				end
			end

			updChip2()

			local btn = InstanceNew("TextButton")
			btn.Name = "ChipInteract"
			btn.BackgroundTransparency = 1
			btn.Text = "Use"
			btn.TextColor3 = Color3.new(1, 1, 1)
			btn.Size = UDim2.new(1, 0, 1, 0)
			btn.ZIndex = (chip.ZIndex or 1) + 1
			btn.Parent = chip

			chipBtn = btn

			MouseButtonFix(btn, function()
				if type(opts.sideSet) == "function" or type(opts.sideGet) == "function" then
					chipOn = not chipOn
					updChip2()
					if type(opts.sideSet) == "function" then
						pcall(opts.sideSet, chipOn)
					end
				else
					box:CaptureFocus()
				end
			end)
		else
			tgl:Destroy()
		end
	end

	input.Title.Text = label
	NAmanage.SetSearch.tag(input, label)
	box.Text = defaultText or ""
	box.PlaceholderText = placeholder or ""
	box.TextXAlignment = Enum.TextXAlignment.Center
	box.TextTruncate = Enum.TextTruncate.None

	input.LayoutOrder = NAgui._nextLayoutOrder()
	input.Parent = NAUIMANAGER.SettingsList
	NAmanage.registerElementForCurrentTab(input)
	NAgui.atchSettings(input, "input:"..tostring(label)..":"..tostring(input.LayoutOrder), 0.08)

	local lastW
	local mobileInputPollConn
	local resize

	local function stopMobileInputPoll()
		if mobileInputPollConn then
			mobileInputPollConn:Disconnect()
			mobileInputPollConn = nil
		end
	end

	local function startMobileInputPoll()
		stopMobileInputPoll()
		if not (RunService and UserInputService and UserInputService.TouchEnabled) then
			return
		end

		local accum = 0
		mobileInputPollConn = RunService.Heartbeat:Connect(function(dt)
			if not (input and input.Parent and box and box.Parent) then
				stopMobileInputPoll()
				return
			end
			local okFocused, isFocused = pcall(function()
				return box:IsFocused()
			end)
			if not (okFocused and isFocused == true) then
				stopMobileInputPoll()
				return
			end
			accum += tonumber(dt) or 0
			if accum < 0.05 then
				return
			end
			accum = 0
			resize()
		end)
	end

	resize = function()
		if not (input and frame and box) then
			return
		end

		local textW = NAgui.getInputTextWidth(box)
		local minW = NAgui.getInputMinWidth(frame)
		local maxW

		local cw = input.AbsoluteSize.X
		if (not cw or cw <= 0) and input.Parent then
			cw = input.Parent.AbsoluteSize.X
		end
		if (not cw or cw <= 0) and NAUIMANAGER and NAUIMANAGER.SettingsList then
			cw = NAUIMANAGER.SettingsList.AbsoluteSize.X
		end

		if cw and cw > 0 then
			local tw = (input.Title and input.Title.TextBounds.X or 0)
			local gap = 32
			if chipRow then
				local extra = chipRow.Size.X.Offset
				if extra <= 0 then
					extra = 45
				end
				gap = gap + extra
			end
			maxW = cw - tw - gap
		end

		local w = math.max(textW, minW)
		local hit = false
		if maxW then
			local clamped = math.max(minW, math.min(w, maxW))
			hit = clamped >= (maxW - 0.5)
			w = clamped
		end

		box.TextXAlignment = hit and Enum.TextXAlignment.Left or Enum.TextXAlignment.Center

		if type(w) ~= "number" then
			return
		end

		if not lastW or math.abs(lastW - w) > 0.5 then
			lastW = w
			frame.Size = UDim2.new(0, w, 0, 30)
			if chipRow then
				local fw = frame.Size.X.Offset
				if fw <= 0 then fw = w end
				chipRow.Position = UDim2.new(1, -15 - fw - 6, 0.5, 0)
				frame.Position = UDim2.new(1, -15, 0.5, 0)
			end
		end
	end

	box.Focused:Connect(function()
		startMobileInputPoll()
		resize()
	end)

	box.FocusLost:Connect(function()
		stopMobileInputPoll()
		local commitText = tostring(box.Text or "")
		local measureText = NAgui.getInputMeasureText(box)
		if commitText == "" and measureText ~= "" then
			commitText = measureText
			box.Text = commitText
		end
		resize()
		pcall(callback, commitText)
	end)

	box:GetPropertyChangedSignal("TextBounds"):Connect(resize)
	box:GetPropertyChangedSignal("Text"):Connect(resize)
	pcall(function()
		box:GetPropertyChangedSignal("ContentText"):Connect(resize)
	end)
	input:GetPropertyChangedSignal("AbsoluteSize"):Connect(resize)
	input:GetPropertyChangedSignal("Parent"):Connect(function()
		if not input.Parent then
			stopMobileInputPoll()
		end
	end)
	if chipBtn then
		if type(opts.sideSet) == "function" or type(opts.sideGet) == "function" then
			MouseButtonFix(chipBtn, function()
				sideOn = not sideOn
				updChip()
				if type(opts.sideSet) == "function" then
					pcall(opts.sideSet, sideOn)
				end
			end)
		else
			MouseButtonFix(chipBtn, function()
				box:CaptureFocus()
			end)
		end
	end

	local function setText(newValue, opts)
		opts = opts or {}
		local text = tostring(newValue or "")
		if not opts.force and box.Text == text then
			if opts.fire then
				pcall(callback, text)
			end
			return
		end
		box.Text = text
		resize()
		if opts.fire then
			pcall(callback, text)
		end
	end

	local entry = {
		input = input;
		get = function()
			return box.Text
		end;
		set = function(v, opts)
			setText(v, opts)
		end;
	}

	NAgui._inputRegistry[label] = entry

	input:GetPropertyChangedSignal("Parent"):Connect(function()
		if not input.Parent and NAgui._inputRegistry[label] == entry then
			NAgui._inputRegistry[label] = nil
		end
	end)

	resize()

	return input
end

NAgui.setInputValue = function(label, value, opts)
	local entry = NAgui._inputRegistry and NAgui._inputRegistry[label]
	if not entry then return end
	entry.set(value, opts or { fire = false })
end

NAmanage.SyncPrefixUI = function(opts)
	if not NAgui then return end
	local prefixValue = opt and tostring(opt.prefix or "") or ""
	if prefixValue == "" then
		prefixValue = ";"
	end
	opts = opts or {}
	local setterOpts = {
		force = opts.force == true,
		fire = opts.fire == true,
	}
	if NAgui.setKeybindValue then
		NAgui.setKeybindValue("Prefix", prefixValue, setterOpts)
		return
	end
	if NAgui.setInputValue then
		NAgui.setInputValue("Prefix", prefixValue, setterOpts)
	end
end

NAmanage.SyncUIScaleUI = function(opts)
	if not (NAgui and NAgui.setInputValue) then return end
	opts = opts or {}
	local value = opts.value
	if value == nil then
		value = NAUIScale
	end
	local clamped = NAmanage.ClampUIScale(value, 1)
	local setterOpts = {
		force = opts.force ~= false,
		fire = opts.fire == true,
	}
	NAgui.setInputValue("UI Scale", Format("%.2f", clamped), setterOpts)
end

NAmanage._uiAutoSync = NAmanage._uiAutoSync or { toggles = {} }

NAmanage.RegisterToggleAutoSync = function(label, getter, opts)
	if type(label) ~= "string" or type(getter) ~= "function" then return end
	local store = NAmanage._uiAutoSync
	local entry = store.toggles[label]
	if not entry then
		entry = { getter = getter, last = nil, opts = opts }
		store.toggles[label] = entry
	else
		entry.getter = getter
		entry.opts = opts or entry.opts
	end
end

NAmanage.RunUIAutoSync = function()
	local store = NAmanage._uiAutoSync
	if not store then return end
	local toggleStore = store.toggles
	if toggleStore and NAgui and NAgui.setToggleState then
		for label, watcher in pairs(toggleStore) do
			local success, rawValue = pcall(watcher.getter)
			if success then
				local normalized = nil
				if watcher.opts and type(watcher.opts.normalize) == "function" then
					local ok, result = pcall(watcher.opts.normalize, rawValue)
					if ok then
						normalized = result
					end
				end
				if normalized == nil then
					normalized = rawValue and true or false
				end
				local registry = NAgui._toggleRegistry
				if registry and registry[label] then
					if watcher.last == nil or watcher.last ~= normalized then
						watcher.last = normalized
						local fireCallback = watcher.opts and watcher.opts.fire == true
						NAgui.setToggleState(label, normalized, {
							force = true,
							fire = fireCallback and true or false,
						})
					end
				else
					watcher.last = nil
				end
			end
		end
	end
end

NAmanage.StartUIAutoSyncLoop = function()
	if NAmanage._uiAutoSyncLoopStarted then return end
	NAmanage._uiAutoSyncLoopStarted = true
	NAmanage._uiAutoSyncLoopAlive = true
	Spawn(function()
		local idleStreak = 0
		while NAmanage._uiAutoSyncLoopAlive do
			local store = NAmanage._uiAutoSync
			local hasToggles = store and store.toggles and next(store.toggles) ~= nil
			if hasToggles then
				local ok, err = pcall(NAmanage.RunUIAutoSync)
				if ok then
					idleStreak = 0
				else
					idleStreak = math.min(idleStreak + 1, 10)
					warn("[NA] UI auto-sync failed:", err)
				end
			else
				idleStreak = math.min(idleStreak + 1, 12)
			end

			local sleepTime = hasToggles and 0.35 or math.min(6, 1.5 + idleStreak * 0.35)
			if hasToggles then
				if NAmanage.isLoad and NAmanage.isLoad() then
					sleepTime = 0.6
				end
				if NAStuff and NAStuff.NASCREENGUI and NAStuff.NASCREENGUI.Enabled == false then
					sleepTime = math.max(sleepTime, 0.8)
				end
				if idleStreak > 0 then
					sleepTime = sleepTime + math.min(0.5, idleStreak * 0.05)
				end
			end
			Wait(sleepTime)
		end
	end)
end

NAmanage.StartUIAutoSyncLoop()

NAgui.addKeybind = function(label, defaultKey, callback)
	if not NAUIMANAGER.SettingsList then return end
	callback = type(callback) == "function" and callback or function() end
	local connKey = "NAgui_keybind:"..tostring(label)
	NAlib.disconnect(connKey)
	local keybind = templates.Keybind:Clone()
	keybind.Title.Text = label
	NAmanage.SetSearch.tag(keybind, label)
	local frame = keybind.KeybindFrame
	local box = frame and frame.KeybindBox
	local rowStroke = keybind:FindFirstChild("UIStroke")
	local frameStroke = frame and frame:FindFirstChildWhichIsA("UIStroke")
	local title = keybind:FindFirstChild("Title")
	local defaultKeyText = tostring(defaultKey or "Unknown")
	if defaultKeyText == "" then
		defaultKeyText = "Unknown"
	end

	local keybindSymbolAliases = {
		["!"] = "One",
		["\""] = "Quote",
		["#"] = "Three",
		["$"] = "Four",
		["%"] = "Five",
		["&"] = "Seven",
		["'"] = "Quote",
		["("] = "Nine",
		[")"] = "Zero",
		["*"] = "Eight",
		["+"] = "Equals",
		[";"] = "Semicolon",
		[":"] = "Semicolon",
		[","] = "Comma",
		["<"] = "Comma",
		["."] = "Period",
		[">"] = "Period",
		["/"] = "Slash",
		["?"] = "Slash",
		["\\"] = "BackSlash",
		["|"] = "BackSlash",
		["`"] = "Backquote",
		["~"] = "Backquote",
		["-"] = "Minus",
		["_"] = "Minus",
		["="] = "Equals",
		["["] = "LeftBracket",
		["{"] = "LeftBracket",
		["]"] = "RightBracket",
		["}"] = "RightBracket",
		["@"] = "Two",
		["^"] = "Six",
	}
	local keybindDigitAliases = {
		["0"] = "Zero",
		["1"] = "One",
		["2"] = "Two",
		["3"] = "Three",
		["4"] = "Four",
		["5"] = "Five",
		["6"] = "Six",
		["7"] = "Seven",
		["8"] = "Eight",
		["9"] = "Nine",
	}

	local function safeKeyCodeLookup(name)
		if type(name) ~= "string" or name == "" then
			return nil
		end
		local ok, code = pcall(function()
			return Enum.KeyCode[name]
		end)
		if ok and code and code ~= Enum.KeyCode.Unknown then
			return code
		end
		return nil
	end

	local function resolveKeyCode(text)
		if type(text) ~= "string" then
			return Enum.KeyCode.Unknown, nil
		end
		local clean = text:match("^%s*(.-)%s*$")
		if not clean or clean == "" then
			return Enum.KeyCode.Unknown, nil
		end
		if #clean == 1 then
			local alias = keybindSymbolAliases[clean] or keybindDigitAliases[clean]
			if alias then
				local aliasCode = safeKeyCodeLookup(alias)
				if aliasCode then
					return aliasCode, aliasCode.Name
				end
			end
		end
		clean = clean:gsub("^Enum%.KeyCode%.", "")
		local direct = safeKeyCodeLookup(clean)
		if direct then
			return direct, direct.Name
		end
		local lower = Lower(clean)
		for _, enumKey in ipairs(Enum.KeyCode:GetEnumItems()) do
			if Lower(enumKey.Name) == lower then
				return enumKey, enumKey.Name
			end
		end
		return Enum.KeyCode.Unknown, clean
	end

	local defaultKeyCode, defaultDisplay = resolveKeyCode(defaultKeyText)
	if defaultDisplay and defaultDisplay ~= "" then
		defaultKeyText = defaultDisplay
	end
	local boundKeyCode = defaultKeyCode
	box.Text = defaultKeyText
	local runCallback
	local tweenFrameWidth

	local function setKeyText(newValue, opts)
		opts = opts or {}
		local text = tostring(newValue or "")
		if text == "" then
			text = defaultKeyText
		end
		local code, normalized = resolveKeyCode(text)
		if normalized and normalized ~= "" then
			text = normalized
		end
		if not opts.force and box.Text == text then
			if opts.fire then
				runCallback(text)
			end
			return
		end
		box.Text = text
		boundKeyCode = code
		tweenFrameWidth()
		if opts.fire then
			runCallback(text)
		end
	end

	keybind.LayoutOrder = NAgui._nextLayoutOrder()
	keybind.Parent = NAUIMANAGER.SettingsList
	NAmanage.registerElementForCurrentTab(keybind)

	local capturing = false
	local baseRowColor = keybind.BackgroundColor3
	local hoverRowColor = baseRowColor:Lerp(Color3.new(1, 1, 1), 0.08)
	local baseFrameColor = frame and frame.BackgroundColor3 or Color3.fromRGB(45, 45, 50)
	local focusFrameColor = baseFrameColor:Lerp(Color3.new(1, 1, 1), 0.1)
	local baseFrameStrokeColor = frameStroke and frameStroke.Color or Color3.fromRGB(72, 72, 72)
	local focusFrameStrokeColor = Color3.fromRGB(155, 100, 255)
	local frameFocused = false
	local lastPulseAt = 0
	local pulseCooldown = 0.09
	local pulseHold = 0.08
	local pulseResetAt = 0
	local pulseResetRunning = false

	local function tw(obj, info, goal)
		if not obj then return nil end
		local same = true
		for prop, target in pairs(goal) do
			local ok, current = pcall(function()
				return obj[prop]
			end)
			if not ok or current ~= target then
				same = false
				break
			end
		end
		if same then
			return nil
		end
		local ok, tween = pcall(function()
			return __lt.cm("TweenService", "Create", obj, info, goal)
		end)
		if ok and tween then
			tween:Play()
			return tween
		end
		return nil
	end

	local function flashKeybindError(message)
		tw(keybind, TweenInfo.new(0.25, Enum.EasingStyle.Exponential, Enum.EasingDirection.Out), {
			BackgroundColor3 = Color3.fromRGB(85, 0, 0)
		})
		if rowStroke then
			tw(rowStroke, TweenInfo.new(0.25, Enum.EasingStyle.Exponential, Enum.EasingDirection.Out), {
				Transparency = 1
			})
		end
		local prevTitle = title and title.Text or nil
		if title then
			title.Text = "Callback Error"
		end
		warn("[NA] Keybind callback error ("..tostring(label).."): "..tostring(message))
		Delay(0.5, function()
			if not keybind.Parent then
				return
			end
			if title and prevTitle ~= nil then
				title.Text = prevTitle
			end
			tw(keybind, TweenInfo.new(0.35, Enum.EasingStyle.Exponential, Enum.EasingDirection.Out), {
				BackgroundColor3 = baseRowColor
			})
			if rowStroke then
				tw(rowStroke, TweenInfo.new(0.35, Enum.EasingStyle.Exponential, Enum.EasingDirection.Out), {
					Transparency = 0
				})
			end
		end)
	end

	runCallback = function(...)
		local ok, err = pcall(callback, ...)
		if not ok then
			flashKeybindError(err)
		end
	end

	local function setFrameFocused(focused, force)
		focused = focused == true
		if not force and frameFocused == focused then
			return
		end
		frameFocused = focused
		if frame then
			tw(frame, TweenInfo.new(0.2, Enum.EasingStyle.Exponential, Enum.EasingDirection.Out), {
				BackgroundColor3 = frameFocused and focusFrameColor or baseFrameColor
			})
		end
		if frameStroke then
			tw(frameStroke, TweenInfo.new(0.25, Enum.EasingStyle.Exponential, Enum.EasingDirection.Out), {
				Color = frameFocused and focusFrameStrokeColor or baseFrameStrokeColor
			})
		end
	end

	local function schedulePulseReset()
		pulseResetAt = os.clock() + pulseHold
		if pulseResetRunning then
			return
		end
		pulseResetRunning = true
		Spawn(function()
			while keybind and keybind.Parent do
				local remaining = pulseResetAt - os.clock()
				if remaining > 0 then
					Wait(math.min(remaining, 0.05))
				else
					if not capturing then
						setFrameFocused(false, false)
					end
					break
				end
			end
			pulseResetRunning = false
			pulseResetAt = 0
		end)
	end

	tweenFrameWidth = function()
		if not (frame and box) then
			return
		end
		local width = box.TextBounds.X + 24
		if width < 24 then
			width = 24
		end
		tw(frame, TweenInfo.new(0.55, Enum.EasingStyle.Exponential, Enum.EasingDirection.Out), {
			Size = UDim2.new(0, width, 0, 30)
		})
	end

	if rowStroke then
		rowStroke.Transparency = 1
		tw(rowStroke, TweenInfo.new(0.7, Enum.EasingStyle.Exponential, Enum.EasingDirection.Out), { Transparency = 0 })
	end
	if title then
		title.TextTransparency = 1
		tw(title, TweenInfo.new(0.7, Enum.EasingStyle.Exponential, Enum.EasingDirection.Out), { TextTransparency = 0 })
	end
	keybind.BackgroundTransparency = 1
	tw(keybind, TweenInfo.new(0.7, Enum.EasingStyle.Exponential, Enum.EasingDirection.Out), { BackgroundTransparency = 0 })
	tweenFrameWidth()

	NAlib.connect(connKey, keybind.MouseEnter:Connect(function()
		tw(keybind, TweenInfo.new(0.25, Enum.EasingStyle.Exponential, Enum.EasingDirection.Out), {
			BackgroundColor3 = hoverRowColor
		})
	end))
	NAlib.connect(connKey, keybind.MouseLeave:Connect(function()
		tw(keybind, TweenInfo.new(0.25, Enum.EasingStyle.Exponential, Enum.EasingDirection.Out), {
			BackgroundColor3 = baseRowColor
		})
	end))

	NAlib.connect(connKey, box.Focused:Connect(function()
		capturing = true
		pulseResetAt = 0
		box.Text = ""
		setFrameFocused(true, true)
	end))

	NAlib.connect(connKey, box.FocusLost:Connect(function()
		capturing = false
		pulseResetAt = 0
		local typed = box.Text
		if typed == nil or typed == "" then
			box.Text = defaultKeyText
		end
		local code, normalized = resolveKeyCode(box.Text)
		if normalized and normalized ~= "" then
			box.Text = normalized
		end
		boundKeyCode = code
		setFrameFocused(false, true)
		tweenFrameWidth()
	end))

	NAlib.connect(connKey, UserInputService.InputBegan:Connect(function(input, processed)
		if not input or input.UserInputType ~= Enum.UserInputType.Keyboard then
			return
		end
		local keyCode = input.KeyCode
		if keyCode == Enum.KeyCode.Unknown then
			return
		end
		if capturing and input.KeyCode ~= Enum.KeyCode.Unknown then
			local keyName = keyCode.Name
			box:ReleaseFocus()
			box.Text = keyName
			boundKeyCode = keyCode
			capturing = false
			pulseResetAt = 0
			setFrameFocused(false, true)
			runCallback(keyName)
		elseif not capturing and boundKeyCode ~= Enum.KeyCode.Unknown and not processed and keyCode == boundKeyCode then
			local now = os.clock()
			if now - lastPulseAt >= pulseCooldown then
				lastPulseAt = now
				setFrameFocused(true, false)
				schedulePulseReset()
			end
			runCallback()
		end
	end))

	NAlib.connect(connKey, box:GetPropertyChangedSignal("Text"):Connect(function()
		local code = resolveKeyCode(box.Text)
		boundKeyCode = code
		tweenFrameWidth()
	end))

	local entry = {
		keybind = keybind;
		get = function()
			return box.Text
		end;
		set = function(v, opts)
			setKeyText(v, opts)
		end;
		getKeyCode = function()
			return boundKeyCode
		end;
	}

	NAgui._keybindRegistry[label] = entry
	NAlib.connect(connKey, keybind:GetPropertyChangedSignal("Parent"):Connect(function()
		if keybind.Parent then
			return
		end
		if NAgui._keybindRegistry[label] == entry then
			NAgui._keybindRegistry[label] = nil
		end
		NAlib.disconnect(connKey)
	end))

	return keybind
end

NAgui.setKeybindValue = function(label, value, opts)
	local entry = NAgui._keybindRegistry and NAgui._keybindRegistry[label]
	if not entry then return end
	if not (entry.keybind and entry.keybind.Parent) then
		NAgui._keybindRegistry[label] = nil
		return
	end
	entry.set(value, opts or { fire = false })
end

NAgui.addSlider = function(label, min, max, defaultValue, increment, suffix, callback)
	if not NAUIMANAGER.SettingsList then return end
	callback = type(callback) == "function" and callback or function() end
	NAgui._sliderConnCounter = (NAgui._sliderConnCounter or 0) + 1
	local connKey = "NAgui_slider:"..tostring(label)..":"..tostring(NAgui._sliderConnCounter)
	local slider = templates.Slider:Clone()
	slider.Title.Text = label
	NAmanage.SetSearch.tag(slider, label)

	slider.LayoutOrder = NAgui._nextLayoutOrder()
	slider.Parent = NAUIMANAGER.SettingsList
	NAmanage.registerElementForCurrentTab(slider)

	local interact = slider.Main.Interact
	local progress = slider.Main.Progress
	local infoText = slider.Main.Information
	local rowStroke = slider:FindFirstChild("UIStroke")
	local title = slider:FindFirstChild("Title")
	local mainStroke = slider.Main and slider.Main:FindFirstChildWhichIsA("UIStroke")
	local progressStroke = progress and progress:FindFirstChildWhichIsA("UIStroke")

	local dragging = false
	local currentValue = defaultValue
	local step = tonumber(increment) or 0
	local range = max - min
	local dragInputChangedConn
	local dragInputEndedConn
	local dragStepConn
	local pendingPointerX
	local baseRowColor = slider.BackgroundColor3
	local hoverRowColor = baseRowColor:Lerp(Color3.new(1, 1, 1), 0.08)
	local mainStrokeIdleTransparency = (mainStroke and typeof(mainStroke.Transparency) == "number") and mainStroke.Transparency or 0.4
	local progressStrokeIdleTransparency = (progressStroke and typeof(progressStroke.Transparency) == "number") and progressStroke.Transparency or 0.3

	local function tw(obj, info, goal)
		if not obj then return nil end
		local ok, tween = pcall(function()
			return __lt.cm("TweenService", "Create", obj, info, goal)
		end)
		if ok and tween then
			tween:Play()
			return tween
		end
		return nil
	end

	local function flashSliderError(message)
		tw(slider, TweenInfo.new(0.25, Enum.EasingStyle.Exponential, Enum.EasingDirection.Out), {
			BackgroundColor3 = Color3.fromRGB(85, 0, 0)
		})
		if rowStroke then
			tw(rowStroke, TweenInfo.new(0.25, Enum.EasingStyle.Exponential, Enum.EasingDirection.Out), {
				Transparency = 1
			})
		end
		local prevTitle = title and title.Text or nil
		if title then
			title.Text = "Callback Error"
		end
		warn("[NA] Slider callback error ("..tostring(label).."): "..tostring(message))
		Delay(0.5, function()
			if not slider.Parent then
				return
			end
			if title and prevTitle ~= nil then
				title.Text = prevTitle
			end
			tw(slider, TweenInfo.new(0.35, Enum.EasingStyle.Exponential, Enum.EasingDirection.Out), {
				BackgroundColor3 = baseRowColor
			})
			if rowStroke then
				tw(rowStroke, TweenInfo.new(0.35, Enum.EasingStyle.Exponential, Enum.EasingDirection.Out), {
					Transparency = 0
				})
			end
		end)
	end

	local function runCallback(value)
		local ok, err = pcall(callback, value)
		if not ok then
			flashSliderError(err)
		end
	end

	local function quantize(value)
		if step == 0 then
			return math.clamp(value, min, max)
		end
		local scaled = (value - min) / step
		local rounded = math.floor(scaled + 0.5)
		local quantized = min + rounded * step
		if quantized < min then quantized = min end
		if quantized > max then quantized = max end
		return quantized
	end

	local function progressGoalForPercent(percent)
		percent = math.clamp(percent or 0, 0, 1)
		local width = interact and interact.AbsoluteSize.X or 0
		if width > 0 then
			local pixel = math.max(5, width * percent)
			return UDim2.new(0, pixel, 1, 0)
		end
		return UDim2.new(percent, 0, 1, 0)
	end

	local function applyValue(value, opts)
		opts = opts or {}
		local quantized = quantize(value)
		local changed = currentValue ~= quantized
		currentValue = quantized
		local percent = (range ~= 0) and ((quantized - min) / range) or 0
		local goalSize = progressGoalForPercent(percent)
		if opts.animate == false then
			progress.Size = goalSize
		else
			tw(progress, TweenInfo.new(0.45, Enum.EasingStyle.Exponential, Enum.EasingDirection.Out), {
				Size = goalSize
			})
		end
		infoText.Text = Format("%.14g", quantized)..(suffix or "")
		if opts.fire ~= false and (changed or opts.forceFire == true) then
			runCallback(quantized)
		end
	end

	local function updateSliderValueFromPos(x)
		local relX = math.clamp(x - interact.AbsolutePosition.X, 0, interact.AbsoluteSize.X)
		local percent = relX / interact.AbsoluteSize.X
		local value = min + range * percent
		applyValue(value)
	end

	local function disconnectDragListeners()
		if dragInputChangedConn then
			dragInputChangedConn:Disconnect()
			dragInputChangedConn = nil
		end
		if dragInputEndedConn then
			dragInputEndedConn:Disconnect()
			dragInputEndedConn = nil
		end
		if dragStepConn then
			dragStepConn:Disconnect()
			dragStepConn = nil
		end
		pendingPointerX = nil
	end

	local function stopDrag()
		dragging = false
		disconnectDragListeners()
		if mainStroke then
			tw(mainStroke, TweenInfo.new(0.6, Enum.EasingStyle.Exponential, Enum.EasingDirection.Out), {
				Transparency = mainStrokeIdleTransparency
			})
		end
		if progressStroke then
			tw(progressStroke, TweenInfo.new(0.6, Enum.EasingStyle.Exponential, Enum.EasingDirection.Out), {
				Transparency = progressStrokeIdleTransparency
			})
		end
	end

	local function ensureDragListeners()
		disconnectDragListeners()
		dragInputChangedConn = UserInputService.InputChanged:Connect(function(input)
			if not dragging then
				return
			end
			if input.UserInputType == Enum.UserInputType.MouseMovement or input.UserInputType == Enum.UserInputType.Touch then
				pendingPointerX = input.Position.X
			end
		end)
		dragInputEndedConn = UserInputService.InputEnded:Connect(function(input)
			if input.UserInputType == Enum.UserInputType.MouseButton1 or input.UserInputType == Enum.UserInputType.Touch then
				stopDrag()
			end
		end)
		dragStepConn = RunService.RenderStepped:Connect(function()
			local pointerX = pendingPointerX
			if not dragging or pointerX == nil then
				return
			end
			pendingPointerX = nil
			pcall(function()
				updateSliderValueFromPos(pointerX)
			end)
		end)
	end

	NAlib.connect(connKey, interact.InputBegan:Connect(function(input)
		if input.UserInputType == Enum.UserInputType.MouseButton1 or input.UserInputType == Enum.UserInputType.Touch then
			dragging = true
			if mainStroke then
				tw(mainStroke, TweenInfo.new(0.6, Enum.EasingStyle.Exponential, Enum.EasingDirection.Out), {
					Transparency = 1
				})
			end
			if progressStroke then
				tw(progressStroke, TweenInfo.new(0.6, Enum.EasingStyle.Exponential, Enum.EasingDirection.Out), {
					Transparency = 1
				})
			end
			ensureDragListeners()
			pcall(function()
				updateSliderValueFromPos(input.Position.X)
			end)
		end
	end))

	NAlib.connect(connKey, interact.InputEnded:Connect(function(input)
		if input.UserInputType == Enum.UserInputType.MouseButton1 or input.UserInputType == Enum.UserInputType.Touch then
			stopDrag()
		end
	end))

	NAlib.connect(connKey, slider.MouseEnter:Connect(function()
		tw(slider, TweenInfo.new(0.25, Enum.EasingStyle.Exponential, Enum.EasingDirection.Out), {
			BackgroundColor3 = hoverRowColor
		})
	end))
	NAlib.connect(connKey, slider.MouseLeave:Connect(function()
		tw(slider, TweenInfo.new(0.25, Enum.EasingStyle.Exponential, Enum.EasingDirection.Out), {
			BackgroundColor3 = baseRowColor
		})
	end))

	if rowStroke then
		rowStroke.Transparency = 1
		tw(rowStroke, TweenInfo.new(0.7, Enum.EasingStyle.Exponential, Enum.EasingDirection.Out), { Transparency = 0 })
	end
	if title then
		title.TextTransparency = 1
		tw(title, TweenInfo.new(0.7, Enum.EasingStyle.Exponential, Enum.EasingDirection.Out), { TextTransparency = 0 })
	end
	slider.BackgroundTransparency = 1
	tw(slider, TweenInfo.new(0.7, Enum.EasingStyle.Exponential, Enum.EasingDirection.Out), { BackgroundTransparency = 0 })

	applyValue(defaultValue, { fire = false, animate = false })

	local entry = {
		get = function()
			return currentValue
		end;
		set = function(value, opts)
			opts = opts or {}
			if opts.animate == nil then
				opts.animate = true
			end
			applyValue(value, opts)
		end;
	}
	NAgui._sliderRegistry[label] = entry

	NAlib.connect(connKey, slider:GetPropertyChangedSignal("Parent"):Connect(function()
		if not slider.Parent and NAgui._sliderRegistry[label] == entry then
			stopDrag()
			NAgui._sliderRegistry[label] = nil
			Defer(function()
				NAlib.disconnect(connKey)
			end)
		end
	end))

	return slider
end

NAgui.setSliderValue = function(label, value, opts)
	local entry = NAgui._sliderRegistry and NAgui._sliderRegistry[label]
	if not entry then return end
	entry.set(value, opts or { fire = false })
end

NAgui.addDropdown = function(label, values, defaultValue, callback, opts)
	if not NAUIMANAGER.SettingsList then return end
	if not (templates and templates.Dropdown) then return end

	local DropdownSettings
	if type(label) == "table" and values == nil then
		DropdownSettings = label
	else
		opts = opts or {}
		if type(defaultValue) == "function" and callback == nil then
			callback = defaultValue
			defaultValue = nil
		end
		DropdownSettings = {
			Name = tostring(label or "Dropdown"),
			Options = values,
			CurrentOption = defaultValue,
			MultipleOptions = opts.MultipleOptions == true or opts.multipleOptions == true,
			Callback = callback,
			Ext = opts.Ext,
			Flag = opts.Flag,
		}
	end

	DropdownSettings = DropdownSettings or {}
	DropdownSettings.Name = tostring(DropdownSettings.Name or label or "Dropdown")
	DropdownSettings.Options = DropdownSettings.Options or {}
	DropdownSettings.Callback = type(DropdownSettings.Callback) == "function" and DropdownSettings.Callback or function() end
	DropdownSettings.MultipleOptions = DropdownSettings.MultipleOptions == true
	NAgui._dropdownConnCounter = (NAgui._dropdownConnCounter or 0) + 1
	local connKey = "NAgui_dropdown:"..DropdownSettings.Name..":"..tostring(NAgui._dropdownConnCounter)

	local function normalizeOption(option)
		if type(option) == "table" then
			local rawValue = option.value
			if rawValue == nil then
				rawValue = option.id or option.key or option.name or option[1]
			end
			local value = tostring(rawValue or "")
			local rawDisplay = option.display
			if rawDisplay == nil then
				rawDisplay = option.text or option.label or rawValue or value
			end
			return {
				value = value,
				display = tostring(rawDisplay or value),
				selectedDisplay = tostring(option.selectedDisplay or option.SelectedDisplay or rawDisplay or value),
				richText = option.richText == true or option.RichText == true,
			}
		end
		local text = tostring(option)
		return {
			value = text,
			display = text,
			selectedDisplay = text,
			richText = false,
		}
	end

	local function normalizeOptions(raw)
		local out = {}
		if type(raw) ~= "table" then
			return out
		end
		local n = #raw
		if n > 0 then
			for i = 1, n do
				out[#out + 1] = normalizeOption(raw[i])
			end
		else
			for _, v in pairs(raw) do
				out[#out + 1] = normalizeOption(v)
			end
		end
		return out
	end

	DropdownSettings.Options = normalizeOptions(DropdownSettings.Options)

	local function getOptionRecordByValue(value)
		local wanted = tostring(value or "")
		for _, option in ipairs(DropdownSettings.Options) do
			if option.value == wanted then
				return option
			end
		end
		return nil
	end

	local function getOptionDisplay(value)
		local option = getOptionRecordByValue(value)
		if option then
			return option.display
		end
		return tostring(value or "")
	end

	local function getOptionSelectedDisplay(value)
		local option = getOptionRecordByValue(value)
		if option then
			return option.selectedDisplay or option.display
		end
		return tostring(value or "")
	end

	local function hasOptionValue(value)
		return getOptionRecordByValue(value) ~= nil
	end

	local function dropdownUsesRichText()
		if opts and (opts.RichText == true or opts.richText == true) then
			return true
		end
		for _, option in ipairs(DropdownSettings.Options) do
			if option.richText == true then
				return true
			end
		end
		return false
	end

	local dropdown, title, selected, toggle
	local collapsedHeight, openHeight

	local function resizeSelectedLabel()
		if not (dropdown and selected and selected:IsA("TextLabel")) then
			return
		end
		local rowWidth = dropdown.AbsoluteSize.X
		if not rowWidth or rowWidth <= 0 then
			return
		end

		local titleWidth = 0
		if title and title:IsA("TextLabel") then
			titleWidth = title.TextBounds.X
		end

		local toggleWidth = 26
		if toggle and toggle:IsA("GuiObject") then
			local abs = toggle.AbsoluteSize.X
			if abs and abs > 0 then
				toggleWidth = abs
			end
		end

		local leftInset = 12
		local gap = 10
		local rightInset = 10
		local selectedLeft = leftInset
		if title and title:IsA("TextLabel") then
			local titleStart = title.AbsolutePosition.X - dropdown.AbsolutePosition.X
			if not titleStart or titleStart < 0 then
				titleStart = leftInset
			end
			selectedLeft = math.max(selectedLeft, math.floor(titleStart + titleWidth + gap + 0.5))
		end
		local rightLimit = rowWidth - toggleWidth - rightInset
		local available = math.max(72, rightLimit - selectedLeft)
		local selectedHeight = math.max(16, selected.TextBounds.Y > 0 and selected.TextBounds.Y or selected.AbsoluteSize.Y > 0 and selected.AbsoluteSize.Y or 18)
		local headerYOffset = math.max(0, math.floor((collapsedHeight - selectedHeight) * 0.5))

		selected.AnchorPoint = Vector2.new(1, 0)
		selected.Position = UDim2.new(0, rightLimit, 0, headerYOffset)
		selected.Size = UDim2.new(0, available, 0, selectedHeight)
		selected.TextScaled = false
		selected.TextWrapped = false
		selected.TextTruncate = Enum.TextTruncate.AtEnd
		selected.TextXAlignment = Enum.TextXAlignment.Right
	end

	dropdown = templates.Dropdown:Clone()
	if string.find(DropdownSettings.Name, "closed") then
		dropdown.Name = "Dropdown"
	else
		dropdown.Name = DropdownSettings.Name
	end
	dropdown.Visible = true
	dropdown.ClipsDescendants = true
	dropdown.Parent = NAUIMANAGER.SettingsList
	dropdown.LayoutOrder = NAgui._nextLayoutOrder()
	NAmanage.registerElementForCurrentTab(dropdown)
	NAmanage.SetSearch.tag(dropdown, DropdownSettings.Name)
	if NAgui.RegisterStrokesFrom then
		NAgui.RegisterStrokesFrom(dropdown)
	end

	title = dropdown:FindFirstChild("Title")
	selected = dropdown:FindFirstChild("Selected")
	toggle = dropdown:FindFirstChild("Toggle")
	local interact = dropdown:FindFirstChild("Interact")
	local list = dropdown:FindFirstChild("List")
	local listLayout = list and list:FindFirstChildWhichIsA("UIListLayout")
	local optionTemplate = list and list:FindFirstChild("Template")
	local uiStroke = dropdown:FindFirstChild("UIStroke")

	if title and title:IsA("TextLabel") then
		title.Text = DropdownSettings.Name
	end

	if not (interact and interact:IsA("GuiButton")) then
		interact = InstanceNew("TextButton")
		interact.Name = "Interact"
		interact.BackgroundTransparency = 1
		interact.Text = ""
		interact.AutoButtonColor = false
		interact.Parent = dropdown
	end

	if not (list and list:IsA("ScrollingFrame")) then
		list = InstanceNew("ScrollingFrame")
		list.Name = "List"
		list.BackgroundTransparency = 1
		list.BorderSizePixel = 0
		list.AutomaticCanvasSize = Enum.AutomaticSize.Y
		list.ScrollBarThickness = 3
		list.Parent = dropdown
	end

	if not listLayout then
		listLayout = InstanceNew("UIListLayout")
		listLayout.SortOrder = Enum.SortOrder.LayoutOrder
		listLayout.HorizontalAlignment = Enum.HorizontalAlignment.Center
		listLayout.Padding = UDim.new(0, 5)
		listLayout.Parent = list
	end

	collapsedHeight = tonumber((opts and opts.CollapsedHeight) or (opts and opts.collapsedHeight)) or 45
	openHeight = tonumber((opts and opts.OpenHeight) or (opts and opts.openHeight)) or 180
	collapsedHeight = math.max(36, math.floor(collapsedHeight + 0.5))
	openHeight = math.max(collapsedHeight + 20, math.floor(openHeight + 0.5))

	list.Visible = false
	list.Position = UDim2.new(0, 5, 0, 38)
	list.Size = UDim2.new(1, -10, 1, -42)
	list.ScrollBarImageTransparency = 1
	dropdown.Size = UDim2.new(1, -10, 0, collapsedHeight)
	interact.AnchorPoint = Vector2.new(0, 0)
	interact.Position = UDim2.new(0, 0, 0, 0)
	interact.Size = UDim2.new(1, 0, 0, collapsedHeight)

	local selectedColor = (opts and (opts.DropdownSelected or opts.selectedColor)) or Color3.fromRGB(40, 40, 40)
	local unselectedColor = (opts and (opts.DropdownUnselected or opts.unselectedColor)) or Color3.fromRGB(30, 30, 30)
	local hoverColor = (opts and (opts.HoverColor or opts.hoverColor)) or Color3.fromRGB(55, 55, 60)
	local baseColor = dropdown.BackgroundColor3
	local busy = false

	if DropdownSettings.CurrentOption then
		if type(DropdownSettings.CurrentOption) == "string" then
			DropdownSettings.CurrentOption = {DropdownSettings.CurrentOption}
		end
		if not DropdownSettings.MultipleOptions and type(DropdownSettings.CurrentOption) == "table" then
			DropdownSettings.CurrentOption = {DropdownSettings.CurrentOption[1]}
		end
	else
		DropdownSettings.CurrentOption = {}
	end

	local function updateSelectedText()
		if not (selected and selected:IsA("TextLabel")) then
			return
		end
		selected.RichText = dropdownUsesRichText()
		if DropdownSettings.MultipleOptions then
			if #DropdownSettings.CurrentOption == 1 then
				selected.Text = getOptionSelectedDisplay(DropdownSettings.CurrentOption[1])
			elseif #DropdownSettings.CurrentOption == 0 then
				selected.Text = "None"
			else
				selected.Text = "Various"
			end
		else
			selected.Text = getOptionSelectedDisplay(DropdownSettings.CurrentOption[1] or "None")
		end
		resizeSelectedLabel()
	end

	local function eachOptionRow(fn)
		for _, child in ipairs(list:GetChildren()) do
			if child:IsA("Frame") and child.Name ~= "Placeholder" and child.Name ~= "Template" then
				fn(child)
			end
		end
	end

	local function applySelectionColors()
		eachOptionRow(function(row)
			local optionValue = row:GetAttribute("DropdownValue") or row.Name
			local on = table.find(DropdownSettings.CurrentOption, optionValue) ~= nil
			row.BackgroundColor3 = on and selectedColor or unselectedColor
			local rowStroke = row:FindFirstChild("UIStroke")
			if rowStroke and rowStroke:IsA("UIStroke") then
				rowStroke.Transparency = on and 1 or 0
			end
		end)
	end

	local function syncOptionRowVisualState(isOpen)
		eachOptionRow(function(row)
			local rowStroke = row:FindFirstChild("UIStroke")
			local rowTitle = row:FindFirstChild("Title")
			local optionValue = row:GetAttribute("DropdownValue") or row.Name
			local isSelected = table.find(DropdownSettings.CurrentOption, optionValue) ~= nil
			row.BackgroundTransparency = isOpen and 0 or 1
			if rowTitle and rowTitle:IsA("TextLabel") then
				rowTitle.TextTransparency = isOpen and 0 or 1
			end
			if rowStroke and rowStroke:IsA("UIStroke") then
				if isOpen then
					rowStroke.Transparency = isSelected and 1 or 0
				else
					rowStroke.Transparency = 1
				end
			end
		end)
	end

	local function openDropdown()
		if busy then return end
		busy = true
		list.Visible = true
		__lt.cm("TweenService", "Create", dropdown, TweenInfo.new(0.5, Enum.EasingStyle.Exponential), {Size = UDim2.new(1, -10, 0, openHeight)}):Play()
		__lt.cm("TweenService", "Create", list, TweenInfo.new(0.3, Enum.EasingStyle.Exponential), {ScrollBarImageTransparency = 0.7}):Play()
		if toggle then
			__lt.cm("TweenService", "Create", toggle, TweenInfo.new(0.7, Enum.EasingStyle.Exponential), {Rotation = 0}):Play()
		end
		eachOptionRow(function(row)
			local rowStroke = row:FindFirstChild("UIStroke")
			local rowTitle = row:FindFirstChild("Title")
			local optionValue = row:GetAttribute("DropdownValue") or row.Name
			if rowStroke and rowStroke:IsA("UIStroke") then
				if not table.find(DropdownSettings.CurrentOption, optionValue) then
					__lt.cm("TweenService", "Create", rowStroke, TweenInfo.new(0.3, Enum.EasingStyle.Exponential), {Transparency = 0}):Play()
				end
			end
			__lt.cm("TweenService", "Create", row, TweenInfo.new(0.3, Enum.EasingStyle.Exponential), {BackgroundTransparency = 0}):Play()
			if rowTitle and rowTitle:IsA("TextLabel") then
				__lt.cm("TweenService", "Create", rowTitle, TweenInfo.new(0.3, Enum.EasingStyle.Exponential), {TextTransparency = 0}):Play()
			end
		end)
		task.wait(0.05)
		busy = false
	end

	local function closeDropdown()
		if busy then return end
		busy = true
		__lt.cm("TweenService", "Create", dropdown, TweenInfo.new(0.5, Enum.EasingStyle.Exponential), {Size = UDim2.new(1, -10, 0, collapsedHeight)}):Play()
		eachOptionRow(function(row)
			local rowStroke = row:FindFirstChild("UIStroke")
			local rowTitle = row:FindFirstChild("Title")
			__lt.cm("TweenService", "Create", row, TweenInfo.new(0.3, Enum.EasingStyle.Exponential), {BackgroundTransparency = 1}):Play()
			if rowStroke and rowStroke:IsA("UIStroke") then
				__lt.cm("TweenService", "Create", rowStroke, TweenInfo.new(0.3, Enum.EasingStyle.Exponential), {Transparency = 1}):Play()
			end
			if rowTitle and rowTitle:IsA("TextLabel") then
				__lt.cm("TweenService", "Create", rowTitle, TweenInfo.new(0.3, Enum.EasingStyle.Exponential), {TextTransparency = 1}):Play()
			end
		end)
		__lt.cm("TweenService", "Create", list, TweenInfo.new(0.3, Enum.EasingStyle.Exponential), {ScrollBarImageTransparency = 1}):Play()
		if toggle then
			__lt.cm("TweenService", "Create", toggle, TweenInfo.new(0.7, Enum.EasingStyle.Exponential), {Rotation = 180}):Play()
		end
		task.wait(0.35)
		list.Visible = false
		busy = false
	end

	local function toggleDropdown()
		__lt.cm("TweenService", "Create", dropdown, TweenInfo.new(0.2, Enum.EasingStyle.Exponential), {BackgroundColor3 = hoverColor}):Play()
		if uiStroke and uiStroke:IsA("UIStroke") then
			__lt.cm("TweenService", "Create", uiStroke, TweenInfo.new(0.2, Enum.EasingStyle.Exponential), {Transparency = 1}):Play()
		end
		task.wait(0.08)
		__lt.cm("TweenService", "Create", dropdown, TweenInfo.new(0.2, Enum.EasingStyle.Exponential), {BackgroundColor3 = baseColor}):Play()
		if uiStroke and uiStroke:IsA("UIStroke") then
			__lt.cm("TweenService", "Create", uiStroke, TweenInfo.new(0.2, Enum.EasingStyle.Exponential), {Transparency = 0}):Play()
		end
		if list.Visible then
			closeDropdown()
		else
			openDropdown()
		end
	end

	local function clearOptionRows()
		eachOptionRow(function(row)
			row:Destroy()
		end)
	end

	local function makeFallbackTemplate()
		local row = InstanceNew("Frame")
		row.Size = UDim2.new(1, -8, 0, 32)
		row.BackgroundColor3 = unselectedColor
		row.BorderSizePixel = 0
		local c = InstanceNew("UICorner")
		c.CornerRadius = UDim.new(0, 6)
		c.Parent = row
		local st = InstanceNew("UIStroke")
		st.Color = Color3.fromRGB(70, 70, 70)
		st.Parent = row
		local txt = InstanceNew("TextLabel")
		txt.Name = "Title"
		txt.AnchorPoint = Vector2.new(0, 0.5)
		txt.Position = UDim2.new(0, 10, 0.5, 0)
		txt.Size = UDim2.new(1, -20, 0, 14)
		txt.BackgroundTransparency = 1
		txt.TextXAlignment = Enum.TextXAlignment.Left
		txt.FontFace = Font.new("rbxasset://fonts/families/Roboto.json", Enum.FontWeight.Regular, Enum.FontStyle.Normal)
		txt.TextColor3 = Color3.fromRGB(245, 245, 250)
		txt.Parent = row
		local btn = InstanceNew("TextButton")
		btn.Name = "Interact"
		btn.BackgroundTransparency = 1
		btn.Text = ""
		btn.Size = UDim2.new(1, 0, 1, 0)
		btn.ZIndex = 50
		btn.Parent = row
		return row
	end

	local function fireCallback(payload)
		local ok, err = pcall(function()
			DropdownSettings.Callback(payload)
		end)
		if not ok then
			__lt.cm("TweenService", "Create", dropdown, TweenInfo.new(0.3, Enum.EasingStyle.Exponential), {BackgroundColor3 = Color3.fromRGB(85, 0, 0)}):Play()
			if uiStroke and uiStroke:IsA("UIStroke") then
				__lt.cm("TweenService", "Create", uiStroke, TweenInfo.new(0.3, Enum.EasingStyle.Exponential), {Transparency = 1}):Play()
			end
			if title and title:IsA("TextLabel") then
				title.Text = "Callback Error"
			end
			warn("[NA] Dropdown callback error:", err)
			task.wait(0.4)
			if title and title:IsA("TextLabel") then
				title.Text = DropdownSettings.Name
			end
			__lt.cm("TweenService", "Create", dropdown, TweenInfo.new(0.3, Enum.EasingStyle.Exponential), {BackgroundColor3 = baseColor}):Play()
			if uiStroke and uiStroke:IsA("UIStroke") then
				__lt.cm("TweenService", "Create", uiStroke, TweenInfo.new(0.3, Enum.EasingStyle.Exponential), {Transparency = 0}):Play()
			end
		end
	end

	local function setDropdownOptions()
		clearOptionRows()
		local templateRow = optionTemplate
		if templateRow and templateRow:IsA("GuiObject") then
			templateRow.Visible = false
		end
		for index, option in ipairs(DropdownSettings.Options) do
			local optionValue = tostring(option.value or "")
			local optionDisplay = tostring(option.display or optionValue)
			local optionRichText = option.richText == true or (opts and (opts.RichText == true or opts.richText == true))
			local row = (templateRow and templateRow:Clone()) or makeFallbackTemplate()
			row.Name = "Option_"..tostring(index)
			row:SetAttribute("DropdownValue", optionValue)
			row.Visible = true
			row.Parent = list
			local rowTitle = row:FindFirstChild("Title")
			local rowInteract = row:FindFirstChild("Interact")
			local rowStroke = row:FindFirstChild("UIStroke")
			if rowTitle and rowTitle:IsA("TextLabel") then
				rowTitle.Text = optionDisplay
				rowTitle.RichText = optionRichText
				rowTitle.TextTransparency = 1
			end
			if rowStroke and rowStroke:IsA("UIStroke") then
				rowStroke.Transparency = 1
			end
			row.BackgroundTransparency = 1

			if not (rowInteract and rowInteract:IsA("GuiButton")) then
				rowInteract = InstanceNew("TextButton")
				rowInteract.Name = "Interact"
				rowInteract.BackgroundTransparency = 1
				rowInteract.Text = ""
				rowInteract.Size = UDim2.new(1, 0, 1, 0)
				rowInteract.Parent = row
			end
			rowInteract.ZIndex = 50

			MouseButtonFix(rowInteract, function()
				if not DropdownSettings.MultipleOptions and table.find(DropdownSettings.CurrentOption, optionValue) then
					return
				end

				local idx = table.find(DropdownSettings.CurrentOption, optionValue)
				if idx then
					table.remove(DropdownSettings.CurrentOption, idx)
				else
					if not DropdownSettings.MultipleOptions then
						table.clear(DropdownSettings.CurrentOption)
					end
					table.insert(DropdownSettings.CurrentOption, optionValue)
				end

				updateSelectedText()
				applySelectionColors()
				fireCallback(DropdownSettings.CurrentOption)

				if not DropdownSettings.MultipleOptions and list.Visible then
					task.wait(0.1)
					closeDropdown()
				end
			end)
		end
		applySelectionColors()
		syncOptionRowVisualState(list.Visible == true)
	end

	updateSelectedText()
	setDropdownOptions()
	if toggle and toggle:IsA("GuiObject") then
		toggle.Rotation = 180
	end

	pcall(function()
		NAlib.connect(connKey, dropdown:GetPropertyChangedSignal("AbsoluteSize"):Connect(resizeSelectedLabel))
	end)
	if title and title:IsA("TextLabel") then
		pcall(function()
			NAlib.connect(connKey, title:GetPropertyChangedSignal("TextBounds"):Connect(resizeSelectedLabel))
		end)
	end
	if selected and selected:IsA("TextLabel") then
		pcall(function()
			NAlib.connect(connKey, selected:GetPropertyChangedSignal("TextBounds"):Connect(resizeSelectedLabel))
		end)
	end
	resizeSelectedLabel()

	MouseButtonFix(interact, toggleDropdown)
	if toggle and toggle:IsA("GuiButton") then
		MouseButtonFix(toggle, toggleDropdown)
	end

	NAlib.connect(connKey, dropdown.MouseEnter:Connect(function()
		if not list.Visible then
			__lt.cm("TweenService", "Create", dropdown, TweenInfo.new(0.3, Enum.EasingStyle.Exponential), {BackgroundColor3 = hoverColor}):Play()
		end
	end))
	NAlib.connect(connKey, dropdown.MouseLeave:Connect(function()
		__lt.cm("TweenService", "Create", dropdown, TweenInfo.new(0.3, Enum.EasingStyle.Exponential), {BackgroundColor3 = baseColor}):Play()
	end))

	function DropdownSettings:Set(NewOption)
		DropdownSettings.CurrentOption = NewOption
		if typeof(DropdownSettings.CurrentOption) == "string" then
			DropdownSettings.CurrentOption = {DropdownSettings.CurrentOption}
		end
		if type(DropdownSettings.CurrentOption) ~= "table" then
			DropdownSettings.CurrentOption = {}
		end
		if not DropdownSettings.MultipleOptions then
			DropdownSettings.CurrentOption = {DropdownSettings.CurrentOption[1]}
		end
		updateSelectedText()
		applySelectionColors()
		fireCallback(NewOption)
	end

	function DropdownSettings:Refresh(optionsTable)
		DropdownSettings.Options = normalizeOptions(optionsTable)
		for i = #DropdownSettings.CurrentOption, 1, -1 do
			local val = DropdownSettings.CurrentOption[i]
			if not hasOptionValue(val) then
				table.remove(DropdownSettings.CurrentOption, i)
			end
		end
		updateSelectedText()
		setDropdownOptions()
	end

	DropdownSettings.Instance = dropdown

	local regKey = DropdownSettings.Name
	local entry = {
		get = function()
			return DropdownSettings.CurrentOption
		end;
		set = function(value, setOpts)
			setOpts = setOpts or {}
			if setOpts.fire == false then
				local prev = DropdownSettings.Callback
				DropdownSettings.Callback = function() end
				DropdownSettings:Set(value)
				DropdownSettings.Callback = prev
				return
			end
			DropdownSettings:Set(value)
		end;
		setOptions = function(newOptions)
			DropdownSettings:Refresh(newOptions)
		end;
		api = DropdownSettings;
	}
	NAgui._dropdownRegistry[regKey] = entry

	NAlib.connect(connKey, dropdown:GetPropertyChangedSignal("Parent"):Connect(function()
		if not dropdown.Parent and NAgui._dropdownRegistry[regKey] == entry then
			NAgui._dropdownRegistry[regKey] = nil
			Defer(function()
				NAlib.disconnect(connKey)
			end)
		end
	end))

	return DropdownSettings
end

NAgui.setDropdownValue = function(label, value, opts)
	local entry = NAgui._dropdownRegistry and NAgui._dropdownRegistry[label]
	if not entry then return end
	entry.set(value, opts or { fire = false, context = "set" })
end

NAgui.setDropdownOptions = function(label, options, opts)
	local entry = NAgui._dropdownRegistry and NAgui._dropdownRegistry[label]
	if not entry then return end
	entry.setOptions(options, opts or {})
end

NAmanage.Topbar_PlayTween=function(key,instance,info,props)
	NAmanage._tweens=NAmanage._tweens or {}
	if NAmanage._tweens[key] then NAmanage._tweens[key]:Cancel() end
	local t=__lt.cm("TweenService", "Create", instance,info,props)
	NAmanage._tweens[key]=t
	t:Play()
	return t
end

NAmanage.Topbar_ButtonCount=function()
	local n=0
	for _ in ipairs(TopBarApp.buttonDefs) do n+=1 end
	return n
end

NAmanage.Topbar_ComputedSize=function()
	local pad=8
	local count=NAmanage.Topbar_ButtonCount()
	local cam=workspace.CurrentCamera
	local vpX=cam and cam.ViewportSize.X or 1280
	local margin=8
	if TopBarApp.mode=="bottom" then
		local tile=44
		local cols=math.max(1, math.min(5, count))
		local rows=math.max(1, math.min(5, math.ceil(count/5)))
		local w=cols*tile+(cols-1)*pad+12
		local h=rows*tile+(rows-1)*pad+12
		w=math.min(w, vpX - margin*2)
		return w,h
	else
		local tile = 48
		local visible = math.max(1, math.min(4, count))
		local w = visible*tile + (visible-1)*pad + 12
		local h = tile + 12
		local maxW = vpX - margin*2
		if w > maxW then
			w = maxW
		end
		return w,h
	end
end

function Topbar_GetMaxOffset()
	if not (TopBarApp and TopBarApp.frame and TopBarApp.toggle) then
		return nil
	end
	local fw = TopBarApp.frame.AbsoluteSize.X
	local bw = TopBarApp.toggle.AbsoluteSize.X
	if fw <= 0 then
		return nil
	end
	local maxOffset = (fw - bw) * 0.5
	if maxOffset < 0 then
		maxOffset = 0
	end
	return maxOffset
end

NAmanage.Topbar_SavePositionPreference=function(opts)
	opts = opts or {}
	if not NATopbarKeepPosition and not opts.force then
		return
	end
	local maxOffset = Topbar_GetMaxOffset()
	if not maxOffset then
		return
	end
	local offset = opts.offset
	if type(offset) ~= "number" then
		if not (TopBarApp and TopBarApp.toggle) then
			return
		end
		offset = TopBarApp.toggle.Position.X.Offset
	end
	local ratio = 0
	if maxOffset > 0 then
		ratio = math.clamp(offset / maxOffset, -1, 1)
	end
	NATopbarPositionRatio = ratio
	NAmanage.NASettingsSet("topbarPositionRatio", ratio)
end

NAmanage.Topbar_ResetPositionPreference=function()
	NATopbarPositionRatio = 0
	NAmanage.NASettingsSet("topbarPositionRatio", 0)
	if TopBarApp and TopBarApp.toggle then
		local pos = TopBarApp.toggle.Position
		TopBarApp.toggle.Position = UDim2.new(0.5, 0, pos.Y.Scale, pos.Y.Offset)
		if TopBarApp.isOpen then
			NAmanage.Topbar_PositionPanel()
		end
	end
end

NAmanage.Topbar_ApplySavedPosition=function()
	if not NATopbarKeepPosition then
		return
	end
	local maxOffset = Topbar_GetMaxOffset()
	if not maxOffset then
		return
	end
	local ratio = math.clamp(NATopbarPositionRatio or 0, -1, 1)
	local offset = ratio * maxOffset
	if TopBarApp and TopBarApp.toggle then
		local pos = TopBarApp.toggle.Position
		TopBarApp.toggle.Position = UDim2.new(0.5, offset, pos.Y.Scale, pos.Y.Offset)
		if TopBarApp.isOpen then
			NAmanage.Topbar_PositionPanel()
		end
	end
end

NAmanage.Topbar_ApplyDock=function(dock)
	dock = dock == "bottom" and "bottom" or "top"
	NATopbarDock = dock
	TopBarApp.dock = dock
	NAmanage.topbar_writeDock(dock)
	if TopBarApp.frame then
		TopBarApp.frame.AnchorPoint = Vector2.new(0, dock == "bottom" and 1 or 0)
		TopBarApp.frame.Position = dock == "bottom" and UDim2.new(0,0,1,0) or UDim2.new(0,0,0,0)
	end
	if TopBarApp.toggle then
		local currentX = TopBarApp.toggle.Position.X.Offset
		local anchor = dock == "bottom" and Vector2.new(0.5,1) or Vector2.new(0.5,0)
		local yScale = dock == "bottom" and 1 or 0
		local yOffset = dock == "bottom" and -10 or 10
		TopBarApp.toggle.AnchorPoint = anchor
		TopBarApp.toggle.Position = UDim2.new(0.5, currentX, yScale, yOffset)
	end
	if NATopbarKeepPosition then
		NAmanage.Topbar_ApplySavedPosition()
	else
		NAmanage.Topbar_ClampToggle()
	end
	if TopBarApp.isOpen then
		NAmanage.Topbar_PositionPanel()
	end
end

NAmanage.Topbar_ChooseSide=function()
	local cam=workspace.CurrentCamera
	if not cam then return end
	local vp=cam.ViewportSize
	local ap,sz=TopBarApp.toggle.AbsolutePosition,TopBarApp.toggle.AbsoluteSize
	local w=NAmanage.Topbar_ComputedSize()
	local canRight=(ap.X+sz.X+8+w)<= (vp.X-8)
	local canLeft=(ap.X-8-w)>=8
	if TopBarApp.sidePref=="right" and not canRight and canLeft then
		TopBarApp.sidePref="left"
	elseif TopBarApp.sidePref=="left" and not canLeft and canRight then
		TopBarApp.sidePref="right"
	elseif not canRight and canLeft then
		TopBarApp.sidePref="left"
	elseif canRight and not canLeft then
		TopBarApp.sidePref="right"
	end
end

NAmanage.Topbar_PositionPanel=function()
	if not (TopBarApp.panel and TopBarApp.toggle) then return end

	local cam = workspace.CurrentCamera
	if not cam then return end

	local vp = cam.ViewportSize
	local tap, tsz = TopBarApp.toggle.AbsolutePosition, TopBarApp.toggle.AbsoluteSize
	local w, h = NAmanage.Topbar_ComputedSize()
	local marginX, gap = 8, 10
	local dock = TopBarApp.dock or NATopbarDock or "top"

	if TopBarApp.mode == "bottom" then
		TopBarApp.panel.Parent = TopBarApp.toggle
		TopBarApp.panel.Size = UDim2.new(0, w, 0, TopBarApp.isOpen and h or 0)

		local openDown = dock ~= "bottom"
		TopBarApp.panel.AnchorPoint = openDown and Vector2.new(0.5, 0) or Vector2.new(0.5, 1)
		TopBarApp.panel.Position = openDown
			and UDim2.new(0.5, 0, 1, gap)
			or  UDim2.new(0.5, 0, 0, -gap)

		local ap = TopBarApp.panel.AbsolutePosition
		local aw = TopBarApp.panel.AbsoluteSize.X
		local dx = 0

		if ap.X < marginX then
			dx = marginX - ap.X
		end
		if ap.X + aw > vp.X - marginX then
			dx = (vp.X - marginX) - (ap.X + aw)
		end

		if dx ~= 0 then
			if openDown then
				TopBarApp.panel.Position = UDim2.new(0.5, dx, 1, gap)
			else
				TopBarApp.panel.Position = UDim2.new(0.5, dx, 0, -gap)
			end
		end
	else
		TopBarApp.panel.Parent = TopBarApp.top
		TopBarApp.panel.Size = UDim2.new(0, w, 0, TopBarApp.isOpen and h or 0)

		local canRight = (tap.X + tsz.X + gap + w) <= vp.X - marginX
		local canLeft  = (tap.X - gap - w) >= marginX

		if TopBarApp.sidePref == "right" and not canRight and canLeft then
			TopBarApp.sidePref = "left"
		elseif TopBarApp.sidePref == "left" and not canLeft and canRight then
			TopBarApp.sidePref = "right"
		elseif not canRight and not canLeft then
			TopBarApp.sidePref = ((vp.X - (tap.X + tsz.X)) >= tap.X) and "right" or "left"
		end

		local dock  = TopBarApp.dock or NATopbarDock or "top"
		local baseY = tap.Y + tsz.Y*0.5
		local y

		if dock == "bottom" then
			y = math.max(baseY + 55, h*0.5 + 4)
		else
			y = math.clamp(baseY, h*0.5 + 8, vp.Y - h*0.5 - 8)
		end

		if TopBarApp.sidePref == "right" then
			TopBarApp.panel.AnchorPoint = Vector2.new(0, 0.5)
			local x = math.min(tap.X + tsz.X + gap, vp.X - marginX - w)
			TopBarApp.panel.Position = UDim2.new(0, x, 0, y)
		else
			TopBarApp.panel.AnchorPoint = Vector2.new(1, 0.5)
			local x = math.max(tap.X - gap, marginX + w)
			TopBarApp.panel.Position = UDim2.new(0, x, 0, y)
		end
	end
end

NAmanage.Topbar_AnimateIcon=function(iconText)
	local ti=TweenInfo.new(0.1,Enum.EasingStyle.Sine,Enum.EasingDirection.Out)
	local ti2=TweenInfo.new(0.1,Enum.EasingStyle.Sine,Enum.EasingDirection.InOut)
	NAmanage.Topbar_PlayTween("icon_shrink",TopBarApp.icon,ti,{TextSize=0}).Completed:Wait()
	TopBarApp.icon.Text=iconText or ""
	TopBarApp.icon.TextSize=0
	NAmanage.Topbar_PlayTween("icon_grow",TopBarApp.icon,ti2,{TextSize=24})
end

NAmanage.Topbar_UpdateToggleVisual=function(open, opts)
	opts = opts or {}
	local ti=TweenInfo.new(0.1,Enum.EasingStyle.Sine,Enum.EasingDirection.InOut)
	local function clamp01(v, fallback)
		local n = tonumber(v)
		if n == nil then return fallback end
		if n < 0 then n = 0 elseif n > 1 then n = 1 end
		return n
	end
	local baseGlass = clamp01(NAStuff.TopbarGlassTransparency or 0.12, 0.12)
	local baseStroke = clamp01(NAStuff.TopbarStrokeTransparency or 0.15, 0.15)
	local bgTarget=open and math.max(0, baseGlass - 0.06) or baseGlass
	local strokeT=open and math.max(0, baseStroke - 0.1) or baseStroke
	NAmanage.Topbar_PlayTween("tglass_bg",TopBarApp.tGlass,ti,{BackgroundTransparency=bgTarget})
	if TopBarApp.tStroke then NAmanage.Topbar_PlayTween("tglass_stroke",TopBarApp.tStroke,ti,{Transparency=strokeT}) end
	local CLOSED_ICON="three-bars-horizontal"
	local OPENED_ICON="twitter"
	if not opts.skipIcon then
		if open then
			NAmanage.Topbar_AnimateIcon(OPENED_ICON)
		else
			NAmanage.Topbar_AnimateIcon(CLOSED_ICON)
		end
	end
end

NAmanage.Topbar_SetOpen=function(state)
	if not TopBarApp.panel then return end
	TopBarApp.isOpen=state
	local w,h=NAmanage.Topbar_ComputedSize()
	TopBarApp.panel.Visible=true
	TopBarApp.underlay.Visible = state
	TopBarApp.scroll.Visible = state
	TopBarApp.underlay.ZIndex=201
	TopBarApp.scroll.ZIndex=202
	NAlib.disconnect("tb_follow")
	TopBarApp.animating=true
	NAmanage.Topbar_PositionPanel()
	local ts=TweenService
	local dur=0.18
	local ease=TweenInfo.new(dur,Enum.EasingStyle.Sine,Enum.EasingDirection.InOut)
	if state then
		TopBarApp.panel.Size=UDim2.new(0,w,0,0)
		local tween=ts:Create(TopBarApp.panel,ease,{Size=UDim2.new(0,w,0,h)})
		tween:Play()
		tween.Completed:Connect(function()
			TopBarApp.animating=false
		end)
		NAlib.connect("tb_follow",RunService.RenderStepped:Connect(function()
			NAmanage.Topbar_PositionPanel()
		end))
	else
		local tween=ts:Create(TopBarApp.panel,ease,{Size=UDim2.new(0,w,0,0)})
		tween:Play()
		tween.Completed:Connect(function()
			if not TopBarApp.isOpen then TopBarApp.panel.Visible=false end
			TopBarApp.animating=false
		end)
	end
	NAmanage.Topbar_UpdateToggleVisual(state)
end

NAmanage.Topbar_Toggle=function()
	NAmanage.Topbar_SetOpen(not TopBarApp.isOpen)
end

NAmanage.Topbar_Rebuild=function()
	if TopBarApp.scroll then TopBarApp.scroll:Destroy() TopBarApp.scroll=nil end
	TopBarApp.scroll=InstanceNew("ScrollingFrame",TopBarApp.panel)
	TopBarApp.scroll.BackgroundTransparency=1
	TopBarApp.scroll.BorderSizePixel=0
	TopBarApp.scroll.Size=UDim2.new(1,0,1,0)
	TopBarApp.scroll.ZIndex=202
	TopBarApp.scroll.ScrollBarThickness=4
	for _,c in ipairs(TopBarApp.scroll:GetChildren()) do c:Destroy() end
	for btn,_ in pairs(TopBarApp.childButtons) do TopBarApp.childButtons[btn]=nil end
	local pad=InstanceNew("UIPadding",TopBarApp.scroll)
	pad.PaddingTop=UDim.new(0,6)
	pad.PaddingBottom=UDim.new(0,6)
	pad.PaddingLeft=UDim.new(0,6)
	pad.PaddingRight=UDim.new(0,6)
	if TopBarApp.layout then TopBarApp.layout:Destroy() TopBarApp.layout=nil end
	local tileBottom=44
	local tileSide=48
	if TopBarApp.mode=="bottom" then
		TopBarApp.scroll.ScrollingDirection=Enum.ScrollingDirection.Y
		local grid=InstanceNew("UIGridLayout",TopBarApp.scroll)
		grid.CellSize=UDim2.new(0,tileBottom,0,tileBottom)
		grid.CellPadding=UDim2.new(0,8,0,8)
		grid.HorizontalAlignment=Enum.HorizontalAlignment.Center
		grid.VerticalAlignment=Enum.VerticalAlignment.Top
		grid.SortOrder=Enum.SortOrder.LayoutOrder
		TopBarApp.layout=grid
	else
		TopBarApp.scroll.ScrollingDirection = Enum.ScrollingDirection.X
		local list = InstanceNew("UIListLayout", TopBarApp.scroll)
		list.FillDirection = Enum.FillDirection.Horizontal
		list.HorizontalAlignment = Enum.HorizontalAlignment.Left
		list.VerticalAlignment = Enum.VerticalAlignment.Center
		list.Padding = UDim.new(0,8)
		list.SortOrder = Enum.SortOrder.LayoutOrder
		TopBarApp.layout = list
	end
	local i=0
	for _,def in ipairs(TopBarApp.buttonDefs) do
		i+=1
		local btn=InstanceNew("TextButton",TopBarApp.scroll)
		btn.Name=def.name.."Btn"
		btn.Size=UDim2.new(0, TopBarApp.mode=="bottom" and tileBottom or tileSide, 0, TopBarApp.mode=="bottom" and tileBottom or tileSide)
		btn.BackgroundTransparency=1
		btn.BorderSizePixel=0
		btn.LayoutOrder=i
		btn.Text=''
		btn.TextTransparency=1
		btn.ZIndex=205
		local bg=InstanceNew("Frame",btn)
		bg.ZIndex=203
		bg.Size=UDim2.new(1,0,1,0)
		bg.BackgroundColor3=Color3.fromRGB(25,25,28)
		bg.BackgroundTransparency=NAStuff.TopbarButtonTransparency or 0.18
		bg.BorderSizePixel=0
		local cr=InstanceNew("UICorner",bg); cr.CornerRadius=UDim.new(0,12)
		local stroke=InstanceNew("UIStroke",bg)
		stroke.Thickness=1
		stroke.Color=NAUISTROKER or Color3.fromRGB(148,93,255)
		stroke.Transparency=0.15
		NAgui.RegisterColoredStroke(stroke)
		local ic=InstanceNew("TextLabel",bg)
		ic.ZIndex=204
		ic.BackgroundTransparency=1
		ic.Size=UDim2.new(0.65,0,0.65,0)
		ic.Position=UDim2.new(0.5,0,0.5,0)
		ic.AnchorPoint=Vector2.new(0.5,0.5)
		ic.FontFace=TopBarApp.icon.FontFace
		ic.Text=def.icon or def.name or ""
		ic.TextColor3=Color3.new(1,1,1)
		ic.TextScaled=false
		ic.TextSize=24
		TopBarApp.childButtons[btn]=def.func
		MouseButtonFix(btn,def.func)
	end
	local function updateCanvas()
		if TopBarApp.mode == "bottom" then
			TopBarApp.scroll.CanvasSize = UDim2.new(0,0,0,TopBarApp.layout.AbsoluteContentSize.Y+12)
		else
			TopBarApp.scroll.CanvasSize = UDim2.new(0,TopBarApp.layout.AbsoluteContentSize.X+12,0,0)
		end
		if not TopBarApp.animating then
			NAmanage.Topbar_PositionPanel()
		end
	end
	NAlib.disconnect("tb_canvas")
	NAlib.connect("tb_canvas",TopBarApp.layout:GetPropertyChangedSignal("AbsoluteContentSize"):Connect(updateCanvas))
	updateCanvas()
end

NAmanage.Topbar_AddButton=function(def)
	TopBarApp.buttonDefs[#TopBarApp.buttonDefs+1]=def
	NAmanage.Topbar_Rebuild()
	NAmanage.SideSwipe_Rebuild()
	if TopBarApp.isOpen then NAmanage.Topbar_PositionPanel() end
end

NAmanage.Topbar_ClampToggle=function()
	if not (TopBarApp and TopBarApp.frame and TopBarApp.toggle) then
		return
	end
	if NATopbarKeepPosition then
		NAmanage.Topbar_ApplySavedPosition()
		return
	end
	local fw=TopBarApp.frame.AbsoluteSize.X
	local bw=TopBarApp.toggle.AbsoluteSize.X
	local maxOffset=math.max((fw-bw)*0.5,0)
	local off=math.clamp(TopBarApp.toggle.Position.X.Offset,-maxOffset,maxOffset)
	local pos=TopBarApp.toggle.Position
	TopBarApp.toggle.Position=UDim2.new(0.5,off,pos.Y.Scale,pos.Y.Offset)
	if TopBarApp.isOpen then
		NAmanage.Topbar_PositionPanel()
	end
end

NAmanage.Topbar_MakeDraggableHorizontal=function(ui)
	local key = "tb_drag_ui"
	NAlib.disconnect(key)
	local dragging=false
	local dragInput,dragStart,startPos

	NAlib.connect(key, ui.InputBegan:Connect(function(input)
		if input.UserInputType==Enum.UserInputType.MouseButton1 or input.UserInputType==Enum.UserInputType.Touch then
			dragging=true
			dragStart=input.Position
			startPos=ui.Position
			local endConn
			endConn=NAlib.connect(key, input.Changed:Connect(function()
				if input.UserInputState==Enum.UserInputState.End then
					dragging=false
					if NATopbarKeepPosition then
						NAmanage.Topbar_SavePositionPreference()
					end
					if endConn then
						endConn:Disconnect()
						endConn=nil
						if NAmanage and NAmanage.prnCon then
							NAmanage.prnCon(key)
						end
					end
				end
			end))
		end
	end))

	NAlib.connect(key, ui.InputChanged:Connect(function(input)
		if input.UserInputType==Enum.UserInputType.MouseMovement or input.UserInputType==Enum.UserInputType.Touch then
			dragInput=input
		end
	end))

	local lastStep=0
	NAlib.disconnect("tb_drag_input")
	NAlib.connect("tb_drag_input",UserInputService.InputChanged:Connect(function(input)
		if input==dragInput and dragging then
			local now=os.clock()
			if now-lastStep<(1/60) then return end
			lastStep=now
			local delta=input.Position-dragStart
			local fw=TopBarApp.frame.AbsoluteSize.X
			local bw=ui.AbsoluteSize.X
			local base=startPos.X.Offset
			local newX=math.clamp(base+delta.X,-(fw-bw)/2,(fw-bw)/2)
			ui.Position=UDim2.new(0.5,newX,startPos.Y.Scale,startPos.Y.Offset)
			if TopBarApp.isOpen then
				NAmanage.Topbar_PositionPanel()
			end
		end
	end))

	ui.Active=true
end

NAmanage.Topbar_SetMode=function(mode)
	if mode~="bottom" and mode~="side" then return end
	TopBarApp.mode=mode
	NAmanage.topbar_writeMode(mode)
	NAmanage.Topbar_Rebuild()
	if TopBarApp.isOpen then NAmanage.Topbar_PositionPanel() end
end

NAmanage.Topbar_SetDock=function(dock)
	dock = dock == "bottom" and "bottom" or "top"
	NATopbarDock = dock
	TopBarApp.dock = dock
	NAmanage.topbar_writeDock(dock)
	NAmanage.Topbar_ApplyDock(dock)
end

