NAmanage.ExecutorSplitEditorLines = NAmanage.ExecutorSplitEditorLines or function(source)
	source = tostring(source or ""):gsub("\r\n", "\n"):gsub("\r", "\n")
	local out = {}
	for line in (source.."\n"):gmatch("(.-)\n") do
		out[#out + 1] = line
	end
	if #out == 0 then
		out[1] = ""
	end
	return out
end

NAmanage.ExecutorJoinEditorLines = NAmanage.ExecutorJoinEditorLines or function(lines)
	if type(lines) ~= "table" or #lines == 0 then
		return ""
	end
	return table.concat(lines, "\n")
end

NAmanage.ExecutorRepairTabText = NAmanage.ExecutorRepairTabText or function(source)
	source = tostring(source or ""):gsub("\r\n", "\n"):gsub("\r", "\n")
	if source == "" then
		return ""
	end
	local var = source:match("unpack%s*%(%s*([%a_][%w_]*)%s*%)")
	if not var then
		return source
	end
	if not (source:find(":FireServer%s*%(%s*unpack%s*%(") or source:find(":InvokeServer%s*%(%s*unpack%s*%(")) then
		return source
	end
	local fixed = {}
	local lastKeyLine
	for line in (source.."\n"):gmatch("(.-)\n") do
		local keyLine = line:match("^%s*%[%s*[%d\"'].-%]%s*=%s*.+$") and line:gsub("%s+", "") or nil
		if not (keyLine and keyLine == lastKeyLine) then
			fixed[#fixed + 1] = line
		end
		lastKeyLine = keyLine
	end
	source = table.concat(fixed, "\n")
	if source:match("^%s*local%s+"..var.."%s*=%s*{") or source:match("^%s*"..var.."%s*=%s*{") then
		return source
	end
	if source:match("^%s*%[%s*[%d\"'].-%]%s*=") then
		return "local "..var.." = {\n"..source
	end
	return source
end

NAmanage.ExecutorSliceEditorLines = NAmanage.ExecutorSliceEditorLines or function(lines, firstLine, lastLine)
	local out = {}
	firstLine = math.max(1, tonumber(firstLine) or 1)
	lastLine = math.max(firstLine, tonumber(lastLine) or firstLine)
	for line = firstLine, lastLine do
		out[#out + 1] = tostring(lines[line] or "")
	end
	if #out == 0 then
		out[1] = ""
	end
	return table.concat(out, "\n")
end

NAmanage.ExecutorReplaceEditorLineRange = NAmanage.ExecutorReplaceEditorLineRange or function(lines, firstLine, lastLine, text)
	lines = type(lines) == "table" and lines or { "" }
	local insertLines = NAmanage.ExecutorSplitEditorLines(text)
	local rebuilt = {}
	firstLine = math.clamp(tonumber(firstLine) or 1, 1, math.max(#lines + 1, 1))
	lastLine = math.clamp(tonumber(lastLine) or (firstLine - 1), firstLine - 1, math.max(#lines, firstLine - 1))
	for line = 1, firstLine - 1 do
		rebuilt[#rebuilt + 1] = tostring(lines[line] or "")
	end
	for _, lineText in ipairs(insertLines) do
		rebuilt[#rebuilt + 1] = tostring(lineText or "")
	end
	for line = lastLine + 1, #lines do
		rebuilt[#rebuilt + 1] = tostring(lines[line] or "")
	end
	if #rebuilt == 0 then
		rebuilt[1] = ""
	end
	return rebuilt
end

NAmanage.ExecutorStripLuaLineForIndent = NAmanage.ExecutorStripLuaLineForIndent or function(line, state)
	line = tostring(line or "")
	state = state or {}
	local out = {}
	local i = 1
	local len = #line
	local function pushSpaces(count)
		if count > 0 then
			out[#out + 1] = string.rep(" ", count)
		end
	end
	while i <= len do
		if state.longClose then
			local closeStart, closeEnd = line:find(state.longClose, i, true)
			if closeStart then
				pushSpaces(closeEnd - i + 1)
				i = closeEnd + 1
				state.longClose = nil
			else
				pushSpaces(len - i + 1)
				break
			end
		else
			local two = line:sub(i, i + 1)
			if two == "--" then
				local eq = line:match("^%-%-%[(=*)%[", i)
				if eq then
					local closePattern = "]"..eq.."]"
					local closeStart = line:find(closePattern, i + 4 + #eq, true)
					if closeStart then
						pushSpaces(len - i + 1)
					else
						state.longClose = closePattern
						pushSpaces(len - i + 1)
					end
				else
					pushSpaces(len - i + 1)
				end
				break
			elseif line:sub(i, i):match("[\"'`]") then
				local quote = line:sub(i, i)
				local j = i + 1
				local escaped = false
				while j <= len do
					local ch = line:sub(j, j)
					if escaped then
						escaped = false
					elseif ch == "\\" then
						escaped = true
					elseif ch == quote then
						break
					end
					j += 1
				end
				if j > len then
					j = len
				end
				pushSpaces(j - i + 1)
				i = j + 1
			else
				local eq = line:match("^%[(=*)%[", i)
				if eq then
					local closePattern = "]"..eq.."]"
					local closeStart, closeEnd = line:find(closePattern, i + 2 + #eq, true)
					if closeStart then
						pushSpaces(closeEnd - i + 1)
						i = closeEnd + 1
					else
						state.longClose = closePattern
						pushSpaces(len - i + 1)
						break
					end
				else
					out[#out + 1] = line:sub(i, i)
					i += 1
				end
			end
		end
	end
	return table.concat(out)
end

NAmanage.ExecutorSplitLuaStatementLine = NAmanage.ExecutorSplitLuaStatementLine or function(line, state)
	line = tostring(line or "")
	state = state or {}
	local parts = {}
	local startPos = 1
	local i = 1
	local len = #line
	while i <= len do
		if state.longClose then
			local closeStart, closeEnd = line:find(state.longClose, i, true)
			if closeStart then
				i = closeEnd + 1
				state.longClose = nil
			else
				break
			end
		else
			local two = line:sub(i, i + 1)
			if two == "--" then
				local eq = line:match("^%-%-%[(=*)%[", i)
				if eq then
					local closePattern = "]"..eq.."]"
					local closeStart, closeEnd = line:find(closePattern, i + 4 + #eq, true)
					if closeStart then
						i = closeEnd + 1
					else
						state.longClose = closePattern
						break
					end
				else
					break
				end
			elseif line:sub(i, i):match("[\"'`]") then
				local quote = line:sub(i, i)
				i += 1
				local escaped = false
				while i <= len do
					local ch = line:sub(i, i)
					if escaped then
						escaped = false
					elseif ch == "\\" then
						escaped = true
					elseif ch == quote then
						break
					end
					i += 1
				end
				i += 1
			else
				local eq = line:match("^%[(=*)%[", i)
				if eq then
					local closePattern = "]"..eq.."]"
					local closeStart, closeEnd = line:find(closePattern, i + 2 + #eq, true)
					if closeStart then
						i = closeEnd + 1
					else
						state.longClose = closePattern
						break
					end
				elseif line:sub(i, i) == ";" then
					parts[#parts + 1] = line:sub(startPos, i - 1)
					startPos = i + 1
					i += 1
				else
					i += 1
				end
			end
		end
	end
	parts[#parts + 1] = line:sub(startPos)
	return parts
end

NAmanage.ExecutorFormatLuaLineSpacing = NAmanage.ExecutorFormatLuaLineSpacing or function(line)
	line = tostring(line or "")
	local out = {}
	local i = 1
	local len = #line
	local function currentText()
		return table.concat(out)
	end
	local function trimRight()
		if #out > 0 then
			out[#out] = out[#out]:gsub("%s+$", "")
			if out[#out] == "" then
				table.remove(out, #out)
			end
		end
	end
	local function append(text)
		out[#out + 1] = text
	end
	local function appendOperator(op)
		trimRight()
		append(" "..op.." ")
		while i <= len and line:sub(i, i):match("%s") do
			i += 1
		end
	end
	local function previousSignificant()
		local text = currentText():gsub("%s+$", "")
		return text:sub(-1)
	end
	local function previousWord()
		return currentText():match("([%a_][%w_]*)%s*$")
	end
	local function isUnaryMinus()
		local prev = previousSignificant()
		local word = previousWord()
		return prev == "" or prev:match("[%(%[%{=,%+%-%*/%%%^#<>~]") or word == "return" or word == "local" or word == "then" or word == "do" or word == "else" or word == "elseif" or word == "and" or word == "or" or word == "not"
	end
	while i <= len do
		local ch = line:sub(i, i)
		local two = line:sub(i, i + 1)
		local three = line:sub(i, i + 2)
		if two == "--" then
			append(line:sub(i))
			break
		elseif ch:match("[\"'`]") then
			local quote = ch
			local startQuote = i
			i += 1
			local escaped = false
			while i <= len do
				local cur = line:sub(i, i)
				if escaped then
					escaped = false
				elseif cur == "\\" then
					escaped = true
				elseif cur == quote then
					break
				end
				i += 1
			end
			if i > len then
				i = len
			end
			append(line:sub(startQuote, i))
			i += 1
		else
			local eq = line:match("^%[(=*)%[", i)
			if eq then
				local closePattern = "]"..eq.."]"
				local closeStart, closeEnd = line:find(closePattern, i + 2 + #eq, true)
				if closeStart then
					append(line:sub(i, closeEnd))
					i = closeEnd + 1
				else
					append(line:sub(i))
					break
				end
			elseif three == "..." then
				append("...")
				i += 3
			elseif three == "//=" or three == "..=" then
				i += 3
				appendOperator(three)
			elseif two == "//" or two == "->" then
				i += 2
				appendOperator(two)
			elseif two == ".." then
				i += 2
				appendOperator("..")
			elseif two == "::" then
				append("::")
				i += 2
			elseif two == "==" or two == "~=" or two == "<=" or two == ">=" or two == "+=" or two == "-=" or two == "*=" or two == "/=" or two == "%=" or two == "^=" then
				i += 2
				appendOperator(two)
			elseif ch == "?" then
				append("?")
				i += 1
			elseif ch == "=" or ch == "+" or ch == "*" or ch == "/" or ch == "%" or ch == "^" or ch == "<" or ch == ">" or ch == "|" or ch == "&" then
				i += 1
				appendOperator(ch)
			elseif ch == "-" then
				if isUnaryMinus() then
					append("-")
					i += 1
					while i <= len and line:sub(i, i):match("%s") do
						i += 1
					end
				else
					i += 1
					appendOperator("-")
				end
			elseif ch == "," then
				trimRight()
				append(", ")
				i += 1
				while i <= len and line:sub(i, i):match("%s") do
					i += 1
				end
			else
				append(ch)
				i += 1
			end
		end
	end
	return table.concat(out):gsub("%s+$", "")
end

NAmanage.ExecutorLuaParenBalance = NAmanage.ExecutorLuaParenBalance or function(line)
	line = tostring(line or "")
	local balance = 0
	local i = 1
	local len = #line
	while i <= len do
		local ch = line:sub(i, i)
		local two = line:sub(i, i + 1)
		if two == "--" then
			break
		elseif ch:match("[\"'`]") then
			local quote = ch
			i += 1
			local escaped = false
			while i <= len do
				local cur = line:sub(i, i)
				if escaped then
					escaped = false
				elseif cur == "\\" then
					escaped = true
				elseif cur == quote then
					break
				end
				i += 1
			end
		elseif ch == "(" then
			balance += 1
		elseif ch == ")" then
			balance -= 1
		end
		i += 1
	end
	return balance
end

NAmanage.ExecutorCollapseLuaShortCalls = NAmanage.ExecutorCollapseLuaShortCalls or function(source)
	local lines = {}
	for line in (tostring(source or "").."\n"):gmatch("(.-)\n") do
		lines[#lines + 1] = line
	end
	if #lines > 0 and lines[#lines] == "" and tostring(source or ""):sub(-1) ~= "\n" then
		table.remove(lines)
	end

	local out = {}
	local i = 1
	local function hasCollapseBlockKeyword(text)
		for _, word in ipairs({ "function", "then", "do", "end", "repeat", "until", "else", "elseif" }) do
			if text:find("%f[%w_]"..word.."%f[^%w_]") then
				return true
			end
		end
		return false
	end
	while i <= #lines do
		local line = lines[i]
		local indent, content = line:match("^(%s*)(.-)%s*$")
		if content and content:match("%(%s*$") then
			local balance = NAmanage.ExecutorLuaParenBalance(content)
			local pieces = { content }
			local j = i + 1
			local canCollapse = balance > 0
			while canCollapse and j <= #lines and balance > 0 do
				local nextContent = lines[j]:match("^%s*(.-)%s*$") or ""
				if nextContent == "" or nextContent:find("%-%-", 1, true) or hasCollapseBlockKeyword(nextContent) then
					canCollapse = false
					break
				end
				pieces[#pieces + 1] = nextContent
				balance += NAmanage.ExecutorLuaParenBalance(nextContent)
				j += 1
			end
			if canCollapse and balance <= 0 and #pieces > 1 then
				local joined = pieces[1]
				for pieceIndex = 2, #pieces do
					local piece = pieces[pieceIndex]
					if piece:match("^%)") then
						joined = joined:gsub("%s+$", "")..piece
					else
						joined = joined:gsub("%s+$", "")..(joined:match("%(%s*$") and "" or " ")..piece
					end
				end
				joined = NAmanage.ExecutorFormatLuaLineSpacing(joined)
				if #joined <= 160 then
					out[#out + 1] = indent..joined
					i = j
				else
					out[#out + 1] = line
					i += 1
				end
			else
				out[#out + 1] = line
				i += 1
			end
		else
			out[#out + 1] = line
			i += 1
		end
	end
	return table.concat(out, "\n")
end

NAmanage.ExecutorFormatLuaSource = NAmanage.ExecutorFormatLuaSource or function(source)
	source = tostring(source or ""):gsub("\r\n", "\n"):gsub("\r", "\n")
	local lines = {}
	local splitState = {}
	for line in (source.."\n"):gmatch("(.-)\n") do
		for _, part in ipairs(NAmanage.ExecutorSplitLuaStatementLine(line, splitState)) do
			lines[#lines + 1] = part
		end
	end
	if #lines > 0 and lines[#lines] == "" and source:sub(-1) ~= "\n" then
		table.remove(lines)
	end

	local formatted = {}
	local indent = 0
	local state = {}
	local indentText = "\t"

	for _, rawLine in ipairs(lines) do
		local line = tostring(rawLine or ""):gsub("%s+$", "")
		local trimmed = line:gsub("^%s+", "")
		local code = NAmanage.ExecutorStripLuaLineForIndent(trimmed, state)
		local spaced = NAmanage.ExecutorFormatLuaLineSpacing(trimmed)
		local compact = code:gsub("^%s+", "")
		local closeOutdent = 0
		local branchOutdent = 0
		if compact ~= "" then
			if compact:match("^end%f[^%w_]") or compact:match("^until%f[^%w_]") or compact:sub(1, 1) == "}" then
				closeOutdent += 1
			end
			if compact:match("^else%f[^%w_]") or compact:match("^elseif%f[^%w_]") then
				branchOutdent += 1
			end
		end
		indent = math.max(indent - closeOutdent - branchOutdent, 0)
		if trimmed == "" then
			formatted[#formatted + 1] = ""
		else
			formatted[#formatted + 1] = string.rep(indentText, indent)..spaced
		end

		local opens = 0
		local closes = 0
		for token in code:gmatch("%f[%w_](%w+)%f[^%w_]") do
			if token == "function" or token == "then" or token == "do" or token == "repeat" then
				opens += 1
			elseif token == "end" or token == "until" then
				closes += 1
			end
		end
		for _ in code:gmatch("{") do opens += 1 end
		for _ in code:gmatch("}") do closes += 1 end
		if compact:match("^else%f[^%w_]") then
			opens += 1
		end
		indent = math.max(indent + opens - math.max(closes - closeOutdent, 0), 0)
	end

	return NAmanage.ExecutorCollapseLuaShortCalls(table.concat(formatted, "\n")):gsub("%s+$", "")
end

NAmanage.ExecutorMergeEditorChunks = NAmanage.ExecutorMergeEditorChunks or function(chunks)
	if type(chunks) ~= "table" or #chunks == 0 then
		return ""
	end
	return table.concat(chunks, "")
end

NAmanage.ExecutorNormalizeTab = NAmanage.ExecutorNormalizeTab or function(tab)
	if not tab then
		return nil
	end
	if type(tab.text) ~= "string" then
		if type(tab.chunks) == "table" and #tab.chunks > 0 then
			tab.text = NAmanage.ExecutorMergeEditorChunks(tab.chunks)
		else
			tab.text = ""
		end
	end
	if type(tab.lines) ~= "table" or #tab.lines == 0 then
		tab.lines = NAmanage.ExecutorSplitEditorLines(tab.text)
	end
	tab.viewLine = math.clamp(tonumber(tab.viewLine or tab.page) or 1, 1, math.max(#tab.lines, 1))
	tab.page = 1
	tab.chunks = { tab.text }
	return tab
end

NAmanage.ExecutorGetTabText = NAmanage.ExecutorGetTabText or function(tab)
	tab = NAmanage.ExecutorNormalizeTab(tab)
	if not tab then
		return ""
	end
	if tab.textDirty == true or type(tab.text) ~= "string" then
		tab.text = NAmanage.ExecutorJoinEditorLines(tab.lines)
		tab.chunks = { tab.text }
		tab.textDirty = false
	end
	return tostring(tab.text or "")
end

NAmanage.ExecutorPlaceSettingsPanel = NAmanage.ExecutorPlaceSettingsPanel or function(settingsPanel)
	settingsPanel.AnchorPoint = Vector2.new(1, 0)
	settingsPanel.Position = UDim2.new(1, -10, 0, 42)
end

NAmanage.ExecutorBindSetting = NAmanage.ExecutorBindSetting or function(toggle, hit, cfg, key, applySettings)
	local function flip()
		cfg[key] = not cfg[key]
		applySettings()
	end
	toggle.MouseButton1Click:Connect(flip)
	if hit then
		hit.MouseButton1Click:Connect(flip)
	end
end

NAmanage.Executor_Init = NAmanage.Executor_Init or function()
	if not (NAUIMANAGER and NAUIMANAGER.ExecutorFrame and NAUIMANAGER.ExecutorContainer) then
		return false
	end

	local frame = NAUIMANAGER.ExecutorFrame
	local container = NAUIMANAGER.ExecutorContainer
	if frame.GetAttribute and NAmanage.GetAttr(frame, "NAExecutorReady") then
		return true
	end
	if frame.SetAttribute then
		NAmanage.SetAttr(frame, "NAExecutorReady", true)
	end

	for _, child in ipairs(container:GetChildren()) do
		child:Destroy()
	end

	local TextServiceRef = TextService
	local UserInputServiceRef = UserInputService
	local GuiServiceRef = GuiService
	local execResponsive = {
		compact = false,
		phone = false,
		lastW = 0,
		lastH = 0,
	}
	local baseExecDir = "Nameless-Admin"
	local execDir = baseExecDir.."/NA-Exec"
	local settingsFile = execDir.."/settings.json"
	local tabsFile = execDir.."/tabs.json"
	local indexFile = execDir.."/scripts.json"
	local scriptsDir = execDir.."/Scripts"
	local folderApiOk = type(isfolder) == "function"
		and type(makefolder) == "function"
	local fsOk = type(isfile) == "function"
		and type(readfile) == "function"
		and type(writefile) == "function"
	local delOk = type(delfile) == "function"
	local listOk = type(listfiles) == "function"
	local cfg = {
		syntax = true,
		lineNumbers = true,
		showHub = true,
	}
	local colors = {
		panel = Color3.fromRGB(17, 17, 21),
		panel2 = Color3.fromRGB(24, 24, 30),
		panel3 = Color3.fromRGB(31, 31, 38),
		stroke = Color3.fromRGB(72, 72, 82),
		text = Color3.fromRGB(235, 235, 242),
		subtle = Color3.fromRGB(170, 170, 180),
		tabIdle = Color3.fromRGB(27, 27, 34),
		tabActive = Color3.fromRGB(40, 40, 52),
		tabTextIdle = Color3.fromRGB(178, 178, 190),
		tabTextActive = Color3.fromRGB(241, 241, 248),
		lineNumber = Color3.fromRGB(125, 125, 140),
		code = Color3.fromRGB(230, 230, 236),
		keyword = Color3.fromRGB(255, 171, 247),
		global = Color3.fromRGB(132, 203, 255),
		string = Color3.fromRGB(166, 226, 128),
		comment = Color3.fromRGB(112, 122, 132),
		number = Color3.fromRGB(255, 214, 112),
		func = Color3.fromRGB(130, 230, 210),
		method = Color3.fromRGB(118, 194, 255),
		property = Color3.fromRGB(205, 194, 255),
		operator = Color3.fromRGB(255, 155, 190),
		bracket = Color3.fromRGB(210, 210, 225),
		success = Color3.fromRGB(156, 235, 174),
		warn = Color3.fromRGB(255, 214, 112),
		error = Color3.fromRGB(255, 146, 146),
	}
	local function makeCornerAndStroke(obj, radius, thickness)
		local corner = InstanceNew("UICorner")
		corner.CornerRadius = UDim.new(0, radius or 8)
		corner.Parent = obj
		local stroke = InstanceNew("UIStroke")
		stroke.Color = colors.stroke
		stroke.Transparency = 0.18
		stroke.Thickness = thickness or 1
		stroke.Parent = obj
		return corner, stroke
	end

	local function makeButton(parent, text, background)
		local button = InstanceNew("TextButton")
		button.AutoButtonColor = false
		button.BackgroundColor3 = background or colors.panel3
		button.BorderSizePixel = 0
		button.Font = Enum.Font.GothamSemibold
		button.Text = text
		button.TextColor3 = colors.text
		button.TextSize = 13
		button.Parent = parent
		makeCornerAndStroke(button, 8, 1)
		button.MouseEnter:Connect(function()
			TweenService:Create(button, TweenInfo.new(0.12, Enum.EasingStyle.Quad, Enum.EasingDirection.Out), {
				BackgroundColor3 = (background or colors.panel3):Lerp(Color3.new(1, 1, 1), 0.06)
			}):Play()
		end)
		button.MouseLeave:Connect(function()
			local targetColor = background or colors.panel3
			if button.GetAttribute and NAmanage.GetAttr(button, "NAExecutorSelected") then
				targetColor = colors.tabActive
			end
			TweenService:Create(button, TweenInfo.new(0.12, Enum.EasingStyle.Quad, Enum.EasingDirection.Out), {
				BackgroundColor3 = targetColor
			}):Play()
		end)
		return button
	end

	local function sanitizeScriptName(name)
		name = tostring(name or "")
		name = name:gsub('[\\/:*?"<>|]', "")
		name = name:gsub("%s+", " ")
		name = name:gsub("^%s+", ""):gsub("%s+$", "")
		if name == "" then
			name = "script"
		end
		if not name:lower():match("%.lua$") then
			name ..= ".lua"
		end
		return name
	end

	local function stripLuaExt(name)
		return tostring(name or ""):gsub("%.lua$", ""):gsub("%.txt$", "")
	end

	local function scriptPath(name)
		return scriptsDir.."/"..sanitizeScriptName(name)
	end

	local ensureExecutorFolders

	local function readScriptIndex()
		local list = {}
		if not (fsOk and isfile(indexFile)) then
			return list
		end
		local ok, raw = pcall(readfile, indexFile)
		if not ok or type(raw) ~= "string" or raw == "" then
			return list
		end
		local okDecode, decoded = pcall(HttpService.JSONDecode, HttpService, raw)
		if okDecode and type(decoded) == "table" then
			for _, value in ipairs(decoded) do
				if type(value) == "string" and value ~= "" then
					list[#list + 1] = sanitizeScriptName(value)
				end
			end
		end
		return list
	end

	local function saveScriptIndex(names)
		if not ensureExecutorFolders() then
			return false
		end
		local seen = {}
		local clean = {}
		for _, name in ipairs(names or {}) do
			local fileName = sanitizeScriptName(name)
			local key = fileName:lower()
			if not seen[key] then
				seen[key] = true
				clean[#clean + 1] = fileName
			end
		end
		table.sort(clean, function(a, b)
			return a:lower() < b:lower()
		end)
		local ok, encoded = pcall(function()
			return HttpService:JSONEncode(clean)
		end)
		if ok and encoded then
			return pcall(writefile, indexFile, encoded)
		end
		return false
	end

	local function addScriptIndex(name)
		local fileName = sanitizeScriptName(name)
		local names = readScriptIndex()
		local exists = false
		for _, item in ipairs(names) do
			if item:lower() == fileName:lower() then
				exists = true
				break
			end
		end
		if not exists then
			names[#names + 1] = fileName
		end
		saveScriptIndex(names)
	end

	local function removeScriptIndex(name)
		local fileName = sanitizeScriptName(name)
		local names = readScriptIndex()
		for i = #names, 1, -1 do
			if names[i]:lower() == fileName:lower() then
				table.remove(names, i)
			end
		end
		saveScriptIndex(names)
	end

	local function setStatus(message, color)
		if NAStuff.ExecutorStatusLabel then
			NAStuff.ExecutorStatusLabel.Text = message or "Ready"
			NAStuff.ExecutorStatusLabel.TextColor3 = color or colors.subtle
		end
	end

	function ensureExecutorFolders()
		if not fsOk then
			return false
		end
		if not folderApiOk then
			return true
		end
		local ok = true
		local function mk(path)
			if not ok then
				return
			end
			local has = false
			local okCheck, result = pcall(isfolder, path)
			if okCheck and result == true then
				has = true
			end
			if not has then
				local okMake = pcall(makefolder, path)
				if not okMake then
					ok = false
				end
			end
		end
		mk(baseExecDir)
		mk(execDir)
		mk(scriptsDir)
		return ok
	end

	if fsOk then
		ensureExecutorFolders()
		pcall(function()
			if isfile(settingsFile) then
				local raw = readfile(settingsFile)
				if raw and raw ~= "" then
					local ok, decoded = pcall(HttpService.JSONDecode, HttpService, raw)
					if ok and type(decoded) == "table" then
						if type(decoded.syntax) == "boolean" then cfg.syntax = decoded.syntax end
						if type(decoded.lineNumbers) == "boolean" then cfg.lineNumbers = decoded.lineNumbers end
						if type(decoded.showHub) == "boolean" then cfg.showHub = decoded.showHub end
						if type(decoded.scriptHub) == "boolean" then cfg.showHub = decoded.scriptHub end
					end
				end
			end
		end)
	end

	local function saveSettings()
		if not fsOk then
			return false
		end
		if not ensureExecutorFolders() then
			return false
		end
		local payload = {
			syntax = cfg.syntax == true,
			lineNumbers = cfg.lineNumbers == true,
			showHub = cfg.showHub ~= false,
			scriptHub = cfg.showHub ~= false,
		}
		local ok, encoded = pcall(function()
			return HttpService:JSONEncode(payload)
		end)
		if ok and encoded then
			local wrote = pcall(writefile, settingsFile, encoded)
			return wrote == true
		end
		return false
	end

	local function getExecutorViewport()
		local screenGui = NAStuff and NAStuff.NASCREENGUI
		if screenGui and screenGui.AbsoluteSize and screenGui.AbsoluteSize.X > 0 and screenGui.AbsoluteSize.Y > 0 then
			return screenGui.AbsoluteSize
		end
		local cam = workspace and workspace.CurrentCamera
		if cam and cam.ViewportSize and cam.ViewportSize.X > 0 and cam.ViewportSize.Y > 0 then
			return cam.ViewportSize
		end
		return Vector2.new(1280, 720)
	end

	local function getSafePad()
		local padX, padY = 12, 12
		if GuiServiceRef and GuiServiceRef.GetGuiInset then
			local ok, insetA, insetB = pcall(function()
				return GuiServiceRef:GetGuiInset()
			end)
			if ok then
				padX += math.max(insetA.X, insetB.X)
				padY += math.max(insetA.Y, insetB.Y)
			end
		end
		return padX, padY
	end

	local function isTouchCompact(vp)
		local touch = UserInputServiceRef and UserInputServiceRef.TouchEnabled
		local mouse = UserInputServiceRef and UserInputServiceRef.MouseEnabled
		local key = UserInputServiceRef and UserInputServiceRef.KeyboardEnabled
		return IsOnMobile or vp.Y < 600 or vp.X < 900 or (touch and not (mouse or key))
	end

	local function clampSize(v, lo, hi)
		v = tonumber(v) or 0
		lo = tonumber(lo) or 0
		hi = tonumber(hi) or lo
		if hi < lo then
			return math.max(1, hi)
		end
		return math.clamp(v, lo, hi)
	end

	local function applyExecutorFrameSize()
		if not frame or not frame.Parent then
			return
		end
		local vp = getExecutorViewport()
		local padX, padY = getSafePad()
		local maxW = math.max(1, vp.X - padX * 2)
		local maxH = math.max(1, vp.Y - padY * 2)
		local mobile = isTouchCompact(vp)
		local defaultW = mobile and math.floor(vp.X * 0.965) or 920
		local defaultH = mobile and math.floor(vp.Y * (vp.Y < 520 and 0.88 or 0.90)) or 540
		local initialized = frame.GetAttribute and NAmanage.GetAttr(frame, "NAExecutorDefaultSized") == true
		local curW = tonumber(frame.Size.X.Offset) or 0
		local curH = tonumber(frame.Size.Y.Offset) or 0
		local targetW = initialized and curW or defaultW
		local targetH = initialized and curH or defaultH
		if targetW <= 0 then
			targetW = defaultW
		end
		if targetH <= 0 then
			targetH = defaultH
		end
		targetW = math.clamp(math.floor(targetW + 0.5), 1, maxW)
		targetH = math.clamp(math.floor(targetH + 0.5), 1, maxH)
		execResponsive.compact = targetW < 760 or targetH < 430
		execResponsive.phone = targetW < 560
		execResponsive.lastW = targetW
		execResponsive.lastH = targetH
		frame.AnchorPoint = Vector2.new(0, 0)
		if frame.AbsoluteSize.X ~= targetW or frame.AbsoluteSize.Y ~= targetH then
			frame.Size = UDim2.fromOffset(targetW, targetH)
		end
		if frame.SetAttribute then
			NAmanage.SetAttr(frame, "NAExecutorDefaultSized", true)
		end
		if not initialized then
			NAmanage.centerFrame(frame)
		else
			local x = math.floor(frame.Position.X.Scale * vp.X + frame.Position.X.Offset + 0.5)
			local y = math.floor(frame.Position.Y.Scale * vp.Y + frame.Position.Y.Offset + 0.5)
			x = math.clamp(x, padX, math.max(padX, vp.X - targetW - padX))
			y = math.clamp(y, padY, math.max(padY, vp.Y - targetH - padY))
			frame.Position = UDim2.fromOffset(x, y)
		end
	end
	NAmanage.Executor_ApplyResponsive = applyExecutorFrameSize
	local rootPad = InstanceNew("UIPadding")
	rootPad.PaddingBottom = UDim.new(0, 10)
	rootPad.PaddingLeft = UDim.new(0, 10)
	rootPad.PaddingRight = UDim.new(0, 10)
	rootPad.PaddingTop = UDim.new(0, 10)
	rootPad.Parent = container

	local topbar = frame:FindFirstChild("Topbar")
	local settingsButton = topbar and topbar:FindFirstChild("Settings")
	if topbar and not settingsButton then
		settingsButton = InstanceNew("TextButton")
		settingsButton.Name = "Settings"
		settingsButton.Parent = topbar
		settingsButton.BorderSizePixel = 0
		settingsButton.TextSize = 15
		settingsButton.TextColor3 = Color3.fromRGB(245, 245, 245)
		settingsButton.BackgroundColor3 = Color3.fromRGB(55, 55, 65)
		settingsButton.Font = Enum.Font.Gotham
		settingsButton.AnchorPoint = Vector2.new(1, 0.5)
		settingsButton.BackgroundTransparency = 0.3
		settingsButton.Size = UDim2.new(0, 24, 0, 24)
		settingsButton.Text = "S"
		settingsButton.Position = UDim2.new(1, -70, 0.5, 0)
		makeCornerAndStroke(settingsButton, 6, 2)
	end

	local tabsBar = InstanceNew("Frame")
	tabsBar.Name = "TabsBar"
	tabsBar.BackgroundTransparency = 1
	tabsBar.BorderSizePixel = 0
	tabsBar.Position = UDim2.new(0, 0, 0, 0)
	tabsBar.Size = UDim2.new(1, 0, 0, 34)
	tabsBar.Parent = container

	local tabScroll = InstanceNew("ScrollingFrame")
	tabScroll.Name = "Tabs"
	tabScroll.Active = true
	tabScroll.BackgroundTransparency = 1
	tabScroll.BorderSizePixel = 0
	tabScroll.CanvasSize = UDim2.new(0, 0, 0, 0)
	tabScroll.Position = UDim2.new(0, 0, 0, 0)
	tabScroll.ScrollBarImageColor3 = colors.subtle
	tabScroll.ScrollBarThickness = 3
	tabScroll.ScrollingDirection = Enum.ScrollingDirection.X
	tabScroll.Size = UDim2.new(1, -42, 1, 0)
	tabScroll.Parent = tabsBar

	local tabWrap = InstanceNew("Frame")
	tabWrap.Name = "Wrap"
	tabWrap.BackgroundTransparency = 1
	tabWrap.BorderSizePixel = 0
	tabWrap.Position = UDim2.new(0, 0, 0, 0)
	tabWrap.Size = UDim2.new(0, 0, 1, 0)
	tabWrap.Parent = tabScroll

	local tabLayout = InstanceNew("UIListLayout")
	tabLayout.FillDirection = Enum.FillDirection.Horizontal
	tabLayout.HorizontalAlignment = Enum.HorizontalAlignment.Left
	tabLayout.Padding = UDim.new(0, 6)
	tabLayout.SortOrder = Enum.SortOrder.LayoutOrder
	tabLayout.VerticalAlignment = Enum.VerticalAlignment.Center
	tabLayout.Parent = tabWrap

	local addTabButton = makeButton(tabsBar, "+", colors.panel3)
	addTabButton.Name = "AddTab"
	addTabButton.Position = UDim2.new(1, -34, 0, 1)
	addTabButton.Size = UDim2.new(0, 34, 0, 28)
