			upButton.Size = UDim2.new(1, 0, 0, 16)
			downButton.AnchorPoint = Vector2.new(0, 1)
			downButton.Position = UDim2.new(0, 0, 1, 0)
			downButton.Size = UDim2.new(1, 0, 0, 16)
			track.Position = UDim2.new(0, 0, 0, 18)
