	local status = InstanceNew("TextLabel")
	status.BackgroundTransparency = 1
	status.Font = Enum.Font.Gotham
	status.Text = fsOk and ("Ready | "..dir) or "Filesystem unavailable"
	status.TextColor3 = fsOk and col.sub or col.err
