	local pageBar = InstanceNew("Frame")
	pageBar.BackgroundTransparency = 1
	pageBar.BorderSizePixel = 0
	pageBar.AnchorPoint = Vector2.new(0.5, 0)
	pageBar.Position = UDim2.new(0.5, 30, 0, 0)
