NAStuff.MgmtUI.loopDel = type(NAStuff.MgmtUI.loopDel) == "string" and NAStuff.MgmtUI.loopDel or "1"
NAStuff.MgmtUI.aexecCmd = type(NAStuff.MgmtUI.aexecCmd) == "string" and NAStuff.MgmtUI.aexecCmd or ""
