originalIO.parseRobloxVersionBody=function(body)
	if type(body) ~= "string" then return nil end
	if body:sub(1,3) == "\239\187\191" then body = body:sub(4) end
	local ok, decoded = pcall(HttpService.JSONDecode, HttpService, body)
	if ok and type(decoded) == "table" then return decoded end
	local a,depth,inStr,esc=nil,0,false,false
	for i=1,#body do
		local c=body:sub(i,i)
		if inStr then
			if esc then esc=false elseif c=="\\" then esc=true elseif c=='"' then inStr=false end
		else
			if c=='"' then inStr=true
			elseif c=='{' then depth=depth+1 a=a or i
			elseif c=='}' and depth>0 then
				depth=depth-1
				if depth==0 and a then
					local ok2, j = pcall(HttpService.JSONDecode, HttpService, body:sub(a,i))
					if ok2 and type(j)=="table" then return j end
				end
			end
		end
	end
	return nil
end

originalIO.normalizeRobloxVersionData=function(decoded)
	if type(decoded) ~= "table" then
		return nil
	end

	local function normKey(value)
		if type(value) ~= "string" then
			return ""
		end
		return Lower(value):gsub("[^%w]", "")
	end

	local function readValue(tbl, keys)
		if type(tbl) ~= "table" or type(keys) ~= "table" then
			return nil
		end
		for i = 1, #keys do
			local key = keys[i]
			local value = tbl[key]
			if value ~= nil and tostring(value) ~= "" then
				return tostring(value)
			end
		end
		local wanted = {}
		for i = 1, #keys do
			wanted[normKey(keys[i])] = true
		end
		for key, value in pairs(tbl) do
			if value ~= nil and tostring(value) ~= "" and wanted[normKey(key)] then
				return tostring(value)
			end
		end
		return nil
	end

	local function normalizeCandidate(tbl)
		if type(tbl) ~= "table" then
			return nil
		end

		local out = {
			Windows = readValue(tbl, {"Windows", "windows", "win", "WindowsVersion", "windowsVersion"});
			Mac = readValue(tbl, {"Mac", "mac", "MacVersion", "macVersion"});
			Android = readValue(tbl, {"Android", "android", "AndroidVersion", "androidVersion"});
			iOS = readValue(tbl, {"iOS", "ios", "IOS", "iOs", "iOSVersion", "iosVersion"});
			WindowsDate = readValue(tbl, {"WindowsDate", "windowsDate", "WindowsUpdated", "windowsUpdated", "windowsLastUpdated"});
			MacDate = readValue(tbl, {"MacDate", "macDate", "MacUpdated", "macUpdated", "macLastUpdated"});
			AndroidDate = readValue(tbl, {"AndroidDate", "androidDate", "AndroidUpdated", "androidUpdated", "androidLastUpdated"});
			iOSDate = readValue(tbl, {"iOSDate", "iosDate", "IOSDate", "iOSUpdated", "iosUpdated", "iosLastUpdated"});
		}

		local genericVersion = readValue(tbl, {"version", "Version", "clientVersionUpload", "clientVersion"})
		local genericDate = readValue(tbl, {"fetchedAt", "updatedAt", "timestamp", "date"})
		if genericVersion then
			out.Windows = out.Windows or genericVersion
			out.Mac = out.Mac or genericVersion
			out.Android = out.Android or genericVersion
			out.iOS = out.iOS or genericVersion
		end
		if genericDate then
			out.WindowsDate = out.WindowsDate or genericDate
			out.MacDate = out.MacDate or genericDate
			out.AndroidDate = out.AndroidDate or genericDate
			out.iOSDate = out.iOSDate or genericDate
		end

		if out.Windows or out.Mac or out.Android or out.iOS then
			return out
		end
		return nil
	end

	local candidates = {
		decoded;
		decoded.current;
		decoded.data;
		decoded.data and decoded.data.current;
		decoded.versions;
		decoded.versions and decoded.versions.current;
	}
	for _, candidate in ipairs(candidates) do
		local normalized = normalizeCandidate(candidate)
		if normalized then
			return normalized
		end
	end

	return nil
end

originalIO.fetchGitHubCommits = function(forceRefresh)
	local cached = NAStuff.GitHubCommits
	local lastFetch = NAStuff.GitHubCommitsLastFetch or 0
	if cached and not forceRefresh and (tick() - lastFetch) < 300 then
		return true, cached
	end

	local requestFunc = opt and opt.NAREQUEST
	if type(requestFunc) ~= "function" then
		return false, "HTTP request function is unavailable"
	end

	local baseUrl = opt and opt.githubUrl
	if type(baseUrl) ~= "string" or baseUrl == "" then
		return false, "GitHub URL is not configured"
	end

	local endpoints = {}
	local function appendEndpoint(url)
		if url and url ~= "" then
			Insert(endpoints, url)
		end
	end

	appendEndpoint(baseUrl)

	if not baseUrl:lower():find("^https?://r%.jina%.ai/") then
		appendEndpoint("https://r.jina.ai/"..baseUrl)
	end

	if _na_env and rawget(_na_env, "GITHUB_PROXY") then
		local proxy = tostring(_na_env.GITHUB_PROXY)
		if proxy ~= "" then
			appendEndpoint(proxy)
		end
	end

	local headers = {}
	for key, value in pairs(NAStuff.GitHubCommitHeaders or {}) do
		headers[key] = value
	end

	local lastError
	for _, endpoint in ipairs(endpoints) do
		local sep = endpoint:find("?", 1, true) and "&" or "?"
		local cacheBuster = "_="..tostring(os.time())..tostring(math.random(1, 1e6))
		local url = endpoint..sep..cacheBuster
		local okRequest, response = pcall(requestFunc, {
			Url = url;
			Method = "GET";
			Headers = headers;
			Timeout = 8;
			FollowRedirects = true;
			SslVerify = false;
		})
		if okRequest and response then
			local status = tonumber(response.StatusCode) or tonumber(response.Status)
			local body = response.Body or response.body
			if status == 200 and type(body) == "string" then
				local decodeOk, decoded = pcall(HttpService.JSONDecode, HttpService, body)
				if decodeOk and type(decoded) == "table" then
					NAStuff.GitHubCommits = decoded
					NAStuff.GitHubCommitsLastFetch = tick()
					return true, decoded
				else
					lastError = "Invalid JSON response"
				end
			elseif status == 304 and cached then
				NAStuff.GitHubCommitsLastFetch = tick()
				return true, cached
			else
				local statusText = status and tostring(status) or "unknown"
				lastError = Format("GitHub request failed (HTTP %s)", statusText)
			end
		else
			local err = okRequest and "Unknown response error" or tostring(response)
			lastError = err
		end
	end

	if type(baseUrl) == "string" and baseUrl ~= "" then
		local sep = baseUrl:find("?", 1, true) and "&" or "?"
		local cacheBuster = "_="..tostring(os.time())..tostring(math.random(1, 1e6))
		local directUrl = baseUrl..sep..cacheBuster
		local okDirect, bodyDirect = pcall(function()
			return HttpService:GetAsync(directUrl)
		end)
		if okDirect and type(bodyDirect) == "string" then
			local decodeOk, decoded = pcall(HttpService.JSONDecode, HttpService, bodyDirect)
			if decodeOk and type(decoded) == "table" then
				NAStuff.GitHubCommits = decoded
				NAStuff.GitHubCommitsLastFetch = tick()
				return true, decoded
			end
		end
	end

	return false, lastError or NAStuff.GitHubFailureText
end

originalIO.sanitizeCommitMessage = function(message)
	message = tostring(message or "(no message)")
	message = message:gsub("[%c]", " ")
	message = message:gsub("%s+", " ")
	if #message > 70 then
		message = message:sub(1, 67).."..."
	end
	return message
end

originalIO.formatCommitAuthor = function(commit)
	if type(commit) ~= "table" then
		return "Unknown author"
	end
	local commitInfo = commit.commit or {}
	local authorInfo = commitInfo.author or {}
	local fallbackAuthor = commit.author or {}
	local nickname = authorInfo.name
	local username = fallbackAuthor.login
	if nickname and username then
		if nickname == username then
			return nickname
		else
			return Format("%s (%s)", nickname, username)
		end
	elseif nickname then
		return nickname
	elseif username then
		return username
	end
	return "Unknown author"
end

originalIO.formatCommitDate = function(isoDate)
	if type(isoDate) ~= "string" then
		return "Unknown date", nil
	end
	local year, month, day, hour, minute = isoDate:match("^(%d+)%-(%d+)%-(%d+)T(%d+):(%d+)")
	if year and month and day and hour and minute then
		local display = Format("%02d/%02d/%s %s:%s UTC", tonumber(month), tonumber(day), year, hour, minute)
		local shortDate = Format("%02d/%02d/%s", tonumber(month), tonumber(day), year)
		return display, shortDate
	end
	return isoDate, nil
end

NAmanage.FormatGitHubCommitSummary = function(commit)
	if type(commit) ~= "table" then
		return NAStuff.GitHubFailureText
	end
	local sha = commit.sha and tostring(commit.sha):sub(1, 7) or "unknown"
	local commitInfo = commit.commit or {}
	local message = originalIO.sanitizeCommitMessage(commitInfo.message)
	return Format("%s (%s)", message, sha)
end

NAmanage.UpdateGitHubCommitUI = function(commits, statusMessage)
	commits = commits or NAStuff.GitHubCommits
	local commit = (type(commits) == "table" and commits[1]) or nil
	local messageField = NAStuff.GitHubCommitMessageField
	local authorField = NAStuff.GitHubCommitAuthorField
	local dateField = NAStuff.GitHubCommitDateField

	local endpointField = NAStuff.GitHubEndpointField
	if endpointField then
		endpointField.Text = (type(opt.githubUrl) == "string" and opt.githubUrl ~= "" and opt.githubUrl) or "Unavailable"
	end

	if commit then
		local message = NAmanage.FormatGitHubCommitSummary(commit)
		local authorDisplay = originalIO.formatCommitAuthor(commit)
		local commitInfo = commit.commit or {}
		local authorInfo = commitInfo.author or commitInfo.committer or {}
		local dateDisplay, shortDate = originalIO.formatCommitDate(authorInfo.date)

		if messageField then
			messageField.Text = message or NAStuff.GitHubEmptyText
		end
		if authorField then
			authorField.Text = authorDisplay or NAStuff.GitHubEmptyText
		end
		if dateField then
			dateField.Text = dateDisplay or NAStuff.GitHubEmptyText
		end

		if shortDate then
			opt.NAupdDate = shortDate
		end
	else
		local fallback = statusMessage or NAStuff.GitHubEmptyText
		if messageField then
			messageField.Text = fallback
		end
		if authorField then
			authorField.Text = fallback
		end
		if dateField then
			dateField.Text = fallback
		end
	end
end

NAmanage.RefreshGitHubCommits = function(forceRefresh)
	local ok, result = originalIO.fetchGitHubCommits(forceRefresh)
	if ok then
		NAmanage.UpdateGitHubCommitUI(result)
	else
		local message = result or NAStuff.GitHubFailureText
		if type(message) == "string" and #message > 128 then
			message = message:sub(1, 125).."..."
		end
		warn("[NA] GitHub commit fetch failed:", message)
		NAmanage.UpdateGitHubCommitUI(nil, "Error: "..message)
	end
	return ok
end

originalIO.fetchRobloxVersionData=function(forceRefresh)
	local cached = NAStuff.RobloxVersionData
	local lastFetch = NAStuff.RobloxVersionLastFetch or 0
	if cached and not forceRefresh and (tick() - lastFetch) < 300 then
		return true, cached
	end

	local function decodeAndCache(body)
		if type(body) ~= "string" or body == "" then
			return nil
		end
		local decoded = originalIO.normalizeRobloxVersionData(originalIO.parseRobloxVersionBody(body))
		if decoded then
			NAStuff.RobloxVersionData = decoded
			NAStuff.RobloxVersionLastFetch = tick()
			NAStuff.RobloxVersionFromRemote = true
			return decoded
		end
		return nil
	end

	local function extractResponseBody(response)
		if type(response) == "string" then
			return response
		end
		if type(response) ~= "table" then
			return nil
		end
		local body = response.Body
			or response.body
			or response.Data
			or response.data
			or response.Text
			or response.text
			or response.Content
			or response.content
			or response.ResponseBody
			or response.responseBody
			or response[1]
		if type(body) == "table" then
			body = body.Body
				or body.body
				or body.Data
				or body.data
				or body.Text
				or body.text
				or body.Content
				or body.content
				or body.ResponseBody
				or body.responseBody
				or body[1]
		end
		return type(body) == "string" and body or nil
	end

	local function statusOk(response)
		if type(response) ~= "table" then
			return true
		end
		local code = tonumber(response.StatusCode)
			or tonumber(response.Status)
			or tonumber(response.statusCode)
			or tonumber(response.status)
			or tonumber(response.Code)
			or tonumber(response.code)
		if not code then
			return true
		end
		return code >= 200 and code < 300
	end

	local requestFunc = opt and opt.NAREQUEST
	local function tryRequest(url, payload)
		if type(requestFunc) ~= "function" then
			return nil
		end
		local okReq, response = pcall(requestFunc, payload)
		if not (okReq and response and statusOk(response)) then
			return nil
		end
		local body = extractResponseBody(response)
		return decodeAndCache(body)
	end

	local function tryGetAsync(url)
		if not (HttpService and type(HttpService.GetAsync) == "function") then
			return nil
		end
		local okHttp, body = pcall(HttpService.GetAsync, HttpService, url)
		if okHttp and type(body) == "string" then
			return decodeAndCache(body)
		end
		return nil
	end

	local function tryHttpGet(url)
		local okHttp, body = pcall(function()
			return game and game.HttpGet and game:HttpGet(url)
		end)
		if okHttp and type(body) == "string" then
			return decodeAndCache(body)
		end
		return nil
	end

	local function localDeviceFallback()
		local okVersion, currentVersion = pcall(function()
			return version and version() or nil
		end)
		if not okVersion or type(currentVersion) ~= "string" or currentVersion == "" then
			if _VERSION then
				currentVersion = tostring(_VERSION)
			else
				return nil
			end
		end

		local fallback = {}
		local nowText = os.date("!%m/%d/%Y, %I:%M:%S %p UTC")
		local sourceText = "Local Client ("..nowText..")"
		fallback.Windows = currentVersion
		fallback.WindowsDate = sourceText
		fallback.Mac = currentVersion
		fallback.MacDate = sourceText
		fallback.Android = currentVersion
		fallback.AndroidDate = sourceText
		fallback.iOS = currentVersion
		fallback.iOSDate = sourceText
		return fallback
	end

	local requestPayloads = {
		function(url)
			return {
				Url = url;
				Method = "GET";
				Headers = NAStuff.RobloxVersionHeaders;
				Timeout = 8;
				FollowRedirects = true;
				SslVerify = false;
			}
		end;
		function(url)
			return {
				Url = url;
				Method = "GET";
				Headers = { ["Accept"] = "application/json" };
				Timeout = 8;
				FollowRedirects = true;
				SslVerify = false;
			}
		end;
		function(url)
			return {
				Url = url;
				Method = "GET";
				Headers = { ["Accept"] = "application/json" };
			}
		end;
		function(url)
			return {
				Url = url;
				Method = "GET";
			}
		end;
		function(url)
			return {
				url = url;
				method = "GET";
			}
		end;
	}

	local attempts = forceRefresh and 1 or 2
	for attempt = 1, attempts do
		for _, baseUrl in ipairs(NAStuff.RobloxVersionEndpoints) do
			if baseUrl and baseUrl ~= "" then
				local url = baseUrl..((Find(baseUrl, "?", 1, true) and "&" or "?").."_="..tostring(os.time())..tostring(math.random(1,1e6)))
				if type(requestFunc) == "function" then
					for i = 1, #requestPayloads do
						local decoded = tryRequest(url, requestPayloads[i](url))
						if decoded then
							return true, decoded
						end
					end
				end
				local decodedAsync = tryGetAsync(url)
				if decodedAsync then
					return true, decodedAsync
				end
				local decodedHttpGet = tryHttpGet(url)
				if decodedHttpGet then
					return true, decodedHttpGet
				end
			end
		end
		if attempt < attempts then
			Wait(0.15)
		end
	end

	local localFallback = localDeviceFallback()
	if localFallback then
		NAStuff.RobloxVersionData = localFallback
		NAStuff.RobloxVersionLastFetch = tick()
		NAStuff.RobloxVersionFromRemote = false
		return true, localFallback
	end

	if type(cached) == "table" and next(cached) ~= nil then
		return true, cached
	end

	return false, cached
end

NAStuff.RobloxVersionLoadingText = "Loading..."
NAStuff.RobloxVersionMissingText = "Unavailable"
NAStuff.RobloxVersionFailureText = "Failed to load"

NAStuff.RobloxVersionRows = {}
NAStuff.RobloxVersionFromRemote = NAStuff.RobloxVersionFromRemote == true
originalIO.addRobloxVersionSection=function(sectionTitle, versionKey, dateKey)
	NAgui.addSection(sectionTitle)
	local versionField = NAgui.addInfo("Version", NAStuff.RobloxVersionLoadingText)
	local updatedField = NAgui.addInfo("Last Updated", NAStuff.RobloxVersionLoadingText)
	Insert(NAStuff.RobloxVersionRows, {
		versionKey = versionKey;
		dateKey = dateKey;
		versionField = versionField;
		dateField = updatedField;
	})
end

originalIO.withRobloxVersionTab=function(callback)
	if type(callback) ~= "function" then
		return false
	end

	local targetTab = NA_TABS.TAB_ROBLOX_DATA

	local deadline = os.clock() + 5
	while os.clock() < deadline do
		if TabManager and TabManager.tabs and TabManager.tabs[targetTab] and NAgui and NAgui.setTab and NAgui.getActiveTab then
			break
		end
		Wait()
	end

	if not (TabManager and TabManager.tabs and TabManager.tabs[targetTab] and NAgui and NAgui.setTab and NAgui.getActiveTab) then
		return false
	end

	local previousTab = NAgui.getActiveTab()
	if previousTab ~= targetTab then
		pcall(NAgui.setTab, targetTab)
	end

	local ok, result = pcall(callback)

	if previousTab and previousTab ~= targetTab then
		pcall(NAgui.setTab, previousTab)
	end

	return ok, result
end

originalIO.hasRobloxVersionData=function(data)
	if type(data) ~= "table" then
		return false
	end
	local keys = { "Windows", "Mac", "Android", "iOS" }
	for i = 1, #keys do
		local value = data[keys[i]]
		if value ~= nil and tostring(value) ~= "" then
			return true
		end
	end
	return false
end

originalIO.renderRobloxVersionSections=function(ok, data)
	local canRenderRemote = ok and NAStuff.RobloxVersionFromRemote == true and originalIO.hasRobloxVersionData(data)
	if not canRenderRemote then
		NAStuff.RobloxVersionRows = {}
		return false
	end

	local rendered = false
	local okRender = originalIO.withRobloxVersionTab(function()
		NAStuff.RobloxVersionRows = {}
		NAgui.addSection("Powered by weao.xyz API")
		originalIO.addRobloxVersionSection("Windows", "Windows", "WindowsDate")
		originalIO.addRobloxVersionSection("Mac", "Mac", "MacDate")
		originalIO.addRobloxVersionSection("Android", "Android", "AndroidDate")
		originalIO.addRobloxVersionSection("iOS", "iOS", "iOSDate")

		local fallbackText = ok and NAStuff.RobloxVersionMissingText or NAStuff.RobloxVersionFailureText
		for _, entry in ipairs(NAStuff.RobloxVersionRows) do
			if entry.versionField then
				local v = (type(data) == "table" and data[entry.versionKey]) or fallbackText
				entry.versionField.Text = v and tostring(v) or fallbackText
			end
			if entry.dateField then
				local d = (type(data) == "table" and data[entry.dateKey]) or fallbackText
				entry.dateField.Text = d and tostring(d) or fallbackText
			end
		end

		rendered = true
	end)

	return okRender == true and rendered == true
end

SpawnCall(function()
	local clientVersion = "Unknown"
	local okVersion, versionValue = pcall(function()
		return version and version() or nil
	end)
	if okVersion and versionValue ~= nil then
		clientVersion = tostring(versionValue)
	elseif _VERSION then
		clientVersion = tostring(_VERSION)
	end
	local luauVersion = tostring(_VERSION or "")
	local textValue = clientVersion
	if luauVersion ~= "" and luauVersion ~= clientVersion then
		textValue = clientVersion.."-"..luauVersion
	end
	NAgui.addInfo("Your Version", textValue, {
		minTextSize = 11;
		clampAlignLeft = false;
		autoShrink = true;
	})
end)

NAgui.addTab(NA_TABS.TAB_CONTRIBUTORS, { order = 14, textIcon = "code" })
NAgui.setTab(NA_TABS.TAB_CONTRIBUTORS)

if not NAStuff.ContributorsTabInitialized then
	NAmanage._sourceTrail = NAmanage._sourceTrail or function()
		if type(NAStuff.Contributors) == "table" and #NAStuff.Contributors > 0 then
			return NAStuff.Contributors
		end

		local sealed = {
			{
				name = { 104, 140, 132, 122, 136, 128, 114 };
				handle = { 82, 127, 136, 136, 123, 141, 118, 132, 140, 120, 118, 143, 144, 128, 135 };
				role = { 97, 138, 130, 122, 136 };
				link = { 122, 135, 136, 133, 137, 81, 64, 65, 122, 125, 137, 126, 140, 115, 64, 118, 131, 130, 69, 131, 133, 133, 120, 138, 122, 136, 144, 117, 115, 140, 141, 132, 139 };
			};
			{
				name = { 104, 124, 132, 122, 136 };
				handle = { 82, 86, 131, 136, 131, 124, 125, 126, 116 };
				role = { 97, 138, 130, 122, 136 };
				link = { 122, 135, 136, 133, 137, 81, 64, 65, 122, 125, 137, 126, 140, 115, 64, 118, 131, 130, 69, 90, 128, 133, 128, 121, 129, 130, 120, 62, 136 };
			};
			{
				name = { 131, 124, 132, 138 };
				handle = { 82, 127, 140, 137, 123 };
				role = { 97, 133, 125, 124, 127, 133, 114, 126, 51, 99, 140, 132, 124, 131 };
				link = { 122, 135, 136, 133, 137, 81, 64, 65, 122, 125, 137, 126, 140, 115, 64, 118, 131, 130, 69, 131, 137, 134, 120 };
			};
		}

		local function unseal(nums)
			local chars = {}
			for i = 1, #nums do
				chars[i] = string.char(nums[i] - ((i % 7) + 17))
			end
			return table.concat(chars)
		end

		local decoded = {}
		for i, row in ipairs(sealed) do
			decoded[i] = {
				name = unseal(row.name);
				handle = unseal(row.handle);
				role = unseal(row.role);
				link = unseal(row.link);
			}
		end
		NAStuff.Contributors = decoded
		return decoded
	end

	local function copyContributorLink(label, url)
		url = tostring(url or "")
		if url == "" then
			return
		end
		if type(setclipboard) == "function" then
			local okCopy = pcall(setclipboard, url)
			if okCopy then
				DoNotif(label.." link copied.", 2)
				return
			end
		end
		if type(DoWindow) == "function" then
			DoWindow(url, label)
		else
			DoNotif(label..": "..url, 4)
		end
	end

	NAgui.addSection("Official Contributors")
	for _, contributor in ipairs(NAmanage._sourceTrail()) do
		local name = tostring(contributor.name or "")
		local handle = tostring(contributor.handle or "")
		local role = tostring(contributor.role or "")
		local link = tostring(contributor.link or "")
		local label = name
		if handle ~= "" then
			label = label.." ("..handle..")"
		end
		NAgui.addInfo(role ~= "" and role or "Contributor", label, {
			minTextSize = 10;
			autoShrink = true;
		})
		if link ~= "" then
			NAgui.addButton("Copy "..name.." GitHub", function()
				copyContributorLink(name, link)
			end)
		end
	end

	NAgui.addSection("Verification")
	NAgui.addInfo("Trust Note", "If this looks different, check it against the official repo.", {
		textSize = 12;
		minTextSize = 8;
		autoShrink = true;
	})
	NAgui.addButton("Copy Official Repository", function()
		copyContributorLink("Official repository", NAmanage._sourceGlyph(NAStuff.officialRepoLink))
	end)
	NAgui.addButton("Copy Official Source", function()
		copyContributorLink("Official source", opt.loader or "")
	end)

	NAStuff.ContributorsTabInitialized = true
end

NAgui.addTab(NA_TABS.TAB_ADMIN_INFO, { order = 15, textIcon = "github" })
NAgui.setTab(NA_TABS.TAB_ADMIN_INFO)

if not NAStuff.GitHubTabInitialized then
	NAgui.addSection("Latest Commit")
	NAStuff.GitHubCommitMessageField = NAgui.addInfo("Commit", NAStuff.GitHubLoadingText)
	NAStuff.GitHubCommitAuthorField = NAgui.addInfo("Author", NAStuff.GitHubLoadingText)
	NAStuff.GitHubCommitDateField = NAgui.addInfo("Updated", NAStuff.GitHubLoadingText)

	NAgui.addButton("Refresh Commits", function()
		NAmanage.UpdateGitHubCommitUI(nil, NAStuff.GitHubLoadingText)
		SpawnCall(function()
			local ok, result = originalIO.fetchGitHubCommits(true)
			if ok then
				NAmanage.UpdateGitHubCommitUI(result)
				if DoNotif then
					DoNotif("GitHub commits updated.", 2)
				end
			else
				local message = result or NAStuff.GitHubFailureText
				if type(message) == "string" and #message > 128 then
					message = message:sub(1, 125).."..."
				end
				warn("[NA] GitHub commit refresh failed:", message)
				NAmanage.UpdateGitHubCommitUI(nil, "Error: "..tostring(message))
				if DoNotif then
					DoNotif("Failed to refresh GitHub commits.", 3)
				end
			end
		end)
	end)

	NAStuff.GitHubTabInitialized = true
end

SpawnCall(function()
	local ok, data = originalIO.fetchRobloxVersionData()
	originalIO.renderRobloxVersionSections(ok, data)
end)

NAmanage.UpdateGitHubCommitUI(nil, NAStuff.GitHubLoadingText)

SpawnCall(function()
	NAmanage.RefreshGitHubCommits(false)
end)

NAgui.setTab(NAgui.getActiveTab())

SpawnCall(function()
	Wait()
	local defaultTab = (NA_TABS and NA_TABS.TAB_GENERAL) or (TabManager and TabManager.lastNonAll) or NAgui.getActiveTab()
	if defaultTab and TabManager and TabManager.current ~= defaultTab then
		NAgui.setTab(defaultTab)
	end
end)

pcall(function()
	if type(NAmanage.queueAssetMethodResync) == "function" then
		NAmanage.queueAssetMethodResync({ 0.25, 3 }, { silent = true })
	end
	if type(NAmanage.isCommandDataStale) == "function" and NAmanage.isCommandDataStale() then
		if NAAssetsLoading and NAAssetsLoading.setStatus then
			NAAssetsLoading.setStatus("warming command list and autofill")
		end
		if type(NAmanage.queueCommandDataBuild) == "function" then
			pcall(NAmanage.queueCommandDataBuild, { force = true })
		elseif type(NAgui.loadCMDS) == "function" then
			pcall(NAgui.loadCMDS, { force = true })
		end
	end
	if NAAssetsLoading and NAAssetsLoading.setStatus and NAAssetsLoading.setPercent and NAAssetsLoading.completed then
		NAAssetsLoading.setStatus("ready")
		NAAssetsLoading.setPercent(1)
		if typeof(NAAssetsLoading.completed) == "Instance" then
			NAmanage.SetAttr(NAAssetsLoading.completed, "Completed", true)
		elseif type(NAAssetsLoading.completed) == "table" then
			NAAssetsLoading.completed.Completed = true
		end
		NAAssetsLoading._finalized = true
		NAAssetsLoading.ui = nil
		NAAssetsLoading.setStatus = nil
		NAAssetsLoading.setPercent = nil
		NAAssetsLoading.completed = nil
		NAAssetsLoading.getSkip = nil
		NAAssetsLoading.setMinimizedState = nil
		NAAssetsLoading.progress = nil
		NAAssetsLoading.progressPercent = nil
	end
	if NAStuff.AutoPreloadAssets then
		Defer(function()
			Wait(1.5)
			NAmanage.StartAssetPreload({
				silent = true,
				st = true,
			})
		end)
	end
end)

